                try self.reportInvalidClassElementModifierForProperty(mods);
                const name_id = try self.internPropertyName(name_tok, name_span);
                const name_node = try self.builder.addIdentifier(name_span, name_id);
                const prop = try self.builder.addObjectPropertyFullEx(
                    .{ .start = member_start.span.start, .end = self.tokens[self.cursor - 1].span.end },
                    name_node,
                    default_value,
                    type_anno,
                    false,
                    default_value == hir_mod.none_node_id,
                    false,
                    mods.is_static,
                    mods.visibility,
                    mods.is_override,
                    mods.is_accessor,
                );
                try members.append(self.gpa, prop);
                continue;
            }
            // Unknown — advance to keep error-recovery flowing.
            _ = self.advance();
        }
        const close = if (recovered_nested_declaration)
            self.peek()
        else if (self.peek().kind == .close_brace)
            self.advance()
        else blk: {
            const at = self.peek();
            if (!self.hasDiagnosticAt(1005, at.span.start)) {
                try self.reportCodeAtWithMatchedPair(
                    at.span.start,
                    at.line,
                    1005,
                    "'}' expected.",
                    class_body_open.span.start,
                    "{",
                    "}",
                );
            }
            break :blk at;
        };
        return try self.builder.addClass(
            .{ .start = span_start, .end = close.span.end },
            name,
            class_type_params,
            extends,
            implements_list.items,
            members.items,
            is_abstract,
        );
    }

    fn parseClassStaticBlockBody(self: *Parser) ParseError!NodeId {
        self.static_block_depth += 1;
        defer self.static_block_depth -= 1;
        self.function_depth += 1;
        defer self.function_depth -= 1;

        const prev_loop_depth = self.loop_depth;
        const prev_loop_switch_depth = self.loop_switch_depth;
        const prev_outer_loop_or_switch_active = self.outer_loop_or_switch_active;
        self.outer_loop_or_switch_active = prev_outer_loop_or_switch_active or prev_loop_switch_depth > 0;
        self.loop_depth = 0;
        self.loop_switch_depth = 0;
        defer self.loop_depth = prev_loop_depth;
        defer self.loop_switch_depth = prev_loop_switch_depth;
        defer self.outer_loop_or_switch_active = prev_outer_loop_or_switch_active;

        return try self.parseBlockStatement();
    }

    fn memberAccessToTypeRef(self: *Parser, expr: NodeId, args: []const NodeId) ParseError!NodeId {
        var names: std.ArrayListUnmanaged(hir_mod.StringId) = .empty;
        defer names.deinit(self.gpa);
        var cur = expr;
        while (self.hir.kindOf(cur) == .member_access) {
            const m = hir_mod.memberOf(self.hir, cur);
            try names.append(self.gpa, m.name);
            cur = m.object;
        }
        if (self.hir.kindOf(cur) != .identifier or names.items.len == 0) return expr;
        const root = hir_mod.identifierOf(self.hir, cur).name;
        try names.append(self.gpa, root);

        var qualifiers: std.ArrayListUnmanaged(NodeId) = .empty;
        defer qualifiers.deinit(self.gpa);
        var i = names.items.len;
        while (i > 1) {
            i -= 1;
            const q_name = names.items[i];
            const q_node = try self.builder.addIdentifier(self.hir.spanOf(cur), q_name);
            try qualifiers.append(self.gpa, q_node);
        }
        const final_name = names.items[0];
        return try self.builder.addTypeRef(
            .{ .start = self.hir.spanOf(expr).start, .end = self.tokens[self.cursor - 1].span.end },
            final_name,
            qualifiers.items,
            args,
        );
    }

    /// Tracks the TS access-modifier keywords the member-parsing
    /// loop has consumed before the member name. Other modifiers
    /// (`override`, `declare`, `out`, `in`) are parsed but discarded
    /// — access modifiers, `static`, `accessor`, `readonly`,
    /// `async`, `abstract` flow into HIR for decorator and class-
    /// member emit.
    const ClassModifiers = struct {
        visibility: hir_mod.Visibility = .public,
        has_accessibility: bool = false,
        accessibility_token: ?Token = null,
        is_static: bool = false,
        is_async: bool = false,
        is_override: bool = false,
        is_abstract: bool = false,
        is_readonly: bool = false,
        is_accessor: bool = false,
        accessor_token: ?Token = null,
        const_token: ?Token = null,
        invalid_class_element_modifier: ?Token = null,
        /// `declare` is valid on class *property* members (it tells the
        /// type system the field is initialized externally) but invalid
        /// on methods/constructors/accessors. Track it separately from
        /// the unconditional-invalid `export` keyword so the
        /// member-kind branch can decide whether to surface TS1031.
        declare_token: ?Token = null,
        async_token: ?Token = null,
        abstract_token: ?Token = null,
        readonly_token: ?Token = null,
        static_token: ?Token = null,
        override_token: ?Token = null,
        first_modifier_token: ?Token = null,
        reported_duplicate_accessibility: bool = false,
    };

    fn skipClassModifiers(self: *Parser) ParseError!ClassModifiers {
        var mods: ClassModifiers = .{};
        while (true) {
            const k = self.peek().kind;
            // `export` isn't in `isModifierKeyword` (it's a top-level
            // statement keyword), but inside a class body it shows up
            // only in error fixtures like `class C { export foo() }`.
            // Capture it here so `reportInvalidClassElementModifier`
            // can fire TS1031. Mirrors upstream
            // `parserConstructorDeclaration3`, `parserMemberFunctionDeclaration4`,
            // `parserMemberVariableDeclaration4`.
            if (k == .kw_export) {
                const next_can_start_member = canStartClassMemberAfterModifier(self.peekAt(1).kind);
                if (!next_can_start_member and !self.peekAt(1).kind.isModifierKeyword()) {
                    return mods;
                }
                const mod = self.advance();
                if (mods.first_modifier_token == null) mods.first_modifier_token = mod;
                if (mods.invalid_class_element_modifier == null) mods.invalid_class_element_modifier = mod;
                continue;
            }
            if (k == .kw_const) {
                const next_can_start_member = canStartClassMemberAfterModifier(self.peekAt(1).kind);
                if (!next_can_start_member and !self.peekAt(1).kind.isModifierKeyword()) {
                    return mods;
                }
                const mod = self.advance();
                if (mods.first_modifier_token == null) mods.first_modifier_token = mod;
                if (mods.const_token == null) mods.const_token = mod;
                continue;
            }
            if (k.isModifierKeyword()) {
                const next_can_start_member = canStartClassMemberAfterModifier(self.peekAt(1).kind);
                if (!next_can_start_member and !self.peekAt(1).kind.isModifierKeyword()) {
                    return mods;
                }
                if (isAccessibilityModifier(k) and
                    !next_can_start_member and
                    !self.peekAt(1).kind.isModifierKeyword())
                {
                    return mods;
                }
                if (mods.is_static and isAccessibilityModifier(k) and next_can_start_member) {
                    const mod = self.advance();
                    if (mods.first_modifier_token == null) mods.first_modifier_token = mod;
                    const mod_name = self.source[mod.span.start..mod.span.end];
                    const msg = try std.fmt.allocPrint(self.diag_arena.allocator(), "'{s}' modifier must precede 'static' modifier.", .{mod_name});
                    try self.reportCodeAt(mod.span.start, mod.line, 1029, msg);
                    mods.visibility = switch (k) {
                        .kw_private => .private,
                        .kw_protected => .protected,
                        else => .public,
                    };
                    mods.has_accessibility = true;
                    mods.accessibility_token = mod;
                    continue;
                }
                if (mods.is_static and isAccessibilityModifier(k)) return mods;
                const modifier_token = self.peek();
                if (mods.first_modifier_token == null) mods.first_modifier_token = modifier_token;
                switch (k) {
                    .kw_private, .kw_protected, .kw_public => {
                        const mod = self.advance();
                        if (mods.is_override) {
                            const which: []const u8 = switch (k) {
                                .kw_private => "'private'",
                                .kw_protected => "'protected'",
                                else => "'public'",
                            };
                            const msg = try std.fmt.allocPrint(
                                self.diag_arena.allocator(),
                                "{s} modifier must precede 'override' modifier.",
                                .{which},
                            );
                            try self.reportCodeAt(mod.span.start, mod.line, 1029, msg);
                        }
                        // tsc only reports TS1028 once per modifier list
                        // — emit on the FIRST duplicate, then suppress
                        // subsequent ones to match upstream baselines.
                        if (mods.has_accessibility and !mods.reported_duplicate_accessibility) {
                            try self.reportCodeAt(mod.span.start, mod.line, 1028, "Accessibility modifier already seen.");
                            mods.reported_duplicate_accessibility = true;
                        }
                        mods.has_accessibility = true;
                        mods.accessibility_token = mod;
                        mods.visibility = switch (k) {
                            .kw_private => .private,
                            .kw_protected => .protected,
                            else => .public,
                        };
                        continue;
                    },
                    .kw_static => {
                        const mod = self.advance();
                        if (mods.is_async) {
                            try self.reportCodeAt(mod.span.start, mod.line, 1029, "'static' modifier must precede 'async' modifier.");
                        }
                        if (mods.is_override) {
                            try self.reportCodeAt(mod.span.start, mod.line, 1029, "'static' modifier must precede 'override' modifier.");
                        }
                        if (mods.is_static) {
                            try self.reportCodeAt(mod.span.start, mod.line, 1434, "Unexpected keyword or identifier.");
                        }
                        mods.is_static = true;
                        if (mods.static_token == null) mods.static_token = mod;
                        continue;
                    },
                    .kw_async => {
                        mods.is_async = true;
                        if (mods.async_token == null) mods.async_token = self.peek();
                    },
                    .kw_override => {
                        const mod = self.peek();
                        if (mods.is_async) {
                            try self.reportCodeAt(mod.span.start, mod.line, 1029, "'override' modifier must precede 'async' modifier.");
                        }
                        if (mods.is_override) {
                            try self.reportCodeAt(mod.span.start, mod.line, 1030, "'override' modifier already seen.");
                        }
                        if (mods.is_readonly) {
                            try self.reportCodeAt(mod.span.start, mod.line, 1029, "'override' modifier must precede 'readonly' modifier.");
                        }
                        if (mods.declare_token != null) {
                            try self.reportCodeAt(mod.span.start, mod.line, 1040, "'override' modifier cannot be used in an ambient context.");
                        }
                        mods.is_override = true;
                        if (mods.override_token == null) mods.override_token = mod;
                    },
                    .kw_abstract => {
                        if (mods.is_override) {
                            const mod = self.peek();
                            try self.reportCodeAt(mod.span.start, mod.line, 1029, "'abstract' modifier must precede 'override' modifier.");
                        }
                        mods.is_abstract = true;
                        if (mods.abstract_token == null) mods.abstract_token = self.peek();
                    },
                    .kw_export => {
                        if (mods.invalid_class_element_modifier == null) mods.invalid_class_element_modifier = self.peek();
                    },
                    .kw_declare => {
                        if (mods.is_override) {
                            const mod = self.peek();
                            try self.reportCodeAt(mod.span.start, mod.line, 1040, "'override' modifier cannot be used in an ambient context.");
                        }
                        if (mods.declare_token == null) mods.declare_token = self.peek();
                    },
                    .kw_readonly => {
                        // TS1030: `'readonly' modifier already seen.`
                        // Emit at the second `readonly` token.
                        if (mods.is_readonly) {
                            try self.reportCodeAt(self.peek().span.start, self.peek().line, 1030, "'readonly' modifier already seen.");
                        }
                        mods.is_readonly = true;
                        if (mods.readonly_token == null) mods.readonly_token = self.peek();
                    },
                    .kw_accessor => {
                        // `accessor x = …` modifier (TS 4.9 / Stage 3).
                        // Only valid in front of a field name — if the
                        // next token starts a same-line member name,
                        // consume the keyword and set the flag. Unlike
                        // `static`, `accessor` does not cross a line
                        // terminator in tsc (`accessor\na` declares a
                        // field named `accessor`, then `a`).
                        const next_tok = self.peekAt(1);
                        if (!next_tok.flags.preceded_by_newline and
                            (isClassMemberNameStart(next_tok.kind) or next_tok.kind == .open_bracket))
                        {
                            mods.is_accessor = true;
                            if (mods.accessor_token == null) mods.accessor_token = self.peek();
                        } else {
                            return mods;
                        }
                    },
                    else => {},
                }
                _ = self.advance();
                continue;
            }
            return mods;
        }
    }

    fn isAccessibilityModifier(kind: TokenKind) bool {
        return kind == .kw_public or kind == .kw_private or kind == .kw_protected;
    }

    fn isParameterPropertyModifier(kind: TokenKind) bool {
        return switch (kind) {
            .kw_public,
            .kw_private,
            .kw_protected,
            .kw_readonly,
            .kw_override,
            => true,
            else => false,
        };
    }

    /// TS1390 — reserved keywords that may not be used as a parameter
    /// name. These are exactly the keywords that upstream tsc's
    /// `isStartOfParameter` rejects: a parameter may begin with `...`,
    /// `@`, a modifier, a binding identifier/pattern, or a type start,
    /// so any *other* keyword reaching the parameter-name position is
    /// reported via `parsingContextErrors(PCParameters)` as
    /// `'{0}' is not allowed as a parameter name`.
    ///
    /// Deliberately EXCLUDED (each is a valid parameter start upstream):
    ///   * contextual keywords (`async`, `type`, `yield`, `await`, `of`,
    ///     `as`, …) — these are binding identifiers in this position;
    ///   * type-start keywords (`void`, `typeof`, `null`, `true`,
    ///     `false`, `new`, `import`, `this`) — `isStartOfType` accepts
    ///     them, so tsc parses them and errors elsewhere;
    ///   * parameter-property / strict-reserved modifier keywords
    ///     (`public`, `private`, `protected`, `static`, `readonly`,
    ///     `let`, `interface`, …) — handled by their own diagnostics.
    /// Mirrors `reservedWords3.ts`.
    fn reservedWordInvalidAsParamName(kind: TokenKind) bool {
        return switch (kind) {
            .kw_break,
            .kw_case,
            .kw_catch,
            .kw_class,
            .kw_const,
            .kw_continue,
            .kw_debugger,
            .kw_default,
            .kw_delete,
            .kw_do,
            .kw_else,
            .kw_enum,
            .kw_export,
            .kw_extends,
            .kw_finally,
            .kw_for,
            .kw_function,
            .kw_if,
            .kw_in,
            .kw_instanceof,
            .kw_return,
            .kw_super,
            .kw_switch,
            .kw_throw,
            .kw_try,
            .kw_var,
            .kw_while,
            .kw_with,
            => true,
            else => false,
        };
    }

    /// Modifier keywords that are syntactically parsed as modifiers but
    /// are never valid on a parameter — they surface as TS1090. The
    /// parameter-property modifiers (`public`/`readonly`/…) are handled
    /// separately and are not listed here.
    fn isInvalidParameterModifier(kind: TokenKind) bool {
        return switch (kind) {
            .kw_export,
            .kw_declare,
            .kw_async,
            .kw_static,
            => true,
            else => false,
        };
    }

    /// Whether the token after a candidate parameter modifier can begin
    /// a binding name (identifier / pattern / rest / another modifier).
    /// Mirrors tsc's `canFollowModifier`; when false the keyword is the
    /// parameter name itself (e.g. `function f(static)`), not a modifier.
    fn parameterModifierIsFollowedByName(kind: TokenKind) bool {
        return switch (kind) {
            .identifier,
            .open_brace,
            .open_bracket,
            .dot_dot_dot,
            .string_literal,
            .number_literal,
            .kw_public,
            .kw_private,
            .kw_protected,
            .kw_readonly,
            .kw_override,
            .kw_export,
            .kw_declare,
            .kw_async,
            .kw_static,
            .kw_this,
            => true,
            else => kind.isContextualKeyword(),
        };
    }

    fn isClassMemberNameStart(kind: TokenKind) bool {
        return kind == .identifier or
            kind == .private_identifier or
            kind == .string_literal or
            kind == .number_literal or
            kind == .kw_constructor or
            kind == .kw_interface or
            kind == .open_bracket or
            kind.isContextualKeyword();
    }

    fn canStartClassMemberAfterModifier(kind: TokenKind) bool {
        return isClassMemberNameStart(kind) or kind == .asterisk or kind == .at;
    }

    fn isReservedBindingNameToken(kind: TokenKind) bool {
        return kind.isKeyword() and !kind.isContextualKeyword();
    }

    fn reportAmbientClassImplementation(self: *Parser, member_start: Token) ParseError!void {
        if (!self.isAmbientContextAt(member_start.span.start)) return;
        try self.reportCodeAt(member_start.span.start, member_start.line, 1183, "An implementation cannot be declared in ambient contexts.");
    }

    fn reportAmbientClassImplementationAt(self: *Parser, pos: u32, line: u32) ParseError!void {
        if (!self.isAmbientContextAt(pos)) return;
        try self.reportCodeAt(pos, line, 1183, "An implementation cannot be declared in ambient contexts.");
    }

    fn reportInvalidClassElementModifier(self: *Parser, mods: ClassModifiers) ParseError!void {
        if (mods.invalid_class_element_modifier) |bad| {
            const mod_name = self.source[bad.span.start..bad.span.end];
            const msg = try std.fmt.allocPrint(self.diag_arena.allocator(), "'{s}' modifier cannot appear on class elements of this kind.", .{mod_name});
            try self.reportCodeAt(bad.span.start, bad.line, 1031, msg);
        }
        // TS1024: `readonly` is only valid on a property declaration,
        // property signature, index signature, or parameter property. The
        // method/accessor/constructor paths that call this helper are all
        // ineligible, so a captured `readonly` modifier is a grammar error
        // anchored at the keyword. Property members route through
        // `reportInvalidClassElementModifierForProperty` and index
        // signatures consume their own `readonly`, so neither reaches here.
        // Mirrors `privateNamesIncompatibleModifiers.ts(11,5)`.
        if (mods.readonly_token) |bad| {
            try self.reportCodeAt(bad.span.start, bad.line, 1024, "'readonly' modifier can only appear on a property declaration or index signature.");
        }
        // `declare` is invalid on methods/constructors/accessors only.
        // Callers parsing a class *property* skip this branch entirely
        // by using `reportInvalidClassElementModifierForProperty`.
        if (mods.declare_token) |bad| {
            const mod_name = self.source[bad.span.start..bad.span.end];
            const msg = try std.fmt.allocPrint(self.diag_arena.allocator(), "'{s}' modifier cannot appear on class elements of this kind.", .{mod_name});
            try self.reportCodeAt(bad.span.start, bad.line, 1031, msg);
        }
    }

    fn reportClassMemberConstKeyword(self: *Parser, mods: ClassModifiers) ParseError!void {
        if (mods.const_token) |bad| {
            const mod_name = self.source[bad.span.start..bad.span.end];
            const msg = try std.fmt.allocPrint(self.diag_arena.allocator(), "A class member cannot have the '{s}' keyword.", .{mod_name});
            try self.reportCodeAt(bad.span.start, bad.line, 1248, msg);
        }
    }

    fn reportInvalidDefiniteAssignmentAssertion(
        self: *Parser,
        bang_token: ?Token,
        type_annotation: NodeId,
        initializer: NodeId,
    ) ParseError!void {
        const bad = bang_token orelse return;
        if (initializer != hir_mod.none_node_id) {
            try self.reportCodeAt(bad.span.start, bad.line, 1263, "Declarations with initializers cannot also have definite assignment assertions.");
        } else if (type_annotation == hir_mod.none_node_id) {
            try self.reportCodeAt(bad.span.start, bad.line, 1264, "Declarations with definite assignment assertions must also have type annotations.");
        }
    }

    /// Class-property variant of the definite-assignment grammar check.
    /// Mirrors upstream tsgo `checkGrammarProperty` (grammarchecks.go
    /// ~L1928): when a property bears a `!` postfix token it cascades
    /// TS1263 (has initializer) → TS1264 (no type annotation) → TS1255
    /// for the remaining "not permitted in this context" case. The
    /// TS1255 default fires when the `!` carries a type and no
    /// initializer but the property is NOT a plain instance field of a
    /// concrete class — i.e. it sits in an ambient context (`declare`),
    /// or is `static`, or is `abstract`. Anchored at the `!` token to
    /// match tsc's `grammarErrorOnNode(postfixToken, …)` span.
    fn reportClassPropertyDefiniteAssignment(
        self: *Parser,
        bang_token: ?Token,
        type_annotation: NodeId,
        initializer: NodeId,
        mods: ClassModifiers,
        member_start: u32,
    ) ParseError!void {
        const bad = bang_token orelse return;
        if (initializer != hir_mod.none_node_id) {
            try self.reportCodeAt(bad.span.start, bad.line, 1263, "Declarations with initializers cannot also have definite assignment assertions.");
            return;
        }
        if (type_annotation == hir_mod.none_node_id) {
            try self.reportCodeAt(bad.span.start, bad.line, 1264, "Declarations with definite assignment assertions must also have type annotations.");
            return;
        }
        const is_ambient = self.isAmbientContextAt(member_start) or mods.declare_token != null;
        if (is_ambient or mods.is_static or mods.is_abstract) {
            try self.reportCodeAt(bad.span.start, bad.line, 1255, "A definite assignment assertion '!' is not permitted in this context.");
        }
    }

    /// Variable-declaration variant of the definite-assignment grammar
    /// check. Mirrors upstream `checkGrammarVariableDeclaration`
    /// (grammarchecks.go ~L1587): a `!` postfix cascades TS1263 (has
    /// initializer) → TS1264 (no type annotation) → TS1255 for the
    /// "not permitted in this context" remainder. The TS1255 case is
    /// reached when the binding bears a type and no initializer but the
    /// declaration sits in an ambient context (`declare let v!: T;`) —
    /// matching tsc's `nodeFlags & Ambient` arm of the default branch.
    /// A plain `let x!: T;` in a normal variable statement stays clean.
    fn reportVariableDefiniteAssignment(
        self: *Parser,
        bang_token: ?Token,
        type_annotation: NodeId,
        initializer: NodeId,
        is_ambient: bool,
    ) ParseError!void {
        const bad = bang_token orelse return;
        if (initializer != hir_mod.none_node_id) {
            try self.reportCodeAt(bad.span.start, bad.line, 1263, "Declarations with initializers cannot also have definite assignment assertions.");
            return;
        }
        if (type_annotation == hir_mod.none_node_id) {
            try self.reportCodeAt(bad.span.start, bad.line, 1264, "Declarations with definite assignment assertions must also have type annotations.");
            return;
        }
        if (is_ambient) {
            try self.reportCodeAt(bad.span.start, bad.line, 1255, "A definite assignment assertion '!' is not permitted in this context.");
        }
    }

    fn reportOptionalAutoAccessor(self: *Parser, question_token: ?Token) ParseError!void {
        const bad = question_token orelse return;
        try self.reportCodeAt(bad.span.start, bad.line, 1276, "An 'accessor' property cannot be declared optional.");
    }

    fn reportAccessorModifierOnlyOnProperty(self: *Parser, mods: ClassModifiers) ParseError!void {
        if (mods.accessor_token) |bad| {
            try self.reportCodeAt(bad.span.start, bad.line, 1275, "'accessor' modifier can only appear on a property declaration.");
        }
    }

    fn reportPrivateIdentifierModifierDiagnostics(self: *Parser, mods: ClassModifiers, is_property: bool) ParseError!void {
        if (mods.accessibility_token) |bad| {
            if (!self.hasDiagnosticAt(18010, bad.span.start)) {
                try self.reportCodeAt(bad.span.start, bad.line, 18010, "An accessibility modifier cannot be used with a private identifier.");
            }
        }
        if (!is_property) return;
        if (mods.declare_token) |bad| {
            const mod_name = self.source[bad.span.start..bad.span.end];
            const msg = try std.fmt.allocPrint(self.diag_arena.allocator(), "'{s}' modifier cannot be used with a private identifier.", .{mod_name});
            if (!self.hasDiagnosticAt(18019, bad.span.start)) {
                try self.reportCodeAt(bad.span.start, bad.line, 18019, msg);
            }
        }
        if (mods.abstract_token) |bad| {
            const mod_name = self.source[bad.span.start..bad.span.end];
            const msg = try std.fmt.allocPrint(self.diag_arena.allocator(), "'{s}' modifier cannot be used with a private identifier.", .{mod_name});
            if (!self.hasDiagnosticAt(18019, bad.span.start)) {
                try self.reportCodeAt(bad.span.start, bad.line, 18019, msg);
            }
        }
    }

    fn reportPrivateIdentifierTargetDiagnostic(self: *Parser, tok: Token) ParseError!void {
        if (self.target_es2015_or_later) return;
        if (self.hasDiagnosticAt(18028, tok.span.start)) return;
        try self.reportCodeAt(tok.span.start, tok.line, 18028, "Private identifiers are only available when targeting ECMAScript 2015 and higher.");
    }

    fn hasDiagnosticAt(self: *const Parser, code: u32, pos: u32) bool {
        for (self.diagnostics.items) |d| {
            if (d.code == code and d.pos == pos) return true;
        }
        return false;
    }

    /// Property-kind class members accept `declare` (the field is
    /// initialized externally); only `export` is unconditionally
    /// rejected with TS1031.
    fn reportInvalidClassElementModifierForProperty(self: *Parser, mods: ClassModifiers) ParseError!void {
        const bad = mods.invalid_class_element_modifier orelse return;
        const mod_name = self.source[bad.span.start..bad.span.end];
        const msg = try std.fmt.allocPrint(self.diag_arena.allocator(), "'{s}' modifier cannot appear on class elements of this kind.", .{mod_name});
        try self.reportCodeAt(bad.span.start, bad.line, 1031, msg);
    }

    fn reportUnknownKeywordOrIdentifierSuggestionForClassProperty(
        self: *Parser,
        name_tok: Token,
        type_anno: NodeId,
        default_value: NodeId,
    ) ParseError!bool {
        if (type_anno != hir_mod.none_node_id or default_value != hir_mod.none_node_id) return false;
        const next = self.peek();
        if (next.kind == .eof or
            next.kind == .close_brace or
            next.kind == .semicolon or
            next.flags.preceded_by_newline)
        {
            return false;
        }
        const name_text = self.source[name_tok.span.start..name_tok.span.end];
        const suggestion = try self.classMemberKeywordSuggestion(name_text) orelse return false;
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Unknown keyword or identifier. Did you mean '{s}'?",
            .{suggestion},
        );
        try self.reportCodeAt(name_tok.span.start, name_tok.line, 1435, msg);
        self.skipMalformedClassFieldTail();
        return true;
    }

    fn classMemberKeywordSuggestion(self: *Parser, name: []const u8) ParseError!?[]const u8 {
        const candidates = [_][]const u8{
            "abstract",
            "accessor",
            "async",
            "class",
            "const",
            "constructor",
            "declare",
            "export",
            "extends",
            "function",
            "implements",
            "interface",
            "let",
            "module",
            "namespace",
            "private",
            "protected",
            "public",
            "readonly",
            "static",
            "type",
            "var",
        };
        if (try self.spaceSeparatedKeywordSuggestion(name, &candidates)) |suggestion| return suggestion;
        var best: ?[]const u8 = null;
        var best_distance: usize = std.math.maxInt(usize);
        for (candidates) |candidate| {
            const distance = levenshteinIcase(name, candidate);
            if (distance < best_distance) {
                best = candidate;
                best_distance = distance;
            }
        }
        const threshold = @max(@as(usize, 2), name.len / 4);
        return if (best != null and best_distance <= threshold) best else null;
    }

    fn spaceSeparatedKeywordSuggestion(self: *Parser, name: []const u8, candidates: []const []const u8) ParseError!?[]const u8 {
        for (candidates) |candidate| {
            if (name.len > candidate.len + 2 and std.mem.startsWith(u8, name, candidate)) {
                return try std.fmt.allocPrint(self.diag_arena.allocator(), "{s} {s}", .{ candidate, name[candidate.len..] });
            }
        }
        return null;
    }

    fn levenshteinIcase(a: []const u8, b: []const u8) usize {
        var previous_buf: [128]usize = undefined;
        var current_buf: [128]usize = undefined;
        if (b.len + 1 > previous_buf.len) return std.math.maxInt(usize);
        for (0..b.len + 1) |i| previous_buf[i] = i;
        var i: usize = 0;
        while (i < a.len) : (i += 1) {
            current_buf[0] = i + 1;
            var j: usize = 0;
            while (j < b.len) : (j += 1) {
                const ca = std.ascii.toLower(a[i]);
                const cb = std.ascii.toLower(b[j]);
                const cost: usize = if (ca == cb) 0 else 1;
                const del = previous_buf[j + 1] + 1;
                const ins = current_buf[j] + 1;
                const sub = previous_buf[j] + cost;
                current_buf[j + 1] = @min(@min(del, ins), sub);
            }
            @memcpy(previous_buf[0 .. b.len + 1], current_buf[0 .. b.len + 1]);
        }
        return previous_buf[b.len];
    }

    fn reportMissingClassMemberImplementation(self: *Parser, member_start: Token, mods: ClassModifiers) ParseError!void {
        _ = self;
        _ = member_start;
        _ = mods;
        // Class-member missing implementation diagnostics are handled by
        // the checker, which has the full overload group. Reporting here
        // double-emits TS2391 once checker diagnostics are merged with
        // parser diagnostics.
    }

    fn isAmbientContext(self: *const Parser) bool {
        return self.ambient_depth > 0 or self.is_declaration_file;
    }

    fn isAmbientContextAt(self: *const Parser, pos: u32) bool {
        if (self.ambient_depth > 0) return true;
        if (self.virtualSectionFilenameAt(pos)) |filename| {
            return isDeclarationFilename(filename);
        }
        return self.is_declaration_file;
    }

    fn isVirtualDeclarationSectionAt(self: *const Parser, pos: u32) bool {
        const filename = self.virtualSectionFilenameAt(pos) orelse return false;
        return isDeclarationFilename(filename);
    }

    fn isJavaScriptSyntaxAt(self: *const Parser, pos: u32) bool {
        if (self.virtualSectionFilenameAt(pos)) |filename| {
            return isJavaScriptFilename(filename);
        }
        return self.is_javascript_file;
    }

    fn isJsxSyntaxAt(self: *const Parser, pos: u32) bool {
        if (self.virtualSectionFilenameAt(pos)) |filename| {
            if (isJsxFilename(filename)) return true;
            return isJavaScriptFilename(filename) and std.mem.indexOf(u8, self.source, "@jsx:") != null;
        }
        return self.is_tsx;
    }

    fn isJsxFilename(filename: []const u8) bool {
        return std.mem.endsWith(u8, filename, ".tsx") or
            std.mem.endsWith(u8, filename, ".jsx");
    }

    fn isDeclarationFilename(filename: []const u8) bool {
        if (std.mem.endsWith(u8, filename, ".d.ts")) return true;
        if (std.mem.endsWith(u8, filename, ".d.mts")) return true;
        if (std.mem.endsWith(u8, filename, ".d.cts")) return true;
        if (std.mem.endsWith(u8, filename, ".d.hm")) return true;
        if (std.mem.endsWith(u8, filename, ".d.home")) return true;
        return std.mem.endsWith(u8, filename, ".ts") and std.mem.indexOf(u8, filename, ".d.") != null;
    }

    fn isJavaScriptFilename(filename: []const u8) bool {
        return std.mem.endsWith(u8, filename, ".js") or
            std.mem.endsWith(u8, filename, ".jsx") or
            std.mem.endsWith(u8, filename, ".mjs") or
            std.mem.endsWith(u8, filename, ".cjs");
    }

    fn isJsonFilename(filename: []const u8) bool {
        return std.mem.endsWith(u8, filename, ".json");
    }

    fn nextVirtualSectionStartAfter(self: *const Parser, pos: u32) ?usize {
        const start: usize = @min(@as(usize, pos), self.source.len);
        var scan = start;
        while (scan < self.source.len) {
            const line_end = std.mem.indexOfScalarPos(u8, self.source, scan, '\n') orelse self.source.len;
            const line = self.source[scan..line_end];
            if (std.mem.indexOf(u8, line, "@filename:") != null or
                std.mem.indexOf(u8, line, "@Filename:") != null)
            {
                return scan;
            }
            if (line_end == self.source.len) break;
            scan = line_end + 1;
        }
        return null;
    }

    fn skipVirtualJsonSection(self: *Parser) bool {
        const current = self.peek();
        if (current.kind == .eof) return false;
        const filename = self.virtualSectionFilenameAt(current.span.start) orelse return false;
        if (!isJsonFilename(filename)) return false;
        const next_section_start = self.nextVirtualSectionStartAfter(current.span.start + 1) orelse self.source.len;
        while (self.peek().kind != .eof and self.peek().span.start < next_section_start) {
            _ = self.advance();
        }
        return true;
    }

    fn reportTypeArgumentsOnlyInTsIfNeeded(self: *Parser, args: []const NodeId) ParseError!void {
        if (args.len == 0) return;
        const first_span = self.hir.spanOf(args[0]);
        if (!self.isJavaScriptSyntaxAt(first_span.start)) return;
        try self.reportCodeAt(first_span.start, self.lineForPos(first_span.start), 8011, "Type arguments can only be used in TypeScript files.");
    }

    fn reportExportAssignmentOnlyInTsIfNeeded(self: *Parser, tok: Token) ParseError!void {
        if (!self.isJavaScriptSyntaxAt(tok.span.start)) return;
        try self.reportCodeAt(tok.span.start, tok.line, 8003, "'export =' can only be used in TypeScript files.");
    }

    fn reportImplementsOnlyInTsIfNeeded(self: *Parser, tok: Token) ParseError!void {
        if (!self.isJavaScriptSyntaxAt(tok.span.start)) return;
        try self.reportCodeAt(tok.span.start, tok.line, 8005, "'implements' clauses can only be used in TypeScript files.");
    }

    fn reportTypeAliasOnlyInTsIfNeeded(self: *Parser, tok: Token) ParseError!void {
        if (!self.isJavaScriptSyntaxAt(tok.span.start)) return;
        try self.reportCodeAt(tok.span.start, tok.line, 8008, "Type aliases can only be used in TypeScript files.");
    }

    fn reportParameterModifiersOnlyInTsIfNeeded(self: *Parser, tok: Token) ParseError!void {
        if (!self.isJavaScriptSyntaxAt(tok.span.start)) return;
        try self.reportCodeAt(tok.span.start, tok.line, 8012, "Parameter modifiers can only be used in TypeScript files.");
    }

    fn reportNonNullOnlyInTsIfNeeded(self: *Parser, pos: u32) ParseError!void {
        if (!self.isJavaScriptSyntaxAt(pos)) return;
        try self.reportCodeAt(pos, self.lineForPos(pos), 8013, "Non-null assertions can only be used in TypeScript files.");
    }

    fn reportTypeAssertionOnlyInTsIfNeeded(self: *Parser, type_node: NodeId) ParseError!void {
        const type_span = self.hir.spanOf(type_node);
        if (!self.isJavaScriptSyntaxAt(type_span.start)) return;
        try self.reportCodeAt(type_span.start, self.lineForPos(type_span.start), 8016, "Type assertion expressions can only be used in TypeScript files.");
    }

    fn sourceHasErasableSyntaxOnlyDirective(self: *const Parser) bool {
        return std.mem.indexOf(u8, self.source, "@erasableSyntaxOnly: true") != null or
            std.mem.indexOf(u8, self.source, "@erasableSyntaxOnly:true") != null;
    }

    fn sourceHasStrictTrueDirective(self: *const Parser) bool {
        return std.mem.indexOf(u8, self.source, "@strict: true") != null or
            std.mem.indexOf(u8, self.source, "@strict:true") != null;
    }

    fn reportErasableSyntaxOnlyTypeAssertionIfNeeded(self: *Parser, less_tok: Token) ParseError!void {
        if (!self.sourceHasErasableSyntaxOnlyDirective()) return;
        try self.reportCodeAt(less_tok.span.start, less_tok.line, 1294, "This syntax is not allowed when 'erasableSyntaxOnly' is enabled.");
    }

    fn syntheticTypeAssertionOperandAt(self: *Parser, tok: Token) ParseError!NodeId {
        return try self.builder.addLiteralNumber(.{ .start = tok.span.start, .end = tok.span.start }, 0);
    }

    fn virtualSectionFilenameAt(self: *const Parser, pos: u32) ?[]const u8 {
        if (std.mem.indexOf(u8, self.source, "@filename:") == null and
            std.mem.indexOf(u8, self.source, "@Filename:") == null)
        {
            return null;
        }
        const limit: usize = @min(@as(usize, pos), self.source.len);
        var last: ?usize = null;
        var line_start: usize = 0;
        while (line_start <= limit and line_start < self.source.len) {
            const line_end = std.mem.indexOfScalarPos(u8, self.source, line_start, '\n') orelse self.source.len;
            const line = self.source[line_start..line_end];
            if (std.mem.indexOf(u8, line, "@filename:") != null or
                std.mem.indexOf(u8, line, "@Filename:") != null)
            {
                last = line_start;
            }
            if (line_end >= limit or line_end == self.source.len) break;
            line_start = line_end + 1;
        }
        const section = last orelse return null;
        const line_end = std.mem.indexOfScalarPos(u8, self.source, section, '\n') orelse self.source.len;
        const line = self.source[section..line_end];
        const marker = std.mem.indexOf(u8, line, "@filename:") orelse
            (std.mem.indexOf(u8, line, "@Filename:") orelse return null);
        return std.mem.trim(u8, line[marker + "@filename:".len ..], " \t\r");
    }

    fn nextClassMemberNameMatches(self: *const Parser, current: Token) bool {
        const idx = self.nextClassMemberNameIndex() orelse return false;
        const next = self.tokens[idx];
        return self.classMemberNameTextMatches(current, next);
    }

    fn nextClassMemberLooksLikeImplementation(self: *const Parser) bool {
        var idx = self.nextClassMemberNameIndex() orelse return false;
        idx += 1;
        if (idx < self.tokens.len and self.tokens[idx].kind == .question) idx += 1;
        if (idx < self.tokens.len and self.tokens[idx].kind == .less_than) {
            while (idx < self.tokens.len and self.tokens[idx].kind != .open_paren and self.tokens[idx].kind != .open_brace and self.tokens[idx].kind != .semicolon and self.tokens[idx].kind != .close_brace) : (idx += 1) {}
        }
        if (idx >= self.tokens.len or self.tokens[idx].kind != .open_paren) return false;
        idx = self.skipBalancedLookahead(idx);
        if (idx < self.tokens.len and self.tokens[idx].kind == .colon) {
            idx += 1;
            while (idx < self.tokens.len and self.tokens[idx].kind != .open_brace and self.tokens[idx].kind != .semicolon and self.tokens[idx].kind != .close_brace) : (idx += 1) {}
        }
        return idx < self.tokens.len and self.tokens[idx].kind == .open_brace;
    }

    fn nextClassMemberNameIndex(self: *const Parser) ?usize {
        var idx: usize = self.cursor;
        while (idx < self.tokens.len) {
            while (idx < self.tokens.len and self.tokens[idx].kind == .at) {
                idx = self.skipDecoratorLookahead(idx);
            }
            if (idx < self.tokens.len and self.tokens[idx].kind.isModifierKeyword()) {
                idx += 1;
                continue;
            }
            break;
        }
        if (idx < self.tokens.len and self.tokens[idx].kind == .asterisk) idx += 1;
        if (idx >= self.tokens.len) return null;
        return idx;
    }

    fn skipDecoratorLookahead(self: *const Parser, start: usize) usize {
        var idx = start + 1;
        if (idx >= self.tokens.len) return idx;

        if (self.tokens[idx].kind == .open_paren) {
            idx = self.skipBalancedLookahead(idx);
        } else {
            idx += 1;
        }

        while (idx < self.tokens.len) {
            if (self.tokens[idx].kind == .dot and idx + 1 < self.tokens.len) {
                idx += 2;
                continue;
            }
            if (self.tokens[idx].kind == .open_paren) {
                idx = self.skipBalancedLookahead(idx);
                continue;
            }
            break;
        }
        return idx;
    }

    fn skipBalancedLookahead(self: *const Parser, start: usize) usize {
        var idx = start;
        var depth: usize = 0;
        while (idx < self.tokens.len) : (idx += 1) {
            switch (self.tokens[idx].kind) {
                .open_paren, .open_bracket, .open_brace => depth += 1,
                .close_paren, .close_bracket, .close_brace => {
                    if (depth == 0) return idx + 1;
                    depth -= 1;
                    if (depth == 0) return idx + 1;
                },
                else => {},
            }
        }
        return idx;
    }

    fn classMemberNameTextMatches(self: *const Parser, a: Token, b: Token) bool {
        const a_text = self.classMemberNameText(a);
        const b_text = self.classMemberNameText(b);
        return std.mem.eql(u8, a_text, b_text);
    }

    fn classMemberNameText(self: *const Parser, tok: Token) []const u8 {
        const raw = self.source[tok.span.start..tok.span.end];
        if (tok.kind == .string_literal and raw.len >= 2) return raw[1 .. raw.len - 1];
        return raw;
    }

    fn isReservedTypeNameToken(self: *const Parser, tok: Token) bool {
        const raw = self.source[tok.span.start..tok.span.end];
        return std.mem.eql(u8, raw, "any") or
            std.mem.eql(u8, raw, "unknown") or
            std.mem.eql(u8, raw, "never") or
            std.mem.eql(u8, raw, "void") or
            std.mem.eql(u8, raw, "undefined") or
            std.mem.eql(u8, raw, "string") or
            std.mem.eql(u8, raw, "number") or
            std.mem.eql(u8, raw, "boolean") or
            std.mem.eql(u8, raw, "bigint") or
            std.mem.eql(u8, raw, "symbol") or
            std.mem.eql(u8, raw, "object");
    }

    fn parseComputedClassMember(
        self: *Parser,
        member_start: Token,
        mods: ClassModifiers,
        is_generator: bool,
        key_generator_depth: u32,
    ) ParseError!NodeId {
        const class_computed_open = try self.expect(.open_bracket, "'[' to start computed class member");
        const key = blk: {
            const prev_generator_depth = self.generator_depth;
            self.generator_depth = key_generator_depth;
            defer self.generator_depth = prev_generator_depth;
            break :blk try self.parseExpression();
        };
        _ = try self.expectClosingMatch(.close_bracket, "']' to close computed class member name", class_computed_open.span.start, "[", "]");

        var value: NodeId = hir_mod.none_node_id;
        var type_anno: NodeId = hir_mod.none_node_id;
        var is_method = false;
        if (is_generator or self.peek().kind == .open_paren or self.peek().kind == .less_than) {
            var type_params: []NodeId = &.{};
            var owns_tps = false;
            if (self.peek().kind == .less_than) {
                type_params = try self.parseTypeParameterDeclaration();
                owns_tps = true;
            }
            defer if (owns_tps) self.gpa.free(type_params);
            const params = try self.parseParameterList();
            defer self.gpa.free(params);
            var return_type: NodeId = hir_mod.none_node_id;
            if (self.match(.colon)) return_type = try self.parseReturnTypeAnnotation(params);
            var body: NodeId = hir_mod.none_node_id;
            if (self.peek().kind == .open_brace) {
                const prev_generator_depth = self.generator_depth;
                self.generator_depth = if (is_generator) prev_generator_depth + 1 else 0;
                self.function_depth += 1;
                if (mods.is_async) self.async_function_depth += 1;
                defer {
                    self.generator_depth = prev_generator_depth;
                    self.function_depth -= 1;
                    if (mods.is_async) self.async_function_depth -= 1;
                }
                body = try self.parseBlockStatement();
                try self.reportAmbientClassImplementation(member_start);
            } else {
                try self.consumeStatementTerminator();
            }
            value = try self.builder.addFnDeclGeneric(
                .{ .start = member_start.span.start, .end = self.tokens[self.cursor - 1].span.end },
                hir_mod.none_node_id,
                type_params,
                params,
                return_type,
                body,
                .{
                    .is_method = true,
                    .is_private = mods.visibility == .private,
                    .is_protected = mods.visibility == .protected,
                    .is_static = mods.is_static,
                    .is_async = mods.is_async,
                    .is_generator = is_generator,
                    .is_override = mods.is_override,
                    .is_abstract = mods.is_abstract,
                },
            );
            is_method = true;
            try self.reportAccessorModifierOnlyOnProperty(mods);
        } else {
            const optional_member_token: ?Token = if (self.peek().kind == .question) self.advance() else null;
            const definite_assignment_token: ?Token = if (self.peek().kind == .bang) self.advance() else null;
            if (self.match(.colon)) {
                type_anno = try self.parseTypeAnnotation();
                _ = self.match(.question);
                _ = self.match(.bang);
            }
            if (self.match(.equal)) value = try self.parseAssignmentExpression();
            try self.reportInvalidDefiniteAssignmentAssertion(definite_assignment_token, type_anno, value);
            if (mods.is_accessor) {
                try self.reportOptionalAutoAccessor(optional_member_token);
            }
            self.consumeClassPropertyTerminator() catch |err| switch (err) {
                error.UnexpectedToken => self.skipMalformedClassFieldTail(),
                else => return err,
            };
        }

        return try self.builder.addObjectPropertyFull(
            .{ .start = member_start.span.start, .end = self.tokens[self.cursor - 1].span.end },
            key,
            value,
            type_anno,
            true,
            value == hir_mod.none_node_id,
            is_method,
            mods.is_static,
            mods.visibility,
            mods.is_override,
        );
    }

    fn skipMalformedClassFieldTail(self: *Parser) void {
        while (self.peek().kind != .eof and self.peek().kind != .close_brace) {
            if (self.match(.semicolon)) return;
            if (self.peek().flags.preceded_by_newline) return;
            _ = self.advance();
        }
    }

    fn skipMalformedGeneratorClassMemberTail(self: *Parser) void {
        var depth: u32 = 0;
        while (self.peek().kind != .eof) {
            const t = self.peek();
            if (depth == 0) {
                if (t.kind == .semicolon) {
                    _ = self.advance();
                    return;
                }
                if (t.kind == .close_brace) return;
                if (t.flags.preceded_by_newline and canStartClassMemberAfterModifier(t.kind)) return;
            }
            switch (t.kind) {
                .open_paren, .open_bracket, .open_brace => {
                    depth += 1;
                    _ = self.advance();
                },
                .close_paren, .close_bracket, .close_brace => {
                    _ = self.advance();
                    if (depth == 0) return;
                    depth -= 1;
                    if (depth == 0 and t.kind == .close_brace) return;
                },
                else => _ = self.advance(),
            }
        }
    }

    fn consumeClassPropertyTerminator(self: *Parser) ParseError!void {
        if (self.peek().kind == .at and !self.peek().flags.preceded_by_newline) {
            const dec_tok = self.peek();
            try self.reportCodeAt(dec_tok.span.start, dec_tok.line, 1436, "Decorators must precede the name and all keywords of property declarations.");
            return;
        }
        try self.consumeStatementTerminator();
    }

    fn parseClassMemberDecoratorExpression(self: *Parser) ParseError!NodeId {
        return try self.parseDecoratorExpressionBody();
    }

    fn parseInterfaceDeclaration(self: *Parser) ParseError!NodeId {
        const start = self.advance(); // interface
        const name_node: NodeId = name_blk: {
            if (self.peek().kind == .open_brace) {
                const brace = self.peek();
                try self.reportCodeAt(brace.span.start, brace.line, 1438, "Interface must be given a name.");
                break :name_blk try self.missingIdentifierAt(brace.span.start);
            }
            const name_tok = if (self.peek().kind == .identifier or
                self.peek().kind == .kw_interface or
                self.peek().kind.isContextualKeyword() or
                self.peek().kind.isPrimitiveTypeKeyword())
                self.advance()
            else
                try self.expect(.identifier, "interface name");
            if (name_tok.kind.isPrimitiveTypeKeyword() or self.isReservedTypeNameToken(name_tok)) {
                const raw = self.source[name_tok.span.start..name_tok.span.end];
                const msg = try std.fmt.allocPrint(self.diag_arena.allocator(), "Interface name cannot be '{s}'.", .{raw});
                try self.reportCodeAt(name_tok.span.start, name_tok.line, 2427, msg);
            }
            const name_id_str = try self.internToken(name_tok);
            break :name_blk try self.builder.addIdentifier(tokenSpan(name_tok), name_id_str);
        };
        var type_params: []NodeId = &.{};
        var owns_tps = false;
        if (self.peek().kind == .less_than) {
            type_params = try self.parseTypeParameterDeclarationIn(.variance_only);
            owns_tps = true;
        }
        defer if (owns_tps) self.gpa.free(type_params);
        var extends_list: std.ArrayListUnmanaged(NodeId) = .empty;
        defer extends_list.deinit(self.gpa);
        if (self.peek().kind == .kw_extends) {
            const extends_tok = self.advance();
            if (self.peek().kind == .open_brace or self.peek().kind == .eof) {
                try self.reportCodeAt(extends_tok.span.end, extends_tok.line, 1097, "'extends' list cannot be empty.");
            } else {
                while (true) {
                    const ref = try self.parseTypeReferenceWithOptionalChainDiagnostic(
                        2499,
                        "An interface can only extend an identifier/qualified-name with optional type arguments.",
                        true,
                    );
                    try extends_list.append(self.gpa, ref);
                    if (self.peek().kind == .kw_extends) {
                        const duplicate = self.advance();
                        try self.reportCodeAt(duplicate.span.start, duplicate.line, 1172, "'extends' clause already seen.");
                        while (self.peek().kind != .open_brace and
                            self.peek().kind != .comma and
                            self.peek().kind != .eof)
                        {
                            _ = self.advance();
                        }
                        break;
                    }
                    if (!self.match(.comma)) break;
                }
            }
        }
        if (self.peek().kind == .kw_implements) {
            const impl = self.advance();
            try self.reportCodeAt(impl.span.start, impl.line, 1176, "Interface declaration cannot have 'implements' clause.");
            while (self.peek().kind != .open_brace and self.peek().kind != .eof) _ = self.advance();
        }
        const iface_body_open = try self.expect(.open_brace, "'{' to open interface body");
        var members: std.ArrayListUnmanaged(NodeId) = .empty;
        defer members.deinit(self.gpa);
        const saved_in_iface = self.parsing_interface_body;
        self.parsing_interface_body = true;
        defer self.parsing_interface_body = saved_in_iface;
        try self.parseTypeMemberList(&members);
        const close = if (self.peek().kind == .close_brace)
            self.advance()
        else blk: {
            const at = self.peek();
            const suppress_after_unterminated_type_args = at.kind == .eof and
                self.diagnostics.items.len > 0 and
                self.diagnostics.items[self.diagnostics.items.len - 1].code == 1005 and
                std.mem.eql(u8, self.diagnostics.items[self.diagnostics.items.len - 1].message, "'>' expected.");
            if (!suppress_after_unterminated_type_args) {
                try self.reportCodeAtWithMatchedPair(
                    at.span.start,
                    at.line,
                    1005,
                    "'}' expected.",
                    iface_body_open.span.start,
                    "{",
                    "}",
                );
            }
            break :blk at;
        };
        return try self.builder.addInterface(
            .{ .start = start.span.start, .end = close.span.end },
            name_node,
            type_params,
            extends_list.items,
            members.items,
        );
    }

    fn parseTypeAlias(self: *Parser) ParseError!NodeId {
        const start = self.advance(); // type
        var alias_name_is_void = false;
        // Accept primitive-type keywords (`any`, `string`, `number`,
        // …) as the alias-name token so we can emit the upstream
        // TS2457 ("Type alias name cannot be '<reserved>'.") at the
        // exact source column. Without this branch the parser bails
        // with TS1005 ("';' expected.") and the rest of the file
        // recovers badly. Mirrors `reservedNamesInAliases.ts`.
        const peek_kind = self.peek().kind;
        const name_node: NodeId = name_blk: {
            if (peek_kind == .equal) {
                const equal = self.peek();
                try self.reportCodeAt(equal.span.start, equal.line, 1439, "Type alias must be given a name.");
                break :name_blk try self.missingIdentifierAt(equal.span.start);
            }
            const name_tok = if (peek_kind == .identifier or self.tokenLexemeIsReservedTypeAliasName())
                self.advance()
            else
                try self.expect(.identifier, "type alias name");
            if (name_tok.flags.preceded_by_newline) {
                try self.reportCodeAt(name_tok.span.start, name_tok.line, 1142, "Line break not permitted here.");
            }
            try self.reportTypeAliasOnlyInTsIfNeeded(name_tok);
            // TS2457 — `Type alias name cannot be '<reserved>'.` fires for
            // primitive-type keywords used as type alias names. Mirrors
            // `reservedNamesInAliases.ts` lines 2-7.
            const name_text = self.source[name_tok.span.start..name_tok.span.end];
            if (isReservedTypeAliasName(name_text)) {
                alias_name_is_void = std.mem.eql(u8, name_text, "void");
                const msg = try std.fmt.allocPrint(
                    self.diag_arena.allocator(),
                    "Type alias name cannot be '{s}'.",
                    .{name_text},
                );
                try self.diagnostics.append(self.gpa, .{
                    .pos = name_tok.span.start,
                    .line = name_tok.line,
                    .code = 2457,
                    .message = msg,
                });
            }
            const name_id = try self.internToken(name_tok);
            break :name_blk try self.builder.addIdentifier(tokenSpan(name_tok), name_id);
        };
        var type_params: []NodeId = &.{};
        var owns_tps = false;
        if (self.peek().kind == .less_than) {
            type_params = try self.parseTypeParameterDeclarationIn(.variance_only);
            owns_tps = true;
        }
        defer if (owns_tps) self.gpa.free(type_params);
        if (self.peek().kind == .semicolon or self.peek().kind == .eof or self.peek().flags.preceded_by_newline) {
            const anchor = self.peek();
            try self.reportCodeAt(anchor.span.start, anchor.line, 1005, "'=' expected.");
            if (self.peek().kind == .semicolon) _ = self.advance();
            const end_pos = self.tokens[self.cursor - 1].span.end;
            return try self.builder.addTypeAlias(
                .{ .start = start.span.start, .end = end_pos },
                name_node,
                type_params,
                try self.typeRefName("unknown", .{ .start = anchor.span.start, .end = anchor.span.start }),
            );
        }
        const equal_tok = try self.expect(.equal, "'=' in type alias");
        const aliased_start = self.peek();
        const aliased = try self.parseTypeAnnotation();
        if (alias_name_is_void) {
            try self.reportCodeAt(start.span.start, start.line, 2304, "Cannot find name 'type'.");
            try self.reportCodeAt(equal_tok.span.start, equal_tok.line, 1109, "Expression expected.");
            if (aliased_start.kind == .identifier) {
                const rhs_name = self.source[aliased_start.span.start..aliased_start.span.end];
                const msg = try std.fmt.allocPrint(
                    self.diag_arena.allocator(),
                    "'{s}' only refers to a type, but is being used as a value here.",
                    .{rhs_name},
                );
                try self.reportCodeAt(aliased_start.span.start, aliased_start.line, 2693, msg);
            }
        }
        try self.consumeStatementTerminator();
        const end_pos = self.tokens[self.cursor - 1].span.end;
        return try self.builder.addTypeAlias(
            .{ .start = start.span.start, .end = end_pos },
            name_node,
            type_params,
            aliased,
        );
    }

    fn parseEnumDeclaration(self: *Parser) ParseError!NodeId {
        const start = self.advance(); // enum
        // TS1046: A top-level `enum` in a `.d.ts` file without a
        // leading `declare` / `export` modifier is invalid. Anchored
        // at the `enum` keyword to match upstream tsc's column on
        // `parserEnumDeclaration3.d.ts(1,1)`.
        if (self.isAmbientContextAt(start.span.start) and
            self.block_depth == 0 and
            self.namespace_depth == 0 and
            self.ambient_depth == 0 and
            !self.in_export_declaration)
        {
            try self.reportCodeAt(start.span.start, start.line, 1046, "Top-level declarations in .d.ts files must start with either a 'declare' or 'export' modifier.");
        }
        const name_tok = if (self.peek().kind == .identifier or self.peek().kind.isContextualKeyword())
            self.advance()
        else if (isReservedBindingNameToken(self.peek().kind)) blk: {
            const tok = self.advance();
            try self.reportReservedWordCannotBeUsedHere(tok);
            break :blk tok;
        } else try self.expect(.identifier, "enum name");
        const enum_body_open = try self.expect(.open_brace, "'{' to open enum body");
        // Enum member initializers are not a generator context even
        // when the enum sits inside a generator body — `yield` there
        // is TS1163 (awaitAndYield: `enum E { baz = yield 1 }` inside
        // `async function* test`).
        const saved_generator_depth = self.generator_depth;
        self.generator_depth = 0;
        defer self.generator_depth = saved_generator_depth;
        var members: std.ArrayListUnmanaged(NodeId) = .empty;
        defer members.deinit(self.gpa);
        var recovered_member_list_boundary = false;
        while (self.peek().kind != .close_brace and self.peek().kind != .eof) {
            const member_start = self.peek();
            // `@` cannot begin an enum member, but it can begin a
            // declaration in the enclosing source-elements context.
            // Match parseDelimitedList(PCEnumMembers): emit TS1132 and
            // yield without consuming the token so outer declaration
            // recovery can process the decorator sequence.
            if (member_start.kind == .at) {
                try self.reportCodeAt(member_start.span.start, member_start.line, 1132, "Enum member expected.");
                recovered_member_list_boundary = true;
                break;
            }
            if (member_start.kind == .comma) {
                const comma = self.advance();
                try self.reportCodeAt(comma.span.start, comma.line, 1132, "Enum member expected.");
                continue;
            }
            if (member_start.kind == .invalid) {
                const bad = self.advance();
                try self.reportCodeAt(bad.span.start, bad.line, 1127, "Invalid character.");
                if (self.peek().kind == .comma) _ = self.advance();
                continue;
            }
            var is_computed = false;
            const name_node = if (self.peek().kind == .open_bracket) blk: {
                const open = self.advance();
                const key = try self.parseExpression();
                _ = try self.expectClosingMatch(.close_bracket, "']' to close computed enum member name", open.span.start, "[", "]");
                // Record the full `[name]` width so a colocated TS1357
                // (single-`[` width) at the same `(line,col)` sorts
                // before this wider TS1164 per tsc's
                // `compareDiagnostics` (smaller length wins).
                // Mirrors `parserComputedPropertyName30.ts(4,5)`.
                const close_end = self.tokens[self.cursor - 1].span.end;
                const ts1164_span: u32 = if (close_end > open.span.start) close_end - open.span.start else 1;
                try self.reportCodeWithSpanAt(open.span.start, open.line, 1164, ts1164_span, "Computed property names are not allowed in enums.");
                is_computed = true;
                break :blk key;
            } else blk: {
                const member_tok = if (self.peek().kind == .string_literal or self.peek().kind == .number_literal)
                    self.advance()
                else
                    try self.expectIdentifierLike();
                if (member_tok.kind == .number_literal) {
                    try self.reportCodeAt(member_tok.span.start, member_tok.line, 2452, "An enum member cannot have a numeric name.");
                }
                // TS18024 — ECMAScript `#name` identifiers may only
                // appear as class member names; an enum member named
                // `#x` is invalid. Mirrors upstream `privateNameEnum`.
                if (member_tok.kind == .private_identifier) {
                    try self.reportCodeAt(member_tok.span.start, member_tok.line, 18024, "An enum member cannot be named with a private identifier.");
                }
                const name_id = try self.internPropertyName(member_tok, tokenSpan(member_tok));
                break :blk try self.builder.addIdentifier(tokenSpan(member_tok), name_id);
            };
            var value: NodeId = hir_mod.none_node_id;
            var recovered_bad_separator = false;
            if (self.peek().kind == .colon) {
                const colon = self.advance();
                try self.reportCodeAt(colon.span.start, colon.line, 1357, "An enum member name must be followed by a ',', '=', or '}'.");
                recovered_bad_separator = true;
            }
            if (self.match(.equal)) value = try self.parseAssignmentExpression();
            const member = try self.builder.addObjectProperty(
                .{ .start = member_start.span.start, .end = self.tokens[self.cursor - 1].span.end },
                name_node,
                value,
                is_computed,
                value == hir_mod.none_node_id,
                false,
            );
            try members.append(self.gpa, member);
            if (recovered_bad_separator) continue;
            if (self.match(.comma)) continue;
            // No separator before the next token — if it can start
            // another enum member (identifier, string/number literal,
            // computed `[`), tsc emits TS1357 and recovers by parsing
            // the next member instead of bailing out of the enum
            // body. Mirrors `parserComputedPropertyName30.ts(4,5)`.
            const next = self.peek();
            const can_start_member = next.kind == .identifier or
                next.kind == .string_literal or
                next.kind == .number_literal or
                next.kind == .open_bracket or
                next.kind.isContextualKeyword();
            if (can_start_member) {
                // Width = 1 so a colocated TS1164 (wider `[name]`
                // span) at the same `(line,col)` sorts after this
                // TS1357 per tsc's `compareDiagnostics` (smaller
                // length wins). See the matching wide-span TS1164
                // emission in the computed-key branch above.
                try self.reportCodeWithSpanAt(next.span.start, next.line, 1357, 1, "An enum member name must be followed by a ',', '=', or '}'.");
                continue;
            }
            break;
        }
        const close_end = if (recovered_member_list_boundary)
            self.peek().span.start
        else if (self.peek().kind == .close_brace) blk: {
            break :blk self.advance().span.end;
        } else blk: {
            const close = self.peek();
            const diag_pos = if (close.kind == .eof and self.cursor > 0 and self.tokens[self.cursor - 1].kind == .invalid)
                self.tokens[self.cursor - 1].span.start + 1
            else
                close.span.start;
            try self.reportCodeAtWithMatchedPair(
                diag_pos,
                close.line,
                1005,
                "'}' expected.",
                enum_body_open.span.start,
                "{",
                "}",
            );
            if (close.kind == .eof) self.enum_recovered_missing_close_at_eof = true;
            break :blk diag_pos;
        };
        const name_id = try self.internToken(name_tok);
        const name_node = try self.builder.addIdentifier(tokenSpan(name_tok), name_id);
        return try self.builder.addEnum(
            .{ .start = start.span.start, .end = close_end },
            name_node,
            members.items,
            false,
        );
    }

    fn parseNamespaceDeclaration(self: *Parser) ParseError!NodeId {
        const start = self.advance(); // namespace / module
        const has_declare_modifier = self.cursor >= 2 and self.tokens[self.cursor - 2].kind == .kw_declare;
        // TS1046: A top-level `namespace` / `module` in a `.d.ts` file
        // without a leading `declare` / `export` modifier is invalid.
        // Anchored at the `namespace` / `module` keyword to match
        // upstream tsc's column on
        // `parserModuleDeclaration{1,2,4}.d.ts(1,1)`.
        if (self.isAmbientContextAt(start.span.start) and
            self.block_depth == 0 and
            self.namespace_depth == 0 and
            self.ambient_depth == 0 and
            !self.in_export_declaration)
        {
            try self.reportCodeAt(start.span.start, start.line, 1046, "Top-level declarations in .d.ts files must start with either a 'declare' or 'export' modifier.");
        }
        const name_tok: Token = name_blk: {
            if (self.peek().kind == .string_literal) break :name_blk self.advance();
            if (self.peek().kind == .open_brace) {
                const brace = self.peek();
                try self.reportCodeAt(brace.span.start, brace.line, 1437, "Namespace must be given a name.");
                break :name_blk .{
                    .span = .{ .start = brace.span.start, .end = brace.span.start },
                    .kind = .identifier,
                    .flags = .{},
                    .line = brace.line,
                };
            }
            break :name_blk try self.expectIdentifierLike();
        };
        if (name_tok.kind == .kw_namespace or name_tok.kind == .kw_module) {
            const name_text = self.source[name_tok.span.start..name_tok.span.end];
            const msg = try std.fmt.allocPrint(self.diag_arena.allocator(), "Namespace name cannot be '{s}'.", .{name_text});
            try self.reportCodeAt(name_tok.span.start, name_tok.line, 2819, msg);
        }
        // TS1035: A quoted-name namespace/module declaration is only
        // legal in an ambient context (after `declare` or inside a
        // `.d.ts` file). Bare `module "Foo" {}` in a `.ts` file is an
        // augmentation form that requires the ambient marker. Mirrors
        // upstream tsc on `parserModuleDeclaration1.ts(1,8)`.
        if (name_tok.kind == .string_literal and
            self.ambient_depth == 0 and
            !self.isAmbientContextAt(start.span.start))
        {
            try self.reportCodeAt(name_tok.span.start, name_tok.line, 1035, "Only ambient modules can use quoted names.");
        }
        // TS2436: `declare module "./foo"` / `declare module "../bar"`
        // is rejected by upstream tsc — ambient module declarations
        // must name non-relative external modules. The check applies
        // only to string-literal ambient names (the dotted-identifier
        // form `declare module Foo.Bar {}` is a namespace and has no
        // relative-path concept). Anchored at the literal token.
        if (name_tok.kind == .string_literal and
            (self.ambient_depth > 0 or self.isAmbientContextAt(start.span.start)))
        {
            const lit = self.source[name_tok.span.start..name_tok.span.end];
            if (lit.len >= 3) {
                const inner = lit[1 .. lit.len - 1];
                const is_relative_name = moduleNameTextIsRelative(inner);
                const is_external_module_augmentation = is_relative_name and
                    self.top_level_external_module_indicator and
                    self.block_depth == 0 and
                    self.namespace_depth == 0;
                if (is_relative_name and !is_external_module_augmentation) {
                    try self.reportCodeAt(name_tok.span.start, name_tok.line, 2436, "Ambient module declaration cannot specify relative module name.");
                }
            }
        }
        // TS2435: explicit nested ambient modules
        // (`declare module "outer" { declare module "inner" {} }`)
        // and string-named modules nested in identifier namespaces are
        // rejected. A bare `module "Observable" { ... }` inside a
        // string-named ambient module is the module-augmentation form
        // tsc accepts and re-roots at the global external module name.
        // Mirrors `moduleAugmentationInAmbientModule3`.
        if (name_tok.kind == .string_literal and
            self.namespace_depth > 0 and
            (self.ambient_depth > 0 or self.isAmbientContextAt(start.span.start)) and
            (has_declare_modifier or !self.in_string_named_module))
        {
            try self.reportCodeAt(name_tok.span.start, name_tok.line, 2435, "Ambient modules cannot be nested in other modules or namespaces.");
        }
        var name_end = name_tok.span.end;
        var is_dotted = false;
        while (self.peek().kind == .dot) {
            is_dotted = true;
            _ = self.advance();
            const part = try self.expectIdentifierLike();
            name_end = part.span.end;
        }
        // Body-less ambient module declaration: `declare module "foo";`
        // (or terminated by ASI). Common in `.d.ts` shims. Skip the
        // brace-block parse and produce an empty-bodied namespace.
        const ambient_bodyless = name_tok.kind == .string_literal and
            self.ambient_depth > 0 and
            self.peek().kind != .open_brace;
        if (ambient_bodyless) {
            try self.consumeStatementTerminator();
            const name_id_b = try self.internStringLiteral(name_tok);
            const name_node_b = try self.builder.addIdentifier(.{ .start = name_tok.span.start, .end = name_end }, name_id_b);
            return try self.builder.addNamespace(
                .{ .start = start.span.start, .end = self.tokens[self.cursor - 1].span.end },
                name_node_b,
                &.{},
            );
        }
        const ns_body_open = try self.expect(.open_brace, "'{' to open namespace body");
        const old_in_string_named_module = self.in_string_named_module;
        const is_known_module_augmentation = self.namespaceDeclarationIsKnownExternalModuleAugmentation(name_tok, old_in_string_named_module);
        self.namespace_depth += 1;
        defer self.namespace_depth -= 1;
        const allows_nested_declare = has_declare_modifier and is_dotted;
        if (allows_nested_declare) self.dotted_ambient_namespace_depth += 1;
        defer if (allows_nested_declare) {
            self.dotted_ambient_namespace_depth -= 1;
        };
        if (is_known_module_augmentation) self.module_augmentation_depth += 1;
        defer {
            if (is_known_module_augmentation) self.module_augmentation_depth -= 1;
        }
        self.in_string_named_module = name_tok.kind == .string_literal;
        defer self.in_string_named_module = old_in_string_named_module;
        var body: std.ArrayListUnmanaged(NodeId) = .empty;
        defer body.deinit(self.gpa);
        while (self.hasPendingStatement() or (self.peek().kind != .close_brace and self.peek().kind != .eof)) {
            try body.append(self.gpa, try self.parseStatement());
        }
        const close_end = if (self.peek().kind == .close_brace) blk: {
            break :blk self.advance().span.end;
        } else blk: {
            const close = self.peek();
            if (close.kind == .eof and self.enum_recovered_missing_close_at_eof) {
                self.enum_recovered_missing_close_at_eof = false;
            } else {
                try self.reportCodeAtWithMatchedPair(
                    close.span.start,
                    close.line,
                    1005,
                    "'}' expected.",
                    ns_body_open.span.start,
                    "{",
                    "}",
                );
            }
            break :blk close.span.start;
        };
        const name_id = if (name_tok.kind == .string_literal)
            try self.internStringLiteral(name_tok)
        else
            self.interner.intern(self.source[name_tok.span.start..name_end]) catch return error.OutOfMemory;
        const name_node = try self.builder.addIdentifier(.{ .start = name_tok.span.start, .end = name_end }, name_id);
        return try self.builder.addNamespace(
            .{ .start = start.span.start, .end = close_end },
            name_node,
            body.items,
        );
    }

    fn parseImportDeclaration(self: *Parser) ParseError!NodeId {
        const start = self.advance(); // import
        const import_idx = self.cursor - 1;
        if (self.block_depth == 0 and self.namespace_depth == 0 and self.ambient_depth == 0) {
            self.top_level_external_module_indicator = true;
            self.top_level_module_syntax_indicator = true;
        }
        if (self.moduleElementContextIsIllegal()) {
            // TS1232 / TS1473: an import declaration (ES import or
            // `import x =`) nested inside a block or control-flow body.
            // JavaScript files use the module-only wording upstream.
            if (self.is_javascript_file) {
                try self.reportCodeAt(start.span.start, start.line, 1473, "An import declaration can only be used at the top level of a module.");
            } else {
                try self.reportCodeAt(start.span.start, start.line, 1232, "An import declaration can only be used at the top level of a namespace or module.");
            }
        }
        if (self.module_augmentation_depth > 0 and !self.importKeywordBeginsImportEquals(import_idx)) {
            try self.reportCodeAt(start.span.start, start.line, 2667, "Imports are not permitted in module augmentations. Consider moving them to the enclosing external module.");
        }
        var is_type_only = false;
        var type_kw_start: u32 = start.span.start;
        var type_kw_line: u32 = start.line;
        if (self.peek().kind == .kw_type) {
            if (self.peekAt(1).kind != .equal and
                !(self.peekAt(1).kind == .kw_from and self.peekAt(2).kind == .string_literal))
            {
                const type_tok = self.advance();
                is_type_only = true;
                type_kw_start = type_tok.span.start;
                type_kw_line = type_tok.line;
            }
        }
        var default_binding: NodeId = hir_mod.none_node_id;
        var namespace_binding: NodeId = hir_mod.none_node_id;
        var named: std.ArrayListUnmanaged(NodeId) = .empty;
        defer named.deinit(self.gpa);
        var default_binding_had_comma = false;
        // Whether a `{ ... }` named-imports clause was actually present
        // (even if empty). An empty `import foo, {} from "m"` is valid —
        // distinct from `import foo, from "m"` (no clause), which needs
        // the TS1005 "'{' expected" recovery below.
        var saw_named_imports_brace = false;

        // Deferred import modifier: `import defer * as ns from "m"`. `defer`
        // is contextual, so disambiguate exactly as tsc's
        // `parseImportDeclarationOrImportEqualsDeclaration`: after a `defer`
        // identifier, treat it as the modifier unless the next token shows
        // `defer` is itself the imported name (`import defer from "m"` /
        // `import defer, {x} from "m"` / `import defer = require(...)`).
        var is_deferred = false;
        var deferred_clause_start: u32 = 0;
        if ((self.peek().kind == .identifier or self.peek().kind.isContextualKeyword()) and
            self.tokenTextEquals(self.peek(), "defer") and !is_type_only)
        {
            const after = self.peekAt(1).kind;
            const parse_as_defer = if (after == .kw_from)
                self.peekAt(2).kind != .string_literal
            else
                after != .comma and after != .equal;
            if (parse_as_defer) {
                is_deferred = true;
                deferred_clause_start = self.peek().span.start;
                _ = self.advance(); // consume `defer`
            }
        }

        const import_equals_star_recovery = is_type_only and
            (self.peek().kind == .identifier or self.peek().kind == .kw_await or self.peek().kind.isContextualKeyword()) and
            self.peekAt(1).kind == .asterisk;
        const import_equals_missing_before_declaration = !is_deferred and
            (self.peek().kind == .identifier or self.peek().kind == .kw_await or self.peek().kind.isContextualKeyword()) and
            self.peekAt(1).kind != .comma and
            self.peekAt(1).kind != .kw_from and
            tokenStartsDeclarationStatementAfterVariableList(self.peekAt(1).kind);
        if ((self.peek().kind == .identifier or self.peek().kind == .kw_await or self.peek().kind.isContextualKeyword()) and
            (self.peekAt(1).kind == .equal or import_equals_star_recovery or import_equals_missing_before_declaration))
        {
            const alias_tok = self.peek();
            const has_equals = self.peekAt(1).kind == .equal;
            if (has_equals and is_type_only and self.peekAt(2).kind != .kw_require) {
                try self.reportCodeAt(
                    start.span.start,
                    start.line,
                    1392,
                    "An import alias cannot use 'import type'",
                );
            }
            if (has_equals and alias_tok.kind == .kw_await and (self.peekAt(2).kind == .kw_require or self.top_level_export_indicator)) {
                try self.reportCodeAt(
                    alias_tok.span.start,
                    alias_tok.line,
                    1262,
                    "Identifier expected. 'await' is a reserved word at the top-level of a module.",
                );
            }
            const alias_id = try self.internToken(alias_tok);
            const alias_node = try self.builder.addIdentifier(tokenSpan(alias_tok), alias_id);
            _ = self.advance(); // local alias
            if (!has_equals) {
                const missing_equal_at = self.peek();
                try self.reportCodeAt(missing_equal_at.span.start, missing_equal_at.line, 1005, "'=' expected.");
                if (import_equals_missing_before_declaration) {
                    const empty_module = self.interner.intern("") catch return error.OutOfMemory;
                    return try self.builder.addImport(
                        .{ .start = start.span.start, .end = alias_tok.span.end },
                        empty_module,
                        alias_node,
                        hir_mod.none_node_id,
                        hir_mod.none_node_id,
                        &.{},
                        is_type_only,
                    );
                }
                const star = self.advance();
                if (self.peek().kind == .kw_as and self.peekAt(2).kind == .kw_from) {
                    const from_tok = self.peekAt(2);
                    try self.reportCodeAt(from_tok.span.start, from_tok.line, 1434, "Unexpected keyword or identifier.");
                }
                const empty_module = self.interner.intern("") catch return error.OutOfMemory;
                return try self.builder.addImport(
                    .{ .start = start.span.start, .end = star.span.end },
                    empty_module,
                    alias_node,
                    hir_mod.none_node_id,
                    hir_mod.none_node_id,
                    &.{},
                    is_type_only,
                );
            }
            _ = self.advance(); // =
            var module_id = self.interner.intern("") catch return error.OutOfMemory;
            var module_specifier_pos: ?u32 = null;
            var import_equals = hir_mod.none_node_id;
            var is_require_equals = false;
            if (self.peek().kind == .kw_require and self.peekAt(1).kind == .open_paren and self.peekAt(2).kind == .string_literal) {
                is_require_equals = true;
                _ = self.advance(); // require
                const require_open = self.advance(); // (
                const mod_tok = self.advance();
                module_id = try self.internStringLiteral(mod_tok);
                module_specifier_pos = mod_tok.span.start;
                // TS1147: `import name = require("…")` inside an internal
                // namespace is illegal. tsc fires at the module-specifier
                // string-literal token. Ambient string-named modules
                // (`declare module "foo" { … }`) are exempt — those are
                // external module declarations where require-imports are
                // legitimate. Mirrors upstream
                // `importDeclarationInModuleDeclaration1.errors.txt`.
                if (self.namespace_depth > 0 and !self.in_string_named_module) {
                    try self.reportCodeAtWithSpan(
                        mod_tok.span.start,
                        mod_tok.line,
                        mod_tok.span.end - mod_tok.span.start,
                        1147,
                        "Import declarations in a namespace cannot reference a module.",
                    );
                }
                try self.reportAmbientRelativeModuleIfNeededAt(mod_tok, start.span.start, start.line);
                _ = try self.expectClosingMatch(.close_paren, "')' after require module specifier", require_open.span.start, "(", ")");
                try self.consumeStatementTerminator();
            } else if (self.peek().kind == .kw_require and self.peekAt(1).kind == .open_paren) {
                try self.consumeImportEqualsTail();
            } else {
                if (self.peek().kind == .identifier or self.peek().kind.isContextualKeyword() or self.peek().kind.isKeyword()) {
                    import_equals = try self.parseImportEqualsEntityName();
                    try self.consumeStatementTerminator();
                } else {
                    try self.consumeImportEqualsTail();
                }
            }
            const end_pos = self.tokens[self.cursor - 1].span.end;
            const import_node = try self.builder.addImport(
                .{ .start = start.span.start, .end = end_pos },
                module_id,
                alias_node,
                hir_mod.none_node_id,
                import_equals,
                &.{},
                is_type_only,
            );
            self.hir.import_payloads.items[self.hir.payloads.items[import_node]].module_specifier_pos = module_specifier_pos;
            if (is_require_equals) {
                if (self.module_augmentation_depth > 0) {
                    try self.reportCodeAt(start.span.start, start.line, 2667, "Imports are not permitted in module augmentations. Consider moving them to the enclosing external module.");
                }
                self.hir.import_payloads.items[self.hir.payloads.items[import_node]].is_require_equals = true;
            }
            return import_node;
        }

        if (self.peek().kind == .string_literal) {
            // bare side-effect import: `import "module";`
            const mod_tok = self.advance();
            try self.reportAmbientRelativeModuleIfNeededAt(mod_tok, start.span.start, start.line);
            // Optional import attributes: `with { type: "json" }` (TS 5.3+)
            // or legacy `assert { type: "json" }` — parsed and discarded.
            try self.skipImportAttributesClause();
            try self.consumeStatementTerminator();
            const mod_id = try self.internStringLiteral(mod_tok);
            const import_node = try self.builder.addImport(
                .{ .start = start.span.start, .end = self.tokens[self.cursor - 1].span.end },
                mod_id,
                hir_mod.none_node_id,
                hir_mod.none_node_id,
                hir_mod.none_node_id,
                &.{},
                is_type_only,
            );
            self.hir.import_payloads.items[self.hir.payloads.items[import_node]].module_specifier_pos = mod_tok.span.start;
            return import_node;
        }

        // Default binding?
        if (self.peek().kind == .identifier or self.peek().kind.isContextualKeyword()) {
            const name_tok = self.advance();
            if (name_tok.kind == .kw_await and self.top_level_external_module_indicator) {
                try self.reportCodeAt(
                    name_tok.span.start,
                    name_tok.line,
                    1262,
                    "Identifier expected. 'await' is a reserved word at the top-level of a module.",
                );
            }
            const id = try self.internToken(name_tok);
            default_binding = try self.builder.addIdentifier(tokenSpan(name_tok), id);
            if (!self.match(.comma)) {
                // Only default — proceed to from clause.
            } else {
                default_binding_had_comma = true;
            }
        }

        // Namespace/named bindings may follow a default binding only when a
        // comma was consumed. Mirrors TypeScript's parseImportClause gate.
        const can_parse_named_bindings = default_binding == hir_mod.none_node_id or default_binding_had_comma;

        // Namespace import: `* as ns`?
        if (can_parse_named_bindings and self.match(.asterisk)) {
            // Recover from `import * from "..."` (missing `as`) — emit
            // TS1005 'as' expected. then continue to treat the next
            // identifier-like token (including the contextual keyword
            // `from`) as the namespace binding. Mirrors tsc's recovery
            // in `invalidSyntaxNamespaceImportWith{Commonjs,AMD,System}`
            // where the original `import * from Zero from "./0"`
            // yields the full TS1005 'as' / TS1005 'from' / TS1141 /
            // TS1005 ';' cascade.
            const had_as = self.match(.kw_as);
            if (!had_as) {
                const here = self.peek();
                try self.reportCodeAt(here.span.start, here.line, 1005, "'as' expected.");
            }
            const k = self.peek().kind;
            const has_name = blk: {
                if (k == .identifier) break :blk true;
                if (k.isKeyword() or k.isContextualKeyword()) {
                    // Accept reserved/contextual words after a real
                    // `as`, and also after the synthetic `as` recovery
                    // (so `* from Zero from "..."` treats `from` as
                    // the namespace name).
                    break :blk true;
                }
                break :blk false;
            };
            if (has_name) {
                const name_tok = try self.expectIdentifierLike();
                if (name_tok.kind == .kw_await and self.top_level_external_module_indicator) {
                    try self.reportCodeAt(
                        name_tok.span.start,
                        name_tok.line,
                        1262,
                        "Identifier expected. 'await' is a reserved word at the top-level of a module.",
                    );
                }
                const id = try self.internToken(name_tok);
                namespace_binding = try self.builder.addIdentifier(tokenSpan(name_tok), id);
            }
        }
        // Named imports: `{ a, b as c, type d }`?
        else if (can_parse_named_bindings and self.peek().kind == .open_brace) {
            saw_named_imports_brace = true;
            const named_imports_open = self.advance();
            while (self.peek().kind != .close_brace and self.peek().kind != .eof) {
                const spec_start = self.peek();
                if (!self.tokenCanStartModuleExportName(self.peek())) {
                    const bad = self.peek();
                    try self.reportCodeAt(bad.span.start, bad.line, 1003, "Identifier expected.");
                    if (bad.kind == .asterisk) {
                        try self.reportCodeAt(bad.span.start, bad.line, 1141, "String literal expected.");
                        _ = self.advance();
                        if (self.peek().kind == .close_brace) {
                            const close = self.advance();
                            try self.reportCodeAt(close.span.start, close.line, 1109, "Expression expected.");
                        }
                        if (self.peek().kind == .kw_from) {
                            const from_tok = self.peek();
                            try self.reportCodeAt(from_tok.span.start, from_tok.line, 1434, "Unexpected keyword or identifier.");
                        }
                        const mod_id = self.interner.intern("") catch return error.OutOfMemory;
                        return try self.builder.addImport(
                            .{ .start = start.span.start, .end = self.tokens[self.cursor - 1].span.end },
                            mod_id,
                            default_binding,
                            namespace_binding,
                            hir_mod.none_node_id,
                            named.items,
                            is_type_only,
                        );
                    }
                    _ = self.advance();
                    if (!self.match(.comma)) break;
                    continue;
                }
                const parsed_spec = try self.parseImportOrExportSpecifier(true);
                const imported_tok = parsed_spec.imported;
                const local_tok_for_diag = parsed_spec.local;
                const spec_type_only = parsed_spec.is_type_only;
                // TS2206 — a named import specifier cannot carry its own
                // `type` modifier when the whole statement is already an
                // `import type {...}`. Anchored at the specifier's `type`
                // keyword. Mirrors `checkGrammarTypeOnlyNamedImportsOrExports`.
                if (is_type_only and spec_type_only) {
                    try self.reportCodeAt(spec_start.span.start, spec_start.line, 2206, "The 'type' modifier cannot be used on a named import when 'import type' is used on its import statement.");
                }
                const imported_is_string_literal = imported_tok.kind == .string_literal;
                const local_id = try self.internModuleExportName(local_tok_for_diag);
                const imported_id = try self.internModuleExportName(imported_tok);
                const local_is_string_literal = local_tok_for_diag.kind == .string_literal;
                if (local_tok_for_diag.kind == .kw_await and self.top_level_external_module_indicator) {
                    try self.reportCodeAt(
                        local_tok_for_diag.span.start,
                        local_tok_for_diag.line,
                        1262,
                        "Identifier expected. 'await' is a reserved word at the top-level of a module.",
                    );
                }
                if (self.tokenTextEquals(local_tok_for_diag, "yield") and self.top_level_external_module_indicator) {
                    try self.reportCodeAt(
                        local_tok_for_diag.span.start,
                        local_tok_for_diag.line,
                        1214,
                        "Identifier expected. 'yield' is a reserved word in strict mode. Modules are automatically in strict mode.",
                    );
                }
                const spec = try self.builder.addImportSpecifierFull(
                    .{ .start = spec_start.span.start, .end = self.tokens[self.cursor - 1].span.end },
                    imported_id,
                    local_id,
                    spec_type_only,
                    imported_is_string_literal,
                    local_is_string_literal,
                    imported_tok.span.start,
                    local_tok_for_diag.span.start,
                );
                try named.append(self.gpa, spec);
                if (!self.match(.comma)) break;
            }
            _ = try self.expectClosingMatch(.close_brace, "'}' to close named imports", named_imports_open.span.start, "{", "}");
        }
        if (default_binding_had_comma and
            namespace_binding == hir_mod.none_node_id and
            named.items.len == 0 and
            !saw_named_imports_brace and
            self.peek().kind == .kw_from)
        {
            const from_tok = self.peek();
            try self.reportCodeAt(from_tok.span.start, from_tok.line, 1005, "'{' expected.");
        }

        if (is_type_only and default_binding != hir_mod.none_node_id and
            (namespace_binding != hir_mod.none_node_id or named.items.len != 0))
        {
            // Upstream anchors TS1363 at the `type` keyword (col after
            // `import `), not the leading `import` keyword. Mirrors
            // `grammarErrors.errors.txt: /b.ts(1,8)`.
            try self.reportCodeAt(
                type_kw_start,
                type_kw_line,
                1363,
                "A type-only import can specify a default import or named bindings, but not both.",
            );
        }

        // End of the import clause (the binding, before `from`) — anchors the
        // deferred-import grammar diagnostics in the checker.
        const deferred_clause_end: u32 = self.tokens[self.cursor - 1].span.end;

        if (self.peek().kind != .kw_from) {
            const here = self.peek();
            try self.reportCodeAt(here.span.start, here.line, 1005, "'from' expected.");
        } else {
            _ = self.advance();
        }
        var recovered_comma_from_tail = false;
        var recovered_invalid_star_module = false;
        const mod_tok: Token = blk: {
            if (self.peek().kind == .string_literal) {
                break :blk self.advance();
            }
            // Recovery: the module specifier is missing or a non-string
            // token. Emit TS1141 at the current token and synthesize an
            // empty string literal. If the offending token is an
            // identifier/keyword that can be consumed without breaking
            // continued parsing, advance past it so the trailing tokens
            // (e.g. a second `from` after `import * from Zero from
            // "./0"`) get their own `';' expected.` diagnostic.
            const here = self.peek();
            try self.reportCodeAt(here.span.start, here.line, 1141, "String literal expected.");
            if (here.kind == .comma and self.peekAt(1).kind == .kw_from) {
                _ = self.advance();
                _ = self.advance();
                if (self.peek().kind == .string_literal) {
                    const string_tok = self.advance();
                    try self.reportCodeAt(string_tok.span.start, string_tok.line, 1005, "';' expected.");
                }
                _ = self.match(.semicolon);
                recovered_comma_from_tail = true;
            } else if (here.kind == .asterisk) {
                // `import defaultBinding * as ns from "m"` lacks the comma
                // required before a namespace import. TypeScript parses the
                // `* as` pair as the malformed module expression, reports the
                // missing terminator at `ns`, then resumes with `ns` as the
                // next statement so downstream name diagnostics survive.
                _ = self.advance();
                _ = self.match(.kw_as);
                const terminator = self.peek();
                try self.reportCodeAt(terminator.span.start, terminator.line, 1005, "';' expected.");
                if (self.peekAt(1).kind == .kw_from) {
                    const from_tok = self.peekAt(1);
                    try self.reportCodeAt(from_tok.span.start, from_tok.line, 1434, "Unexpected keyword or identifier.");
                }
                recovered_invalid_star_module = true;
            }
            const advance_over: bool = switch (here.kind) {
                .identifier => true,
                else => false,
            };
            if (!recovered_comma_from_tail and advance_over) _ = self.advance();
            const synth = Token{
                .kind = .string_literal,
                .span = .{ .start = here.span.start, .end = here.span.start },
                .line = here.line,
                .flags = .{},
            };
            break :blk synth;
        };
        // Optional import attributes: `with { type: "json" }` (TS 5.3+)
        // or legacy `assert { type: "json" }` — parsed and discarded.
        try self.skipImportAttributesClause();
        if (!recovered_comma_from_tail and !recovered_invalid_star_module) try self.consumeStatementTerminator();
        try self.reportAmbientRelativeModuleIfNeededAt(mod_tok, start.span.start, start.line);
        const mod_id = if (mod_tok.span.start == mod_tok.span.end)
            (self.interner.intern("") catch return error.OutOfMemory)
        else
            try self.internStringLiteral(mod_tok);
        const end_pos = self.tokens[self.cursor - 1].span.end;
        const import_node = try self.builder.addImport(
            .{ .start = start.span.start, .end = end_pos },
            mod_id,
            default_binding,
            namespace_binding,
            hir_mod.none_node_id,
            named.items,
            is_type_only,
        );
        self.hir.import_payloads.items[self.hir.payloads.items[import_node]].module_specifier_pos = if (mod_tok.span.start == mod_tok.span.end)
            null
        else
            mod_tok.span.start;
        if (is_deferred) {
            const payload = &self.hir.import_payloads.items[self.hir.payloads.items[import_node]];
            payload.is_deferred = true;
            payload.deferred_clause_start = deferred_clause_start;
            payload.deferred_clause_end = deferred_clause_end;
        }
        return import_node;
    }

    fn consumeImportEqualsTail(self: *Parser) ParseError!void {
        if (self.peek().kind == .kw_require and self.peekAt(1).kind == .open_paren) {
            const arg = self.peekAt(2);
            if (arg.kind != .string_literal) {
                try self.reportCodeAt(arg.span.start, arg.line, 1141, "String literal expected.");
            }
        }
        var depth: i32 = 0;
        var saw_token = false;
        while (true) {
            const t = self.peek();
            if (t.kind == .eof or t.kind == .semicolon) break;
            if (depth == 0 and (t.kind == .close_brace or (saw_token and t.flags.preceded_by_newline))) break;
            switch (t.kind) {
                .open_paren, .open_brace, .open_bracket => depth += 1,
                .close_paren, .close_brace, .close_bracket => {
                    if (depth > 0) {
                        depth -= 1;
                    } else {
                        break;
                    }
                },
                else => {},
            }
            _ = self.advance();
            saw_token = true;
        }
        _ = self.match(.semicolon);
    }

    fn parseImportEqualsEntityName(self: *Parser) ParseError!NodeId {
        const start = self.peek();
        const name_tok = try self.expectIdentifierLike();
        var name_id = try self.internToken(name_tok);

        var qualifier: std.ArrayListUnmanaged(NodeId) = .empty;
        defer qualifier.deinit(self.gpa);
        var previous_tok = name_tok;

        while (self.peek().kind == .dot) {
            _ = self.advance();
            const next_tok = try self.expectIdentifierLike();
            const prev_node = try self.builder.addIdentifier(tokenSpan(previous_tok), name_id);
            try qualifier.append(self.gpa, prev_node);
            previous_tok = next_tok;
            name_id = try self.internToken(next_tok);
        }

        return try self.builder.addTypeRef(
            .{ .start = start.span.start, .end = self.tokens[self.cursor - 1].span.end },
            name_id,
            qualifier.items,
            &.{},
        );
    }

    /// Optional import-attributes clause appearing after a module
    /// specifier or in a re-export's `from`. Accepts:
    ///   * `with { type: "json", name: "foo" }` — TS 5.3+ syntax
    ///   * `assert { type: "json" }` — legacy (deprecated) syntax
    /// Both are parsed for compatibility and discarded — v0 does not
    /// store the attribute payload on the HIR import node.
    fn skipImportAttributesClause(self: *Parser) ParseError!void {
        const k = self.peek().kind;
        const is_with = k == .kw_with;
        const is_assert = k == .identifier and std.mem.eql(
            u8,
            self.source[self.peek().span.start..self.peek().span.end],
            "assert",
        );
        if (!is_with and !is_assert) return;
        // Only treat the keyword as an attributes clause when followed
        // by `{` — otherwise `with` is reserved for `with` statements
        // (we just leave it for whatever surrounding context handles).
        // A trailing `with` / `assert` with no `{` is reported as the
        // tsc-style `TS1005: '{' expected.` anchored at the column right
        // after the keyword (matches `importAttributes4`/`importAssertion4`).
        const keyword_tok = self.peek();
        if (self.peekAt(1).kind != .open_brace) {
            const next_tok = self.peekAt(1);
            const next_is_terminator = switch (next_tok.kind) {
                .semicolon, .eof, .close_brace, .close_paren => true,
                else => false,
            };
            // Heuristic: only synthesize the missing-`{` diagnostic when the
            // `with` keyword sits at the tail of an import (or before a
            // statement terminator / newline). Otherwise leave the
            // surrounding parser to handle it (e.g. `with` statements).
            if (next_is_terminator or next_tok.flags.preceded_by_newline) {
                // tsc anchors TS1005 `'{' expected.` at the next "meaningful"
                // token position. When the keyword sits immediately before a
                // newline + EOF, that's the column-1 start of the next line
                // (`importAssertion4` baseline `(2,1)`); when the keyword is
                // the very last byte of the file with no newline, it's the
                // column right after the keyword (`importAttributes4` `(1,34)`).
                const anchor_pos: u32 = if (next_tok.flags.preceded_by_newline)
                    next_tok.span.start
                else
                    keyword_tok.span.end;
                const anchor_line: u32 = if (next_tok.flags.preceded_by_newline)
                    next_tok.line
                else
                    keyword_tok.line;
                try self.reportCodeAt(anchor_pos, anchor_line, 1005, "'{' expected.");
                _ = self.advance(); // consume the dangling `with` / `assert`
            }
            return;
        }
        _ = self.advance(); // `with` / `assert`
        const open_brace_tok = try self.expect(.open_brace, "'{' to start import attributes");
        while (self.peek().kind != .close_brace and self.peek().kind != .eof) {
            // key: identifier-like or string literal
            const key_kind = self.peek().kind;
            if (key_kind == .string_literal) {
                _ = self.advance();
            } else if (key_kind == .identifier or key_kind.isKeyword()) {
                _ = self.advance();
            } else {
                const bad = self.advance();
                try self.reportCodeAt(bad.span.start, bad.line, 1478, "Identifier or string literal expected.");
                while (self.peek().kind != .comma and self.peek().kind != .close_brace and self.peek().kind != .eof) {
                    _ = self.advance();
                }
                if (!self.match(.comma)) break;
                continue;
            }
            _ = try self.expect(.colon, "':' in import attribute");
            // value: must be a string-literal expression per spec. tsc
            // parses any assignment expression for the value and reports
            // TS2858 in the checker when it isn't a plain string literal
            // (`import * as x from "m" with { field: 0 }`). Home discards
            // the attribute payload, so the parser is the faithful
            // emission point. Anchored at the value-expression start,
            // matching `importAssertionNonstring`/`importAttributes6`.
            const val_tok = self.peek();
            const val_node = try self.parseAssignmentExpression();
            if (self.hir.kindOf(val_node) != .literal_string) {
                try self.reportCodeAt(val_tok.span.start, val_tok.line, 2858, "Import attribute values must be string literal expressions.");
            }
            if (!self.match(.comma)) break;
        }
        if (self.peek().kind != .close_brace) {
            // Synthesize `TS1005: '}' expected.` matching tsc's
            // `importAttributes5`/`importAssertion5` baselines. tsc anchors
            // it at the next "meaningful" token — that's column-1 of the
            // following line when the `{` is followed by a newline + EOF
            // (`importAssertion5` `(2,1)`), and the column right after `{`
            // when the file ends with no newline (`importAttributes5` `(1,36)`).
            const next_tok = self.peek();
            const anchor_pos: u32 = if (next_tok.kind == .eof and !next_tok.flags.preceded_by_newline)
                open_brace_tok.span.end
            else
                next_tok.span.start;
            const anchor_line: u32 = if (next_tok.kind == .eof and !next_tok.flags.preceded_by_newline)
                open_brace_tok.line
            else
                next_tok.line;
            try self.reportCodeAtWithMatchedPair(
                anchor_pos,
                anchor_line,
                1005,
                "'}' expected.",
                open_brace_tok.span.start,
                "{",
                "}",
            );
            return;
        }
        _ = self.advance(); // closing `}`
    }

    /// Given the index of an `import` keyword token, report whether it
    /// begins an import-equals declaration (`import name = …`, optionally
    /// `import type name = …`). Those accept an `export` modifier and
    /// stay clean; all other import forms reject modifiers (TS1191).
    fn importKeywordBeginsImportEquals(self: *const Parser, import_idx: usize) bool {
        if (import_idx >= self.tokens.len or self.tokens[import_idx].kind != .kw_import) return false;
        var i = import_idx + 1;
        // `import type name = require(…)` is still an import-equals.
        if (i < self.tokens.len and self.tokens[i].kind == .kw_type and
            i + 1 < self.tokens.len and self.tokens[i + 1].kind != .equal)
        {
            i += 1;
        }
        if (i + 1 >= self.tokens.len) return false;
        const name = self.tokens[i].kind;
        const is_name = name == .identifier or name == .kw_await or
            name.isContextualKeyword() or name.isKeyword();
        return is_name and self.tokens[i + 1].kind == .equal;
    }

    const ModifierlessExportKind = enum { assignment, declaration };

    /// Given the index of an `export` keyword token, classify whether it
    /// begins an *export assignment* (`export = …`) or an *export
    /// declaration* (`export { … }`, `export * …`, `export type { … }`,
    /// `export type * …`) — the two forms that reject leading modifiers
    /// (TS1120 / TS1193). Returns null for anything else (e.g. `export
    /// interface`, `export var`), which stays the duplicate-export case.
    fn modifierlessExportKind(self: *const Parser, export_idx: usize) ?ModifierlessExportKind {
        if (export_idx >= self.tokens.len or self.tokens[export_idx].kind != .kw_export) return null;
        var i = export_idx + 1;
        if (i >= self.tokens.len) return null;
        if (self.tokens[i].kind == .equal) return .assignment;
        // Skip an optional `type` only when it is the type-only re-export
        // marker (`export type { … }` / `export type * …`).
        if (self.tokens[i].kind == .kw_type and i + 1 < self.tokens.len and
            (self.tokens[i + 1].kind == .open_brace or self.tokens[i + 1].kind == .asterisk))
        {
            i += 1;
        }
        if (i >= self.tokens.len) return null;
        return switch (self.tokens[i].kind) {
            .open_brace, .asterisk => .declaration,
            else => null,
        };
    }

    fn parseExportDeclaration(self: *Parser) ParseError!NodeId {
        const start = self.advance(); // export
        // A `declare` modifier recorded by the statement dispatcher
        // anchors TS1120 / TS1193 on the `declare` keyword itself.
        const pending_modifier = self.pending_decl_modifier;
        self.pending_decl_modifier = null;
        if (self.block_depth == 0 and self.namespace_depth == 0 and self.ambient_depth == 0) {
            self.top_level_external_module_indicator = true;
            self.top_level_module_syntax_indicator = true;
            self.top_level_export_indicator = true;
        }
        if ((self.peek().kind == .identifier or self.peek().kind.isContextualKeyword()) and
            self.tokenTextEquals(self.peek(), "defer") and
            self.peekAt(1).kind == .asterisk)
        {
            try self.reportCodeAt(start.span.start, start.line, 1128, "Declaration or statement expected.");
            return try self.parseExpressionStatement();
        }
        if ((self.peek().kind == .kw_module and self.peekAt(1).kind == .string_literal) or
            (self.peek().kind == .kw_declare and self.peekAt(1).kind == .kw_module and self.peekAt(2).kind == .string_literal))
        {
            try self.reportCodeAt(start.span.start, start.line, 2668, "'export' modifier cannot be applied to ambient modules and module augmentations since they are always visible.");
        }
        if (self.peek().kind == .kw_export) {
            // `export export = x` / `export export { … }` / `export export * …`
            // — here the leading `export` is a *modifier* on an export
            // assignment / export declaration, which reject modifiers.
            // tsc anchors TS1120 / TS1193 on the first token (the leading
            // `export`). Every other doubled-export form (`export export
            // interface`, `export export var`, …) is the duplicate-modifier
            // case and stays TS1030 anchored on the second `export`.
            // Mirrors `exportAssignmentWithExportModifier` and the
            // `export export { C }` line in `plainJSGrammarErrors.js`.
            if (self.modifierlessExportKind(self.cursor)) |kind| {
                switch (kind) {
                    .assignment => try self.reportCodeAt(start.span.start, start.line, 1120, "An export assignment cannot have modifiers."),
                    .declaration => try self.reportCodeAt(start.span.start, start.line, 1193, "An export declaration cannot have modifiers."),
                }
                _ = self.advance(); // consume the second `export` so the
                // construct itself parses below as the real keyword.
            } else {
                const dup = self.advance();
                try self.reportCodeAt(dup.span.start, dup.line, 1030, "'export' modifier already seen.");
            }
        }
        // `type` after `export` is the type-only marker only when
        // the next token is `{` (named re-export) or `*` (namespace
        // re-export). `export type Foo = T;` and `export type Foo {}`
        // are type-alias / interface declarations — we must NOT eat
        // the `type` keyword in those cases.
        var is_type_only: bool = false;
        if (self.peek().kind == .kw_type) {
            const next = self.peekAt(1).kind;
            if (next == .open_brace or next == .asterisk) {
                _ = self.advance();
                is_type_only = true;
            }
        }
        const empty_string = self.interner.intern("") catch return error.OutOfMemory;
        if (self.module_augmentation_depth > 0) {
            switch (self.peek().kind) {
                .equal, .open_brace, .asterisk, .kw_default => try self.reportCodeAt(start.span.start, start.line, 2666, "Exports and export assignments are not permitted in module augmentations."),
                else => {},
            }
        }

        // CommonJS-style `export = value;`. The ES-facing HIR has no
        // dedicated export-assignment node yet; parse and preserve the
        // assigned expression as an export payload so multi-file fixtures
        // keep their module shape without producing a parser diagnostic.
        if (self.match(.equal)) {
            try self.reportExportAssignmentOnlyInTsIfNeeded(start);
            // `declare export = x` — the `declare` modifier is disallowed
            // on an export assignment (TS1120, anchored on `declare`).
            if (pending_modifier) |pm| {
                try self.reportCodeAt(pm.span.start, pm.line, 1120, "An export assignment cannot have modifiers.");
            }
            if (self.moduleElementContextIsIllegal()) {
                // TS1231: `export =` nested inside a block or control-flow
                // body. Anchored at the `export` keyword to match upstream
                // tsc on `moduleElementsInWrongContext.ts(13,5)`.
                try self.reportCodeAt(start.span.start, start.line, 1231, "An export assignment must be at the top level of a file or module declaration.");
            } else if (self.namespace_depth > 0 and self.ambient_depth == 0) {
                try self.reportCodeAt(start.span.start, start.line, 1063, "An export assignment cannot be used in a namespace.");
            }
            const expr = try self.parseAssignmentExpression();
            try self.consumeStatementTerminator();
            const end_pos = self.tokens[self.cursor - 1].span.end;
            return try self.builder.addExportEquals(
                .{ .start = start.span.start, .end = end_pos },
                expr,
                empty_string,
            );
        }

        // `export import Foo = ns.Foo;` inside namespaces/global
        // augmentations is an import-alias declaration. Route it
        // through `parseImportDeclaration` so the HIR records the
        // `Foo` binding + `ns.Foo` reference — the checker's
        // `appendImportEqualsNamespacePathForLocal` walks up to find
        // this binding when resolving `typeof Foo` / qualified type
        // references against the alias. Mirrors fixture
        // `typeofAnExportedType.ts(33,23)` / `(34,23)`.
        if (self.peek().kind == .kw_import) {
            // `export import Foo = …` is a valid export-import-equals
            // alias and stays clean. Any *other* `export import` form
            // (`export import { … }`, `export import "m"`,
            // `export import Foo from`, `export import * as`) is an ES
            // import declaration carrying a disallowed `export` modifier
            // → TS1191, anchored on the leading `export` (the first
            // token). Mirrors `es6Import*WithExport` and the
            // `export import 'fs'` line in `plainJSGrammarErrors.js`.
            if (!self.importKeywordBeginsImportEquals(self.cursor)) {
                try self.reportCodeAt(start.span.start, start.line, 1191, "An import declaration cannot have modifiers.");
            }
            const import_node = try self.parseImportDeclaration();
            // Record the leading `export` modifier on the import-equals
            // node so the checker can surface TS1269 when the alias
            // target resolves to a type / type-only namespace under
            // isolatedModules-like flags.
            if (self.hir.kindOf(import_node) == .import_decl and
                hir_mod.importOf(self.hir, import_node).import_equals != hir_mod.none_node_id)
            {
                self.hir.markImportExported(import_node);
            }
            return import_node;
        }

        // `export as namespace Foo;` is a declaration-file/global UMD
        // export form. Keep it parseable for JS declaration conformance
        // even though the current HIR has no dedicated representation.
        if (self.match(.kw_as)) {
            _ = try self.expect(.kw_namespace, "'namespace' after 'export as'");
            _ = try self.expectIdentifierLike();
            try self.consumeStatementTerminator();
            const end_pos = self.tokens[self.cursor - 1].span.end;
            // Three positional checks mirror upstream `bindSourceFile`
            // / `checkSourceFile` ordering for `GlobalModuleExport`:
            //   TS1316 — appears anywhere other than the source-file
            //   top level (inside a namespace body, ambient module
            //   body, function body, …).
            //   TS1315 — top-level but the containing file isn't a
            //   `.d.ts` declaration file.
            //   TS1314 — `.d.ts` and top-level, but no other top-level
            //   import/export. `export as namespace` itself does not
            //   promote a script file to a module under TypeScript.
            // Only one of the three fires per declaration; the squiggle
            // covers the full `export as namespace Foo;` span. Matches
            // baselines `umd-errors.errors.txt` (err1, err2, err4, err5).
            const span_len: u32 = end_pos - start.span.start;
            if (self.block_depth > 0 or self.namespace_depth > 0 or self.ambient_depth > 0) {
                try self.reportCodeAtWithSpan(start.span.start, start.line, span_len, 1316, "Global module exports may only appear at top level.");
            } else if (!self.isAmbientContextAt(start.span.start)) {
                try self.reportCodeAtWithSpan(start.span.start, start.line, span_len, 1315, "Global module exports may only appear in declaration files.");
            } else if (!self.hasNonNamespaceExportModuleIndicator()) {
                try self.reportCodeAtWithSpan(start.span.start, start.line, span_len, 1314, "Global module exports may only appear in module files.");
            }
            return try self.builder.addBlock(.{ .start = start.span.start, .end = end_pos }, &.{});
        }

        // export default <expr>;
        if (self.match(.kw_default)) {
            if (self.peek().kind == .at) {
                const dec_start = self.peek();
                const dec_expr = try self.parseDecoratorExpression();
                const dec = try self.builder.addDecorator(
                    .{ .start = dec_start.span.start, .end = self.tokens[self.cursor - 1].span.end },
                    dec_expr,
                );
                if (self.peek().kind == .kw_class or
                    (self.peek().kind == .kw_abstract and self.abstractClassFollowsOnSameLine()))
                {
                    const class_decl = try self.parseClassDeclaration();
                    try self.pending_statements.append(self.gpa, class_decl);
                    return try self.builder.addExport(
                        .{ .start = start.span.start, .end = self.hir.spanOf(class_decl).end },
                        dec,
                        &.{},
                        empty_string,
                        is_type_only,
                        true,
                    );
                }
                try self.report("decorators are not valid here", "");
                return try self.builder.addExport(
                    .{ .start = start.span.start, .end = self.hir.spanOf(dec).end },
                    dec,
                    &.{},
                    empty_string,
                    is_type_only,
                    true,
                );
            }
            const default_starts_declaration = switch (self.peek().kind) {
                .kw_class, .kw_function, .kw_interface => true,
                .kw_async => self.peekAt(1).kind == .kw_function,
                else => false,
            };
            if (default_starts_declaration) {
                try self.reportModifierInBlock(start);
            } else if (self.moduleElementContextIsIllegal()) {
                try self.reportCodeAt(start.span.start, start.line, 1258, "A default export must be at the top level of a file or module declaration.");
            }
            if (!self.moduleElementContextIsIllegal() and self.namespace_depth > 0 and self.ambient_depth == 0) {
                try self.reportCodeAt(start.span.start, start.line, 1319, "A default export can only be used in an ECMAScript-style module.");
            }
            // `export default` may be followed by a class/function
            // *declaration* (no statement-terminator) — those have
            // their own statement parser; otherwise it's an
            // expression value.
            const decl = switch (self.peek().kind) {
                .kw_class => try self.parseClassDeclaration(),
                .kw_function => try self.parseFunctionDeclaration(false, false),
                .kw_async => blk: {
                    if (self.peekAt(1).kind == .kw_function) {
                        _ = self.advance();
                        self.async_function_depth += 1;
                        defer self.async_function_depth -= 1;
                        const fd = try self.parseFunctionDeclaration(false, false);
                        self.hir.markFnAsync(fd);
                        break :blk fd;
                    }
                    const expr = try self.parseAssignmentExpression();
                    try self.consumeStatementTerminator();
                    break :blk expr;
                },
                .kw_interface => try self.parseInterfaceDeclaration(),
                else => blk: {
                    const expr = try self.parseAssignmentExpression();
                    try self.consumeStatementTerminator();
                    break :blk expr;
                },
            };
            const end_pos = self.tokens[self.cursor - 1].span.end;
            return try self.builder.addExport(
                .{ .start = start.span.start, .end = end_pos },
                decl,
                &.{},
                empty_string,
                is_type_only,
                true,
            );
        }

        // `declare export { … }` / `declare export * …` — the `declare`
        // modifier is disallowed on an export declaration (TS1193,
        // anchored on `declare`). Other `declare export <decl>` forms
        // (e.g. `declare export class`) keep `export` on the declaration
        // and are not reported here.
        if (pending_modifier) |pm| {
            if (self.peek().kind == .open_brace or self.peek().kind == .asterisk) {
                try self.reportCodeAt(pm.span.start, pm.line, 1193, "An export declaration cannot have modifiers.");
            }
        }

        // export { a, b as c } [from "m"];
        if (self.peek().kind == .open_brace) {
            const named_exports_open = self.advance();
            if (self.moduleElementContextIsIllegal()) {
                // TS1233 / TS1474: `export { ... }` nested inside a block
                // or control-flow body. JavaScript files use the
                // module-only wording upstream.
                if (self.is_javascript_file) {
                    try self.reportCodeAt(start.span.start, start.line, 1474, "An export declaration can only be used at the top level of a module.");
                } else {
                    try self.reportCodeAt(start.span.start, start.line, 1233, "An export declaration can only be used at the top level of a namespace or module.");
                }
            }
            var named: std.ArrayListUnmanaged(NodeId) = .empty;
            defer named.deinit(self.gpa);
            while (self.peek().kind != .close_brace and self.peek().kind != .eof) {
                const spec_start = self.peek();
                const parsed_spec = try self.parseImportOrExportSpecifier(false);
                const spec_type_only = parsed_spec.is_type_only;
                // TS2207 — a named export specifier cannot carry its own
                // `type` modifier when the whole statement is already an
                // `export type {...}`. Anchored at the specifier's `type`
                // keyword. Mirrors `checkGrammarTypeOnlyNamedImportsOrExports`.
                if (is_type_only and spec_type_only) {
                    try self.reportCodeAt(spec_start.span.start, spec_start.line, 2207, "The 'type' modifier cannot be used on a named export when 'export type' is used on its export statement.");
                }
                const imported_tok = parsed_spec.imported;
                const imported_id = try self.internModuleExportName(imported_tok);
                const imported_is_string_literal = imported_tok.kind == .string_literal;
                const local_tok = parsed_spec.local;
                const local_id = try self.internModuleExportName(local_tok);
                const local_is_string_literal = local_tok.kind == .string_literal;
                const spec = try self.builder.addImportSpecifierFull(
                    .{ .start = spec_start.span.start, .end = self.tokens[self.cursor - 1].span.end },
                    imported_id,
                    local_id,
                    spec_type_only,
                    imported_is_string_literal,
                    local_is_string_literal,
                    imported_tok.span.start,
                    local_tok.span.start,
                );
                try named.append(self.gpa, spec);
                if (!self.match(.comma)) break;
            }
            _ = try self.expectClosingMatch(.close_brace, "'}' to close named exports", named_exports_open.span.start, "{", "}");
            var module_id = empty_string;
            var module_tok_start: u32 = 0;
            var module_tok_line: u32 = 0;
            var has_module_specifier = false;
            if (self.match(.kw_from)) {
                const mod_tok = try self.expect(.string_literal, "module specifier");
                module_id = try self.internStringLiteral(mod_tok);
                module_tok_start = mod_tok.span.start;
                module_tok_line = mod_tok.line;
                has_module_specifier = true;
                try self.reportAmbientRelativeModuleIfNeededAt(mod_tok, start.span.start, start.line);
                try self.skipImportAttributesClause();
            }
            try self.consumeStatementTerminator();
            const end_pos = self.tokens[self.cursor - 1].span.end;
            // TS1194: an `export { ... }` re-export inside an
            // identifier-named namespace (not a string-named external
            // module). A module-specifier re-export (`export {x} from "m"`)
            // is always illegal in a namespace and is anchored at the
            // specifier string (`exportDeclarationsInAmbientNamespaces2.ts
            // (6,23)`). A bare `export { x }` re-export is illegal only in a
            // *non-ambient* namespace and is anchored at the whole node
            // (`es6ModuleInternalNamedImports.ts(22,5)`); inside a `declare
            // namespace` it is a legal local re-export
            // (`reExportAliasMakesInstantiated.ts`).
            if (self.namespace_depth > 0 and !self.in_string_named_module and !self.moduleElementContextIsIllegal()) {
                if (has_module_specifier) {
                    try self.reportCodeAt(module_tok_start, module_tok_line, 1194, "Export declarations are not permitted in a namespace.");
                } else if (self.ambient_depth == 0) {
                    try self.reportCodeAt(start.span.start, start.line, 1194, "Export declarations are not permitted in a namespace.");
                }
            }
            return try self.builder.addExport(
                .{ .start = start.span.start, .end = end_pos },
                hir_mod.none_node_id,
                named.items,
                module_id,
                is_type_only,
                false,
            );
        }

        // export * [as ns] from "m";
        if (self.match(.asterisk)) {
            if (self.moduleElementContextIsIllegal()) {
                // TS1233 / TS1474: `export * from "m"` nested inside a
                // block or control-flow body. JavaScript files use the
                // module-only wording upstream.
                if (self.is_javascript_file) {
                    try self.reportCodeAt(start.span.start, start.line, 1474, "An export declaration can only be used at the top level of a module.");
                } else {
                    try self.reportCodeAt(start.span.start, start.line, 1233, "An export declaration can only be used at the top level of a namespace or module.");
                }
            }
            var ns_alias: hir_mod.StringId = empty_string;
            var ns_alias_is_string_literal = false;
            var ns_alias_pos: u32 = 0;
            if (self.match(.kw_as)) {
                const ns_tok = try self.expectModuleExportName();
                ns_alias_is_string_literal = ns_tok.kind == .string_literal;
                ns_alias = try self.internModuleExportName(ns_tok);
                ns_alias_pos = ns_tok.span.start;
            }
            _ = try self.expect(.kw_from, "'from' after 'export *'");
            const mod_tok = try self.expect(.string_literal, "module specifier");
            try self.reportAmbientRelativeModuleIfNeededAt(mod_tok, start.span.start, start.line);
            try self.skipImportAttributesClause();
            try self.consumeStatementTerminator();
            const mod_id = try self.internStringLiteral(mod_tok);
            const end_pos = self.tokens[self.cursor - 1].span.end;
            // TS1194: `export * from "m"` inside an identifier-named
            // namespace. As a module-specifier re-export, upstream anchors
            // the error at the specifier string (checkExternalImport-
            // OrExportDeclaration).
            if (self.namespace_depth > 0 and !self.in_string_named_module and !self.moduleElementContextIsIllegal()) {
                try self.reportCodeAt(mod_tok.span.start, mod_tok.line, 1194, "Export declarations are not permitted in a namespace.");
            }
            return try self.builder.addExportFullWithNamespaceAliasPos(
                .{ .start = start.span.start, .end = end_pos },
                hir_mod.none_node_id,
                &.{},
                mod_id,
                is_type_only,
                false,
                true,
                ns_alias,
                ns_alias_is_string_literal,
                ns_alias_pos,
            );
        }

        // `export` can modify declarations, but not statement-only forms.
        // Report at the invalid modifier and recover by parsing the statement
        // itself rather than wrapping it in an export node.
        if (tokenStartsNonDeclarationStatement(self.peek().kind)) {
            try self.reportCodeAt(start.span.start, start.line, 1128, "Declaration or statement expected.");
            return try self.parseStatement();
        }

        // export <decl>
        // `export` is a modifier on the following declaration; nested in a
        // block it is TS1184, matching `export function`/`export var` etc.
        try self.reportModifierInBlock(start);
        const old_in_export_declaration = self.in_export_declaration;
        self.in_export_declaration = true;
        defer self.in_export_declaration = old_in_export_declaration;
        const decl = try self.parseStatement();
        // TS1211: `export class { … }` without a name AND without the
        // `default` modifier. Class expressions are exempt (statement
        // dispatch only reaches here for declaration position). Anchor
        // at the `export` keyword with the keyword's span (6 chars).
        // Mirrors `exportClassWithoutName.ts(1,1)`. We can extract the
        // class node from a wrapping export-declaration that produced
        // `addExport`, but here the parsed `decl` IS the class itself
        // (parseStatement returns the class declaration directly when
        // we passed through the regular `export <decl>` path).
        if (self.hir.kindOf(decl) == .class_decl) {
            const class_payload = hir_mod.classOf(self.hir, decl);
            if (class_payload.name == hir_mod.none_node_id) {
                try self.reportCodeAtWithSpan(
                    start.span.start,
                    start.line,
                    start.span.end - start.span.start,
                    1211,
                    "A class declaration without the 'default' modifier must have a name.",
                );
            }
        }
        const end_pos = self.hir.spanOf(decl).end;
        return try self.builder.addExport(
            .{ .start = start.span.start, .end = end_pos },
            decl,
            &.{},
            empty_string,
            is_type_only,
            false,
        );
    }

    fn tokenStartsNonDeclarationStatement(kind: TokenKind) bool {
        return switch (kind) {
            .kw_break,
            .kw_continue,
            .kw_debugger,
            .kw_do,
            .kw_for,
            .kw_if,
            .kw_return,
            .kw_switch,
            .kw_throw,
            .kw_try,
            .kw_while,
            .kw_with,
            => true,
            else => false,
        };
    }

    fn tokenStartsDeclarationStatementAfterVariableList(kind: TokenKind) bool {
        return switch (kind) {
            .kw_function,
            .kw_class,
            .kw_interface,
            .kw_type,
            .kw_enum,
            .kw_namespace,
            .kw_module,
            .kw_import,
            .kw_export,
            .kw_declare,
            .kw_abstract,
            => true,
            else => false,
        };
    }

    /// Parse a "left-hand-side" expression — primary + member-call
    /// chain. Used for `extends` clauses where a full assignment-level
    /// expression isn't grammatical.
    fn parseLeftHandSideExpression(self: *Parser) ParseError!NodeId {
        return try self.parseCallOrMemberExpression();
    }

    /// Parse a decorator expression after the `@` sigil. `@foo`,
    /// `@foo.bar`, `@foo()`, `@foo(arg, arg)` — all valid.
    fn parseDecoratorExpression(self: *Parser) ParseError!NodeId {
        _ = try self.expect(.at, "'@' to start decorator");
        if (self.peek().kind == .kw_enum) {
            const tok = self.peek();
            try self.reportCodeAt(tok.span.start, tok.line, 1109, "Expression expected.");
            const empty = self.interner.intern("") catch return error.OutOfMemory;
            return try self.builder.addIdentifier(.{ .start = tok.span.start, .end = tok.span.start }, empty);
        }
        const expr = try self.parseDecoratorExpressionBody();
        try self.validateDecoratorExpression(expr);
        return expr;
    }

    fn parseDecoratorExpressionBody(self: *Parser) ParseError!NodeId {
        var node = try self.parsePrimaryExpression();
        while (true) {
            const t = self.peek();
            switch (t.kind) {
                .dot => {
                    _ = self.advance();
                    const name_tok = try self.expectIdentifierLike();
                    const name_id = try self.internToken(name_tok);
                    node = try self.builder.addMemberAccess(.{ .start = self.hir.spanOf(node).start, .end = name_tok.span.end }, node, name_id, false);
                },
                .question_dot => {
                    _ = self.advance();
                    if (self.peek().kind == .open_paren) {
                        const args = try self.parseArgumentList();
                        defer self.gpa.free(args);
                        node = try self.builder.addOptionalCall(.{ .start = self.hir.spanOf(node).start, .end = self.tokens[self.cursor - 1].span.end }, node, args);
                    } else if (self.peek().kind == .open_bracket) {
                        const ob = self.advance();
                        node = try self.finishElementAccess(node, true, ob.span.start);
                    } else {
                        const name_tok = try self.expectIdentifierLike();
                        const name_id = try self.internToken(name_tok);
                        node = try self.builder.addMemberAccess(.{ .start = self.hir.spanOf(node).start, .end = name_tok.span.end }, node, name_id, true);
                    }
                },
                .open_paren => {
                    const args = try self.parseArgumentList();
                    defer self.gpa.free(args);
                    node = try self.builder.addCall(.{ .start = self.hir.spanOf(node).start, .end = self.tokens[self.cursor - 1].span.end }, node, args);
                },
                .less_than => {
                    if (self.findCallTypeArgsEnd(self.cursor)) |after_gt| {
                        const type_args = try self.parseExplicitCallTypeArgs(after_gt);
                        defer self.gpa.free(type_args);
                        if (self.peek().kind == .no_substitution_template or self.peek().kind == .template_head) {
                            node = try self.parseTaggedTemplateWithTypeArgs(node, type_args);
                        } else {
                            const args = try self.parseArgumentList();
                            defer self.gpa.free(args);
                            node = try self.builder.addCallWithTypeArgs(.{ .start = self.hir.spanOf(node).start, .end = self.tokens[self.cursor - 1].span.end }, node, args, type_args);
                        }
                    } else break;
                },
                .bang => {
                    _ = self.advance();
                    const sp: Span = .{ .start = self.hir.spanOf(node).start, .end = t.span.end };
                    try self.reportNonNullOnlyInTsIfNeeded(sp.start);
                    node = try self.builder.addNonNullExpression(sp, node);
                },
                .no_substitution_template, .template_head => {
                    node = try self.parseTaggedTemplateWithTypeArgs(node, &.{});
                },
                else => break,
            }
        }
        return node;
    }

    fn validateDecoratorExpression(self: *Parser, expr: NodeId) ParseError!void {
        if (self.parenthesizedNodeStart(expr) != null) return;
        const invalid_span = self.invalidDecoratorSyntaxSpan(expr) orelse return;
        const expr_span = self.hir.spanOf(expr);
        try self.reportCodeAtWithSpan(
            expr_span.start,
            self.sourceLineAtPos(expr_span.start),
            expr_span.end - expr_span.start,
            1497,
            "Expression must be enclosed in parentheses to be used as a decorator.",
        );
        try self.reportCodeAtWithSpan(
            invalid_span.start,
            self.sourceLineAtPos(invalid_span.start),
            invalid_span.end - invalid_span.start,
            1498,
            "Invalid syntax in decorator.",
        );
    }

    fn invalidDecoratorSyntaxSpan(self: *Parser, expr: NodeId) ?Span {
        var node = expr;
        var can_have_call_expression = true;
        var error_span: ?Span = null;
        while (node != hir_mod.none_node_id) {
            switch (self.hir.kindOf(node)) {
                .non_null_expr => {
                    node = hir_mod.asExpressionOf(self.hir, node).expr;
                    continue;
                },
                .call_expr => {
                    const call = hir_mod.callOf(self.hir, node);
                    if (self.nodeSpanContainsByte(node, '`')) error_span = self.hir.spanOf(node);
                    if (!can_have_call_expression) error_span = self.hir.spanOf(node);
                    if (call.optional) error_span = self.optionalChainTokenSpan(node) orelse self.hir.spanOf(node);
                    node = call.callee;
                    can_have_call_expression = false;
                    continue;
                },
                .member_access => {
                    const member = hir_mod.memberOf(self.hir, node);
                    if (member.optional) error_span = self.optionalChainTokenSpan(node) orelse self.hir.spanOf(node);
                    node = member.object;
                    can_have_call_expression = false;
                    continue;
                },
                .identifier => break,
                else => {
                    error_span = self.hir.spanOf(node);
                    break;
                },
            }
        }
        return error_span;
    }

    fn nodeSpanContainsByte(self: *Parser, node: NodeId, needle: u8) bool {
        const sp = self.hir.spanOf(node);
        if (sp.end > self.source.len or sp.start >= sp.end) return false;
        return std.mem.indexOfScalar(u8, self.source[sp.start..sp.end], needle) != null;
    }

    fn optionalChainTokenSpan(self: *Parser, node: NodeId) ?Span {
        const sp = self.hir.spanOf(node);
        if (sp.start >= sp.end or sp.end > self.source.len) return null;
        const text = self.source[sp.start..sp.end];
        if (std.mem.indexOf(u8, text, "?.")) |rel| {
            const start = sp.start + @as(u32, @intCast(rel));
            return .{ .start = start, .end = start + 2 };
        }
        return null;
    }

    fn recoverNestedVarInitializer(self: *Parser) ParseError!NodeId {
        const var_tok = self.advance();
        try self.reportCodeAt(var_tok.span.start, var_tok.line, 1109, "Expression expected.");

        const name_tok = try self.expectIdentifierLike();
        try self.reportInvalidVariableDeclarationName(name_tok);
        try self.reportInvalidStrictName(name_tok);
        try self.reportInvalidFutureReservedName(name_tok);
        try self.reportInvalidYieldName(name_tok, true);
        try self.reportAwaitBindingIfReserved(name_tok);
        const name_id = try self.internToken(name_tok);
        const name_node = try self.builder.addIdentifier(tokenSpan(name_tok), name_id);

        // The recovered nested declaration behaves as an explicit `any`
        // declaration in tsc's subsequent-variable compatibility check.
        const any_id = self.interner.intern("any") catch return error.OutOfMemory;
        const any_type = try self.builder.addTypeRef(
            .{ .start = name_tok.span.end, .end = name_tok.span.end },
            any_id,
            &.{},
            &.{},
        );
        const recovered_decl = try self.builder.addVarDeclEx(
            .var_decl,
            .{ .start = var_tok.span.start, .end = name_tok.span.end },
            name_node,
            any_type,
            hir_mod.none_node_id,
            false,
            false,
            self.isAmbientContextAt(var_tok.span.start),
        );
        try self.pending_statements.append(self.gpa, recovered_decl);

        if (!self.peek().flags.preceded_by_newline and
            (self.peek().kind == .plus or self.peek().kind == .minus or
                self.peek().kind == .bang or self.peek().kind == .tilde))
        {
            const bad_unary = self.peek();
            try self.reportCodeAt(bad_unary.span.start, bad_unary.line, 1005, "',' expected.");
            _ = try self.parseUnaryExpression();
        }

        return try self.builder.addTypeRef(
            .{ .start = var_tok.span.start, .end = var_tok.span.start },
            any_id,
            &.{},
            &.{},
        );
    }

    fn parseVarDecl(self: *Parser) ParseError!NodeId {
        const start = self.advance(); // let/const/var
        if (self.isAmbientContextAt(start.span.start) and
            self.block_depth == 0 and
            self.namespace_depth == 0 and
            self.ambient_depth == 0 and
            !self.in_export_declaration)
        {
            try self.reportCodeAt(start.span.start, start.line, 1046, "Top-level declarations in .d.ts files must start with either a 'declare' or 'export' modifier.");
        }
        const old_in_top_level_module_binding_decl = self.in_top_level_module_binding_decl;
        self.in_top_level_module_binding_decl = self.top_level_external_module_indicator and
            self.block_depth == 0 and self.namespace_depth == 0 and self.ambient_depth == 0;
        defer self.in_top_level_module_binding_decl = old_in_top_level_module_binding_decl;
        const decl_kind: hir_mod.NodeKind = switch (start.kind) {
            .kw_let => .let_decl,
            .kw_const => .const_decl,
            .kw_var => .var_decl,
            else => unreachable,
        };
        // Destructuring binding (`const { a } = obj`, `const [b] = arr`)
        // stores the pattern in the var-decl's `name` slot in the same
        // way parameters stash an `object_pattern` / `array_pattern`.
        // `name_list_was_empty` tracks the TS1123 path so the TS1155
        // "'const' declarations must be initialized." follow-on is
        // suppressed — tsc only reports the empty-list diagnostic on
        // fixtures like `VariableDeclaration1_es6` (`const` alone).
        var name_list_was_empty = false;
        const name_node: NodeId = if (self.peek().kind == .semicolon or self.peek().kind == .eof) blk: {
            const empty_pos = start.span.end;
            try self.reportCodeAt(empty_pos, start.line, 1123, "Variable declaration list cannot be empty.");
            const empty_id = self.interner.intern("") catch return error.OutOfMemory;
            name_list_was_empty = true;
            break :blk try self.builder.addIdentifier(.{ .start = empty_pos, .end = empty_pos }, empty_id);
        } else if (self.peek().kind == .open_brace or self.peek().kind == .open_bracket) blk: {
            break :blk try self.parseBindingPattern();
        } else id_blk: {
            const name_tok = try self.expectIdentifierLike();
            // TS18029: ECMAScript `#name` identifiers may only
            // appear as class members; `const #foo = 3` is invalid
            // and tsc emits this dedicated diagnostic. Mirrors
            // upstream `privateNameNotAllowedOutsideClass` and
            // `privateNamesNotAllowedInVariableDeclarations`.
            if (name_tok.kind == .private_identifier) {
                try self.reportCodeAt(name_tok.span.start, name_tok.line, 18029, "Private identifiers are not allowed in variable declarations.");
            }
            // TS1216: `__esModule` is reserved as the marker tsc
            // emits when downleveling ECMAScript modules to
            // CommonJS / AMD / UMD. `export var __esModule = …`
            // would collide with the runtime helper. Mirrors
            // upstream `checkESModuleMarker` in checker.ts (anchored
            // at the binding name with the identifier's span).
            // Fires only for top-level exported bindings — nested
            // names inside a namespace / block / ambient context
            // don't participate in the module marker emission.
            if (self.in_export_declaration and
                self.block_depth == 0 and
                self.namespace_depth == 0 and
                self.ambient_depth == 0 and
                name_tok.kind == .identifier and
                std.mem.eql(u8, self.source[name_tok.span.start..name_tok.span.end], "__esModule"))
            {
                try self.reportCodeAtWithSpan(
                    name_tok.span.start,
                    name_tok.line,
                    name_tok.span.end - name_tok.span.start,
                    1216,
                    "Identifier expected. '__esModule' is reserved as an exported marker when transforming ECMAScript modules.",
                );
            }
            try self.reportInvalidVariableDeclarationName(name_tok);
            try self.reportInvalidStrictName(name_tok);
            try self.reportInvalidFutureReservedName(name_tok);
            try self.reportInvalidYieldName(name_tok, true);
            try self.reportAwaitBindingIfReserved(name_tok);
            try self.reportAwaitReservedInAsyncContext(name_tok);
            const name_id = try self.internToken(name_tok);
            break :id_blk try self.builder.addIdentifier(tokenSpan(name_tok), name_id);
        };

        // Definite-assignment assertion in declarations: `let x!: T`.
        // It affects TS control-flow checks only; HIR keeps the same
        // declaration shape and the emitter erases it.
        const definite_assignment_token: ?Token = if (self.peek().kind == .bang) self.advance() else null;

        var type_annotation: NodeId = hir_mod.none_node_id;
        var recovered_private_indexed_access = false;
        if (self.match(.colon)) {
            // Detect a stray type predicate in variable declaration
            // type position: `var x: <id-or-this> is T`. Upstream tsc
            // emits TS1228 ("A type predicate is only allowed in
            // return type position for functions and methods.")
            // anchored on the predicate's `arg` token. Mirrors fixture
            // `typePredicateOnVariableDeclaration01` (`var x: this is
            // string;`). The `<ident> is T` variant is left to the
            // generic type-annotation parser because the upstream
            // baseline reshapes it as a TS2304 + TS1005-pair recovery.
            const ann_first = self.peek();
            const ann_second = self.peekAt(1);
            if (ann_first.kind == .kw_this and
                ann_second.kind == .kw_is and
                !ann_second.flags.preceded_by_newline)
            {
                try self.reportCodeAt(ann_first.span.start, ann_first.line, 1228, "A type predicate is only allowed in return type position for functions and methods.");
                _ = self.advance(); // this
                _ = self.advance(); // is
                type_annotation = try self.parseTypeAnnotation();
            } else {
                type_annotation = try self.parseTypeAnnotation();
            }
        }

        if (type_annotation != hir_mod.none_node_id and
            self.hir.kindOf(type_annotation) == .indexed_access_type and
            self.peek().kind == .private_identifier and
            self.cursor > 0 and
            self.tokens[self.cursor - 1].kind == .open_bracket)
        {
            recovered_private_indexed_access = true;
            const private_tok = self.advance();
            const private_name = try self.internToken(private_tok);
            const private_node = try self.builder.addIdentifier(tokenSpan(private_tok), private_name);
            const recovered_decl = try self.builder.addVarDeclEx(
                decl_kind,
                tokenSpan(private_tok),
                private_node,
                hir_mod.none_node_id,
                hir_mod.none_node_id,
                false,
                false,
                self.isAmbientContextAt(start.span.start),
            );
            try self.pending_statements.append(self.gpa, recovered_decl);

            if (self.peek().kind == .close_bracket) {
                const close = self.advance();
                try self.reportCodeAt(close.span.start, close.line, 1005, "',' expected.");
            }
            if (self.peek().kind == .equal) {
                const equal = self.advance();
                try self.reportCodeAt(equal.span.start, equal.line, 1134, "Variable declaration expected.");
            }
            if (self.peek().kind == .number_literal or self.peek().kind == .string_literal) {
                const value = self.advance();
                try self.reportCodeAt(value.span.start, value.line, 1134, "Variable declaration expected.");
            }
        }

        var init_node: NodeId = hir_mod.none_node_id;
        if (self.match(.equal)) {
            if (self.peek().kind == .kw_var) {
                type_annotation = try self.recoverNestedVarInitializer();
            } else {
                init_node = try self.parseAssignmentExpression();
            }
        }
        var recovered_initializer_arrow_tail = false;
        var recovered_declaration_list_boundary = false;
        const is_ambient_decl = self.isAmbientContextAt(start.span.start);
        try self.reportVariableDefiniteAssignment(definite_assignment_token, type_annotation, init_node, is_ambient_decl);
        try self.recoverRegexVariableDeclarationTail(init_node);
        if (init_node != hir_mod.none_node_id and self.peek().kind == .colon) {
            const colon_tok = self.advance();
            try self.reportCodeAt(colon_tok.span.start, colon_tok.line, 1005, "',' expected.");
            const after_colon = self.peek();
            // A literal here is a malformed second declarator, not an
            // arrow return type. Preserve the following statement token
            // so source-element recovery can report it independently.
            if (after_colon.kind == .number_literal or after_colon.kind == .string_literal or
                after_colon.kind == .kw_true or after_colon.kind == .kw_false or
                after_colon.kind == .kw_null or after_colon.kind == .kw_undefined)
            {
                try self.reportCodeAt(after_colon.span.start, after_colon.line, 1134, "Variable declaration expected.");
                _ = self.advance();
            } else {
                while (self.peek().kind != .arrow and
                    self.peek().kind != .semicolon and
                    self.peek().kind != .comma and
                    self.peek().kind != .eof)
                {
                    _ = self.advance();
                }
                if (self.peek().kind == .arrow) {
                    const arrow_tok = self.advance();
                    try self.reportCodeAt(arrow_tok.span.start, arrow_tok.line, 1005, "';' expected.");
                    recovered_initializer_arrow_tail = true;
                }
            }
        }
        if (self.peek().kind == .number_literal and
            self.cursor > 0 and
            self.tokens[self.cursor - 1].kind == .number_literal and
            !self.peek().flags.preceded_by_newline)
        {
            const bad = self.advance();
            try self.reportCodeAt(bad.span.start, bad.line, 1005, "',' expected.");
        }
        if (decl_kind == .const_decl and
            init_node == hir_mod.none_node_id and
            !is_ambient_decl and
            !name_list_was_empty and
            !recovered_private_indexed_access)
        {
            // `const {}` and `const []` already raise TS1182
            // ("A destructuring declaration must have an
            // initializer.") from the checker; tsc does not
            // additionally surface the TS1155 ("must be
            // initialized") so we suppress the duplicate here.
            // Similarly, `const` with no bindings already raises
            // TS1123 (empty declaration list); suppressing TS1155
            // here matches tsc on `VariableDeclaration1_es6`.
            const name_kind = self.hir.kindOf(name_node);
            if (name_kind != .object_pattern and name_kind != .array_pattern) {
                try self.reportCodeAt(self.hir.spanOf(name_node).start, start.line, 1155, "'const' declarations must be initialized.");
            }
        }
        while (self.match(.comma)) {
            const comma_tok = self.tokens[self.cursor - 1];
            if (self.peek().kind == .semicolon or self.peek().kind == .eof) {
                try self.reportCodeAt(comma_tok.span.start, comma_tok.line, 1009, "Trailing comma not allowed.");
                break;
            }
            if (self.peek().kind == .kw_return and self.peek().flags.preceded_by_newline) {
                try self.reportCodeAt(comma_tok.span.start, comma_tok.line, 1009, "Trailing comma not allowed.");
                break;
            }
            if (self.peek().kind == .string_literal or self.peek().kind == .number_literal) {
                const bad_decl = self.advance();
                try self.reportCodeAt(bad_decl.span.start, bad_decl.line, 1134, "Variable declaration expected.");
                continue;
            }
            const extra_name: NodeId = if (self.peek().kind == .open_brace or self.peek().kind == .open_bracket) blk: {
                break :blk try self.parseBindingPattern();
            } else id_blk: {
                const name_tok = try self.expectIdentifierLike();
                try self.reportInvalidVariableDeclarationName(name_tok);
                try self.reportInvalidStrictName(name_tok);
                try self.reportInvalidFutureReservedName(name_tok);
                try self.reportAwaitBindingIfReserved(name_tok);
                const name_id = try self.internToken(name_tok);
                break :id_blk try self.builder.addIdentifier(tokenSpan(name_tok), name_id);
            };
            const extra_definite_assignment_token: ?Token = if (self.peek().kind == .bang) self.advance() else null;
            var extra_type: NodeId = hir_mod.none_node_id;
            if (self.match(.colon)) extra_type = try self.parseTypeAnnotation();
            var extra_init: NodeId = hir_mod.none_node_id;
            if (self.match(.equal)) extra_init = try self.parseAssignmentExpression();
            try self.reportVariableDefiniteAssignment(extra_definite_assignment_token, extra_type, extra_init, is_ambient_decl);
            try self.recoverRegexVariableDeclarationTail(extra_init);
            if (decl_kind == .const_decl and extra_init == hir_mod.none_node_id and !is_ambient_decl) {
                const extra_kind = self.hir.kindOf(extra_name);
                if (extra_kind != .object_pattern and extra_kind != .array_pattern) {
                    try self.reportCodeAt(self.hir.spanOf(extra_name).start, start.line, 1155, "'const' declarations must be initialized.");
                }
            }
            const extra_start = self.hir.spanOf(extra_name).start;
            const extra_end = if (self.cursor > 0) self.tokens[self.cursor - 1].span.end else self.hir.spanOf(extra_name).end;
            const extra_decl = try self.builder.addVarDeclEx(
                decl_kind,
                .{ .start = extra_start, .end = extra_end },
                extra_name,
                extra_type,
                extra_init,
                false,
                false,
                is_ambient_decl,
            );
            try self.pending_statements.append(self.gpa, extra_decl);
        }
        if (init_node != hir_mod.none_node_id and
            !self.peek().flags.preceded_by_newline and
            (self.peek().kind == .kw_typeof or self.peek().kind == .kw_delete or
                self.peek().kind == .kw_void or self.peek().kind == .tilde))
        {
            const bad_unary = self.peek();
            try self.reportCodeAt(bad_unary.span.start, bad_unary.line, 1005, "',' expected.");
            _ = try self.parseUnaryExpression();
        }
        // `parseDelimitedList(PCVariableDeclarations)` reports a missing
        // comma before a declaration-start token, then yields to the outer
        // statement parsing context. Keep that token unread so an invalid
        // sequence such as `var F = @dec function () {}` can recover the
        // trailing function declaration and emit its own TS1003 at `(`.
        // This is the parser-list boundary used by typescript-go rather
        // than a missing statement terminator.
        if (!recovered_initializer_arrow_tail and
            !self.peek().flags.preceded_by_newline and
            tokenStartsDeclarationStatementAfterVariableList(self.peek().kind))
        {
            const boundary = self.peek();
            try self.reportCodeAt(boundary.span.start, boundary.line, 1005, "',' expected.");
            recovered_declaration_list_boundary = true;
        }
        if (!recovered_initializer_arrow_tail and !recovered_declaration_list_boundary) {
            try self.consumeStatementTerminator();
        }

        const stmt_span: Span = .{ .start = start.span.start, .end = self.tokens[self.cursor - 1].span.end };
        return try self.builder.addVarDeclEx(
            decl_kind,
            stmt_span,
            name_node,
            type_annotation,
            init_node,
            false,
            false,
            is_ambient_decl,
        );
    }

    fn recoverRegexVariableDeclarationTail(self: *Parser, init_node: NodeId) ParseError!void {
        if (init_node == hir_mod.none_node_id or self.hir.kindOf(init_node) != .literal_regex) return;
        const close = self.peek();
        if (close.kind != .close_bracket or close.flags.preceded_by_newline) return;

        try self.reportCodeAt(close.span.start, close.line, 1005, "',' expected.");
        _ = self.advance();

        const bad_decl = self.peek();
        if (bad_decl.kind == .semicolon or
            bad_decl.kind == .eof or
            bad_decl.kind == .close_brace or
            bad_decl.flags.preceded_by_newline)
        {
            return;
        }
        try self.reportCodeAt(bad_decl.span.start, bad_decl.line, 1134, "Variable declaration expected.");
        _ = self.advance();
    }

    /// Parse a Stage 3 explicit-resource-management declaration:
    ///   `using x = expr;`
    ///   `await using x = expr;`
    /// `await_using` selects the async-dispose form. The binding is
    /// lowered to a `const_decl`-shaped HIR node with the `is_using` /
    /// `is_await_using` flag set on its payload — for v0 emitters can
    /// continue treating it as `const`. Try/finally lowering for
    /// `[Symbol.dispose]()` / `[Symbol.asyncDispose]()` is a follow-up.
    /// Parse the target identifier (or recover from a binding pattern)
    /// of a single `using` / `await using` binder. When the binder is
    /// `[a, b]` / `{ a }`, emit TS1492 ("'using' declarations may not
    /// have binding patterns") at the pattern's start, skip over the
    /// pattern, and return a synthetic identifier token rooted at the
    /// pattern's open bracket so downstream HIR shape is preserved.
    fn parseUsingDeclBindingTarget(self: *Parser, await_using: bool) ParseError!Token {
        const tok = self.peek();
        if (tok.kind == .open_bracket or tok.kind == .open_brace) {
            const message = if (await_using)
                "'await using' declarations may not have binding patterns."
            else
                "'using' declarations may not have binding patterns.";
            try self.reportCodeAt(tok.span.start, tok.line, 1492, message);
            // Skip the binding pattern's content so the rest of the
            // declarator (`= initializer`) stays parseable. Walk
            // brackets/braces with a tiny depth counter.
            const open = self.advance();
            var depth: u32 = 1;
            while (depth > 0) {
                const cur = self.peek();
                if (cur.kind == .eof) break;
                if (cur.kind == .open_bracket or cur.kind == .open_brace) depth += 1;
                if (cur.kind == .close_bracket or cur.kind == .close_brace) depth -= 1;
                _ = self.advance();
            }
            // Synthesize a placeholder identifier token at the pattern's
            // open bracket so the var-decl HIR has a usable name slot.
            return .{
                .kind = .identifier,
                .span = open.span,
                .line = open.line,
                .flags = open.flags,
            };
        }
        return try self.expect(.identifier, "identifier in using declaration");
    }

    /// Variant of `parseUsingDeclBindingTarget` used when we've
    /// already committed to treating the source as a using-decl with
    /// a real binding pattern (top-level `using {a} = ...`). Instead
    /// of skipping the pattern we keep its structure so the checker
    /// can emit the per-property TS2339 / TS2488 diagnostics tsc
    /// produces against the initializer. Returns the binding pattern
    /// node directly.
    fn parseUsingDeclBindingPattern(self: *Parser, await_using: bool) ParseError!NodeId {
        const tok = self.peek();
        std.debug.assert(tok.kind == .open_brace or tok.kind == .open_bracket);
        const message = if (await_using)
            "'await using' declarations may not have binding patterns."
        else
            "'using' declarations may not have binding patterns.";
        try self.reportCodeAt(tok.span.start, tok.line, 1492, message);
        return try self.parseBindingPattern();
    }

    fn parseUsingDecl(self: *Parser, await_using: bool, decorated: bool) ParseError!NodeId {
        const start = self.advance(); // `using` or `await`
        if (await_using) {
            _ = self.advance(); // `using` token following `await`
        }
        const in_ambient = self.ambient_depth > 0;
        // TS1495 (await using) / TS1491 (using) — `'export'` / `'declare'`
        // modifier cannot appear on a `using` / `await using` declaration.
        // tsc emits this in place of the generic TS1545/TS1546 ambient
        // diagnostic (or alongside it for bare `export <kind>`). Detect
        // the modifier by scanning the source bytes immediately preceding
        // `start.span.start` for `declare` or `export` and anchor the
        // diagnostic there. Mirrors upstream `usingDeclarations.13.ts` and
        // `awaitUsingDeclarations.11.ts`.
        var emitted_modifier_diag = false;
        blk: {
            const src = self.source;
            const start_pos = start.span.start;
            if (start_pos == 0) break :blk;
            // Walk backwards skipping whitespace, find the preceding
            // identifier-like token text.
            var i: usize = start_pos;
            while (i > 0 and (src[i - 1] == ' ' or src[i - 1] == '\t')) : (i -= 1) {}
            const word_end = i;
            while (i > 0) : (i -= 1) {
                const c = src[i - 1];
                if ((c >= 'a' and c <= 'z') or (c >= 'A' and c <= 'Z') or c == '_' or c == '$' or (c >= '0' and c <= '9')) continue;
                break;
            }
            if (i >= word_end) break :blk;
            const word = src[i..word_end];
            const modifier = if (std.mem.eql(u8, word, "export"))
                @as(?[]const u8, "export")
            else if (std.mem.eql(u8, word, "declare"))
                @as(?[]const u8, "declare")
            else
                null;
            if (modifier) |mod_name| {
                // Compute line for this position — use start.line as a
                // proxy since the modifier is on the same logical line.
                const code: u32 = if (await_using) 1495 else 1491;
                const msg = if (await_using)
                    try std.fmt.allocPrint(
                        self.diag_arena.allocator(),
                        "'{s}' modifier cannot appear on an 'await using' declaration.",
                        .{mod_name},
                    )
                else
                    try std.fmt.allocPrint(
                        self.diag_arena.allocator(),
                        "'{s}' modifier cannot appear on a 'using' declaration.",
                        .{mod_name},
                    );
                try self.reportCodeAt(@intCast(i), start.line, code, msg);
                emitted_modifier_diag = true;
            }
        }
        if (in_ambient and !emitted_modifier_diag) {
            // `using` / `await using` declarations are not legal in
            // ambient contexts (TS1545 / TS1546). Emit the specific
            // diagnostic and short-circuit the function/top-level
            // gating (which doesn't apply when the file would never
            // emit code anyway).
            const code: u32 = if (await_using) 1546 else 1545;
            const message = if (await_using)
                "'await using' declarations are not allowed in ambient contexts."
            else
                "'using' declarations are not allowed in ambient contexts.";
            try self.reportCodeAt(start.span.start, start.line, code, message);
        } else if (await_using and !emitted_modifier_diag) {
            // `await using` requires either an async function context
            // OR top-level of a module. "Top-level" here means any
            // position that isn't enclosed by a function — `{}` blocks,
            // `if`/`while` arms, switch case bodies don't count as
            // function boundaries. The module indicator is derived
            // from a top-level `import`/`export` having been seen.
            const inside_function = self.function_depth > 0;
            const file_is_module = self.top_level_external_module_indicator;
            if (self.static_block_depth > 0) {
                try self.reportCodeAt(start.span.start, start.line, 18054, "'await using' statements cannot be used inside a class static block.");
            } else if (inside_function and self.async_function_depth == 0) {
                try self.reportCodeAt(start.span.start, start.line, 2852, "'await using' statements are only allowed within async functions and at the top levels of modules.");
            } else if (!inside_function and !file_is_module and self.namespace_depth == 0) {
                try self.reportCodeAt(start.span.start, start.line, 2853, "'await using' statements are only allowed at the top level of a file when that file is a module, but this file has no imports or exports. Consider adding an empty 'export {}' to make this file a module.");
            }
        }
        if (self.in_switch_case_clause) {
            // A `using`/`await using` directly under a `case`/`default`
            // clause (without its own enclosing block) is TS1547/TS1548
            // — distinct from the more general TS1156 ("must be inside
            // a block") that fires for bare `if`/`else` arms.
            const code: u32 = if (await_using) 1548 else 1547;
            const message = if (await_using)
                "'await using' declarations are not allowed in 'case' or 'default' clauses unless contained within a block."
            else
                "'using' declarations are not allowed in 'case' or 'default' clauses unless contained within a block.";
            try self.reportCodeAt(start.span.start, start.line, code, message);
        } else if (self.unbraced_statement_block_depth) |depth| if (self.block_depth == depth) {
            const message = if (await_using)
                "'await using' declarations can only be declared inside a block."
            else
                "'using' declarations can only be declared inside a block.";
            try self.reportCodeAt(start.span.start, start.line, 1156, message);
        };
        // Branch on binding shape: an object-binding-pattern head
        // (`using {a} = …`) keeps the pattern structure so the
        // checker can emit the per-property TS2339/TS2488 against the
        // initializer. All other heads use the existing token-based
        // path that synthesizes a placeholder identifier.
        const want_binding_pattern = self.peek().kind == .open_brace;
        var name_node: NodeId = hir_mod.none_node_id;
        var name_span_start: u32 = start.span.start;
        var name_span_line: u32 = start.line;
        if (want_binding_pattern) {
            const pat_tok = self.peek();
            name_span_start = pat_tok.span.start;
            name_span_line = pat_tok.line;
            name_node = try self.parseUsingDeclBindingPattern(await_using);
        } else {
            const name_tok = try self.parseUsingDeclBindingTarget(await_using);
            const name_id = try self.internToken(name_tok);
            name_node = try self.builder.addIdentifier(tokenSpan(name_tok), name_id);
            name_span_start = name_tok.span.start;
            name_span_line = name_tok.line;
        }

        var type_annotation: NodeId = hir_mod.none_node_id;
        if (self.match(.colon)) {
            type_annotation = try self.parseTypeAnnotation();
        }

        const must_init_msg = if (await_using)
            "'await using' declarations must be initialized."
        else
            "'using' declarations must be initialized.";
        var init_node: NodeId = hir_mod.none_node_id;
        if (self.match(.equal)) {
            init_node = try self.parseAssignmentExpression();
        } else if (!in_ambient and !decorated) {
            // Ambient `using` / `await using` declarations don't carry
            // initializers — TS suppresses TS1155 in that case because
            // the more specific TS1545/TS1546 already fires. Decorated
            // using-declarations also suppress it (decoratorOnUsing:
            // tsc drops the decorators and reports nothing on
            // `@dec using x`).
            try self.reportCodeAt(name_span_start, name_span_line, 1155, must_init_msg);
        }
        while (self.match(.comma)) {
            const extra_name_tok = try self.parseUsingDeclBindingTarget(await_using);
            if (self.match(.colon)) {
                _ = try self.parseTypeAnnotation();
            }
            if (self.match(.equal)) {
                _ = try self.parseAssignmentExpression();
            } else if (!in_ambient and !decorated) {
                try self.reportCodeAt(extra_name_tok.span.start, extra_name_tok.line, 1155, must_init_msg);
            }
        }
        try self.consumeStatementTerminator();

        const stmt_span: Span = .{ .start = start.span.start, .end = self.tokens[self.cursor - 1].span.end };
        return try self.builder.addVarDeclEx(
            .const_decl,
            stmt_span,
            name_node,
            type_annotation,
            init_node,
            !await_using,
            await_using,
            false,
        );
    }

    fn parseReturnStatement(self: *Parser) ParseError!NodeId {
        const kw = self.advance(); // return
        var value: NodeId = hir_mod.none_node_id;
        // ASI rule: `return\n…` returns void unless the expression is
        // on the same line. We approximate via the
        // `preceded_by_newline` flag of the next token.
        if (self.peek().kind != .semicolon and self.peek().kind != .close_brace and
            self.peek().kind != .eof and !self.peek().flags.preceded_by_newline)
        {
            value = try self.parseExpression();
        }
        try self.consumeStatementTerminator();
        const end_pos: u32 = if (self.cursor > 0) self.tokens[self.cursor - 1].span.end else kw.span.end;
        return try self.builder.addReturn(.{ .start = kw.span.start, .end = end_pos }, value);
    }

    fn parseBlockStatement(self: *Parser) ParseError!NodeId {
        return self.parseBlockStatementWithMissingOpenBrace(false);
    }

    fn parseBlockStatementWithMissingOpenBrace(self: *Parser, ignore_missing_open: bool) ParseError!NodeId {
        const open = self.peek();
        const open_parsed = open.kind == .open_brace;
        if (open_parsed) {
            _ = self.advance();
        } else if (ignore_missing_open) {
            try self.reportCodeAt(open.span.start, open.line, 1005, "'{' expected.");
        } else {
            _ = try self.expect(.open_brace, "'{' to start block");
        }
        self.block_depth += 1;
        defer self.block_depth -= 1;
        // A `{}` block under a `case` clause body resets the bare-clause
        // gate: TS1547/TS1548 only fire on `using`/`await using`
        // declarations that aren't wrapped in their own block.
        const prev_in_case_clause = self.in_switch_case_clause;
        self.in_switch_case_clause = false;
        defer self.in_switch_case_clause = prev_in_case_clause;
        var stmts: std.ArrayListUnmanaged(NodeId) = .empty;
        defer stmts.deinit(self.gpa);
        var recovered_class_member_boundary = false;
        while (self.hasPendingStatement() or (self.peek().kind != .close_brace and self.peek().kind != .eof)) {
            if (self.classMethodBlockHitClassMemberBoundary()) {
                const bad = self.peek();
                try self.reportCodeAt(bad.span.start, bad.line, 1128, "Declaration or statement expected.");
                recovered_class_member_boundary = true;
                break;
            }
            try stmts.append(self.gpa, try self.parseStatement());
        }
        if (recovered_class_member_boundary) {
            const end_pos = if (self.cursor > 0) self.tokens[self.cursor - 1].span.end else open.span.end;
            return try self.builder.addBlock(.{ .start = open.span.start, .end = end_pos }, stmts.items);
        }
        if (self.peek().kind == .eof) {
            const at = self.peek();
            var missing_open_already_reported = false;
            for (self.diagnostics.items) |diagnostic| {
                if (diagnostic.pos == at.span.start and diagnostic.code == 1005 and
                    std.mem.eql(u8, diagnostic.message, "'{' expected."))
                {
                    missing_open_already_reported = true;
                    break;
                }
            }
            if (missing_open_already_reported) {
                return try self.builder.addBlock(.{ .start = open.span.start, .end = at.span.start }, stmts.items);
            }
            if (open_parsed) {
                try self.reportCodeAtWithMatchedPair(
                    at.span.start,
                    at.line,
                    1005,
                    "'}' expected.",
                    open.span.start,
                    "{",
                    "}",
                );
            } else {
                try self.reportCodeAt(at.span.start, at.line, 1005, "'}' expected.");
            }
            return try self.builder.addBlock(.{ .start = open.span.start, .end = at.span.start }, stmts.items);
        }
        const close = if (open_parsed)
            try self.expectClosingMatch(.close_brace, "'}' to close block", open.span.start, "{", "}")
        else
            try self.expect(.close_brace, "'}' to close block");
        // tsc: a `{...}` parsed as a statement block immediately
        // followed by `=` is almost certainly a destructuring
        // assignment missing its wrapping parentheses (`{a} = b` should
        // be `({a} = b)`). `parseBlock` emits TS2809 at the `=` and
        // consumes it. Mirrors upstream `parseBlock`'s trailing-equals
        // recovery (fixture `parserDestructuringAssignment*`).
        if (self.peek().kind == .equal) {
            const eq = self.peek();
            try self.reportCodeAt(eq.span.start, eq.line, 2809, "Declaration or statement expected. This follows a block of statements, so if you intended to write a destructuring assignment you might need to wrap the whole assignment in parentheses.");
            _ = self.advance();
        }
        return try self.builder.addBlock(span(open, close), stmts.items);
    }

    fn classMethodBlockHitClassMemberBoundary(self: *const Parser) bool {
        if (self.class_body_depth == 0 or self.function_depth == 0) return false;
        const t = self.peek();
        if (!t.flags.preceded_by_newline) return false;
        if (t.kind != .kw_public and t.kind != .kw_private and
            t.kind != .kw_protected and t.kind != .kw_static)
        {
            return false;
        }
        var idx: usize = @intCast(self.cursor + 1);
        while (idx < self.tokens.len and self.tokens[idx].kind.isModifierKeyword()) : (idx += 1) {}
        if (idx >= self.tokens.len) return false;
        const name = self.tokens[idx];
        if (!isClassMemberNameStart(name.kind)) return false;
        idx += 1;
        if (idx < self.tokens.len and self.tokens[idx].kind == .question) idx += 1;
        if (idx < self.tokens.len and self.tokens[idx].kind == .less_than) {
            idx = self.skipBalancedTypeArgumentLookahead(idx);
        }
        if (idx >= self.tokens.len) return false;
        return self.tokens[idx].kind == .open_paren;
    }

    fn skipBalancedTypeArgumentLookahead(self: *const Parser, start: usize) usize {
        var idx = start;
        var depth: usize = 0;
        while (idx < self.tokens.len) : (idx += 1) {
            switch (self.tokens[idx].kind) {
                .less_than => depth += 1,
                .greater_than => {
                    if (depth == 0) return idx;
                    depth -= 1;
                    if (depth == 0) return idx + 1;
                },
                .eof, .open_brace, .close_brace, .semicolon => return idx,
                else => {},
            }
        }
        return idx;
    }

    fn parseExpressionStatement(self: *Parser) ParseError!NodeId {
        if (self.peek().kind == .asterisk) {
            const star = self.advance();
            try self.reportCodeAt(self.utf8ColumnAdjustedPosOnLine(star.span.start), star.line, 1109, "Expression expected.");
            if (!self.peek().flags.preceded_by_newline and arrayLiteralElementCanStart(self.peek().kind)) {
                const expr = try self.parseExpression();
                if (self.hir.kindOf(expr) == .identifier) {
                    const expr_span = self.hir.spanOf(expr);
                    const adjusted_start = self.utf8ColumnAdjustedPosOnLine(expr_span.start);
                    if (adjusted_start != expr_span.start) {
                        self.hir.spans.items[expr] = .{
                            .start = adjusted_start,
                            .end = adjusted_start + (expr_span.end - expr_span.start),
                        };
                    }
                }
                try self.consumeStatementTerminator();
                return expr;
            }
            const recovered = try self.builder.addLiteralNumber(.{ .start = star.span.start, .end = star.span.start }, 0);
            try self.consumeStatementTerminator();
            return recovered;
        }
        const expr = try self.parseExpression();
        if (self.hir.kindOf(expr) == .identifier and self.cursor > 0) {
            const expr_tok = self.tokens[self.cursor - 1];
            if (!self.peek().flags.preceded_by_newline and self.tokenTextEquals(expr_tok, "declare")) {
                return expr;
            }
            if (!self.peek().flags.preceded_by_newline and
                (self.tokenTextEquals(expr_tok, "namespace") or self.tokenTextEquals(expr_tok, "module")) and
                !tokenCanStartNamespaceDeclarationName(self.peek().kind))
            {
                const invalid_name = self.advance();
                const name_text = self.source[invalid_name.span.start..invalid_name.span.end];
                const msg = try std.fmt.allocPrint(self.diag_arena.allocator(), "Namespace name cannot be '{s}'.", .{name_text});
                try self.reportCodeAt(invalid_name.span.start, invalid_name.line, 2819, msg);
            }
        }
        try self.consumeStatementTerminator();
        return expr;
    }

    fn consumeStatementTerminator(self: *Parser) ParseError!void {
        if (self.match(.semicolon)) return;
        // ASI: if the next token starts on a new line, or is `}`, or is
        // EOF, accept the absence of a semicolon.
        const t = self.peek();
        if (t.kind == .invalid) {
            const bad = self.advance();
            try self.reportCodeAt(bad.span.start, bad.line, 1127, "Invalid character.");
            if (self.match(.semicolon)) return;
            const after_invalid = self.peek();
            if (after_invalid.kind == .eof or
                after_invalid.kind == .close_brace or
                after_invalid.flags.preceded_by_newline)
            {
                return;
            }
        }
        if (t.kind == .eof or t.kind == .close_brace or t.flags.preceded_by_newline) return;
        if ((t.kind == .identifier or t.kind.isContextualKeyword()) and
            self.cursor >= 2 and
            self.tokens[self.cursor - 1].kind == .kw_as and
            self.tokens[self.cursor - 2].kind == .asterisk)
        {
            // Type-only import-equals recovery leaves `as ns from` behind.
            // End the recovered `as` expression at `ns` without consuming it
            // so both trailing identifiers still reach the checker.
            try self.reportCodeAt(t.span.start, t.line, 1005, "';' expected.");
            return;
        }
        if (t.kind == .kw_static and self.cursor > 0 and self.tokens[self.cursor - 1].kind == .identifier) {
            const prev = self.tokens[self.cursor - 1];
            try self.reportCodeAt(prev.span.start, prev.line, 1434, "Unexpected keyword or identifier.");
            return;
        }
        if (t.kind == .kw_from and
            self.cursor >= 3 and
            self.tokens[self.cursor - 2].kind == .kw_as and
            self.tokens[self.cursor - 3].kind == .asterisk)
        {
            // Continuation of the malformed `default * as ns from` import
            // recovery. Its missing-semicolon diagnostic was already emitted
            // at `ns`; leave `from` for the next statement so it remains a
            // checked identifier after the recovery-owned TS1434.
            var has_unexpected_from = false;
            for (self.diagnostics.items) |d| {
                if (d.code == 1434 and d.pos == t.span.start) {
                    has_unexpected_from = true;
                    break;
                }
            }
            if (!has_unexpected_from) {
                try self.reportCodeAt(t.span.start, t.line, 1434, "Unexpected keyword or identifier.");
            }
            return;
        }
        if (t.kind == .string_literal and
            self.cursor > 0 and
            self.tokens[self.cursor - 1].kind == .kw_from)
        {
            _ = self.advance();
            _ = self.match(.semicolon);
            return;
        }
        if (t.kind == .identifier and self.cursor > 0 and self.tokens[self.cursor - 1].kind == .number_literal) {
            if (t.flags.has_escape) {
                try self.reportCodeAt(t.span.start, t.line, 1005, "';' expected.");
                try self.reportCannotFindNameToken(t);
                _ = self.advance();
            }
            return;
        }
        if (t.kind == .colon and self.peekAt(1).kind == .arrow) {
            try self.reportCodeAt(t.span.start, t.line, 1005, "',' expected.");
            _ = self.advance();
            const arrow_tok = self.peek();
            try self.reportCodeAt(arrow_tok.span.start, arrow_tok.line, 1005, "';' expected.");
            _ = self.advance();
            return;
        }
        if (t.kind == .arrow) {
            try self.reportCodeAt(t.span.start, t.line, 1005, "';' expected.");
            _ = self.advance();
            return;
        }
        if (t.kind == .close_bracket) {
            try self.reportCodeAt(t.span.start, t.line, 1005, "';' expected.");
            _ = self.advance();
            return;
        }
        // §6.A parserArrowFunctionExpression3: `a = (() => { } || a)` —
        // the recovery path inside `parsePrimaryExpression`'s
        // `open_paren` arm absorbs the missing-`)` diagnostic and
        // returns control here with the trailing `)` still unread.
        // Treat the stray close-paren the same way as a stray
        // close-bracket: emit canonical TS1005 `';' expected.` at the
        // token and consume it so the next statement parses cleanly.
        if (t.kind == .close_paren) {
            try self.reportCodeAt(t.span.start, t.line, 1005, "';' expected.");
            _ = self.advance();
            return;
        }
        if (t.kind == .number_literal and
            t.span.start < t.span.end and
            self.source[t.span.start] == '.' and
            self.cursor > 0 and
            self.tokens[self.cursor - 1].kind == .identifier)
        {
            const prev = self.tokens[self.cursor - 1];
            try self.reportCodeAt(prev.span.start, prev.line, 1434, "Unexpected keyword or identifier.");
            try self.reportCannotFindNameToken(prev);
            return;
        }
        if (t.kind == .dot and
            self.cursor > 0 and
            self.tokens[self.cursor - 1].kind == .identifier and
            self.peekAt(1).kind == .number_literal and
            !self.peekAt(1).flags.preceded_by_newline)
        {
            const prev = self.tokens[self.cursor - 1];
            try self.reportCodeAt(prev.span.start, prev.line, 1434, "Unexpected keyword or identifier.");
            try self.reportCannotFindNameToken(prev);
            _ = self.advance();
            return;
        }
        if (t.kind == .dot) {
            try self.reportCodeAt(t.span.start, t.line, 1005, "';' expected.");
            _ = self.advance();
            return;
        }
        if (t.kind == .open_brace or t.kind == .open_paren) {
            if (t.kind == .open_paren and
                self.cursor >= 4 and
                self.tokens[self.cursor - 2].kind == .dot and
                self.tokens[self.cursor - 3].kind == .kw_import and
                self.tokens[self.cursor - 4].kind == .kw_typeof and
                self.tokenTextEquals(self.tokens[self.cursor - 1], "defer"))
            {
                // `parseImportTypeReference` deliberately leaves this `(`
                // unread after recovering `typeof import.defer`. Upstream
                // ends the malformed type alias without another semicolon
                // diagnostic, then parses `(specifier).member` as a value
                // expression statement.
                return;
            }
            try self.reportCodeAt(t.span.start, t.line, 1005, "';' expected.");
            return;
        }
        // §6.A parserArrowFunctionExpression2: `a = () => { } || a` —
        // when an arrow with a block body completes the assignment
        // expression and the next token is a logical infix operator
        // (`||`, `&&`, `??`), tsc reports TS1005 at the operator and
        // continues parsing the RHS as a separate statement so the
        // trailing identifier still reaches the checker for TS2304.
        // Without this branch the recovery returns
        // `error.UnexpectedToken`, `parseSourceFile` aborts, and the
        // LHS / RHS identifiers never bind. Advance past the operator
        // here so `parsePrimaryExpression`'s default-else doesn't pile
        // on an extra TS1109 the upstream baseline doesn't expect.
        if (t.kind == .pipe_pipe or
            t.kind == .ampersand_ampersand or
            t.kind == .question_question)
        {
            try self.reportCodeAt(t.span.start, t.line, 1005, "';' expected.");
            _ = self.advance();
            return;
        }
        // §6.A 2000-3000 ratchet: align the missing-terminator
        // fallback with tsc's canonical TS1005 "';' expected." prose
        // rather than a Home-internal "expected ';' or newline after
        // statement" payload. Mirrors fixtures like `parserFuzz1` and
        // `parser.numericSeparators.decmialNegative` where the
        // recovery anchor lands on the offending token.
        try self.reportCodeAt(t.span.start, t.line, 1005, "';' expected.");
        return error.UnexpectedToken;
    }

    /// Skip a type annotation by walking it until a delimiter — used
    /// only in salvage paths where producing a real HIR type node
    /// isn't necessary (the body of an interface, the rhs of a
    /// `type X =`, etc.). Most callers prefer `parseTypeAnnotation`.
    fn skipTypeAnnotation(self: *Parser) ParseError!void {
        var depth: i32 = 0;
        while (true) {
            const t = self.peek();
            if (depth == 0) {
                switch (t.kind) {
                    .equal, .semicolon, .comma, .greater_than, .close_paren, .close_brace, .close_bracket, .eof => return,
                    else => {},
                }
            }
            switch (t.kind) {
                .less_than, .open_paren, .open_brace, .open_bracket => depth += 1,
                .greater_than, .close_paren, .close_brace, .close_bracket => depth -= 1,
                else => {},
            }
            _ = self.advance();
            if (t.kind == .eof) return;
        }
    }

    // ========================================================================
    // Type annotation parser
    // ========================================================================
    //
    // Grammar (subset, builds out as features land):
    //
    //   Type            = ConditionalType
    //   ConditionalType = UnionType ('extends' UnionType '?' Type ':' Type)?
    //   UnionType       = ('|')? IntersectionType ('|' IntersectionType)*
    //   IntersectionType= ('&')? ArrayType ('&' ArrayType)*
    //   ArrayType       = NonArrayType ('[]' | '[' Type ']')*
    //   NonArrayType    = PrimaryType
    //   PrimaryType     = LiteralType | KeyofType | TypeofType | InferType
    //                   | TupleType | ParenType | TypeRef
    //                   | FnType
    //
    // We keep the parser permissive for forms it doesn't fully model
    // yet (object types {…} are lowered as a synthetic `unknown` type
    // ref so consumers see *something* without halting).

    /// Public entry: parse a single type annotation starting at the
    /// current cursor. Returns a HIR type node id.
    fn parseTypeAnnotation(self: *Parser) ParseError!NodeId {
        return try self.parseConditionalType();
    }

    /// Parse a return-type annotation, with detection of type
    /// predicates (`arg is T`) and assertion functions (`asserts
    /// arg is T`). Falls through to `parseTypeAnnotation` for the
    /// regular case. `params` is the function's positional parameter
    /// list — each is a `parameter` HIR node, looked up by name to
    /// resolve the predicate's `arg`.
    fn parseReturnTypeAnnotation(self: *Parser, params: []const NodeId) ParseError!NodeId {
        const start_cursor = self.cursor;
        const start_span_start = self.peek().span.start;
        // `asserts <ident>` ...
        if (self.peek().kind == .kw_asserts and
            self.peekAt(1).kind == .identifier and
            !self.peekAt(1).flags.preceded_by_newline)
        {
            _ = self.advance(); // asserts
            const arg_tok = self.advance();
            const arg_id = try self.internToken(arg_tok);
            // `asserts <ident>` (predicate-less) — narrows to truthy.
            if (self.peek().kind != .kw_is or self.peek().flags.preceded_by_newline) {
                const idx = self.findParamIndex(params, arg_id) orelse 0xFFFF;
                return try self.builder.addTypePredicate(
                    .{ .start = start_span_start, .end = arg_tok.span.end },
                    @intCast(idx),
                    arg_id,
                    hir_mod.none_node_id,
                    true,
                );
            }
            _ = self.advance(); // is
            const target = try self.parseTypeAnnotation();
            const idx = self.findParamIndex(params, arg_id) orelse 0xFFFF;
            return try self.builder.addTypePredicate(
                .{ .start = start_span_start, .end = self.hir.spanOf(target).end },
                @intCast(idx),
                arg_id,
                target,
                true,
            );
        }
        // `<ident> is T`
        if (self.peek().kind == .identifier and
            self.peekAt(1).kind == .kw_is and
            !self.peekAt(1).flags.preceded_by_newline)
        {
            const arg_tok = self.advance();
            const arg_id = try self.internToken(arg_tok);
            _ = self.advance(); // is
            const target = try self.parseTypeAnnotation();
            const idx = self.findParamIndex(params, arg_id) orelse 0xFFFF;
            return try self.builder.addTypePredicate(
                .{ .start = start_span_start, .end = self.hir.spanOf(target).end },
                @intCast(idx),
                arg_id,
                target,
                false,
            );
        }
        // `this is T`
        if (self.peek().kind == .kw_this and
            self.peekAt(1).kind == .kw_is and
            !self.peekAt(1).flags.preceded_by_newline)
        {
            _ = self.advance(); // this
            const this_id = self.interner.intern("this") catch return error.OutOfMemory;
            _ = self.advance(); // is
            const target = try self.parseTypeAnnotation();
            return try self.builder.addTypePredicate(
                .{ .start = start_span_start, .end = self.hir.spanOf(target).end },
                0xFFFF,
                this_id,
                target,
                false,
            );
        }
        // Not a predicate — fall through. Restore cursor (we may
        // have advanced past `asserts` only to find no `<ident>`).
        self.cursor = start_cursor;
        return self.parseTypeAnnotation();
    }

    /// Look up a parameter by interned name; return its 0-based
    /// positional index or null. `this` parameters return null
    /// (caller falls back to the 0xFFFF sentinel for `this`).
    fn findParamIndex(self: *Parser, params: []const NodeId, name: hir_mod.StringId) ?usize {
        for (params, 0..) |p, i| {
            if (self.hir.kindOf(p) != .parameter) continue;
            const pp = hir_mod.parameterOf(self.hir, p);
            if (pp.name == hir_mod.none_node_id) continue;
            if (self.hir.kindOf(pp.name) != .identifier) continue;
            const id = hir_mod.identifierOf(self.hir, pp.name);
            if (id.name == name) return i;
        }
        return null;
    }

    fn parseConditionalType(self: *Parser) ParseError!NodeId {
        const check = try self.parseUnionType();
        if (self.hir.kindOf(check) == .infer_type and self.peek().kind == .question) {
            const inf = hir_mod.inferTypeOf(self.hir, check);
            if (inf.constraint != hir_mod.none_node_id) {
                _ = self.advance();
                const bare = try self.builder.addInferType(self.hir.spanOf(check), inf.name, hir_mod.none_node_id);
                // Mark BOTH the synthesised bare infer AND the original
                // `infer X extends C` node (which is now orphaned —
                // its constraint became the conditional's extends_t
                // and the bare took its place as check) so the
                // post-parse TS1338 walker doesn't flag either. The
                // shorthand is legal syntax.
                try self.synthetic_infer_check_nodes.put(self.gpa, bare, {});
                try self.synthetic_infer_check_nodes.put(self.gpa, check, {});
                const true_branch = try self.parseTypeAnnotation();
                _ = try self.expect(.colon, "':' in conditional type");
                const false_branch = try self.parseTypeAnnotation();
                const sp: Span = .{
                    .start = self.hir.spanOf(check).start,
                    .end = self.hir.spanOf(false_branch).end,
                };
                return try self.builder.addConditionalType(sp, bare, inf.constraint, true_branch, false_branch);
            }
        }
        if (self.peek().kind != .kw_extends) return check;
        const extends_kw = self.advance(); // extends
        _ = extends_kw;
        const extends_t = try self.parseUnionType();
        if (!self.match(.question)) return check;
        const true_branch = try self.parseTypeAnnotation();
        _ = try self.expect(.colon, "':' in conditional type");
        const false_branch = try self.parseTypeAnnotation();
        const sp: Span = .{
            .start = self.hir.spanOf(check).start,
            .end = self.hir.spanOf(false_branch).end,
        };
        return try self.builder.addConditionalType(sp, check, extends_t, true_branch, false_branch);
    }

    fn parseUnionType(self: *Parser) ParseError!NodeId {
        // Leading `|` is allowed: `type T = | A | B`.
        const had_leading_pipe = self.match(.pipe);
        const first = if (had_leading_pipe)
            try self.parseFunctionOrConstructorTypeToError(.union_type)
        else
            try self.parseIntersectionType();
        if (self.peek().kind != .pipe) return first;
        var members: std.ArrayListUnmanaged(NodeId) = .empty;
        defer members.deinit(self.gpa);
        try members.append(self.gpa, first);
        while (self.match(.pipe)) {
            const m = try self.parseFunctionOrConstructorTypeToError(.union_type);
            try members.append(self.gpa, m);
        }
        const sp: Span = .{
            .start = self.hir.spanOf(first).start,
            .end = self.hir.spanOf(members.items[members.items.len - 1]).end,
        };
        return try self.builder.addUnionType(sp, members.items);
    }

    fn parseIntersectionType(self: *Parser) ParseError!NodeId {
        const had_leading_ampersand = self.match(.ampersand);
        const first = if (had_leading_ampersand)
            try self.parseFunctionOrConstructorTypeToError(.intersection_type)
        else
            try self.parseTypeOperator();
        if (self.peek().kind != .ampersand) return first;
        var members: std.ArrayListUnmanaged(NodeId) = .empty;
        defer members.deinit(self.gpa);
        try members.append(self.gpa, first);
        while (self.match(.ampersand)) {
            const m = try self.parseFunctionOrConstructorTypeToError(.intersection_type);
            try members.append(self.gpa, m);
        }
        const sp: Span = .{
            .start = self.hir.spanOf(first).start,
            .end = self.hir.spanOf(members.items[members.items.len - 1]).end,
        };
        return try self.builder.addIntersectionType(sp, members.items);
    }

    const FunctionOrConstructorTypeDiagnosticContext = enum { union_type, intersection_type };

    fn parseFunctionOrConstructorTypeToError(self: *Parser, context: FunctionOrConstructorTypeDiagnosticContext) ParseError!NodeId {
        if (!self.isStartOfFunctionOrConstructorType()) {
            return switch (context) {
                .union_type => try self.parseIntersectionType(),
                .intersection_type => try self.parseTypeOperator(),
            };
        }
        const is_constructor = self.isStartOfConstructorType();
        const node = try self.parseTypeOperator();
        const type_span = self.hir.spanOf(node);
        const code: u32 = switch (context) {
            .union_type => if (is_constructor) 1386 else 1385,
            .intersection_type => if (is_constructor) 1388 else 1387,
        };
        const message = switch (context) {
            .union_type => if (is_constructor)
                "Constructor type notation must be parenthesized when used in a union type."
            else
                "Function type notation must be parenthesized when used in a union type.",
            .intersection_type => if (is_constructor)
                "Constructor type notation must be parenthesized when used in an intersection type."
            else
                "Function type notation must be parenthesized when used in an intersection type.",
        };
        try self.reportCodeAt(type_span.start, self.lineAt(type_span.start), code, message);
        return node;
    }

    fn isStartOfFunctionOrConstructorType(self: *const Parser) bool {
        return self.isStartOfConstructorType() or self.isStartOfFunctionType();
    }

    fn isStartOfConstructorType(self: *const Parser) bool {
        return self.peek().kind == .kw_new or
            (self.peek().kind == .kw_abstract and self.peekAt(1).kind == .kw_new);
    }

    fn isStartOfFunctionType(self: *const Parser) bool {
        return switch (self.peek().kind) {
            .less_than => true,
            .open_paren => self.parenStartsDirectFunctionType(),
            else => false,
        };
    }

    fn parenStartsDirectFunctionType(self: *const Parser) bool {
        var depth: i32 = 0;
        var i = self.cursor;
        while (i < self.tokens.len) : (i += 1) {
            const tk = self.tokens[i].kind;
            switch (tk) {
                .open_paren, .open_bracket, .open_brace, .less_than => depth += 1,
                .close_paren, .close_bracket, .close_brace, .greater_than, .greater_greater, .greater_greater_greater => {
                    const count: u8 = switch (tk) {
                        .greater_greater => 2,
                        .greater_greater_greater => 3,
                        else => 1,
                    };
                    var n: u8 = 0;
                    while (n < count) : (n += 1) {
                        depth -= 1;
                        if (depth == 0) {
                            return i + 1 < self.tokens.len and self.tokens[i + 1].kind == .arrow;
                        }
                    }
                    if (depth < 0) return false;
                },
                .eof => return false,
                else => {},
            }
        }
        return false;
    }

    /// `keyof T`, `typeof e`, `infer X`, `readonly T[]`; other forms fall
    /// through to `parseArrayType`.
    fn parseTypeOperator(self: *Parser) ParseError!NodeId {
        const t = self.peek();
        switch (t.kind) {
            .kw_keyof => {
                _ = self.advance();
                const operand = try self.parseTypeOperator();
                const sp: Span = .{ .start = t.span.start, .end = self.hir.spanOf(operand).end };
                return try self.builder.addKeyofType(sp, operand);
            },
            .kw_typeof => {
                _ = self.advance();
                // `typeof` in a type position consumes a value
                // expression. Keep the HIR compact by interning the
                // qualified token span as an identifier-like ref.
                if (self.peek().kind == .kw_import) {
                    const import_t = try self.parseImportTypeReference();
                    const operand = try self.parseArrayTypePostfix(import_t);
                    const sp: Span = .{ .start = t.span.start, .end = self.hir.spanOf(operand).end };
                    const typeof_t = try self.builder.addTypeofType(sp, operand);
                    return try self.parseArrayTypePostfix(typeof_t);
                }
                const ref_start = switch (self.peek().kind) {
                    .identifier, .kw_default, .kw_undefined, .kw_super, .kw_this, .kw_function => self.advance(),
                    .kw_yield => if (!self.isYieldReservedName(self.peek())) self.advance() else {
                        const bad = self.peek();
                        try self.reportInvalidYieldName(bad, true);
                        const ref = try self.recoverInvalidTypeofTypeOperand(bad);
                        const sp: Span = .{ .start = t.span.start, .end = self.hir.spanOf(ref).end };
                        const typeof_t = try self.builder.addTypeofType(sp, ref);
                        return try self.parseArrayTypePostfix(typeof_t);
                    },
                    else => if (self.peek().kind.isPrimitiveTypeKeyword()) self.advance() else {
                        const bad = self.peek();
                        try self.reportCodeAt(bad.span.start, bad.line, 1003, "Identifier expected.");
                        const ref = try self.recoverInvalidTypeofTypeOperand(bad);
                        const sp: Span = .{ .start = t.span.start, .end = self.hir.spanOf(ref).end };
                        const typeof_t = try self.builder.addTypeofType(sp, ref);
                        return try self.parseArrayTypePostfix(typeof_t);
                    },
                };
                var ref_name_end = ref_start.span.end;
                while (self.peek().kind == .dot and
                    (self.peekAt(1).kind == .identifier or
                        self.peekAt(1).kind == .private_identifier or
                        self.peekAt(1).kind.isKeyword()))
                {
                    _ = self.advance();
                    ref_name_end = self.advance().span.end;
                }
                if (self.peek().kind == .dot) {
                    const dot = self.advance();
                    try self.reportCodeAt(dot.span.end, dot.line, 1003, "Identifier expected.");
                }
                var ref_end = ref_name_end;
                const recover_function_tail = ref_start.kind == .kw_function;
                if (self.peek().kind == .less_than) {
                    const args = try self.parseTypeArgumentList();
                    self.gpa.free(args);
                    ref_end = self.tokens[self.cursor - 1].span.end;
                }
                const ref_id = self.interner.intern(self.source[ref_start.span.start..ref_name_end]) catch return error.OutOfMemory;
                const ref = try self.builder.addIdentifier(.{ .start = ref_start.span.start, .end = ref_end }, ref_id);
                const sp: Span = .{ .start = t.span.start, .end = ref_end };
                const typeof_t = try self.builder.addTypeofType(sp, ref);
                if (recover_function_tail) try self.recoverInvalidTypeofFunctionTail();
                return try self.parseArrayTypePostfix(typeof_t);
            },
            .kw_infer => {
                _ = self.advance();
                const name_tok = try self.expect(.identifier, "name after 'infer'");
                const name_id = try self.internToken(name_tok);
                var constraint: NodeId = hir_mod.none_node_id;
                if (self.match(.kw_extends)) {
                    constraint = try self.parseTypeOperator();
                }
                const end_pos: u32 = if (constraint != hir_mod.none_node_id)
                    self.hir.spanOf(constraint).end
                else
                    name_tok.span.end;
                return try self.builder.addInferType(.{ .start = t.span.start, .end = end_pos }, name_id, constraint);
            },
            .kw_readonly => {
                const readonly_tok = self.advance();
                const operand_parenthesized = self.readonlyOperandIsBareParenthesizedType();
                const operand = try self.parseTypeOperator();
                const sp: Span = .{ .start = readonly_tok.span.start, .end = self.hir.spanOf(operand).end };
                return try self.builder.addReadonlyType(sp, operand, operand_parenthesized);
            },
            .kw_unique => {
                const unique_tok = self.advance();
                if (self.peek().kind == .kw_symbol) {
                    const symbol_tok = self.advance();
                    const id = self.interner.intern("symbol") catch return error.OutOfMemory;
                    return try self.builder.addTypeRef(.{ .start = unique_tok.span.start, .end = symbol_tok.span.end }, id, &.{}, &.{});
                }
                // `unique` must be followed by `symbol`. tsc reports
                // "'symbol' expected" and recovers by parsing the (wrong)
                // operand type so the remainder of the file still parses —
                // without this, the unconsumed operand strands the rest of
                // the source. Mirrors uniqueSymbolsErrors.ts(2,41). The
                // recovered type is `unknown` (an error type), so no TS1335
                // is attached to `unique <non-symbol>` (matching tsc, which
                // emits only the parse error there).
                const next = self.peek();
                try self.reportCodeAt(next.span.start, next.line, 1005, "'symbol' expected.");
                const operand = try self.parseTypeOperator();
                const id = self.interner.intern("unknown") catch return error.OutOfMemory;
                return try self.builder.addTypeRef(.{ .start = unique_tok.span.start, .end = self.hir.spanOf(operand).end }, id, &.{}, &.{});
            },
            else => return try self.parseArrayType(),
        }
    }

    fn readonlyOperandIsBareParenthesizedType(self: *const Parser) bool {
        if (self.peek().kind != .open_paren) return false;
        var depth: i32 = 0;
        var i = self.cursor;
        while (i < self.tokens.len) : (i += 1) {
            const tk = self.tokens[i].kind;
            switch (tk) {
                .open_paren, .open_bracket, .open_brace, .less_than => depth += 1,
                .close_paren, .close_bracket, .close_brace, .greater_than, .greater_greater, .greater_greater_greater => {
                    const count: u8 = switch (tk) {
                        .greater_greater => 2,
                        .greater_greater_greater => 3,
                        else => 1,
                    };
                    var n: u8 = 0;
                    while (n < count) : (n += 1) {
                        depth -= 1;
                        if (depth == 0 and tk == .close_paren) {
                            const next_index = i + 1;
                            if (next_index >= self.tokens.len) return true;
                            const next = self.tokens[next_index];
                            return next.kind != .open_bracket or next.flags.preceded_by_newline;
                        }
                        if (depth <= 0) break;
                    }
                    if (depth <= 0) return false;
                },
                .eof => return true,
                else => {},
            }
        }
        return true;
    }

    fn recoverInvalidTypeofTypeOperand(self: *Parser, bad: Token) ParseError!NodeId {
        switch (bad.kind) {
            .open_paren => {
                _ = self.advance();
                if (self.peek().kind == .close_paren) _ = self.advance();
                if (self.peek().kind == .colon) {
                    _ = self.advance();
                    self.skipUntilStatementTerminator();
                    const anchor = self.peek();
                    try self.reportCodeAt(anchor.span.start, anchor.line, 1005, "'=>' expected.");
                }
            },
            .open_brace, .open_bracket => try self.skipBalancedInvalidTypeofOperand(),
            .number_literal,
            .bigint_literal,
            .string_literal,
            .regex_literal,
            .no_substitution_template,
            .template_head,
            => {
                _ = self.advance();
            },
            else => {
                _ = self.advance();
            },
        }
        return try self.typeRefName("unknown", tokenSpan(bad));
    }

    fn recoverInvalidTypeofFunctionTail(self: *Parser) ParseError!void {
        if (self.peek().kind == .identifier) {
            const name = self.advance();
            try self.reportCodeAt(name.span.start, name.line, 1005, "',' expected.");
        }
        if (self.peek().kind == .open_paren) {
            const open = self.advance();
            try self.reportCodeAt(open.span.start, open.line, 1005, "',' expected.");
            var depth: u32 = 1;
            while (self.peek().kind != .eof and depth > 0) {
                const k = self.peek().kind;
                if (k == .open_paren) depth += 1;
                if (k == .close_paren) depth -= 1;
                _ = self.advance();
            }
        }
        if (self.peek().kind == .open_brace) {
            const brace = self.peek();
            try self.reportCodeAt(brace.span.start, brace.line, 1005, "'=>' expected.");
            try self.skipBalancedInvalidTypeofOperand();
        }
    }

    fn skipBalancedInvalidTypeofOperand(self: *Parser) ParseError!void {
        const open = self.advance();
        const close_kind: TokenKind = switch (open.kind) {
            .open_brace => .close_brace,
            .open_bracket => .close_bracket,
            .open_paren => .close_paren,
            else => return,
        };
        var depth: u32 = 1;
        while (self.peek().kind != .eof) {
            const k = self.peek().kind;
            if (k == open.kind) {
                depth += 1;
                _ = self.advance();
                continue;
            }
            if (k == close_kind) {
                _ = self.advance();
                depth -= 1;
                if (depth == 0) return;
                continue;
            }
            if (k == .semicolon and depth == 1) return;
            _ = self.advance();
        }
    }

    fn skipUntilStatementTerminator(self: *Parser) void {
        while (self.peek().kind != .eof and self.peek().kind != .semicolon) {
            _ = self.advance();
        }
    }

    fn parseArrayType(self: *Parser) ParseError!NodeId {
        const node = try self.parsePrimaryType();
        return try self.parseArrayTypePostfix(node);
    }

    fn parseArrayTypePostfix(self: *Parser, initial: NodeId) ParseError!NodeId {
        var node = initial;
        while (true) {
            // TS spec: an `[` on a new line after a type does NOT extend
            // the type — there's an implicit no-line-terminator boundary.
            // Without this guard, interface index signatures on the line
            // after a method's return type (`...): void` followed by
            // `[x: number]: I;`) get mis-parsed as `void[x: number]`,
            // emitting a spurious TS1109 / dropping the index member.
            // Matches `taggedTemplateStringsWithTypedTags` family.
            if (self.peek().kind == .open_bracket and !self.peek().flags.preceded_by_newline) {
                const idx_open = self.advance();
                if (self.match(.close_bracket)) {
                    // `T[]`
                    const sp: Span = .{
                        .start = self.hir.spanOf(node).start,
                        .end = self.tokens[self.cursor - 1].span.end,
                    };
                    node = try self.builder.addArrayType(sp, node);
                    continue;
                }
                // A private identifier cannot start an indexed-access type.
                // Keep it unconsumed so declaration recovery can reinterpret
                // the remaining `#name] = ...` tokens like upstream tsc.
                if (self.peek().kind == .private_identifier) {
                    const private_tok = self.peek();
                    try self.reportCodeAtWithMatchedPair(
                        private_tok.span.start,
                        private_tok.line,
                        1005,
                        "']' expected.",
                        idx_open.span.start,
                        "[",
                        "]",
                    );
                    const index = try self.typeRefName("unknown", .{ .start = private_tok.span.start, .end = private_tok.span.start });
                    return try self.builder.addIndexedAccessType(
                        .{ .start = self.hir.spanOf(node).start, .end = idx_open.span.end },
                        node,
                        index,
                    );
                }
                // `T[K]` — indexed access type.
                const index = try self.parseTypeAnnotation();
                _ = try self.expectClosingMatch(.close_bracket, "']' to close indexed access type", idx_open.span.start, "[", "]");
                const sp: Span = .{
                    .start = self.hir.spanOf(node).start,
                    .end = self.tokens[self.cursor - 1].span.end,
                };
                node = try self.builder.addIndexedAccessType(sp, node, index);
                continue;
            }
            if ((self.peek().kind == .question or self.peek().kind == .bang) and
                self.jsDocPostfixTypeMarkerCanRecover())
            {
                const marker = self.advance();
                const base_text = self.source[self.hir.spanOf(node).start..self.hir.spanOf(node).end];
                const suggestion = if (marker.kind == .question)
                    try std.fmt.allocPrint(self.diag_arena.allocator(), "{s} | undefined", .{base_text})
                else
                    base_text;
                const msg = try std.fmt.allocPrint(
                    self.diag_arena.allocator(),
                    "'{s}' at the end of a type is not valid TypeScript syntax. Did you mean to write '{s}'?",
                    .{ self.source[marker.span.start..marker.span.end], suggestion },
                );
                try self.reportCodeAt(self.hir.spanOf(node).start, self.lineAt(self.hir.spanOf(node).start), 17019, msg);
                if (marker.kind == .question) {
                    node = try self.makeNullableType(node, false, marker.span.end);
                }
                continue;
            }
            break;
        }
        return node;
    }

    fn parsePrimaryType(self: *Parser) ParseError!NodeId {
        const t = self.peek();
        return switch (t.kind) {
            // Primitive type keywords — represented as type refs to
            // the global builtin name. The checker resolves them to
            // `Primitive.string_t`, `Primitive.number_t`, etc.
            .kw_any, .kw_unknown, .kw_never, .kw_void, .kw_string, .kw_number, .kw_boolean, .kw_bigint, .kw_symbol, .kw_object, .kw_undefined, .kw_null => blk: {
                _ = self.advance();
                const id = try self.internToken(t);
                var end_pos = t.span.end;
                if (self.peek().kind == .dot and
                    (self.peekAt(1).kind == .identifier or self.peekAt(1).kind.isContextualKeyword() or self.peekAt(1).kind.isPrimitiveTypeKeyword()))
                {
                    const dot = self.advance();
                    try self.reportCodeAt(dot.span.start, dot.line, 1005, "',' expected.");
                    end_pos = self.advance().span.end;
                }
                break :blk try self.builder.addTypeRef(.{ .start = t.span.start, .end = end_pos }, id, &.{}, &.{});
            },
            .kw_true => blk: {
                _ = self.advance();
                const lit = try self.builder.addLiteralBool(tokenSpan(t), true);
                break :blk try self.builder.addLiteralType(tokenSpan(t), lit, false);
            },
            .kw_false => blk: {
                _ = self.advance();
                const lit = try self.builder.addLiteralBool(tokenSpan(t), false);
                break :blk try self.builder.addLiteralType(tokenSpan(t), lit, false);
            },
            .string_literal => blk: {
                _ = self.advance();
                const id = try self.internStringLiteral(t);
                const lit = try self.builder.addLiteralString(tokenSpan(t), id);
                break :blk try self.builder.addLiteralType(tokenSpan(t), lit, false);
            },
            .number_literal => blk: {
                _ = self.advance();
                const slice = self.source[t.span.start..t.span.end];
                // Type-position numeric literals (`: 01 = 01`) get the
                // same TS1121 octal-literal diagnostic as expression-
                // position literals — matches tsc's per-literal scan
                // (the parser flags numeric tokens uniformly,
                // regardless of whether they appear in a type or value
                // context).
                try self.reportStrictLegacyOctal(t, slice);
                try self.reportNumericLiteralDiagnostics(t, slice);
                const value = parseNumericLiteral(slice);
                const lit = try self.builder.addLiteralNumber(tokenSpan(t), value);
                break :blk try self.builder.addLiteralType(tokenSpan(t), lit, false);
            },
            // Template literal type: `\`hello-${T}\`` (in type position).
            .no_substitution_template => blk: {
                _ = self.advance();
                // Strip the backticks and produce a single text part.
                const slice = self.source[t.span.start + 1 .. t.span.end - 1];
                const text_id = self.interner.intern(slice) catch return error.OutOfMemory;
                const text_lit = try self.builder.addLiteralString(tokenSpan(t), text_id);
                break :blk try self.builder.addTemplateLiteralType(tokenSpan(t), &.{text_lit}, &.{});
            },
            .template_head => blk: {
                break :blk try self.parseTemplateLiteralType();
            },
            .minus => blk: {
                // Negative numeric/bigint literal type: `-1`, `-1n`.
                _ = self.advance();
                const next = self.peek();
                switch (next.kind) {
                    .number_literal => {
                        const num = self.advance();
                        const value = parseNumericLiteral(self.source[num.span.start..num.span.end]);
                        const lit = try self.builder.addLiteralNumber(tokenSpan(num), value);
                        break :blk try self.builder.addLiteralType(.{ .start = t.span.start, .end = num.span.end }, lit, true);
                    },
                    .bigint_literal => {
                        const big = self.advance();
                        const slice_with_n = self.source[big.span.start..big.span.end];
                        const digits_slice = slice_with_n[0 .. slice_with_n.len - 1];
                        const id = self.interner.intern(digits_slice) catch return error.OutOfMemory;
                        const lit = try self.builder.addLiteralBigInt(tokenSpan(big), id);
                        break :blk try self.builder.addLiteralType(.{ .start = t.span.start, .end = big.span.end }, lit, true);
                    },
                    else => {
                        _ = try self.expect(.number_literal, "numeric literal after '-' in type");
                        break :blk try self.typeRefName("unknown", tokenSpan(t));
                    },
                }
            },
            .open_paren => try self.parseParenOrFnType(),
            .open_bracket => try self.parseTupleType(),
            .open_brace => try self.parseObjectOrMappedType(),
            .less_than => try self.parseGenericFnType(),
            .asterisk => blk: {
                const star = self.advance();
                try self.reportCodeAt(star.span.start, star.line, 8020, "JSDoc types can only be used inside documentation comments.");
                break :blk try self.typeRefName("any", tokenSpan(star));
            },
            .question => blk: {
                const question = self.advance();
                if (!self.tokenCanStartJSDocNullableType(self.peek().kind)) {
                    try self.reportCodeAt(question.span.start, question.line, 8020, "JSDoc types can only be used inside documentation comments.");
                    break :blk try self.typeRefName("any", tokenSpan(question));
                }
                const inner = try self.parseTypeOperator();
                const inner_text = self.source[self.hir.spanOf(inner).start..self.hir.spanOf(inner).end];
                const msg = try std.fmt.allocPrint(
                    self.diag_arena.allocator(),
                    "'?' at the start of a type is not valid TypeScript syntax. Did you mean to write '{s} | null | undefined'?",
                    .{inner_text},
                );
                try self.reportCodeAt(question.span.start, question.line, 17020, msg);
                break :blk try self.makeNullableType(inner, true, self.hir.spanOf(inner).end);
            },
            .bang => blk: {
                const bang = self.advance();
                const inner = try self.parseTypeOperator();
                const inner_text = self.source[self.hir.spanOf(inner).start..self.hir.spanOf(inner).end];
                const msg = try std.fmt.allocPrint(
                    self.diag_arena.allocator(),
                    "'!' at the start of a type is not valid TypeScript syntax. Did you mean to write '{s}'?",
                    .{inner_text},
                );
                try self.reportCodeAt(bang.span.start, bang.line, 17020, msg);
                break :blk inner;
            },
            .kw_function => try self.parseJSDocFunctionTypeInTypeScript(),
            .close_paren => blk: {
                try self.reportCodeAt(t.span.start, t.line, 1110, "Type expected.");
                const id = self.interner.intern("unknown") catch return error.OutOfMemory;
                break :blk try self.builder.addTypeRef(.{ .start = t.span.start, .end = t.span.start }, id, &.{}, &.{});
            },
            .kw_new => try self.parseConstructorType(false),
            .kw_abstract => blk: {
                if (self.peekAt(1).kind == .kw_new) {
                    _ = self.advance();
                    break :blk try self.parseConstructorType(true);
                }
                _ = self.advance();
                const id = self.interner.intern("unknown") catch return error.OutOfMemory;
                break :blk try self.builder.addTypeRef(tokenSpan(t), id, &.{}, &.{});
            },
            .kw_yield => blk: {
                // `yield` in type position parses as an identifier-named
                // type ref so the type-resolution pass can emit
                // TS2304 ("Cannot find name 'yield'"). In an async
                // generator (`yieldAsTypeIsOk`) tsc keeps the type
                // position silent — no TS1212 + no TS2304. In a plain
                // generator at ES2015+ (`FunctionDeclaration13_es6`)
                // tsc additionally reports TS1212 ("'yield' is a
                // reserved word in strict mode.") because the binder
                // walks types through the strict-mode reservation
                // check.
                const yield_tok = self.advance();
                if (self.generator_depth > 0 and
                    self.target_es2015_or_later and
                    (self.async_function_depth == 0 or self.class_body_depth > 0))
                {
                    if (self.class_body_depth > 0) {
                        try self.reportCodeAt(yield_tok.span.start, yield_tok.line, 1213, "Identifier expected. 'yield' is a reserved word in strict mode. Class definitions are automatically in strict mode.");
                    } else {
                        try self.reportCodeAt(yield_tok.span.start, yield_tok.line, 1212, "Identifier expected. 'yield' is a reserved word in strict mode.");
                    }
                }
                const id = try self.internToken(yield_tok);
                break :blk try self.builder.addTypeRef(tokenSpan(yield_tok), id, &.{}, &.{});
            },
            // `await` in a type-reference position becomes an
            // identifier-named type ref so the type-resolution
            // pass can emit TS2552 ("Cannot find name 'await'.
            // Did you mean 'Awaited'?"). Mirrors tsc which lets
            // the identifier path produce the diagnostic instead
            // of treating `await` as a built-in type keyword.
            // Without this, the bare-token fallthrough would emit
            // a synthetic `unknown` ref and silently swallow the
            // error (asyncFunctionDeclaration13_es*, asyncArrowFunction10_es*).
            .kw_await => blk: {
                const await_tok = self.advance();
                const id = try self.internToken(await_tok);
                break :blk try self.builder.addTypeRef(tokenSpan(await_tok), id, &.{}, &.{});
            },
            .kw_import => try self.parseImportTypeReference(),
            .identifier => try self.parseTypeReference(),
            .kw_public, .kw_private, .kw_protected, .kw_static => blk: {
                const bad = self.advance();
                if (self.class_body_depth > 0) {
                    try self.reportInvalidClassStrictIdentifier(bad);
                } else {
                    try self.reportCodeAt(bad.span.start, bad.line, 1213, "Identifier expected. Reserved words cannot be used as identifiers here.");
                }
                const id = try self.internToken(bad);
                break :blk try self.builder.addTypeRef(tokenSpan(bad), id, &.{}, &.{});
            },
            .kw_this => blk: {
                const this_tok = self.advance();
                const id = self.interner.intern("this") catch return error.OutOfMemory;
                break :blk try self.builder.addTypeRef(tokenSpan(this_tok), id, &.{}, &.{});
            },
            else => {
                // Unknown — emit a synthetic type ref so the upstream
                // HIR shape stays valid; downstream binder / checker
                // will flag the diagnostic.
                //
                // §6.A parserErrorRecovery_ParameterList6: when the
                // bad token is a reserved word (`break`, `continue`,
                // `case`, etc.), tsc treats the token as an identifier
                // for type-resolution purposes so the checker fires
                // TS2304 ("Cannot find name '<word>'") against it.
                // Carry the actual lexeme into the synthetic type ref
                // so the unresolved-type path can surface that name.
                const bad = self.advance();
                const carries_lexeme = switch (bad.kind) {
                    .kw_break, .kw_continue, .kw_case, .kw_class, .kw_const, .kw_debugger, .kw_default, .kw_delete, .kw_do, .kw_else, .kw_enum, .kw_export, .kw_extends, .kw_finally, .kw_for, .kw_function, .kw_if, .kw_import, .kw_in, .kw_instanceof, .kw_let, .kw_return, .kw_super, .kw_switch, .kw_throw, .kw_try, .kw_typeof, .kw_var, .kw_while, .kw_with, .kw_yield, .kw_await => true,
                    else => false,
                };
                const id = if (carries_lexeme)
                    self.interner.intern(self.source[bad.span.start..bad.span.end]) catch return error.OutOfMemory
                else
                    self.interner.intern("unknown") catch return error.OutOfMemory;
                return try self.builder.addTypeRef(tokenSpan(bad), id, &.{}, &.{});
            },
        };
    }

    fn tokenCanStartJSDocNullableType(self: *const Parser, kind: TokenKind) bool {
        _ = self;
        return switch (kind) {
            .identifier,
            .kw_any,
            .kw_unknown,
            .kw_never,
            .kw_void,
            .kw_string,
            .kw_number,
            .kw_boolean,
            .kw_bigint,
            .kw_symbol,
            .kw_object,
            .kw_undefined,
            .kw_null,
            .kw_this,
            .kw_import,
            .kw_function,
            .open_paren,
            .open_bracket,
            .open_brace,
            .asterisk,
            .bang,
            => true,
            else => false,
        };
    }

    fn jsDocPostfixTypeMarkerCanRecover(self: *const Parser) bool {
        if (self.peek().kind == .question and self.tuple_type_depth > 0) {
            const next = self.peekAt(1).kind;
            if (next == .comma or next == .close_bracket) return false;
        }
        const next = self.peekAt(1).kind;
        return switch (next) {
            .equal,
            .comma,
            .semicolon,
            .close_paren,
            .close_bracket,
            .close_brace,
            .greater_than,
            .greater_greater,
            .greater_greater_greater,
            .eof,
            => true,
            else => false,
        };
    }

    fn typeRefName(self: *Parser, name: []const u8, type_span: Span) ParseError!NodeId {
        const id = self.interner.intern(name) catch return error.OutOfMemory;
        return try self.builder.addTypeRef(type_span, id, &.{}, &.{});
    }

    fn makeNullableType(self: *Parser, inner: NodeId, include_undefined: bool, end_pos: u32) ParseError!NodeId {
        var members: std.ArrayListUnmanaged(NodeId) = .empty;
        defer members.deinit(self.gpa);
        try members.append(self.gpa, inner);
        try members.append(self.gpa, try self.typeRefName("null", .{ .start = end_pos, .end = end_pos }));
        if (include_undefined) {
            try members.append(self.gpa, try self.typeRefName("undefined", .{ .start = end_pos, .end = end_pos }));
        }
        return try self.builder.addUnionType(
            .{ .start = self.hir.spanOf(inner).start, .end = end_pos },
            members.items,
        );
    }

    fn parseJSDocFunctionTypeInTypeScript(self: *Parser) ParseError!NodeId {
        const function_tok = self.advance();
        var params: std.ArrayListUnmanaged(NodeId) = .empty;
        defer params.deinit(self.gpa);
        var is_constructor = false;
        var constructor_return: NodeId = hir_mod.none_node_id;

        const jsdoc_fn_open = try self.expect(.open_paren, "'(' after JSDoc function type");
        if (self.peek().kind != .close_paren) {
            var index: usize = 0;
            while (true) : (index += 1) {
                if (index == 0 and self.peek().kind == .kw_new and self.peekAt(1).kind == .colon) {
                    is_constructor = true;
                    _ = self.advance();
                    _ = self.advance();
                    constructor_return = try self.parseTypeAnnotation();
                } else {
                    const param_start = self.peek();
                    var name_node: NodeId = hir_mod.none_node_id;
                    var type_ann: NodeId = hir_mod.none_node_id;
                    if ((self.peek().kind == .kw_this or self.peek().kind == .identifier) and self.peekAt(1).kind == .colon) {
                        const name_tok = self.advance();
                        _ = self.advance();
                        const parsed_type = try self.parseTypeAnnotation();
                        type_ann = try self.typeRefName("any", self.hir.spanOf(parsed_type));
                        const name_id = try self.internToken(name_tok);
                        name_node = try self.builder.addIdentifier(tokenSpan(name_tok), name_id);
                    } else {
                        const parsed_type = try self.parseTypeAnnotation();
                        type_ann = try self.typeRefName("any", self.hir.spanOf(parsed_type));
                        var buf: [32]u8 = undefined;
                        const synthetic = std.fmt.bufPrint(&buf, "__arg{d}", .{params.items.len}) catch return error.OutOfMemory;
                        name_node = try self.builder.addIdentifier(
                            .{ .start = param_start.span.start, .end = param_start.span.start },
                            self.interner.intern(synthetic) catch return error.OutOfMemory,
                        );
                    }
                    try params.append(self.gpa, try self.builder.addParameter(
                        .{ .start = param_start.span.start, .end = self.hir.spanOf(type_ann).end },
                        name_node,
                        type_ann,
                        hir_mod.none_node_id,
                        .{},
                    ));
                }
                if (!self.match(.comma)) break;
                if (self.peek().kind == .close_paren) break;
            }
        }
        const close_tok = try self.expectClosingMatch(.close_paren, "')' after JSDoc function type", jsdoc_fn_open.span.start, "(", ")");
        var ret: NodeId = if (constructor_return != hir_mod.none_node_id)
            constructor_return
        else
            try self.typeRefName("any", .{ .start = close_tok.span.end, .end = close_tok.span.end });
        if (!is_constructor and self.match(.colon)) {
            ret = try self.parseTypeAnnotation();
        }
        const end_pos = self.hir.spanOf(ret).end;
        try self.reportCodeAt(function_tok.span.start, function_tok.line, 8020, "JSDoc types can only be used inside documentation comments.");
        return try self.builder.addFnType(
            .{ .start = function_tok.span.start, .end = end_pos },
            &.{},
            params.items,
            ret,
            is_constructor,
            false,
        );
    }

    /// `(T)` (paren type) or `(a: T) => U` (function type).
    fn parseParenOrFnType(self: *Parser) ParseError!NodeId {
        // Speculative: snapshot cursor; if we see `=>` after the close
        // paren, it's a function type. Otherwise reset and parse as a
        // grouped type.
        const start = self.cursor;
        const open_tok = self.advance(); // '('

        // Quick scan for `=>` ignoring matched delimiters.
        var depth: i32 = 1;
        var i = self.cursor;
        var is_fn = false;
        var is_zero_arg = false;
        if (self.peek().kind == .close_paren) is_zero_arg = true;
        while (i < self.tokens.len) : (i += 1) {
            const tk = self.tokens[i].kind;
            if (tk == .open_paren or tk == .open_bracket or tk == .open_brace or tk == .less_than) depth += 1;
            if (tk == .close_paren or tk == .close_bracket or tk == .close_brace or
                tk == .greater_than or tk == .greater_greater or tk == .greater_greater_greater)
            {
                const count: u8 = switch (tk) {
                    .greater_greater => 2,
                    .greater_greater_greater => 3,
                    else => 1,
                };
                var n: u8 = 0;
                while (n < count) : (n += 1) {
                    depth -= 1;
                    if (depth == 0) {
                        if (i + 1 < self.tokens.len and self.tokens[i + 1].kind == .arrow) {
                            is_fn = true;
                        }
                        break;
                    }
                }
                if (depth == 0) break;
            }
            if (tk == .eof) break;
        }

        if (is_fn or is_zero_arg) {
            // Reset to before the open paren and parse fn type.
            self.cursor = start;
            return try self.parseFnTypeFromParen(false);
        }

        const inner = try self.parseTypeAnnotation();
        const close = try self.expectClosingMatch(.close_paren, "')' to close grouped type", open_tok.span.start, "(", ")");
        _ = close;
        return inner;
    }

    fn parseFnTypeFromParen(self: *Parser, is_constructor: bool) ParseError!NodeId {
        const start = self.peek();
        const params = try self.parseTypeParameterList();
        defer self.gpa.free(params);
        _ = try self.expect(.arrow, "'=>' in function type");
        const ret = try self.parseReturnTypeAnnotation(params);
        const sp: Span = .{ .start = start.span.start, .end = self.hir.spanOf(ret).end };
        return try self.builder.addFnType(sp, &.{}, params, ret, is_constructor, false);
    }

    /// Parse `(p1: T1, p2: T2)` and return parameter HIR nodes.
    fn parseTypeParameterList(self: *Parser) ParseError![]NodeId {
        const fn_type_open = try self.expect(.open_paren, "'(' for fn-type parameter list");
        var params: std.ArrayListUnmanaged(NodeId) = .empty;
        errdefer params.deinit(self.gpa);
        var seen_names: std.AutoHashMapUnmanaged(hir_mod.StringId, Span) = .empty;
        defer seen_names.deinit(self.gpa);
        if (self.peek().kind != .close_paren) {
            while (true) {
                const ps = self.peek();
                var flags: hir_mod.ParamFlags = .{};
                // tsc tolerates `public`/`private`/`protected`/`readonly`/`override`
                // modifiers on parameters in function-type position so the
                // checker can report TS2369 ("A parameter property is only
                // allowed in a constructor implementation"). Without
                // consuming them here we'd bail into `parseTypeAnnotation`
                // and emit a spurious TS1213. Mirrors `parserParameterList5`
                // and `parserParameterList13`.
                var saw_param_property_mod = false;
                var param_property_anchor: Token = ps;
                while (isParameterPropertyModifier(self.peek().kind) and
                    (self.peekAt(1).kind == .identifier or
                        self.peekAt(1).kind == .kw_this or
                        isParameterPropertyModifier(self.peekAt(1).kind) or
                        self.peekAt(1).kind == .dot_dot_dot))
                {
                    const mod = self.advance();
                    if (!saw_param_property_mod) {
                        saw_param_property_mod = true;
                        param_property_anchor = mod;
                    }
                    switch (mod.kind) {
                        .kw_readonly => flags.is_readonly = true,
                        .kw_override => flags.is_override = true,
                        else => {},
                    }
                    flags.is_parameter_property = true;
                }
                if (self.match(.dot_dot_dot)) flags.is_rest = true;
                var name_span = tokenSpan(ps);
                var name_node: NodeId = hir_mod.none_node_id;
                var seen_name: ?hir_mod.StringId = null;
                var type_ann: NodeId = hir_mod.none_node_id;
                if (self.peek().kind == .open_brace or self.peek().kind == .open_bracket) {
                    self.fn_type_binding_pattern_depth += 1;
                    defer self.fn_type_binding_pattern_depth -= 1;
                    name_node = try self.parseBindingPattern();
                    name_span = self.hir.spanOf(name_node);
                    if (self.match(.question)) flags.is_optional = true;
                    if (self.match(.colon)) type_ann = try self.parseTypeAnnotation();
                } else if (self.peek().kind == .identifier or
                    self.peek().kind == .kw_this or
                    (self.peek().kind.isKeyword() and (self.peekAt(1).kind == .colon or self.peekAt(1).kind == .question)))
                {
                    const name_tok = self.advance();
                    name_span = tokenSpan(name_tok);
                    if (self.match(.question)) flags.is_optional = true;
                    if (self.match(.colon)) type_ann = try self.parseTypeAnnotation();
                    const name_id = try self.internToken(name_tok);
                    name_node = try self.builder.addIdentifier(name_span, name_id);
                    seen_name = name_id;
                } else {
                    type_ann = try self.parseTypeAnnotation();
                    try self.reportUnusedRenamesInFnTypeParam(type_ann);
                    var buf: [32]u8 = undefined;
                    const synthetic = std.fmt.bufPrint(&buf, "__arg{d}", .{params.items.len}) catch
                        return error.OutOfMemory;
                    const name_id = self.interner.intern(synthetic) catch return error.OutOfMemory;
                    name_node = try self.builder.addIdentifier(name_span, name_id);
                    seen_name = name_id;
                }
                var default_value: NodeId = hir_mod.none_node_id;
                if (self.match(.equal)) {
                    self.param_initializer_depth += 1;
                    defer self.param_initializer_depth -= 1;
                    default_value = try self.parseAssignmentExpression();
                    if (flags.is_optional) {
                        try self.reportCodeAt(ps.span.start, ps.line, 1015, "Parameter cannot have question mark and initializer.");
                    }
                    if (flags.is_rest) {
                        const name_anchor = self.hir.spanOf(name_node);
                        try self.reportCodeAt(name_anchor.start, self.lineAt(name_anchor.start), 1048, "A rest parameter cannot have an initializer.");
                    }
                }
                const param = try self.builder.addParameter(
                    .{ .start = ps.span.start, .end = self.tokens[self.cursor - 1].span.end },
                    name_node,
                    type_ann,
                    default_value,
                    flags,
                );
                if (saw_param_property_mod) {
                    // TS2369 anchored at the first parameter-property
                    // modifier token. Matches `parserParameterList6.ts(2,19)`
                    // which underlines `public A` starting at `public`.
                    try self.reportCodeAt(param_property_anchor.span.start, param_property_anchor.line, 2369, "A parameter property is only allowed in a constructor implementation.");
                }
                if (seen_name) |name_id| {
                    if (seen_names.get(name_id)) |prev| {
                        try self.reportDuplicateIdentifierNamed(prev.start, self.lineAt(prev.start), name_id);
                        try self.reportDuplicateIdentifierNamed(name_span.start, self.lineAt(name_span.start), name_id);
                    } else {
                        try seen_names.put(self.gpa, name_id, name_span);
                    }
                }
                try params.append(self.gpa, param);
                if (!self.match(.comma)) break;
                if (self.peek().kind == .close_paren) break;
                if (flags.is_rest) {
                    // Upstream points the diagnostic at the `...` rest token.
                    // `ps` was captured before consuming the leading `...`,
                    // so its span.start is the `...` position.
                    try self.reportCodeAt(
                        ps.span.start,
                        ps.line,
                        1014,
                        "A rest parameter must be last in a parameter list.",
                    );
                }
            }
        }
        _ = try self.expectClosingMatch(.close_paren, "')' to close fn-type params", fn_type_open.span.start, "(", ")");
        return try params.toOwnedSlice(self.gpa);
    }

    fn reportUnusedRenamesInFnTypeParam(self: *Parser, node: NodeId) ParseError!void {
        if (node == hir_mod.none_node_id) return;
        switch (self.hir.kindOf(node)) {
            .tuple_type => for (hir_mod.tupleTypeElements(self.hir, node)) |elem| {
                try self.reportUnusedRenamesInFnTypeParam(elem);
            },
            .array_type => try self.reportUnusedRenamesInFnTypeParam(hir_mod.arrayTypeOf(self.hir, node).element),
            .optional_type => try self.reportUnusedRenamesInFnTypeParam(hir_mod.optionalTypeOf(self.hir, node).operand),
            .rest_type => try self.reportUnusedRenamesInFnTypeParam(hir_mod.restTypeOf(self.hir, node).operand),
            .object_type => for (hir_mod.objectTypeMembers(self.hir, node)) |member| {
                if (self.hir.kindOf(member) != .interface_member) continue;
                const im = hir_mod.interfaceMemberOf(self.hir, member);
                if (im.type_node == hir_mod.none_node_id or self.hir.kindOf(im.type_node) != .type_ref) continue;
                const tr = hir_mod.typeRefOf(self.hir, im.type_node);
                if (tr.name == im.name) continue;
                if (hir_mod.typeRefArgs(self.hir, im.type_node).len != 0 or
                    hir_mod.typeRefQualifier(self.hir, im.type_node).len != 0) continue;
                const from = self.interner.get(im.name);
                const to = self.interner.get(tr.name);
                if (to.len == 0 or !std.ascii.isLower(to[0])) continue;
                const type_span = self.hir.spanOf(im.type_node);
                try self.reportUnusedRenameInFnTypeParamAt(type_span.start, self.lineAt(type_span.start), from, to);
            },
            else => {},
        }
    }

    fn reportUnusedRenameInFnTypeBindingPattern(self: *Parser, key_tok: Token, target: NodeId) ParseError!void {
        if (self.fn_type_binding_pattern_depth == 0) return;
        if (key_tok.kind != .identifier) return;
        if (target == hir_mod.none_node_id or self.hir.kindOf(target) != .identifier) return;
        const from_id = try self.internToken(key_tok);
        const target_ident = hir_mod.identifierOf(self.hir, target);
        if (from_id == target_ident.name) return;
        const to = self.interner.get(target_ident.name);
        if (to.len == 0 or !std.ascii.isLower(to[0])) return;
        const from = self.interner.get(from_id);
        const target_span = self.hir.spanOf(target);
        try self.reportUnusedRenameInFnTypeParamAt(target_span.start, self.lineAt(target_span.start), from, to);
    }

    fn reportUnusedRenameInFnTypeParamAt(
        self: *Parser,
        pos: u32,
        line: u32,
        from: []const u8,
        to: []const u8,
    ) ParseError!void {
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "'{s}' is an unused renaming of '{s}'. Did you intend to use it as a type annotation?",
            .{ to, from },
        );
        const related_msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "We can only write a type for '{s}' by adding a type for the entire parameter here.",
            .{from},
        );
        const related = try self.diag_arena.allocator().alloc(RelatedInfo, 1);
        related[0] = .{
            .pos = pos,
            .code = 2843,
            .message = related_msg,
        };
        try self.diagnostics.append(self.gpa, .{
            .pos = pos,
            .line = line,
            .code = 2842,
            .message = msg,
            .related = related,
        });
    }

    /// Parse a template-literal type: `\`a${T}b${U}c\``. Cursor at
    /// `template_head` (`` `a${ ``); we collect each interpolated
    /// type and the trailing text segments until we hit
    /// `template_tail`.
    fn parseTemplateLiteralType(self: *Parser) ParseError!NodeId {
        const head = self.advance(); // template_head
        var text_parts: std.ArrayListUnmanaged(NodeId) = .empty;
        defer text_parts.deinit(self.gpa);
        var type_parts: std.ArrayListUnmanaged(NodeId) = .empty;
        defer type_parts.deinit(self.gpa);
        // Strip leading `\`` and trailing `${` from the head text.
        const head_slice = self.source[head.span.start + 1 .. head.span.end - 2];
        const head_id = self.interner.intern(head_slice) catch return error.OutOfMemory;
        const head_lit = try self.builder.addLiteralString(tokenSpan(head), head_id);
        try text_parts.append(self.gpa, head_lit);

        while (true) {
            // Parse the interpolated type expression.
            const t = try self.parseTypeAnnotation();
            try type_parts.append(self.gpa, t);
            const next = self.peek();
            if (next.kind == .template_middle) {
                _ = self.advance();
                const slice = self.source[next.span.start + 1 .. next.span.end - 2];
                const id = self.interner.intern(slice) catch return error.OutOfMemory;
                const lit = try self.builder.addLiteralString(tokenSpan(next), id);
                try text_parts.append(self.gpa, lit);
                continue;
            }
            if (next.kind == .template_tail) {
                _ = self.advance();
                const slice = self.source[next.span.start + 1 .. next.span.end - 1];
                const id = self.interner.intern(slice) catch return error.OutOfMemory;
                const lit = try self.builder.addLiteralString(tokenSpan(next), id);
                try text_parts.append(self.gpa, lit);
                break;
            }
            try self.reportCodeAt(next.span.start, next.line, 1005, "'}' expected.");
            const empty_id = self.interner.intern("") catch return error.OutOfMemory;
            const empty_lit = try self.builder.addLiteralString(.{ .start = next.span.start, .end = next.span.start }, empty_id);
            try text_parts.append(self.gpa, empty_lit);
            break;
        }

        const sp: Span = .{
            .start = head.span.start,
            .end = if (self.cursor > 0) self.tokens[self.cursor - 1].span.end else head.span.end,
        };
        return try self.builder.addTemplateLiteralType(sp, text_parts.items, type_parts.items);
    }

    fn parseTupleType(self: *Parser) ParseError!NodeId {
        const open = try self.expect(.open_bracket, "'[' to start tuple type");
        self.tuple_type_depth += 1;
        defer self.tuple_type_depth -= 1;
        var elems: std.ArrayListUnmanaged(NodeId) = .empty;
        defer elems.deinit(self.gpa);
        var saw_optional = false;
        var saw_definite_rest = false;
        var reported_tuple_order_error = false;
        while (self.peek().kind != .close_bracket and self.peek().kind != .eof) {
            // Accept (and ignore for now) leading labelled tuple
            // elements: `[x: number, y?: number]`.
            var labeled_optional = false;
            var saw_label_before_type = false;
            if (self.peek().kind == .identifier and
                (self.peekAt(1).kind == .colon or
                    (self.peekAt(1).kind == .question and self.peekAt(2).kind == .colon)))
            {
                saw_label_before_type = true;
                _ = self.advance();
                if (self.match(.question)) labeled_optional = true;
                _ = self.advance();
            }
            // Rest element prefix `...T` (TS 4.0+ variadic tuples).
            // The operand is wrapped in a `rest_type` HIR node so the
            // lowerer / checker can model spread expansion.
            const rest_tok = self.peek();
            const has_rest = self.match(.dot_dot_dot);
            const rest_type_after_label = saw_label_before_type and has_rest;
            var rest_label_optional = false;
            var saw_label_after_rest = false;
            // Tolerate a labeled rest: `[...rest: T[]]` and recover
            // optional rest labels so TS5085 can be reported at the
            // same tuple member rather than cascading into `] expected`.
            if (has_rest and self.peek().kind == .identifier) {
                if (self.peekAt(1).kind == .colon or
                    (self.peekAt(1).kind == .question and self.peekAt(2).kind == .colon))
                {
                    saw_label_after_rest = true;
                    _ = self.advance();
                    if (self.match(.question)) rest_label_optional = true;
                    _ = self.advance();
                }
            }
            const elem_start = self.peek().span.start;
            const elem_line = self.peek().line;
            // Elided tuple element (`[number,,]`) — upstream rejects
            // these with TS1110 "Type expected." at the comma/close
            // position. Detect before parseTypeAnnotation consumes the
            // delimiter and synthesises a recovery `unknown` type ref,
            // which would otherwise hide the diagnostic. Mirrors
            // `TupleType6.ts(1,16)` baseline.
            if (self.peek().kind == .comma or self.peek().kind == .close_bracket) {
                try self.reportCodeAt(elem_start, elem_line, 1110, "Type expected.");
                const id = self.interner.intern("unknown") catch return error.OutOfMemory;
                const synth = try self.builder.addTypeRef(.{ .start = elem_start, .end = elem_start }, id, &.{}, &.{});
                try elems.append(self.gpa, synth);
                if (!self.match(.comma)) break;
                continue;
            }
            var e = try self.parseTypeAnnotation();
            const trailing_optional = self.match(.question); // optional element marker
            if (has_rest and trailing_optional) {
                const elem_span = self.hir.spanOf(e);
                const base_text = self.source[elem_span.start..elem_span.end];
                const suggestion = if (rest_type_after_label)
                    base_text
                else
                    try std.fmt.allocPrint(self.diag_arena.allocator(), "{s} | undefined", .{base_text});
                const msg = try std.fmt.allocPrint(
                    self.diag_arena.allocator(),
                    "'?' at the end of a type is not valid TypeScript syntax. Did you mean to write '{s}'?",
                    .{suggestion},
                );
                try self.reportCodeAt(elem_span.start, self.lineAt(elem_span.start), 17019, msg);
            }
            const this_optional = labeled_optional or rest_label_optional or trailing_optional;
            if (rest_label_optional) {
                try self.reportCodeAt(rest_tok.span.start, rest_tok.line, 5085, "A tuple member cannot be both optional and rest.");
            }
            if (rest_type_after_label) {
                try self.reportCodeAt(rest_tok.span.start, rest_tok.line, 5087, "A labeled tuple element is declared as rest with a '...' before the name, rather than before the type.");
            } else if ((saw_label_before_type or saw_label_after_rest) and trailing_optional) {
                try self.reportCodeAt(elem_start, elem_line, 5086, "A labeled tuple element is declared as optional with a question mark after the name and before the colon, rather than after the type.");
            }
            const is_definite_rest = has_rest and self.tupleRestOperandIsDefiniteArray(e);
            if (!reported_tuple_order_error and has_rest) {
                if (saw_definite_rest and is_definite_rest) {
                    reported_tuple_order_error = true;
                    try self.reportCodeAt(rest_tok.span.start, rest_tok.line, 1265, "A rest element cannot follow another rest element.");
                }
                if (is_definite_rest) saw_definite_rest = true;
            } else if (!reported_tuple_order_error and this_optional and saw_definite_rest) {
                reported_tuple_order_error = true;
                try self.reportCodeAt(elem_start, elem_line, 1266, "An optional element cannot follow a rest element.");
            }
            // TS1257 — a required tuple element cannot follow an
            // optional one. Mirrors `optionalTupleElements1.ts(11,29)`.
            if (!reported_tuple_order_error and saw_optional and !this_optional and !has_rest) {
                reported_tuple_order_error = true;
                try self.reportCodeAt(elem_start, elem_line, 1257, "A required element cannot follow an optional element.");
            }
            if (this_optional) saw_optional = true;
            if (this_optional) {
                const end = if (self.cursor > 0) self.tokens[self.cursor - 1].span.end else elem_start;
                e = try self.builder.addOptionalType(.{ .start = elem_start, .end = end }, e);
            }
            if (has_rest) {
                const end = if (self.cursor > 0) self.tokens[self.cursor - 1].span.end else rest_tok.span.end;
                e = try self.builder.addRestType(.{ .start = rest_tok.span.start, .end = end }, e);
            }
            try elems.append(self.gpa, e);
            if (!self.match(.comma)) break;
        }
        const end_pos = if (self.peek().kind == .close_bracket) blk: {
            const close = self.advance();
            break :blk close.span.end;
        } else blk: {
            const pos = self.peek().span.start;
            try self.reportCodeAtWithMatchedPair(
                pos,
                self.peek().line,
                1005,
                "']' expected.",
                open.span.start,
                "[",
                "]",
            );
            break :blk pos;
        };
        return try self.builder.addTupleType(.{ .start = open.span.start, .end = end_pos }, elems.items);
    }

    fn tupleRestOperandIsDefiniteArray(self: *Parser, node: NodeId) bool {
        return switch (self.hir.kindOf(node)) {
            .array_type => true,
            .type_ref => blk: {
                const r = hir_mod.typeRefOf(self.hir, node);
                if (r.qualifier_len != 0) break :blk false;
                const name = self.interner.get(r.name);
                break :blk std.mem.eql(u8, name, "Array") or std.mem.eql(u8, name, "ReadonlyArray");
            },
            else => false,
        };
    }

    /// `{ ...members... }` — object type literal. Phase 6 lowers to
    /// a real `object_type` HIR node carrying member info (name,
    /// type, optional/readonly/method flags). Mapped types
    /// (`{ [K in T]: V }`) are still parsed via the dedicated path.
    fn parseObjectOrMappedType(self: *Parser) ParseError!NodeId {
        const open = try self.expect(.open_brace, "'{' to start object type");
        // Detect mapped type. The leading shape is one of:
        //   { [K in T]: V }
        //   { readonly [K in T]: V }
        //   { -readonly [K in T]: V }
        //   { +readonly [K in T]: V }
        // We also need to look two tokens ahead for `-readonly` /
        // `+readonly` because the modifier prefixes the bracket.
        var readonly_mod: u8 = 0;
        var lead_consumed: usize = 0;
        if (self.peek().kind == .kw_readonly and self.peekAt(1).kind == .open_bracket) {
            readonly_mod = 1;
            lead_consumed = 1;
        } else if (self.peek().kind == .minus and self.peekAt(1).kind == .kw_readonly and self.peekAt(2).kind == .open_bracket) {
            readonly_mod = 2;
            lead_consumed = 2;
        } else if (self.peek().kind == .plus and self.peekAt(1).kind == .kw_readonly and self.peekAt(2).kind == .open_bracket) {
            readonly_mod = 1;
            lead_consumed = 2;
        }
        var bracket_idx: usize = 0;
        if (lead_consumed > 0) bracket_idx = lead_consumed;
        const at_bracket = self.peek().kind == .open_bracket or
            (lead_consumed > 0 and self.peekAt(@intCast(bracket_idx)).kind == .open_bracket);
        const has_in = if (lead_consumed > 0)
            self.peekAt(@intCast(bracket_idx + 2)).kind == .kw_in
        else
            self.peekAt(2).kind == .kw_in;
        if (at_bracket and has_in) {
            // Consume any leading readonly modifier tokens.
            var c: usize = 0;
            while (c < lead_consumed) : (c += 1) _ = self.advance();
            const mapped_key_open = self.advance(); // `[`
            const k_tok = try self.expect(.identifier, "key in mapped type");
            const k_id = try self.internToken(k_tok);
            _ = try self.expect(.kw_in, "'in' in mapped type");
            const constraint = try self.parseTypeAnnotation();
            // Optional `as Type` key-remapping clause (TS 4.1+):
            //   `{ [K in keyof T as Exclude<K, "private">]: T[K] }`
            // The `as` sits between the constraint and the closing
            // bracket. Its type is evaluated per-key during checking;
            // keys whose remap reduces to `never` are dropped.
            var remap: NodeId = hir_mod.none_node_id;
            if (self.peek().kind == .kw_as) {
                _ = self.advance();
                remap = try self.parseTypeAnnotation();
            }
            _ = try self.expectClosingMatch(.close_bracket, "']' to close mapped type key", mapped_key_open.span.start, "[", "]");
            // Optional `?` / `+?` / `-?` modifier
            var optional_mod: u8 = 0;
            if (self.match(.minus)) {
                _ = try self.expect(.question, "'?' after '-' in mapped type");
                optional_mod = 2;
            } else if (self.match(.plus)) {
                _ = try self.expect(.question, "'?' after '+' in mapped type");
                optional_mod = 1;
            } else if (self.match(.question)) {
                optional_mod = 1;
            }
            // The template type is optional: `{ [P in T] }` is valid and
            // means the template is implicitly `any` (tsc reports TS7039
            // under `noImplicitAny`). Only parse a value when the `:` is
            // present; otherwise leave `value` as `none`.
            const value: NodeId = if (self.match(.colon))
                try self.parseTypeAnnotation()
            else
                hir_mod.none_node_id;
            _ = self.match(.semicolon);
            _ = self.match(.comma);
            // TS7061 — `A mapped type may not declare properties or
            // methods.` A mapped type body is `{ [K in T]: V }` only;
            // any additional declared member is illegal. tsc parses the
            // stray members anyway then grammar-checks the FIRST one. We
            // recover by draining the trailing member list (so the closing
            // `}` still matches and no cascading "'}' expected" fires) and
            // anchoring TS7061 at the first stray member. Mirrors
            // `checkGrammarMappedType`.
            if (self.peek().kind != .close_brace and self.peek().kind != .eof) {
                const stray = self.peek();
                try self.reportCodeAt(stray.span.start, stray.line, 7061, "A mapped type may not declare properties or methods.");
                var stray_members: std.ArrayListUnmanaged(NodeId) = .empty;
                defer stray_members.deinit(self.gpa);
                try self.parseTypeMemberList(&stray_members);
            }
            const close = try self.expectClosingMatch(.close_brace, "'}' to close mapped type", open.span.start, "{", "}");
            const tp = try self.builder.addTypeParameter(tokenSpan(k_tok), k_id, hir_mod.none_node_id, hir_mod.none_node_id, 0, false);
            return try self.builder.addMappedType(.{ .start = open.span.start, .end = close.span.end }, tp, constraint, value, remap, readonly_mod, optional_mod);
        }
        var members: std.ArrayListUnmanaged(NodeId) = .empty;
        defer members.deinit(self.gpa);
        try self.parseTypeMemberList(&members);
        const close = try self.expectClosingMatch(.close_brace, "'}' to close object type", open.span.start, "{", "}");
        return try self.builder.addObjectType(
            .{ .start = open.span.start, .end = close.span.end },
            members.items,
        );
    }

    /// Parse a sequence of TypeScript "type member" declarations
    /// inside `{ … }`. Members are separated by `;`, `,`, or
    /// newline. Each member is one of:
    ///
    ///   `name: T;`        — property
    ///   `name?: T;`       — optional property
    ///   `readonly name: T;` — readonly property
    ///   `name(p: P): R;`  — method-shorthand (lowers to fn_type)
    ///   `[k: string]: V;` — index signature (Phase 6 follow-up)
    ///   `(p): R;`         — call signature (Phase 6 follow-up)
    ///
    /// Index/call/construct signatures are skipped for now —
    /// tracked as Phase 6 follow-ups so the harness can keep
    /// progressing.
    fn parseTypeMemberList(self: *Parser, out: *std.ArrayListUnmanaged(NodeId)) ParseError!void {
        const MethodOptionality = struct {
            optional: bool,
            span: Span,
        };
        const AccessorPair = struct {
            getter: ?Span = null,
            setter: ?Span = null,
        };
        var seen = std.AutoHashMapUnmanaged(hir_mod.StringId, Span){};
        defer seen.deinit(self.gpa);
        var method_optionality = std.AutoHashMapUnmanaged(hir_mod.StringId, MethodOptionality){};
        defer method_optionality.deinit(self.gpa);
        var accessor_pairs = std.AutoHashMapUnmanaged(hir_mod.StringId, AccessorPair){};
        defer accessor_pairs.deinit(self.gpa);
        while (self.peek().kind != .close_brace and self.peek().kind != .eof) {
            const t = self.peek();
            // With no trivia between the tokens, `private[k: K]: V` in a
            // type literal is recovered as an index signature by tsc rather
            // than as an accessibility modifier on a type member.
            if (t.kind == .kw_private and
                self.peekAt(1).kind == .open_bracket and
                t.span.end == self.peekAt(1).span.start)
            {
                const checkpoint = self.cursor;
                _ = self.advance();
                if (try self.tryParseIndexSignature(out, false, false)) continue;
                self.cursor = checkpoint;
            }
            // `static` is illegal on an index signature inside an interface
            // or type literal — tsc emits TS1071 anchored at the `static`
            // keyword (matches `staticIndexSignature4`/`staticIndexSignature5`
            // baselines). Skip the keyword so the index-signature parser
            // takes over the following `[k: K]: V` (or `readonly [k: K]: V`).
            if (t.kind == .kw_static and
                (self.peekAt(1).kind == .open_bracket or
                    (self.peekAt(1).kind == .kw_readonly and self.peekAt(2).kind == .open_bracket)))
            {
                _ = self.advance(); // consume `static`
                try self.reportCodeAt(t.span.start, t.line, 1071, "'static' modifier cannot appear on an index signature.");
                continue;
            }
            // Index signature: `[k: K]: V` or `readonly [k: K]: V`.
            // Detect via `[ ident : ident ]` shape, then commit.
            if (t.kind == .open_bracket or
                (t.kind == .kw_readonly and self.peekAt(1).kind == .open_bracket))
            {
                if (try self.tryParseIndexSignature(out, false, false)) continue;
                if (try self.tryParseComputedTypeMember(out, false)) continue;
                // Not an index signature or supported computed key.
                try self.reportMalformedTypeMemberBracket(t);
                try self.skipUntilTypeMemberSeparator();
                continue;
            }
            // Call signature: `{ <T>(x: T): T }` or `{ (x: T): T }`.
            if (t.kind == .less_than or t.kind == .open_paren) {
                if (self.parseTypeSignatureMember(false)) |sig| {
                    try out.append(self.gpa, sig);
                } else |err| switch (err) {
                    // Malformed call signature (e.g. `<T>;` with no
                    // parameter list). Skip past the separator so the
                    // rest of the object-type body can still parse —
                    // without this catch the error propagates up and
                    // discards every member parsed so far. Mirrors the
                    // recovery shape in the bracketed path above.
                    error.UnexpectedToken => try self.skipUntilTypeMemberSeparator(),
                    else => return err,
                }
                continue;
            }
            // Construct signature: `{ new<T>(x: T): T }`.
            if (t.kind == .kw_new and self.isConstructSignatureStart()) {
                const sig = try self.parseTypeSignatureMember(true);
                try out.append(self.gpa, sig);
                continue;
            }
            // Accessor signatures in interfaces/type literals:
            // `get foo(): T` and `set foo(value: T)`.
            if ((t.kind == .kw_get or t.kind == .kw_set) and self.isTypeAccessorSignatureStart()) {
                const accessor_tok = self.advance();
                const is_getter = accessor_tok.kind == .kw_get;
                const name_tok = self.advance();
                const name_span = tokenSpan(name_tok);
                const name_id = try self.internPropertyName(name_tok, name_span);
                const params = try self.parseTypeParameterList();
                defer self.gpa.free(params);
                var type_node: NodeId = hir_mod.none_node_id;
                if (is_getter) {
                    if (self.match(.colon)) type_node = try self.parseReturnTypeAnnotation(params);
                } else if (params.len > 0 and self.hir.kindOf(params[0]) == .parameter) {
                    const p = hir_mod.parameterOf(self.hir, params[0]);
                    type_node = p.type_annotation;
                }
                if (!is_getter and self.match(.colon)) {
                    _ = try self.parseReturnTypeAnnotation(params);
                }
                if (self.peek().kind == .semicolon or self.peek().kind == .comma) {
                    _ = self.advance();
                } else if (self.peek().kind != .close_brace and self.peek().kind != .eof) {
                    const prev_tok = self.tokens[self.cursor - 1];
                    const next_tok = self.peek();
                    if (prev_tok.line == next_tok.line) {
                        try self.reportCodeAt(next_tok.span.start, next_tok.line, 1005, "';' expected.");
                    }
                }
                const member = try self.builder.addInterfaceMember(
                    .{ .start = accessor_tok.span.start, .end = self.tokens[self.cursor - 1].span.end },
                    name_id,
                    type_node,
                    false,
                    is_getter,
                    false,
                    false,
                );
                var pair = accessor_pairs.get(name_id) orelse AccessorPair{};
                if (is_getter) {
                    if (pair.getter) |prev| {
                        try self.reportDuplicateIdentifierNamed(prev.start, self.lineAt(prev.start), name_id);
                        try self.reportDuplicateIdentifierNamed(name_span.start, name_tok.line, name_id);
                    }
                    pair.getter = name_span;
                } else {
                    if (pair.setter) |prev| {
                        try self.reportDuplicateIdentifierNamed(prev.start, self.lineAt(prev.start), name_id);
                        try self.reportDuplicateIdentifierNamed(name_span.start, name_tok.line, name_id);
                    }
                    pair.setter = name_span;
                }
                try accessor_pairs.put(self.gpa, name_id, pair);
                try out.append(self.gpa, member);
                continue;
            }
            // Accessibility/visibility modifiers (`public`, `private`,
            // `protected`) and `abstract` are not allowed on type members.
            // tsc emits TS1070 anchored at the modifier keyword, then
            // continues parsing the (otherwise-valid) member that follows.
            // Matches `parserModifierOnPropertySignature1` and similar
            // baselines.
            if (t.kind == .kw_public or t.kind == .kw_private or
                t.kind == .kw_protected or t.kind == .kw_abstract)
            {
                const next_tok = self.peekAt(1);
                const next_kind = next_tok.kind;
                // Suppress TS1070 when the modifier sits on its own line —
                // ASI lets tsc treat the keyword as the property name and
                // the next identifier as a separate member. Matches
                // `parserModifierOnPropertySignature2` (no diagnostic).
                if (next_tok.line == t.line and
                    next_kind != .colon and next_kind != .question and
                    next_kind != .semicolon and next_kind != .comma and
                    next_kind != .close_brace and next_kind != .eof and
                    next_kind != .open_paren and next_kind != .less_than)
                {
                    const raw_text = if (t.span.end > t.span.start and
                        t.span.end <= self.source.len)
                        self.source[t.span.start..t.span.end]
                    else
                        "modifier";
                    const msg = std.fmt.allocPrint(
                        self.diag_arena.allocator(),
                        "'{s}' modifier cannot appear on a type member.",
                        .{raw_text},
                    ) catch return error.OutOfMemory;
                    try self.diagnostics.append(self.gpa, .{
                        .pos = t.span.start,
                        .line = t.line,
                        .code = 1070,
                        .message = msg,
                    });
                    _ = self.advance(); // consume the modifier and fall through
                }
            }
            // TS1131: a statement-introducing keyword followed by an
            // identifier (e.g. `var x: T;` inside an interface body) is
            // a misplaced declaration, not a property whose name happens
            // to be the keyword. tsc emits TS1131
            // "Property or signature expected." anchored at the keyword
            // with a span covering the keyword itself. Mirrors
            // `instantiateTypeParameter.ts(2,5)`. We DON'T fire when the
            // next token is `:` / `?` / `(` / `<` / `;` / `,` / `}` —
            // those are legal continuations for a property whose name
            // is the contextual keyword (`interface I { var: T; }` is
            // valid, `interface I { var x: T; }` is not).
            const peek_now = self.peek();
            const looks_like_statement_keyword =
                peek_now.kind == .kw_var or peek_now.kind == .kw_let or
                peek_now.kind == .kw_const or peek_now.kind == .kw_function or
                peek_now.kind == .kw_class or peek_now.kind == .kw_enum or
                peek_now.kind == .kw_import or peek_now.kind == .kw_export or
                peek_now.kind == .kw_interface or peek_now.kind == .kw_if or
                peek_now.kind == .kw_while or peek_now.kind == .kw_for or
                peek_now.kind == .kw_do or peek_now.kind == .kw_switch or
                peek_now.kind == .kw_try or peek_now.kind == .kw_return or
                peek_now.kind == .kw_throw;
            if (looks_like_statement_keyword) {
                const next = self.peekAt(1).kind;
                const is_property_continuation = next == .colon or next == .question or
                    next == .open_paren or next == .less_than or
                    next == .semicolon or next == .comma or
                    next == .close_brace;
                if (!is_property_continuation) {
                    try self.reportCodeAtWithSpan(
                        peek_now.span.start,
                        peek_now.line,
                        peek_now.span.end - peek_now.span.start,
                        1131,
                        "Property or signature expected.",
                    );
                    _ = self.advance(); // consume the offending keyword so recovery proceeds
                }
            }
            var is_readonly = false;
            var is_override = false;
            if (t.kind == .kw_readonly and self.peekAt(1).kind != .colon) {
                _ = self.advance();
                is_readonly = true;
            }
            if (self.peek().kind == .kw_override and self.peekAt(1).kind != .colon) {
                // `override` is not a valid modifier on interface / type
                // members. tsc reports TS1070 anchored at the keyword.
                // Matches override9.ts baseline.
                const ov_tok = self.peek();
                try self.diagnostics.append(self.gpa, .{
                    .pos = ov_tok.span.start,
                    .line = ov_tok.line,
                    .code = 1070,
                    .message = try self.diag_arena.allocator().dupe(u8, "'override' modifier cannot appear on a type member."),
                });
                _ = self.advance();
                is_override = true;
            }
            const name_tok = self.advance();
            var name_span = tokenSpan(name_tok);
            if (name_tok.kind == .number_literal and self.peek().kind == .dot and self.peekAt(1).kind == .colon) {
                const dot_tok = self.advance();
                name_span.end = dot_tok.span.end;
            }
            // TS18016 — ECMAScript private names are not allowed
            // outside class bodies. Type literals / interfaces are
            // outside class bodies so `{ #foo: string }` and
            // `interface I { #foo: T }` are invalid. Mirrors
            // upstream `privateNameAndPropertySignature` /
            // `privateNameInObjectLiteral-3` baselines.
            if (name_tok.kind == .private_identifier) {
                try self.reportCodeAt(name_tok.span.start, name_tok.line, 18016, "Private identifiers are not allowed outside class bodies.");
            }
            // Allow string-literal property names: `"foo": T`.
            const name_id = try self.internPropertyName(name_tok, name_span);
            const is_optional = self.match(.question);

            // Method shorthand: `name<T>(p: T): R` / `name(p: T): R`.
            if (self.peek().kind == .less_than or self.peek().kind == .open_paren) {
                var type_params: []NodeId = &.{};
                var owns_tps = false;
                if (self.peek().kind == .less_than) {
                    type_params = try self.parseTypeParameterDeclaration();
                    owns_tps = true;
                }
                defer if (owns_tps) self.gpa.free(type_params);
                const params = try self.parseTypeParameterList();
                defer self.gpa.free(params);
                var ret: NodeId = hir_mod.none_node_id;
                if (self.peek().kind == .question) {
                    const question_tok = self.advance();
                    try self.reportCodeAt(question_tok.span.start, question_tok.line, 1005, "';' expected.");
                    if (self.peek().kind == .colon) {
                        const colon_tok = self.advance();
                        try self.reportCodeAt(colon_tok.span.start, colon_tok.line, 1131, "Property or signature expected.");
                        _ = self.parseTypeAnnotation() catch {};
                    }
                    _ = self.match(.semicolon);
                    _ = self.match(.comma);
                    const fn_t = try self.builder.addFnType(
                        .{ .start = name_span.start, .end = self.tokens[self.cursor - 1].span.end },
                        type_params,
                        params,
                        ret,
                        false,
                        false,
                    );
                    const member = try self.builder.addInterfaceMember(
                        name_span,
                        name_id,
                        fn_t,
                        is_optional,
                        is_readonly,
                        true,
                        is_override,
                    );
                    try out.append(self.gpa, member);
                    continue;
                }
                if (self.match(.colon)) ret = try self.parseReturnTypeAnnotation(params);
                const fn_t = try self.builder.addFnType(
                    .{ .start = name_span.start, .end = self.tokens[self.cursor - 1].span.end },
                    type_params,
                    params,
                    ret,
                    false,
                    false,
                );
                _ = self.match(.semicolon);
                _ = self.match(.comma);
                const member = try self.builder.addInterfaceMember(
                    name_span,
                    name_id,
                    fn_t,
                    is_optional,
                    is_readonly,
                    true,
                    is_override,
                );
                if (method_optionality.get(name_id)) |prev| {
                    if (prev.optional != is_optional) {
                        // tsc anchors TS2386 at the mismatched (current)
                        // overload's name token, not the first one — its
                        // baseline renderer puts `~~~~~` under the second
                        // signature. Mirror that so single-error fixtures
                        // like `methodSignaturesWithOverloads` line up.
                        try self.reportCodeAt(name_span.start, name_tok.line, 2386, "Overload signatures must all be optional or required.");
                    }
                } else {
                    try method_optionality.put(self.gpa, name_id, .{
                        .optional = is_optional,
                        .span = name_span,
                    });
                }
                try out.append(self.gpa, member);
                continue;
            }

            // Property: `name: T;`.
            var type_node: NodeId = hir_mod.none_node_id;
            if (self.match(.colon)) type_node = try self.parseTypeAnnotation();
            // TS1246/TS1247: a property in an interface body / type
            // literal cannot carry an initializer (`bar: number = 5;`).
            // tsc anchors at the initializer value (the token after `=`)
            // — TS1246 inside `interface { … }`, TS1247 inside a type
            // literal. Mirrors `errorOnInitializerInInterfaceProperty.ts(2,19)`
            // and `errorOnInitializerInObjectTypeLiteralProperty.ts(2,19)`.
            // We detect the `=`, anchor on the next token, consume
            // the initializer expression, and continue so cascading
            // TS1005 stays suppressed.
            if (self.peek().kind == .equal) {
                _ = self.advance(); // consume `=`
                const init_tok = self.peek();
                if (self.parsing_interface_body) {
                    try self.reportCodeAt(init_tok.span.start, init_tok.line, 1246, "An interface property cannot have an initializer.");
                } else {
                    try self.reportCodeAt(init_tok.span.start, init_tok.line, 1247, "A type literal property cannot have an initializer.");
                }
                _ = self.parseAssignmentExpression() catch {};
            }
            if (self.peek().kind == .semicolon or self.peek().kind == .comma) {
                _ = self.advance();
            } else if (self.peek().kind != .close_brace and self.peek().kind != .eof) {
                const prev_tok = self.tokens[self.cursor - 1];
                const next_tok = self.peek();
                if (prev_tok.line == next_tok.line) {
                    try self.reportCodeAt(next_tok.span.start, next_tok.line, 1005, "';' expected.");
                }
            }
            const member = try self.builder.addInterfaceMember(
                name_span,
                name_id,
                type_node,
                is_optional,
                is_readonly,
                false,
                is_override,
            );
            if (seen.get(name_id)) |prev| {
                try self.reportDuplicateIdentifierNamed(prev.start, self.lineAt(prev.start), name_id);
                try self.reportDuplicateIdentifierNamed(name_span.start, self.lineAt(name_span.start), name_id);
            } else {
                try seen.put(self.gpa, name_id, name_span);
            }
            try out.append(self.gpa, member);
        }
    }

    fn parseTypeSignatureMember(self: *Parser, is_constructor: bool) ParseError!NodeId {
        const start = self.peek();
        if (is_constructor) _ = try self.expect(.kw_new, "'new' in construct signature");
        var type_params: []NodeId = &.{};
        var owns_tps = false;
        if (self.peek().kind == .less_than) {
            type_params = try self.parseTypeParameterDeclaration();
            owns_tps = true;
        }
        defer if (owns_tps) self.gpa.free(type_params);
        const params = try self.parseTypeParameterList();
        defer self.gpa.free(params);
        var ret: NodeId = hir_mod.none_node_id;
        if (self.match(.colon)) ret = try self.parseReturnTypeAnnotation(params);
        const end_pos = if (self.cursor > 0) self.tokens[self.cursor - 1].span.end else start.span.end;
        const fn_t = try self.builder.addFnType(
            .{ .start = start.span.start, .end = end_pos },
            type_params,
            params,
            ret,
            is_constructor,
            false,
        );
        _ = self.match(.semicolon);
        _ = self.match(.comma);
        const synthetic_name = if (is_constructor) "__construct" else "__call";
        const name_id = self.interner.intern(synthetic_name) catch return error.OutOfMemory;
        return try self.builder.addInterfaceMember(
            .{ .start = start.span.start, .end = end_pos },
            name_id,
            fn_t,
            false,
            false,
            true,
            false,
        );
    }

    fn isConstructSignatureStart(self: *const Parser) bool {
        return self.peekAt(1).kind == .open_paren or self.peekAt(1).kind == .less_than;
    }

    fn isTypeAccessorSignatureStart(self: *const Parser) bool {
        const name_kind = self.peekAt(1).kind;
        return (name_kind == .identifier or
            name_kind == .string_literal or
            name_kind == .number_literal or
            name_kind.isContextualKeyword()) and
            self.peekAt(2).kind == .open_paren;
    }

    fn reportMalformedTypeMemberBracket(self: *Parser, start: Token) ParseError!void {
        var idx = self.cursor + 1;
        var count: u32 = 0;
        var rest_tok: ?Token = null;
        var accessibility_tok: ?Token = null;
        var question_tok: ?Token = null;
        var comma_tok: ?Token = null;
        var first_ident_tok: ?Token = null;
        var saw_equal = false;
        while (idx < self.tokens.len and
            self.tokens[idx].kind != .close_bracket and
            self.tokens[idx].kind != .close_brace and
            self.tokens[idx].kind != .eof)
        {
            const tok = self.tokens[idx];
            const k = tok.kind;
            if (k == .dot_dot_dot) rest_tok = tok;
            if (isAccessibilityModifier(k)) accessibility_tok = tok;
            if (k == .question) question_tok = tok;
            if (k == .comma) comma_tok = tok;
            if (k == .equal) saw_equal = true;
            if (k == .identifier or k.isContextualKeyword()) {
                if (first_ident_tok == null) first_ident_tok = tok;
                count += 1;
            }
            idx += 1;
        }
        if (rest_tok) |tok| {
            try self.reportCodeAt(tok.span.start, tok.line, 1017, "An index signature cannot have a rest parameter.");
        } else if (accessibility_tok) |tok| {
            try self.reportCodeAt(tok.span.start, tok.line, 2369, "A parameter property is only allowed in a constructor implementation.");
            const anchor = first_ident_tok orelse tok;
            try self.reportCodeAt(anchor.span.start, anchor.line, 1018, "An index signature parameter cannot have an accessibility modifier.");
        } else if (question_tok) |tok| {
            try self.reportCodeAt(tok.span.start, tok.line, 1019, "An index signature parameter cannot have a question mark.");
        } else if (comma_tok) |tok| {
            const anchor = first_ident_tok orelse tok;
            try self.reportCodeAt(anchor.span.start, anchor.line, 1096, "An index signature must have exactly one parameter.");
        } else if (count == 0) {
            try self.reportCodeAt(start.span.start, start.line, 1096, "An index signature must have exactly one parameter.");
        } else if (saw_equal) {
            try self.reportCodeAt(start.span.start, start.line, 1169, "A computed property name in an interface must refer to an expression whose type is a literal type or a 'unique symbol' type.");
            if (first_ident_tok) |ident_tok| try self.reportCannotFindNameToken(ident_tok);
        } else {
            try self.reportCodeAt(start.span.start, start.line, 1169, "A computed property name in an interface must refer to an expression whose type is a literal type or a 'unique symbol' type.");
        }
    }

    fn tryParseComputedTypeMember(self: *Parser, out: *std.ArrayListUnmanaged(NodeId), is_readonly: bool) ParseError!bool {
        const checkpoint = self.cursor;
        const start_tok = self.peek();
        if (self.peek().kind != .open_bracket) return false;
        if (self.computedTypeMemberLooksMalformedIndexSignature()) return false;
        _ = self.advance();
        const key_expr = self.parseExpression() catch {
            self.cursor = checkpoint;
            return false;
        };
        if (self.peek().kind != .close_bracket) {
            self.cursor = checkpoint;
            return false;
        }
        const close_tok = self.advance();
        const name_id = (try self.computedTypeMemberNameFromKey(key_expr)) orelse blk: {
            if (self.computedTypeMemberUnresolvedQualifiedRoot(key_expr)) |root| {
                try self.reportCannotFindNameNode(root, start_tok.line);
                break :blk @as(hir_mod.StringId, 0);
            }
            if (self.hir.kindOf(key_expr) != .identifier) {
                // A computed type-member key whose expression isn't a
                // literal-resolvable name (binary_op, call_expr, etc.)
                // still needs to be reported as a computed-property-
                // name violation, not a malformed index signature.
                // tsc emits TS1169 for interfaces and TS1170 for type
                // literals. Mirrors
                // `computedPropertyNamesDeclarationEmit3_ES{5,6}` for
                // `["" + ""](): void` inside `interface I` and DE4 for
                // the same shape inside `var v: { ... }`.
                if (self.parsing_interface_body) {
                    try self.reportCodeAt(start_tok.span.start, start_tok.line, 1169, "A computed property name in an interface must refer to an expression whose type is a literal type or a 'unique symbol' type.");
                } else {
                    try self.reportCodeAt(start_tok.span.start, start_tok.line, 1170, "A computed property name in a type literal must refer to an expression whose type is a literal type or a 'unique symbol' type.");
                }
                break :blk @as(hir_mod.StringId, 0);
            }
            if (!self.computedTypeMemberIdentifierIsDeclaredValue(key_expr)) {
                try self.reportCannotFindNameNode(key_expr, start_tok.line);
            }
            break :blk @as(hir_mod.StringId, 0);
        };
        if (self.computedSymbolMemberIsNonPropertySymbol(key_expr)) {
            try self.reportCodeAt(start_tok.span.start, start_tok.line, 2464, "A computed property name must be of type 'string', 'number', 'symbol', or 'any'.");
        }
        const is_optional = self.match(.question);
        const member_span: Span = .{ .start = start_tok.span.start, .end = close_tok.span.end };
        if (self.peek().kind == .less_than or self.peek().kind == .open_paren) {
            var type_params: []NodeId = &.{};
            var owns_tps = false;
            if (self.peek().kind == .less_than) {
                type_params = try self.parseTypeParameterDeclaration();
                owns_tps = true;
            }
            defer if (owns_tps) self.gpa.free(type_params);
            const params = try self.parseTypeParameterList();
            defer self.gpa.free(params);
            var ret: NodeId = hir_mod.none_node_id;
            if (self.match(.colon)) ret = try self.parseReturnTypeAnnotation(params);
            const fn_t = try self.builder.addFnType(
                .{ .start = member_span.start, .end = if (self.cursor > 0) self.tokens[self.cursor - 1].span.end else member_span.end },
                type_params,
                params,
                ret,
                false,
                false,
            );
            _ = self.match(.semicolon);
            _ = self.match(.comma);
            const member = try self.builder.addInterfaceMember(member_span, name_id, fn_t, is_optional, is_readonly, true, false);
            // Preserve the computed key expression on the cold
            // side-table so the checker can scan it for type-parameter
            // references (TS2467) without a full HIR-payload rewrite.
            // Mirrors `computedPropertyNames35_ES{5,6}`.
            try self.builder.setInterfaceMemberKeyExpr(member, key_expr);
            try out.append(self.gpa, member);
            return true;
        }
        var type_node: NodeId = hir_mod.none_node_id;
        if (self.match(.colon)) type_node = try self.parseTypeAnnotation();
        _ = self.match(.semicolon);
        _ = self.match(.comma);
        const member = try self.builder.addInterfaceMember(member_span, name_id, type_node, is_optional, is_readonly, false, false);
        try self.builder.setInterfaceMemberKeyExpr(member, key_expr);
        try out.append(self.gpa, member);
        return true;
    }

    fn reportCannotFindNameNode(self: *Parser, node: NodeId, line: u32) ParseError!void {
        if (self.hir.kindOf(node) != .identifier) return;
        const id = hir_mod.identifierOf(self.hir, node);
        const name_text = self.interner.get(id.name);
        const msg = try std.fmt.allocPrint(self.diag_arena.allocator(), "Cannot find name '{s}'.", .{name_text});
        const sp = self.hir.spanOf(node);
        try self.reportCodeAt(sp.start, line, 2304, msg);
    }

    fn reportCannotFindNameToken(self: *Parser, tok: Token) ParseError!void {
        const name_text = self.source[tok.span.start..tok.span.end];
        const msg = try std.fmt.allocPrint(self.diag_arena.allocator(), "Cannot find name '{s}'.", .{name_text});
        try self.reportCodeAt(tok.span.start, tok.line, 2304, msg);
    }

    fn computedTypeMemberLooksMalformedIndexSignature(self: *const Parser) bool {
        var idx = self.cursor + 1;
        var saw_content = false;
        while (idx < self.tokens.len and
            self.tokens[idx].kind != .close_bracket and
            self.tokens[idx].kind != .close_brace and
            self.tokens[idx].kind != .eof)
        {
            saw_content = true;
            switch (self.tokens[idx].kind) {
                .dot_dot_dot, .question, .comma, .equal => return true,
                else => {},
            }
            if (isAccessibilityModifier(self.tokens[idx].kind)) return true;
            idx += 1;
        }
        return !saw_content;
    }

    fn indexSignatureKeyTypeIsValid(self: *const Parser, key_type: NodeId) bool {
        switch (self.hir.kindOf(key_type)) {
            .type_ref => {
                const r = hir_mod.typeRefOf(self.hir, key_type);
                if (r.qualifier_len != 0 or r.args_len != 0) return false;
                const name = self.interner.get(r.name);
                if (std.mem.eql(u8, name, "string") or
                    std.mem.eql(u8, name, "number") or
                    std.mem.eql(u8, name, "symbol")) return true;
                if (std.mem.eql(u8, name, "boolean") or
                    std.mem.eql(u8, name, "bigint") or
                    std.mem.eql(u8, name, "object") or
                    std.mem.eql(u8, name, "any") or
                    std.mem.eql(u8, name, "unknown") or
                    std.mem.eql(u8, name, "never") or
                    std.mem.eql(u8, name, "void") or
                    std.mem.eql(u8, name, "null") or
                    std.mem.eql(u8, name, "undefined")) return false;
                // Defer semantic names (`T`, `Error`, aliases) to the checker:
                // type parameters become TS1337, ordinary object types become
                // TS1268, and branded string aliases are accepted.
                return true;
            },
            .template_literal_type => return true,
            // Unions/intersections of valid key types are themselves
            // valid index-key types (`[k: string | number]`,
            // `[k: `${string}x` & `${string}y`]`). tsc's grammar check
            // (`checkGrammarIndexSignature`) recurses into the
            // constituents and only reports TS1268 when one is invalid.
            // Empty member lists fall back to invalid.
            .union_type => {
                const members = hir_mod.unionTypeMembers(self.hir, key_type);
                if (members.len == 0) return false;
                for (members) |m| {
                    if (!self.indexSignatureKeyTypeIsValid(m)) return false;
                }
                return true;
            },
            .intersection_type => {
                const members = hir_mod.intersectionTypeMembers(self.hir, key_type);
                if (members.len == 0) return false;
                for (members) |m| {
                    if (!self.indexSignatureKeyTypeIsValid(m)) return false;
                }
                return true;
            },
            else => return false,
        }
    }

    fn computedTypeMemberNameFromKey(self: *Parser, key_expr: NodeId) ParseError!?hir_mod.StringId {
        return switch (self.hir.kindOf(key_expr)) {
            .literal_string => hir_mod.literalStringOf(self.hir, key_expr).value,
            .literal_number => blk: {
                const sp = self.hir.spanOf(key_expr);
                if (sp.end > self.source.len or sp.start >= sp.end) break :blk null;
                break :blk self.interner.intern(self.source[sp.start..sp.end]) catch return error.OutOfMemory;
            },
            .identifier => blk: {
                const id = hir_mod.identifierOf(self.hir, key_expr);
                const raw = self.interner.get(id.name);
                if (try self.sourceConstLiteralMemberName(raw)) |name| break :blk name;
                if (self.sourceHasUniqueSymbolConst(raw)) {
                    const synthetic = try std.fmt.allocPrint(self.gpa, "[computed:{s}]", .{raw});
                    defer self.gpa.free(synthetic);
                    break :blk self.interner.intern(synthetic) catch return error.OutOfMemory;
                }
                break :blk null;
            },
            .member_access => try self.symbolMemberNameFromComputedKey(key_expr),
            .as_expr, .satisfies_expr, .type_assertion => blk: {
                const assertion = hir_mod.asExpressionOf(self.hir, key_expr);
                if (try self.computedTypeMemberNameFromKey(assertion.expr)) |name| break :blk name;
                break :blk try self.literalTypeMemberName(assertion.type_node);
            },
            else => null,
        };
    }

    fn literalTypeMemberName(self: *Parser, type_node: NodeId) ParseError!?hir_mod.StringId {
        if (type_node == hir_mod.none_node_id or self.hir.kindOf(type_node) != .type_literal) return null;
        const lit_type = hir_mod.literalTypeOf(self.hir, type_node);
        return switch (self.hir.kindOf(lit_type.literal)) {
            .literal_string => hir_mod.literalStringOf(self.hir, lit_type.literal).value,
            .literal_number => blk: {
                const sp = self.hir.spanOf(type_node);
                if (sp.end > self.source.len or sp.start >= sp.end) break :blk null;
                break :blk self.interner.intern(self.source[sp.start..sp.end]) catch return error.OutOfMemory;
            },
            else => null,
        };
    }

    fn symbolMemberNameFromComputedKey(self: *Parser, key_expr: NodeId) ParseError!?hir_mod.StringId {
        if (self.hir.kindOf(key_expr) != .member_access) return null;
        const m = hir_mod.memberOf(self.hir, key_expr);
        if (self.hir.kindOf(m.object) != .identifier) return null;
        const obj = hir_mod.identifierOf(self.hir, m.object);
        if (!std.mem.eql(u8, self.interner.get(obj.name), "Symbol")) {
            const sp = self.hir.spanOf(key_expr);
            if (sp.end > self.source.len or sp.start >= sp.end) return null;
            const raw = std.mem.trim(u8, self.source[sp.start..sp.end], " \t\r\n");
            if (!self.sourceHasNamespaceUniqueSymbolConst(raw)) return null;
            const synthetic = try std.fmt.allocPrint(self.gpa, "[computed:{s}]", .{raw});
            defer self.gpa.free(synthetic);
            return self.interner.intern(synthetic) catch return error.OutOfMemory;
        }
        const prop = self.interner.get(m.name);
        const synthetic = try std.fmt.allocPrint(self.gpa, "Symbol.{s}", .{prop});
        defer self.gpa.free(synthetic);
        return self.interner.intern(synthetic) catch return error.OutOfMemory;
    }

    fn sourceConstLiteralMemberName(self: *Parser, name: []const u8) ParseError!?hir_mod.StringId {
        var search_start: usize = 0;
        while (std.mem.indexOfPos(u8, self.source, search_start, "const")) |const_pos| {
            search_start = const_pos + "const".len;
            if (const_pos > 0 and sourceIdentChar(self.source[const_pos - 1])) continue;
            if (search_start < self.source.len and sourceIdentChar(self.source[search_start])) continue;
            const after_const = std.mem.trim(u8, self.source[search_start..], " \t\r\n");
            if (!std.mem.startsWith(u8, after_const, name)) continue;
            if (after_const.len > name.len and sourceIdentChar(after_const[name.len])) continue;
            const line_end = std.mem.indexOfScalar(u8, after_const, '\n') orelse after_const.len;
            const line = after_const[0..line_end];
            const eq_pos = std.mem.indexOfScalar(u8, line, '=') orelse continue;
            const rhs = std.mem.trim(u8, line[eq_pos + 1 ..], " \t\r;");
            if (rhs.len == 0) continue;
            if (rhs[0] == '\'' or rhs[0] == '"' or rhs[0] == '`') {
                const quote = rhs[0];
                var end: usize = 1;
                while (end < rhs.len and rhs[end] != quote) : (end += 1) {}
                if (end <= 1 or end >= rhs.len) continue;
                return self.interner.intern(rhs[1..end]) catch return error.OutOfMemory;
            }
            if (std.mem.startsWith(u8, rhs, "Symbol.")) {
                var end: usize = "Symbol.".len;
                while (end < rhs.len and sourceIdentChar(rhs[end])) : (end += 1) {}
                const synthetic = try std.fmt.allocPrint(self.gpa, "Symbol.{s}", .{rhs["Symbol.".len..end]});
                defer self.gpa.free(synthetic);
                return self.interner.intern(synthetic) catch return error.OutOfMemory;
            }
            if (std.mem.startsWith(u8, rhs, "Symbol(")) {
                const synthetic = try std.fmt.allocPrint(self.gpa, "[computed:{s}]", .{name});
                defer self.gpa.free(synthetic);
                return self.interner.intern(synthetic) catch return error.OutOfMemory;
            }
            if (rhs[0] == '-' or (rhs[0] >= '0' and rhs[0] <= '9')) {
                var end: usize = if (rhs[0] == '-') 1 else 0;
                while (end < rhs.len and ((rhs[end] >= '0' and rhs[end] <= '9') or rhs[end] == '.')) : (end += 1) {}
                if (end > 0 and !(end == 1 and rhs[0] == '-')) {
                    return self.interner.intern(rhs[0..end]) catch return error.OutOfMemory;
                }
            }
        }
        return null;
    }

    fn sourceHasUniqueSymbolConst(self: *Parser, name: []const u8) bool {
        return sourceSliceHasUniqueSymbolConst(self.source, name);
    }

    fn sourceHasNamespaceUniqueSymbolConst(self: *Parser, name: []const u8) bool {
        const dot = std.mem.indexOfScalar(u8, name, '.') orelse return false;
        if (dot == 0 or dot + 1 >= name.len) return false;
        const namespace_name = name[0..dot];
        const member_name = name[dot + 1 ..];
        var search_start: usize = 0;
        while (sourceIndexOfNamespaceKeywordParser(self.source, search_start)) |kw| {
            search_start = kw.end;
            var p = kw.end;
            while (p < self.source.len and std.ascii.isWhitespace(self.source[p])) : (p += 1) {}
            if (p + namespace_name.len > self.source.len) continue;
            if (!std.mem.eql(u8, self.source[p .. p + namespace_name.len], namespace_name)) continue;
            const ns_end = p + namespace_name.len;
            if (ns_end < self.source.len and sourceIdentChar(self.source[ns_end])) continue;
            var open = ns_end;
            while (open < self.source.len and self.source[open] != '{') : (open += 1) {}
            if (open >= self.source.len) continue;
            const close = sourceMatchingBraceParser(self.source, open) orelse continue;
            if (sourceSliceHasUniqueSymbolConst(self.source[open + 1 .. close], member_name)) return true;
            search_start = close + 1;
        }
        return false;
    }

    fn sourceSliceHasUniqueSymbolConst(src: []const u8, name: []const u8) bool {
        var search_start: usize = 0;
        while (std.mem.indexOfPos(u8, src, search_start, "const")) |const_pos| {
            search_start = const_pos + "const".len;
            if (const_pos > 0 and sourceIdentChar(src[const_pos - 1])) continue;
            if (search_start < src.len and sourceIdentChar(src[search_start])) continue;
            const after_const = std.mem.trim(u8, src[search_start..], " \t\r\n");
            if (!std.mem.startsWith(u8, after_const, name)) continue;
            if (after_const.len > name.len and sourceIdentChar(after_const[name.len])) continue;
            const line_end = std.mem.indexOfScalar(u8, after_const, '\n') orelse after_const.len;
            const line = after_const[0..line_end];
            const colon_pos = std.mem.indexOfScalar(u8, line, ':') orelse continue;
            const type_end = std.mem.indexOfAnyPos(u8, line, colon_pos + 1, "=;") orelse line.len;
            const type_text = std.mem.trim(u8, line[colon_pos + 1 .. type_end], " \t\r");
            if (std.mem.eql(u8, type_text, "unique symbol")) return true;
        }
        return false;
    }

    const SourceKeywordHitParser = struct {
        start: usize,
        end: usize,
    };

    fn sourceIndexOfNamespaceKeywordParser(src: []const u8, start: usize) ?SourceKeywordHitParser {
        var search_start = start;
        while (search_start < src.len) {
            const ns_pos = std.mem.indexOfPos(u8, src, search_start, "namespace");
            const mod_pos = std.mem.indexOfPos(u8, src, search_start, "module");
            const pos = if (ns_pos) |n|
                if (mod_pos) |m| @min(n, m) else n
            else
                mod_pos orelse return null;
            const keyword = if (std.mem.startsWith(u8, src[pos..], "namespace")) "namespace" else "module";
            const end = pos + keyword.len;
            search_start = end;
            if (pos > 0 and sourceIdentChar(src[pos - 1])) continue;
            if (end < src.len and sourceIdentChar(src[end])) continue;
            return .{ .start = pos, .end = end };
        }
        return null;
    }

    fn sourceMatchingBraceParser(src: []const u8, open: usize) ?usize {
        if (open >= src.len or src[open] != '{') return null;
        var depth: usize = 0;
        var i = open;
        while (i < src.len) : (i += 1) {
            if (src[i] == '{') {
                depth += 1;
            } else if (src[i] == '}') {
                depth -= 1;
                if (depth == 0) return i;
            }
        }
        return null;
    }

    fn computedTypeMemberIdentifierIsDeclaredValue(self: *Parser, key_expr: NodeId) bool {
        if (self.hir.kindOf(key_expr) != .identifier) return false;
        return self.identifierNodeIsDeclaredValue(key_expr);
    }

    fn computedTypeMemberUnresolvedQualifiedRoot(self: *Parser, key_expr: NodeId) ?NodeId {
        var root = key_expr;
        while (self.hir.kindOf(root) == .member_access) {
            root = hir_mod.memberOf(self.hir, root).object;
        }
        if (self.hir.kindOf(root) != .identifier) return null;
        if (self.identifierNodeIsDeclaredValue(root)) return null;
        return root;
    }

    fn identifierNodeIsDeclaredValue(self: *Parser, key_expr: NodeId) bool {
        const id = hir_mod.identifierOf(self.hir, key_expr);
        const raw = self.interner.get(id.name);
        if (std.mem.eql(u8, raw, "Symbol")) return true;
        const keywords = [_][]const u8{ "var", "let", "const", "function", "class", "enum", "namespace", "module" };
        for (keywords) |kw| {
            var search_start: usize = 0;
            while (std.mem.indexOfPos(u8, self.source, search_start, kw)) |kw_pos| {
                search_start = kw_pos + kw.len;
                if (kw_pos > 0 and sourceIdentChar(self.source[kw_pos - 1])) continue;
                if (search_start < self.source.len and sourceIdentChar(self.source[search_start])) continue;
                var p = search_start;
                while (p < self.source.len and
                    (self.source[p] == ' ' or self.source[p] == '\t' or self.source[p] == '\r' or self.source[p] == '\n')) : (p += 1)
                {}
                if (!std.mem.startsWith(u8, self.source[p..], raw)) continue;
                if (p + raw.len < self.source.len and sourceIdentChar(self.source[p + raw.len])) continue;
                return true;
            }
        }
        return false;
    }

    fn sourceIdentChar(c: u8) bool {
        return (c >= 'a' and c <= 'z') or
            (c >= 'A' and c <= 'Z') or
            (c >= '0' and c <= '9') or
            c == '_' or
            c == '$';
    }

    fn computedSymbolMemberIsNonPropertySymbol(self: *Parser, key_expr: NodeId) bool {
        if (self.hir.kindOf(key_expr) != .member_access) return false;
        const m = hir_mod.memberOf(self.hir, key_expr);
        const prop = self.interner.get(m.name);
        return std.mem.eql(u8, prop, "for") or std.mem.eql(u8, prop, "keyFor");
    }

    /// Attempt to parse a `[k: K]: V` (or `readonly [k: K]: V`)
    /// index signature. Returns true if one was consumed and
    /// appended to `out`; returns false (cursor unchanged) when
    /// the bracketed form turns out to be something else (e.g. a
    /// computed key or mapped-type form). Mapped types live in a
    /// dedicated `mapped_type` HIR node and are dispatched
    /// separately by `parseTypeAnnotation`.
    fn tryParseIndexSignature(
        self: *Parser,
        out: *std.ArrayListUnmanaged(NodeId),
        is_static: bool,
        leading_readonly: bool,
    ) ParseError!bool {
        const checkpoint = self.cursor;
        const start_tok = self.peek();
        var is_readonly = leading_readonly;
        if (self.peek().kind == .kw_readonly and self.peekAt(1).kind == .open_bracket) {
            _ = self.advance();
            is_readonly = true;
        }
        if (self.peek().kind != .open_bracket) {
            self.cursor = checkpoint;
            return false;
        }
        // Look for the `[ident : ident]` pattern, optionally followed
        // by `:` (annotation) or `in` (mapped type). Also accept the
        // upstream recovery shape `[ident? ]:` (where the `?` forces
        // index-sig interpretation despite the missing param type) —
        // tsc's checker then surfaces TS1022 at the parameter name.
        // We do both in one pass at parse time so the diagnostic
        // lands without the checker having to model a typeless
        // index-signature parameter. Plain `[ident]: T` (no `?`)
        // stays on the computed-property path so existing fixtures
        // like `object type computed members accept const literal
        // keys` (`type Shape = { [a]: number }` where `a` is a
        // string-typed const) continue to parse cleanly.
        const after_bracket = self.cursor + 1;
        if (after_bracket >= self.tokens.len) {
            self.cursor = checkpoint;
            return false;
        }
        const id1 = self.tokens[after_bracket];
        if (id1.kind != .identifier) {
            self.cursor = checkpoint;
            return false;
        }
        const colon_pos = after_bracket + 1;
        if (colon_pos >= self.tokens.len) {
            self.cursor = checkpoint;
            return false;
        }
        const has_param_type = self.tokens[colon_pos].kind == .colon;
        const is_optional_no_type = self.tokens[colon_pos].kind == .question and
            colon_pos + 1 < self.tokens.len and
            self.tokens[colon_pos + 1].kind == .close_bracket and
            colon_pos + 2 < self.tokens.len and
            self.tokens[colon_pos + 2].kind == .colon;
        if (!has_param_type and !is_optional_no_type) {
            self.cursor = checkpoint;
            return false;
        }
        // Commit to parsing the index signature.
        const index_sig_open = self.advance(); // [
        _ = self.advance(); // key name
        var key_type: NodeId = hir_mod.none_node_id;
        if (has_param_type) {
            _ = self.advance(); // :
            key_type = try self.parseTypeAnnotation();
        } else {
            // `[ident?]: T` — emit TS1022 at the param name. tsc's
            // `checkGrammarIndexSignatureParameters` anchors at the
            // parameter identifier. Consume the `?` so the trailing
            // `]: T` still parses; the `?` itself is invalid on an
            // index-sig param and could be flagged TS1019 in a
            // follow-up pass.
            try self.reportCodeAt(id1.span.start, id1.line, 1022, "An index signature parameter must have a type annotation.");
            _ = self.advance(); // ?
        }
        // If the next token is `in`, this is actually a mapped
        // type — back out so the higher-level parser handles it.
        if (self.peek().kind == .kw_in) {
            self.cursor = checkpoint;
            return false;
        }
        // TS1337: an index-signature key may not be a literal type
        // (`["specific"]: V`, `[42]: V`, `[true]: V`, or a negative
        // numeric literal type). Anchored at the parameter name to
        // mirror tsc's `checkGrammarIndexSignatureParameterType`.
        // Generic-type-param rejection (the second half of the
        // upstream message) needs checker context to know which
        // type-refs resolve to params; deferred.
        if (key_type != hir_mod.none_node_id and
            self.indexSignatureKeyTypeContainsLiteral(key_type))
        {
            try self.reportCodeAt(id1.span.start, id1.line, 1337, "An index signature parameter type cannot be a literal type or generic type. Consider using a mapped object type instead.");
        }
        // TS1020: an index-signature parameter may not carry a default
        // initializer (`[a: number = 1]`). tsc anchors the diagnostic at
        // the parameter name and recovers by consuming the initializer
        // expression so the trailing `]` still parses. Mirrors
        // `indexSignatureWithInitializer1.ts(2,4)`.
        if (self.peek().kind == .equal) {
            try self.reportCodeAt(id1.span.start, id1.line, 1020, "An index signature parameter cannot have an initializer.");
            _ = self.advance(); // `=`
            _ = self.parseAssignmentExpression() catch {
                while (self.peek().kind != .close_bracket and
                    self.peek().kind != .close_brace and
                    self.peek().kind != .eof)
                {
                    _ = self.advance();
                }
            };
        }
        var has_multiple_parameters = false;
        if (self.peek().kind == .comma) {
            // Distinguish a trailing comma (`[key: string,]`, TS1025) from a
            // genuine second parameter (`[a: K, b: K]`, TS1096). tsc anchors
            // TS1025 at the comma. Mirrors `indexSignatureWithTrailingComma`.
            const comma_tok = self.peek();
            const next_after_comma = self.peekAt(1).kind;
            if (next_after_comma == .close_bracket or next_after_comma == .close_brace) {
                try self.reportCodeAt(comma_tok.span.start, comma_tok.line, 1025, "An index signature cannot have a trailing comma.");
                _ = self.advance(); // consume the trailing comma
            } else {
                has_multiple_parameters = true;
                try self.reportCodeAt(id1.span.start, id1.line, 1096, "An index signature must have exactly one parameter.");
                while (self.peek().kind != .close_bracket and self.peek().kind != .close_brace and self.peek().kind != .eof) {
                    _ = self.advance();
                }
            }
        }
        const key_type_valid = key_type != hir_mod.none_node_id and self.indexSignatureKeyTypeIsValid(key_type);
        if (!key_type_valid and key_type != hir_mod.none_node_id and
            !self.indexSignatureKeyTypeContainsLiteral(key_type))
        {
            // Only emit TS1268 when there IS a key type and it's of the
            // wrong shape. The missing-key-type case already surfaced
            // TS1022 above; suppressing TS1268 here keeps the diagnostic
            // list aligned with upstream's grammar-check phase.
            try self.reportCodeAt(id1.span.start, id1.line, 1268, "An index signature parameter type must be 'string', 'number', 'symbol', or a template literal type.");
        }
        _ = try self.expectClosingMatch(.close_bracket, "']' to close index signature", index_sig_open.span.start, "[", "]");
        const value_type: NodeId = if (self.match(.colon)) blk: {
            break :blk try self.parseTypeAnnotation();
        } else blk: {
            break :blk hir_mod.none_node_id;
        };
        if (!self.match(.semicolon) and !self.match(.comma)) {
            const next = self.peek();
            if (next.kind != .close_brace and next.kind != .eof and !next.flags.preceded_by_newline) {
                const prev = self.tokens[self.cursor - 1];
                try self.reportCodeAt(prev.span.end + 1, prev.line, 1005, "';' expected.");
            }
        }
        if (has_multiple_parameters or (value_type == hir_mod.none_node_id and !key_type_valid)) {
            return true;
        }
        // Even when the key type is invalid (TS1268 already reported),
        // store the index signature so the checker can still lower
        // the key/value type-refs and emit follow-on diagnostics like
        // TS2314 (`Generic type … requires N type argument(s)`).
        // Mirrors upstream behaviour for fixtures like
        // `genericTypeReferenceWithoutTypeArgument.ts(12,14)`.
        const sp: Span = .{ .start = start_tok.span.start, .end = self.tokens[self.cursor - 1].span.end };
        // Capture the declared index-parameter name (`key` in
        // `[key: string]: T`) so diagnostic prose can render the
        // user's chosen name instead of the synthetic `x`. Mirrors
        // upstream `getNameFromIndexInfo` which reads the parameter
        // identifier from the index-signature declaration.
        const key_name = try self.internToken(id1);
        const node = try self.builder.addIndexSignature(sp, key_type, value_type, is_readonly, is_static, key_name);
        try out.append(self.gpa, node);
        return true;
    }

    fn indexSignatureKeyTypeContainsLiteral(self: *const Parser, key_type: NodeId) bool {
        if (key_type == hir_mod.none_node_id) return false;
        return switch (self.hir.kindOf(key_type)) {
            .type_literal => true,
            .union_type => blk: {
                for (hir_mod.unionTypeMembers(self.hir, key_type)) |member| {
                    if (self.indexSignatureKeyTypeContainsLiteral(member)) break :blk true;
                }
                break :blk false;
            },
            .intersection_type => blk: {
                for (hir_mod.intersectionTypeMembers(self.hir, key_type)) |member| {
                    if (self.indexSignatureKeyTypeContainsLiteral(member)) break :blk true;
                }
                break :blk false;
            },
            else => false,
        };
    }

    fn skipUntilTypeMemberSeparator(self: *Parser) ParseError!void {
        var depth: i32 = 0;
        while (true) {
            const t = self.peek();
            if (depth == 0) {
                if (t.kind == .semicolon or t.kind == .comma) {
                    _ = self.advance();
                    return;
                }
                if (t.kind == .close_brace or t.kind == .eof) return;
            }
            switch (t.kind) {
                .open_brace, .open_paren, .open_bracket, .less_than => depth += 1,
                .close_brace, .close_paren, .close_bracket, .greater_than => {
                    depth -= 1;
                    if (depth < 0) return;
                },
                else => {},
            }
            _ = self.advance();
        }
    }

    fn parseGenericFnType(self: *Parser) ParseError!NodeId {
        const start = self.peek();
        const tps = try self.parseTypeParameterDeclaration();
        defer self.gpa.free(tps);
        const params = try self.parseTypeParameterList();
        defer self.gpa.free(params);
        _ = try self.expect(.arrow, "'=>' in generic fn type");
        const ret = try self.parseReturnTypeAnnotation(params);
        const sp: Span = .{ .start = start.span.start, .end = self.hir.spanOf(ret).end };
        return try self.builder.addFnType(sp, tps, params, ret, false, false);
    }

    fn parseConstructorType(self: *Parser, is_abstract_constructor: bool) ParseError!NodeId {
        const start = self.advance(); // new
        var tps: []NodeId = &.{};
        var owns_tps = false;
        if (self.peek().kind == .less_than) {
            tps = try self.parseTypeParameterDeclaration();
            owns_tps = true;
        }
        defer if (owns_tps) self.gpa.free(tps);
        const params = try self.parseTypeParameterList();
        defer self.gpa.free(params);
        _ = try self.expect(.arrow, "'=>' in constructor type");
        const ret = try self.parseReturnTypeAnnotation(params);
        const sp: Span = .{ .start = start.span.start, .end = self.hir.spanOf(ret).end };
        return try self.builder.addFnType(sp, tps, params, ret, true, is_abstract_constructor);
    }

    /// Parse `<T, U extends V = D>`. Returns owned slice of
    /// `type_parameter` HIR nodes.
    /// The TS predefined type keywords. These are contextual — they
    /// may appear in identifier-name positions (e.g. as a type-parameter
    /// name) where the checker then rejects them (TS2368). Mirrors tsc's
    /// `checkTypeNameIsReserved` reserved set.
    fn isPredefinedTypeKeyword(kind: ts_lexer.TokenKind) bool {
        return switch (kind) {
            .kw_any,
            .kw_unknown,
            .kw_never,
            .kw_number,
            .kw_bigint,
            .kw_boolean,
            .kw_string,
            .kw_symbol,
            .kw_void,
            .kw_object,
            .kw_undefined,
            => true,
            else => false,
        };
    }

    const TypeParameterContext = enum {
        function_like,
        variance_only,
        class_like,
    };

    fn parseTypeParameterDeclaration(self: *Parser) ParseError![]NodeId {
        return try self.parseTypeParameterDeclarationIn(.function_like);
    }

    fn parseTypeParameterDeclarationIn(self: *Parser, context: TypeParameterContext) ParseError![]NodeId {
        const open_tok = try self.expect(.less_than, "'<' to open type parameters");
        var tps: std.ArrayListUnmanaged(NodeId) = .empty;
        errdefer tps.deinit(self.gpa);
        // TS1098: an empty `<>` type parameter list is invalid. tsc
        // anchors the diagnostic at the `<` token (specifically at
        // the column AFTER `<`). Mirrors upstream tsc on
        // `parserConstructorDeclaration11.ts(2,14)`. The check fires
        // BEFORE the close-`>` is consumed so the error position is
        // accurate.
        if (self.peek().kind == .greater_than) {
            try self.reportCodeAt(open_tok.span.start, open_tok.line, 1098, "Type parameter list cannot be empty.");
        }
        while (self.peek().kind != .greater_than and self.peek().kind != .eof) {
            const tp_start = self.peek();
            var is_const: bool = false;
            var variance: u8 = 0;
            while (self.typeParameterModifierHasNameAfter()) {
                const mod = self.advance();
                switch (mod.kind) {
                    .kw_const => {
                        if (!typeParameterContextAllowsConst(context)) {
                            try self.reportTypeParameterConstModifierDiagnostic(mod);
                        }
                        is_const = true;
                    },
                    .kw_in, .kw_out => {
                        if (!typeParameterContextAllowsVariance(context)) {
                            try self.reportTypeParameterVarianceModifierDiagnostic(mod);
                        }
                        variance |= if (mod.kind == .kw_in) @as(u8, 1) else @as(u8, 2);
                    },
                    else => try self.reportInvalidTypeParameterModifierDiagnostic(mod),
                }
            }
            // Predefined type keywords (`any`, `string`, `number`, …)
            // are contextual: tsc accepts them syntactically as a
            // type-parameter name and lets the checker reject the result
            // with TS2368 ("Type parameter name cannot be '{0}'."). Accept
            // the keyword token here as the name so the checker can run
            // that semantic check; otherwise require a real identifier.
            //
            // When neither path matches, tsc emits the type-parameter-
            // specific TS1139 ("Type parameter declaration expected.")
            // rather than the generic TS1109/TS1003. Anchor the
            // diagnostic at the current token so the column matches
            // upstream (e.g. `dontShowCompilerGeneratedMembers.ts(3,6)`).
            const name_tok = blk_name: {
                if (isPredefinedTypeKeyword(self.peek().kind)) break :blk_name self.advance();
                if (self.peek().kind == .identifier) break :blk_name self.advance();
                const at = self.peek();
                try self.reportCodeAt(
                    at.span.start,
                    at.line,
                    1139,
                    "Type parameter declaration expected.",
                );
                return error.UnexpectedToken;
            };
            const name_id = try self.internToken(name_tok);
            var constraint: NodeId = hir_mod.none_node_id;
            if (self.match(.kw_extends)) constraint = try self.parseTypeAnnotation();
            var default: NodeId = hir_mod.none_node_id;
            if (self.match(.equal)) default = try self.parseTypeAnnotation();
            const tp = try self.builder.addTypeParameter(
                .{ .start = tp_start.span.start, .end = self.tokens[self.cursor - 1].span.end },
                name_id,
                constraint,
                default,
                variance,
                is_const,
            );
            try tps.append(self.gpa, tp);
            if (!self.match(.comma)) break;
        }
        _ = try self.consumeTypeGreater("'>' to close type parameters");
        return try tps.toOwnedSlice(self.gpa);
    }

    fn typeParameterContextAllowsVariance(context: TypeParameterContext) bool {
        return context == .class_like or context == .variance_only;
    }

    fn typeParameterContextAllowsConst(context: TypeParameterContext) bool {
        return context == .class_like or context == .function_like;
    }

    fn typeParameterModifierHasNameAfter(self: *Parser) bool {
        const k = self.peek().kind;
        if (!(k == .kw_const or k.isModifierKeyword())) return false;
        const next = self.peekAt(1);
        if (typeParameterNameCanStart(next.kind)) return true;
        return k == .kw_in and next.kind == .kw_out and typeParameterNameCanStart(self.peekAt(2).kind);
    }

    fn typeParameterNameCanStart(kind: TokenKind) bool {
        return kind == .identifier or isPredefinedTypeKeyword(kind);
    }

    fn reportInvalidTypeParameterModifierDiagnostic(self: *Parser, mod: Token) ParseError!void {
        const mod_name = self.source[mod.span.start..mod.span.end];
        const msg = try std.fmt.allocPrint(self.diag_arena.allocator(), "'{s}' modifier cannot appear on a type parameter", .{mod_name});
        try self.reportCodeAt(mod.span.start, mod.line, 1273, msg);
    }

    fn reportTypeParameterVarianceModifierDiagnostic(self: *Parser, mod: Token) ParseError!void {
        const mod_name = self.source[mod.span.start..mod.span.end];
        const msg = try std.fmt.allocPrint(self.diag_arena.allocator(), "'{s}' modifier can only appear on a type parameter of a class, interface or type alias", .{mod_name});
        try self.reportCodeAt(mod.span.start, mod.line, 1274, msg);
    }

    fn reportTypeParameterConstModifierDiagnostic(self: *Parser, mod: Token) ParseError!void {
        const mod_name = self.source[mod.span.start..mod.span.end];
        const msg = try std.fmt.allocPrint(self.diag_arena.allocator(), "'{s}' modifier can only appear on a type parameter of a function, method or class", .{mod_name});
        try self.reportCodeAt(mod.span.start, mod.line, 1277, msg);
    }

    /// Parse `<A, B<C>>` in type-argument position. Returns owned
    /// slice of parsed type nodes.
    fn parseTypeArgumentList(self: *Parser) ParseError![]NodeId {
        _ = try self.expect(.less_than, "'<' to open type arguments");
        var args: std.ArrayListUnmanaged(NodeId) = .empty;
        errdefer args.deinit(self.gpa);
        while (self.peek().kind != .greater_than and self.peek().kind != .eof) {
            if (self.peek().kind == .invalid) {
                const bad = self.advance();
                try self.reportCodeAt(bad.span.start, bad.line, 1127, "Invalid character.");
                return try args.toOwnedSlice(self.gpa);
            }
            // TS1140 — `parsingContextErrors(TypeArguments)` upstream
            // fires when `isListElement` returns false for the current
            // token (i.e. it isn't `,` and can't start a type). Catch
            // the obvious anti-shapes here so the diagnostic surfaces
            // before parseConditionalType cascades into TS1110
            // ("Type expected.") at the same position. Conservative
            // list: tokens that unambiguously can't begin a type AND
            // aren't list separators or terminators. Sibling of
            // TS1139 we ship from `parseTypeParameter`.
            switch (self.peek().kind) {
                .comma,
                .semicolon,
                .colon,
                .equal,
                .arrow,
                .close_paren,
                .close_brace,
                .close_bracket,
                => {
                    const bad = self.peek();
                    try self.reportCodeAt(bad.span.start, bad.line, 1140, "Type argument expected.");
                    return try args.toOwnedSlice(self.gpa);
                },
                else => {},
            }
            const arg = try self.parseTypeAnnotation();
            try args.append(self.gpa, arg);
            if (!self.match(.comma)) break;
        }
        if (self.peek().kind == .invalid) {
            const bad = self.advance();
            try self.reportCodeAt(bad.span.start, bad.line, 1127, "Invalid character.");
            return try args.toOwnedSlice(self.gpa);
        }
        _ = try self.consumeTypeGreater("'>' to close type arguments");
        return try args.toOwnedSlice(self.gpa);
    }

    /// `Foo`, `Foo.Bar`, `Foo<T, U>`. The lexer hands us the `<` only
    /// when it can tell from context — in type position it's always
    /// generic args, never a comparison.
    fn parseImportTypeReference(self: *Parser) ParseError!NodeId {
        const import_tok = self.advance();
        if (self.peek().kind != .open_paren) {
            // `typeof import.defer("m").X` is parsed by upstream as a
            // malformed import type followed by the value expression
            // `("m").X`. Its recoverable `parseExpected` calls leave the
            // opening parenthesis unread, allowing that trailing expression
            // to be bound and checked normally.
            const argument_start = self.peek();
            try self.reportCodeAt(argument_start.span.start, argument_start.line, 1005, "'(' expected.");
            try self.reportCodeAt(argument_start.span.start, argument_start.line, 1141, "String literal expected.");

            var end_pos = import_tok.span.end;
            if (self.match(.dot)) {
                const member = try self.expectIdentifierLike();
                end_pos = member.span.end;
            }
            const close_anchor = self.peek();
            try self.reportCodeAt(close_anchor.span.start, close_anchor.line, 1005, "')' expected.");

            const any_id = self.interner.intern("any") catch return error.OutOfMemory;
            return try self.builder.addTypeRef(
                .{ .start = import_tok.span.start, .end = end_pos },
                any_id,
                &.{},
                &.{},
            );
        }
        const import_type_open = try self.expect(.open_paren, "'(' after import in import type");
        // tsc emits TS1141 "String literal expected." at the offending
        // token when `import(<non-string>)` appears in type position.
        // Mirror that exact code+phrasing so baselines line up
        // (`importTypeNested`, `importTypeNonString`,
        // `importTypeNestedNoRef`). When the specifier is anything
        // other than a string literal, emit TS1141 at the offending
        // token but continue parsing past the `(...)` so downstream
        // type positions can still be checked. Mirrors tsc — which
        // emits a TS1141 per offending `import(T)` rather than
        // bailing the whole file (`importTypeGeneric.ts`).
        const specifier_is_invalid = self.peek().kind != .string_literal;
        if (specifier_is_invalid) {
            const tok = self.peek();
            try self.reportCodeAt(tok.span.start, tok.line, 1141, "String literal expected.");
            // Skip the specifier expression up to the matching `)` so
            // the qualifier / type-argument tail of this `import(...)`
            // is still parsed (the resulting type is morally `any`).
            var depth: i32 = 0;
            while (self.peek().kind != .eof) {
                if (depth == 0 and self.peek().kind == .close_paren) break;
                const k = self.peek().kind;
                if (k == .open_paren or k == .open_brace or k == .open_bracket) depth += 1;
                if ((k == .close_paren or k == .close_brace or k == .close_bracket) and depth > 0) depth -= 1;
                _ = self.advance();
            }
        } else {
            _ = self.advance();
        }
        if (self.match(.comma)) {
            try self.reportLegacyImportTypeAssertionDiagnostics();
            var depth: i32 = 0;
            while (self.peek().kind != .eof) {
                if (depth == 0 and self.peek().kind == .close_paren) break;
                const k = self.peek().kind;
                if (k == .open_paren or k == .open_brace or k == .open_bracket) depth += 1;
                if ((k == .close_paren or k == .close_brace or k == .close_bracket) and depth > 0) depth -= 1;
                _ = self.advance();
            }
        }
        _ = try self.expectClosingMatch(.close_paren, "')' to close import type", import_type_open.span.start, "(", ")");

        var qualifier: std.ArrayListUnmanaged(NodeId) = .empty;
        defer qualifier.deinit(self.gpa);
        var name_id = self.interner.intern("unknown") catch return error.OutOfMemory;

        if (self.match(.dot)) {
            const first = try self.expectIdentifierLike();
            name_id = try self.internToken(first);
            var prev_tok = first;
            while (self.match(.dot)) {
                const next_tok = try self.expectIdentifierLike();
                const prev_id = name_id;
                const prev_node = try self.builder.addIdentifier(tokenSpan(prev_tok), prev_id);
                try qualifier.append(self.gpa, prev_node);
                name_id = try self.internToken(next_tok);
                prev_tok = next_tok;
            }
        }

        var args: std.ArrayListUnmanaged(NodeId) = .empty;
        defer args.deinit(self.gpa);
        if (self.peek().kind == .less_than) {
            _ = self.advance();
            while (self.peek().kind != .greater_than and self.peek().kind != .eof) {
                if (self.peek().kind == .invalid) {
                    const bad = self.advance();
                    try self.reportCodeAt(bad.span.start, bad.line, 1127, "Invalid character.");
                    break;
                }
                const a = try self.parseTypeAnnotation();
                try args.append(self.gpa, a);
                if (!self.match(.comma)) break;
            }
            _ = try self.consumeTypeGreater("'>' to close import type arguments");
        }

        const end_pos = self.tokens[self.cursor - 1].span.end;
        // When the module specifier was invalid (already reported as
        // TS1141), discard the parsed qualifier/type-args and resolve
        // the whole `import(<bad>).A.B<T>` to `any`. tsc treats the
        // entire reference as opaque so trailing identifiers don't
        // chain into TS2304 / TS2503 noise (`importTypeGeneric.ts`).
        if (specifier_is_invalid) {
            const any_id = self.interner.intern("any") catch return error.OutOfMemory;
            return try self.builder.addTypeRef(
                .{ .start = import_tok.span.start, .end = end_pos },
                any_id,
                &.{},
                &.{},
            );
        }
        return try self.builder.addTypeRef(
            .{ .start = import_tok.span.start, .end = end_pos },
            name_id,
            qualifier.items,
            args.items,
        );
    }

    fn reportLegacyImportTypeAssertionDiagnostics(self: *Parser) ParseError!void {
        if (self.peek().kind != .open_brace) return;
        const outer_open: usize = @intCast(self.cursor);
        const outer_close = self.findMatchingBraceTokenIndex(outer_open) orelse return;
        var i: usize = outer_open + 1;
        while (i < outer_close and i < self.tokens.len) {
            const key_tok = self.tokens[i];
            if (key_tok.kind == .comma) {
                i += 1;
                continue;
            }
            if (i + 2 >= outer_close or self.tokens[i + 1].kind != .colon) {
                i += 1;
                continue;
            }
            const value_i = i + 2;
            if (self.importTypeAttributePropertyNameEquals(key_tok, "assert") and self.tokens[value_i].kind == .open_brace) {
                try self.reportLegacyImportTypeAssertionBlockDiagnostics(value_i);
                return;
            }
            i = self.skipTopLevelObjectPropertyValue(value_i, outer_close);
        }
    }

    fn reportLegacyImportTypeAssertionBlockDiagnostics(self: *Parser, open_i: usize) ParseError!void {
        const close_i = self.findMatchingBraceTokenIndex(open_i) orelse return;
        var attr_count: usize = 0;
        var first_key: ?Token = null;
        var i = open_i + 1;
        while (i < close_i and i < self.tokens.len) {
            const key_tok = self.tokens[i];
            if (key_tok.kind == .comma) {
                i += 1;
                continue;
            }
            if (key_tok.kind == .close_brace or key_tok.kind == .eof) break;
            attr_count += 1;
            if (attr_count == 1) first_key = key_tok;
            if (i + 1 < close_i and self.tokens[i + 1].kind == .colon and i + 2 < close_i) {
                i = self.skipTopLevelObjectPropertyValue(i + 2, close_i);
            } else {
                i += 1;
            }
        }
        const open_tok = self.tokens[open_i];
        if (attr_count != 1) {
            try self.reportCodeAt(
                open_tok.span.start,
                open_tok.line,
                1456,
                "Type import assertions should have exactly one key - `resolution-mode` - with value `import` or `require`.",
            );
            return;
        }
        const key_tok = first_key orelse return;
        if (key_tok.kind == .string_literal and !self.stringLiteralTokenInnerEquals(key_tok, "resolution-mode")) {
            try self.reportCodeAt(
                key_tok.span.start,
                key_tok.line,
                1455,
                "`resolution-mode` is the only valid key for type import assertions.",
            );
        }
    }

    fn findMatchingBraceTokenIndex(self: *const Parser, open_i: usize) ?usize {
        if (open_i >= self.tokens.len or self.tokens[open_i].kind != .open_brace) return null;
        var brace_depth: usize = 0;
        var bracket_depth: usize = 0;
        var paren_depth: usize = 0;
        var i = open_i;
        while (i < self.tokens.len) : (i += 1) {
            switch (self.tokens[i].kind) {
                .open_brace => brace_depth += 1,
                .open_bracket => bracket_depth += 1,
                .open_paren => paren_depth += 1,
                .close_brace => {
                    if (brace_depth == 0) return null;
                    brace_depth -= 1;
                    if (brace_depth == 0 and bracket_depth == 0 and paren_depth == 0) return i;
                },
                .close_bracket => {
                    if (bracket_depth > 0) bracket_depth -= 1;
                },
                .close_paren => {
                    if (paren_depth > 0) paren_depth -= 1;
                },
                .eof => return null,
                else => {},
            }
        }
        return null;
    }

    fn skipTopLevelObjectPropertyValue(self: *const Parser, value_i: usize, limit: usize) usize {
        var brace_depth: usize = 0;
        var bracket_depth: usize = 0;
        var paren_depth: usize = 0;
        var i = value_i;
        while (i < limit and i < self.tokens.len) : (i += 1) {
            switch (self.tokens[i].kind) {
                .open_brace => brace_depth += 1,
                .open_bracket => bracket_depth += 1,
                .open_paren => paren_depth += 1,
                .close_brace => {
                    if (brace_depth == 0) return i;
                    brace_depth -= 1;
                },
                .close_bracket => {
                    if (bracket_depth == 0) return i;
                    bracket_depth -= 1;
                },
                .close_paren => {
                    if (paren_depth == 0) return i;
                    paren_depth -= 1;
                },
                .comma => if (brace_depth == 0 and bracket_depth == 0 and paren_depth == 0) return i + 1,
                else => {},
            }
        }
        return i;
    }

    fn importTypeAttributePropertyNameEquals(self: *const Parser, tok: Token, expected: []const u8) bool {
        if (tok.kind == .string_literal) return self.stringLiteralTokenInnerEquals(tok, expected);
        if (tok.kind == .identifier or tok.kind.isKeyword()) return self.tokenTextEquals(tok, expected);
        return false;
    }

    fn stringLiteralTokenInnerEquals(self: *const Parser, tok: Token, expected: []const u8) bool {
        if (tok.kind != .string_literal) return false;
        const text = self.source[tok.span.start..tok.span.end];
        if (text.len < 2) return false;
        return std.mem.eql(u8, text[1 .. text.len - 1], expected);
    }

    fn parseTypeReference(self: *Parser) ParseError!NodeId {
        return try self.parseTypeReferenceWithOptionalChainDiagnostic(
            2499,
            "An interface can only extend an identifier/qualified-name with optional type arguments.",
            false,
        );
    }

    fn parseImplementsTypeReference(self: *Parser) ParseError!NodeId {
        return try self.parseTypeReferenceWithOptionalChainDiagnostic(
            2500,
            "A class can only implement an identifier/qualified-name with optional type arguments.",
            true,
        );
    }

    fn parseTypeReferenceWithOptionalChainDiagnostic(
        self: *Parser,
        optional_chain_code: u32,
        optional_chain_message: []const u8,
        recover_call_heritage: bool,
    ) ParseError!NodeId {
        const start = self.peek();
        const name_tok = if (self.peek().kind == .identifier or self.peek().kind.isPrimitiveTypeKeyword())
            self.advance()
        else
            try self.expect(.identifier, "type name");
        const final_name = try self.internToken(name_tok);

        var qualifier: std.ArrayListUnmanaged(NodeId) = .empty;
        defer qualifier.deinit(self.gpa);
        var name_id = final_name;

        // `A.B.C` — every `.B` extends the qualifier. Also tolerate
        // `A?.B` for error-recovery; the interface heritage parser
        // notices the `saw_question_dot` flag and surfaces a checker-
        // shape TS2499 anchored at the qualified-name start.
        var saw_question_dot = false;
        while (self.peek().kind == .dot or self.peek().kind == .question_dot) {
            const dot = self.advance();
            if (dot.kind == .question_dot) saw_question_dot = true;
            if (dot.kind == .dot and self.peek().kind == .less_than and !self.peek().flags.preceded_by_newline) {
                try self.reportCodeAt(dot.span.start, dot.line, 8020, "JSDoc types can only be used inside documentation comments.");
                break;
            }
            if (self.peek().flags.preceded_by_newline or self.peek().kind == .eof) {
                try self.reportCodeAt(dot.span.end, dot.line, 1003, "Identifier expected.");
                const prev_node = try self.builder.addIdentifier(tokenSpan(name_tok), name_id);
                try qualifier.append(self.gpa, prev_node);
                name_id = self.interner.intern("unknown") catch return error.OutOfMemory;
                break;
            }
            const next_tok = if (self.peek().kind == .identifier or
                self.peek().kind.isContextualKeyword() or
                self.peek().kind.isPrimitiveTypeKeyword())
                self.advance()
            else
                try self.expect(.identifier, "qualified-name member");
            const prev_id = name_id;
            const prev_node = try self.builder.addIdentifier(tokenSpan(name_tok), prev_id);
            try qualifier.append(self.gpa, prev_node);
            name_id = try self.internToken(next_tok);
        }

        var args: std.ArrayListUnmanaged(NodeId) = .empty;
        defer args.deinit(self.gpa);
        // TS implicit no-line-terminator rule: a `<` on a new line after a
        // type ref does NOT extend it into a generic instantiation. The
        // canonical case is an object-type body like `{ A: B<newline><T>; }`
        // where `<T>;` is a stand-alone call-signature member, not type
        // args for `B`. Without this guard we eagerly consume `<T>` as
        // args and then trip up on the trailing `;`. Mirrors the
        // analogous check in `parseArrayTypePostfix` for `[`.
        if (self.peek().kind == .less_than and !self.peek().flags.preceded_by_newline) {
            _ = self.advance();
            while (self.peek().kind != .greater_than and self.peek().kind != .eof) {
                // TS1140 — see the same gate in `parseTypeArgumentList`
                // below. This path is the qualified-name type-reference
                // parser (`Foo<…>`, `Foo.Bar<…>`); mirror the obvious-
                // anti-token check so `Foo<,>` / `Foo<;>` / `Foo<:>`
                // surface the upstream parser-recovery code rather
                // than cascading through `parseTypeAnnotation` into
                // TS1110 ("Type expected.") at the same anchor.
                switch (self.peek().kind) {
                    .comma,
                    .semicolon,
                    .colon,
                    .equal,
                    .arrow,
                    .close_paren,
                    .close_brace,
                    .close_bracket,
                    => {
                        const bad = self.peek();
                        try self.reportCodeAt(bad.span.start, bad.line, 1140, "Type argument expected.");
                        break;
                    },
                    else => {},
                }
                const a = try self.parseTypeAnnotation();
                try args.append(self.gpa, a);
                if (!self.match(.comma)) break;
            }
            if (isTypeGreaterToken(self.peek().kind)) {
                _ = try self.consumeTypeGreater("'>' to close type arguments");
            } else if (self.peek().kind == .invalid) {
                const bad = self.advance();
                try self.reportCodeAt(bad.span.start, bad.line, 1127, "Invalid character.");
            } else {
                const close_tok = self.peek();
                try self.reportCodeAt(close_tok.span.start, close_tok.line, 1005, "'>' expected.");
            }
        }

        var end_pos = self.tokens[self.cursor - 1].span.end;
        if (recover_call_heritage and self.peek().kind == .open_paren and !self.peek().flags.preceded_by_newline) {
            const open = self.advance();
            var depth: usize = 1;
            while (depth > 0 and self.peek().kind != .eof) {
                const tok = self.advance();
                switch (tok.kind) {
                    .open_paren => depth += 1,
                    .close_paren => depth -= 1,
                    else => {},
                }
            }
            end_pos = self.tokens[self.cursor - 1].span.end;
            _ = open;
            try self.reportCodeAt(start.span.start, start.line, optional_chain_code, optional_chain_message);
        }
        if (saw_question_dot) {
            try self.reportCodeAt(start.span.start, start.line, optional_chain_code, optional_chain_message);
        }
        return try self.builder.addTypeRef(
            .{ .start = start.span.start, .end = end_pos },
            name_id,
            qualifier.items,
            args.items,
        );
    }

    // ========================================================================
    // Expressions — Pratt
    // ========================================================================

    /// Parse a comma-separated expression at expression-statement
    pub fn parseExpression(self: *Parser) ParseError!NodeId {
        return try self.parseExpressionWithIn(true);
    }

    fn parseExpressionNoIn(self: *Parser) ParseError!NodeId {
        return try self.parseExpressionWithIn(false);
    }

    fn parseExpressionWithIn(self: *Parser, allow_in: bool) ParseError!NodeId {
        var left = try self.parseAssignmentExpressionWithIn(allow_in);
        while (self.match(.comma)) {
            const right = try self.parseAssignmentExpressionWithIn(allow_in);
            left = try self.builder.addBinaryOp(
                .{ .start = self.hir.spanOf(left).start, .end = self.hir.spanOf(right).end },
                .comma,
                left,
                right,
            );
        }
        return left;
    }

    fn parseAssignmentExpression(self: *Parser) ParseError!NodeId {
        return try self.parseAssignmentExpressionWithIn(true);
    }

    fn parseAssignmentExpressionWithIn(self: *Parser, allow_in: bool) ParseError!NodeId {
        // Arrow function fast paths:
        //   `x => …`   — single-ident arrow
        //   `() => …`  — zero-arg
        //   `(…) => …` — paren'd arrow (speculative)
        //   `async () => …` / `async x => …`
        //   `<T>(…) => …` — generic arrow
        if (try self.maybeParseArrowFunction()) |arrow| return arrow;

        const left = try self.parseConditionalExpressionWithIn(allow_in);
        const t = self.peek();
        switch (t.kind) {
            .equal => {
                if (self.hir.kindOf(left) == .binary_op and
                    hir_mod.binopOf(self.hir, left).op == .in)
                {
                    const equal = self.advance();
                    try self.reportCodeAt(equal.span.start, equal.line, 1005, "';' expected.");
                    _ = try self.parseAssignmentExpressionWithIn(allow_in);
                    return left;
                }
                _ = self.advance();
                try self.reportInvalidStrictIdentifierNode(left);
                try self.reportInvalidAssignmentTarget(left);
                const right = try self.parseAssignmentExpressionWithIn(allow_in);
                const sp: Span = .{ .start = self.hir.spanOf(left).start, .end = self.hir.spanOf(right).end };
                return try self.builder.addAssignment(sp, left, right, null);
            },
            .plus_equal => return self.parseCompoundAssign(left, .add, allow_in),
            .minus_equal => return self.parseCompoundAssign(left, .sub, allow_in),
            .asterisk_equal => return self.parseCompoundAssign(left, .mul, allow_in),
            .slash_equal => return self.parseCompoundAssign(left, .div, allow_in),
            .percent_equal => return self.parseCompoundAssign(left, .mod, allow_in),
            .asterisk_asterisk_equal => return self.parseCompoundAssign(left, .pow, allow_in),
            .less_less_equal => return self.parseCompoundAssign(left, .shl, allow_in),
            .greater_greater_equal => return self.parseCompoundAssign(left, .shr, allow_in),
            .greater_greater_greater_equal => return self.parseCompoundAssign(left, .shr_unsigned, allow_in),
            .ampersand_equal => return self.parseCompoundAssign(left, .bit_and, allow_in),
            .pipe_equal => return self.parseCompoundAssign(left, .bit_or, allow_in),
            .caret_equal => return self.parseCompoundAssign(left, .bit_xor, allow_in),
            // Logical assignments `??=`, `||=`, `&&=` (ES2021).
            // Lowered to `a = a <op> b` so existing checker logic
            // (nullish-coalescing strips null|undefined from lhs)
            // produces the right result type. Post-statement
            // narrowing for `??=` is applied by the checker.
            .question_question_equal => return self.parseLogicalAssign(left, .nullish, allow_in),
            .pipe_pipe_equal => return self.parseLogicalAssign(left, .@"or", allow_in),
            .ampersand_ampersand_equal => return self.parseLogicalAssign(left, .@"and", allow_in),
            else => return left,
        }
    }

    /// Detect if the next token sequence is an arrow function and
    /// parse it. Returns null on no match (no tokens consumed).
    fn maybeParseArrowFunction(self: *Parser) ParseError!?NodeId {
        const checkpoint = self.cursor;
        const is_async = blk: {
            if (self.peek().kind == .kw_async) {
                const next = self.peekAt(1).kind;
                if (next == .open_paren or next == .identifier or next == .less_than) {
                    _ = self.advance();
                    break :blk true;
                }
            }
            break :blk false;
        };
        const start_tok = if (is_async) self.tokens[checkpoint] else self.peek();

        // Single-ident arrow: `x => …`
        if (isExpressionIdentifierToken(self.peek().kind) and self.peekAt(1).kind == .arrow) {
            const name_tok = self.advance();
            const arrow_tok = self.peek();
            if (arrow_tok.flags.preceded_by_newline) {
                try self.reportCodeAt(arrow_tok.span.start, arrow_tok.line, 1200, "Line terminator not permitted before arrow.");
            }
            _ = self.advance(); // `=>`
            const name_id = try self.internToken(name_tok);
            const ident = try self.builder.addIdentifier(tokenSpan(name_tok), name_id);
            const param = try self.builder.addParameter(
                tokenSpan(name_tok),
                ident,
                hir_mod.none_node_id,
                hir_mod.none_node_id,
                .{},
            );
            self.function_depth += 1;
            if (is_async) self.async_function_depth += 1;
            const prev_generator_depth = self.generator_depth;
            self.generator_depth = 0;
            defer {
                self.generator_depth = prev_generator_depth;
                self.function_depth -= 1;
                if (is_async) self.async_function_depth -= 1;
            }
            const body = try self.parseArrowBody();
            const sp: Span = .{ .start = start_tok.span.start, .end = self.hir.spanOf(body).end };
            return try self.builder.addFnDecl(
                sp,
                hir_mod.none_node_id,
                &.{param},
                hir_mod.none_node_id,
                body,
                .{ .is_arrow = true, .is_async = is_async },
            );
        }

        // Generic arrow: `<T>(…) => …`
        if (self.peek().kind == .less_than) {
            // Speculatively check that the closing `>` is followed by
            // `(`. If so, this is a generic arrow.
            if (self.findMatchingTypeArgsEnd(self.cursor)) |after_args| {
                if (after_args < self.tokens.len and self.tokens[after_args].kind == .open_paren) {
                    const after_paren = self.findMatchingParenEnd(after_args) orelse {
                        self.cursor = checkpoint;
                        return null;
                    };
                    if (after_paren >= self.tokens.len or
                        (self.tokens[after_paren].kind != .arrow and self.tokens[after_paren].kind != .colon))
                    {
                        self.cursor = checkpoint;
                        return null;
                    }
                    const tps = try self.parseTypeParameterDeclaration();
                    defer self.gpa.free(tps);
                    if (try self.tryParseArrowAfterParen(start_tok, is_async, tps)) |arrow| return arrow;
                    // Failed; restore.
                    self.cursor = checkpoint;
                    return null;
                }
            }
            self.cursor = checkpoint;
            return null;
        }

        // Paren-arrow: `(…) => …`. Speculatively check that the
        // close-paren is followed by `=>` or `:` (typed return) before
        // committing.
        if (self.peek().kind == .open_paren) {
            const first_inside = self.peekAt(1).kind;
            if (first_inside != .kw_function and first_inside != .kw_class) {
                if (try self.tryParseArrowAfterParen(start_tok, is_async, &.{})) |arrow| return arrow;
                if (try self.tryParseArrowWithMissingCloseParen(start_tok, is_async, &.{})) |arrow| return arrow;
            }
        }
        // Not an arrow — restore and fall through.
        self.cursor = checkpoint;
        return null;
    }

    /// Returns the cursor index AFTER the matching `>` of a
    /// type-argument list starting at `start` (which must point at
    /// `<`). Returns null if not balanced.
    fn findMatchingTypeArgsEnd(self: *Parser, start: u32) ?u32 {
        if (start >= self.tokens.len or self.tokens[start].kind != .less_than) return null;
        var depth: i32 = 1;
        var i: u32 = start + 1;
        while (i < self.tokens.len) : (i += 1) {
            const tk = self.tokens[i].kind;
            switch (tk) {
                .less_than => depth += 1,
                .greater_than => {
                    depth -= 1;
                    if (depth == 0) return i + 1;
                },
                .greater_greater, .greater_greater_greater => {
                    const count: u8 = if (tk == .greater_greater) 2 else 3;
                    var n: u8 = 0;
                    while (n < count) : (n += 1) {
                        depth -= 1;
                        if (depth == 0) return i + 1;
                    }
                },
                .eof => return null,
                else => {},
            }
        }
        return null;
    }

    /// Speculatively parse `(…)` as arrow params. If it doesn't look
    /// like an arrow (no `=>` after the close-paren / typed return),
    /// rewinds and returns null.
    fn tryParseArrowAfterParen(
        self: *Parser,
        start_tok: Token,
        is_async: bool,
        type_params: []const NodeId,
    ) ParseError!?NodeId {
        const before_paren = self.cursor;
        const diag_checkpoint_at_paren = self.diagnostics.items.len;
        // Find the matching `)`.
        const after_paren_idx = self.findMatchingParenEnd(self.cursor) orelse return null;
        // After `)`, we expect either `=>` (untyped return), `:` then
        // `=>`, or a block body in recovery for `(a: T) {}` /
        // `(...a: T[]) {}` where the arrow is missing.
        if (after_paren_idx >= self.tokens.len) return null;
        const after_kind = self.tokens[after_paren_idx].kind;
        const recover_missing_arrow_before_block = after_kind == .open_brace and
            self.parenContentsLookLikeTypedOrRestParams(self.cursor, after_paren_idx);
        if (after_kind != .arrow and after_kind != .colon and !recover_missing_arrow_before_block) return null;
        if (after_kind == .arrow and
            self.ambiguousParenArrowHasInvalidParameterStart(self.cursor, after_paren_idx - 1))
        {
            return null;
        }
        const recover_numeric_param = after_kind == .arrow and self.parenArrowStartsWithExpressionOnlyToken(self.cursor);
        if (after_kind == .colon) {
            // `(expr): =>` is not a typed arrow in TypeScript. It recovers as
            // a parenthesized expression followed by a stray `:` and `=>`.
            if (after_paren_idx + 1 < self.tokens.len and self.tokens[after_paren_idx + 1].kind == .arrow) return null;
            // We need to scan past the type annotation to find a `=>`.
            // Simple approach: look for the next top-level `=>` before
            // a statement-terminator-class token.
            if (!self.scanForArrowAfterColon(after_paren_idx + 1) and
                !self.scanForMissingArrowBlockAfterColon(after_paren_idx + 1))
            {
                return null;
            }
        }

        // Looks like an arrow — parse for real. Bump
        // `async_function_depth` up front so `await` in the parameter
        // list (e.g. `async (await) => …`) is correctly diagnosed as
        // reserved (TS1359). Decrement before the permanent
        // re-increment that wraps the arrow body further below.
        const saved_numeric_recovery = self.allow_numeric_arrow_param_recovery;
        self.allow_numeric_arrow_param_recovery = recover_numeric_param;
        defer self.allow_numeric_arrow_param_recovery = saved_numeric_recovery;
        if (is_async) self.async_function_depth += 1;
        const params = self.parseParameterList() catch |err| {
            if (is_async) self.async_function_depth -= 1;
            return err;
        };
        if (is_async) self.async_function_depth -= 1;
        defer self.gpa.free(params);

        // Optional return-type annotation. Use the predicate-aware
        // parser so `(x): x is T => ...` works.
        var return_type: NodeId = hir_mod.none_node_id;
        const has_return_colon = self.peek().kind == .colon;
        if (self.match(.colon)) {
            return_type = try self.parseReturnTypeAnnotation(params);
        }
        if (self.peek().kind == .arrow and self.peek().flags.preceded_by_newline) {
            const arrow_tok = self.peek();
            try self.reportCodeAt(arrow_tok.span.start, arrow_tok.line, 1200, "Line terminator not permitted before arrow.");
        }
        if (recover_numeric_param and self.peek().kind == .arrow) {
            const arrow_tok = self.peek();
            try self.reportCodeAt(arrow_tok.span.start, arrow_tok.line, 1005, "',' expected.");
        }
        if (self.peek().kind == .open_brace) {
            const body_tok = self.peek();
            try self.reportCodeAt(body_tok.span.start, body_tok.line, 1005, "'=>' expected.");
        } else {
            _ = try self.expect(.arrow, "'=>' in arrow function");
        }
        self.function_depth += 1;
        if (is_async) self.async_function_depth += 1;
        const prev_generator_depth = self.generator_depth;
        self.generator_depth = 0;
        defer {
            self.generator_depth = prev_generator_depth;
            self.function_depth -= 1;
            if (is_async) self.async_function_depth -= 1;
        }
        const body = try self.parseArrowBody();
        if (recover_numeric_param) try self.reportNumericArrowRecoveryBodyDiagnostics(body);
        // TS parity (parserArrowFunctionExpression8/9/10/11/12): when
        // we're inside the `true` branch of a conditional expression
        // and the speculative arrow has a `:` return-type colon, the
        // arrow only "wins" if the next token is `:` (the outer
        // ternary's terminator). Otherwise rewind and let the
        // surrounding parse treat `(...)` as a parenthesized
        // expression so the ternary's own `:` is matched.
        if (self.disallow_arrow_return_type and has_return_colon and self.peek().kind != .colon) {
            self.cursor = before_paren;
            self.diagnostics.items.len = diag_checkpoint_at_paren;
            return null;
        }
        const sp: Span = .{ .start = start_tok.span.start, .end = self.hir.spanOf(body).end };
        const flags: hir_mod.FnFlags = .{
            .is_arrow = true,
            .is_async = is_async,
        };
        return try self.builder.addFnDeclGeneric(sp, hir_mod.none_node_id, type_params, params, return_type, body, flags);
    }

    fn parenArrowStartsWithExpressionOnlyToken(self: *Parser, open_paren_idx: u32) bool {
        if (open_paren_idx + 1 >= self.tokens.len) return false;
        return switch (self.tokens[open_paren_idx + 1].kind) {
            .number_literal, .bigint_literal, .string_literal, .regex_literal, .no_substitution_template, .template_head => true,
            else => false,
        };
    }

    /// An identifier-first parenthesized head such as `(a, b)` is
    /// ambiguous until a complete parameter list is parsed. tsgo's
    /// speculative `allowAmbiguity=false` path aborts when a later
    /// top-level parameter starts with `(`, since only an identifier or
    /// binding pattern can start a parameter. Rewind so `(a, (b, c)) =>`
    /// recovers as comma expressions instead of an invented arrow.
    fn ambiguousParenArrowHasInvalidParameterStart(self: *const Parser, open_idx: u32, close_idx: u32) bool {
        if (open_idx + 2 >= close_idx or close_idx > self.tokens.len) return false;
        const first = self.tokens[open_idx + 1].kind;
        if (!isExpressionIdentifierToken(first) and first != .kw_this) return false;
        const after_first = self.tokens[open_idx + 2].kind;
        if (after_first != .comma and after_first != .equal and after_first != .close_paren) return false;

        var paren_depth: u32 = 0;
        var bracket_depth: u32 = 0;
        var brace_depth: u32 = 0;
        var at_parameter_start = true;
        var i = open_idx + 1;
        while (i < close_idx) : (i += 1) {
            const kind = self.tokens[i].kind;
            const at_top = paren_depth == 0 and bracket_depth == 0 and brace_depth == 0;
            if (at_top) {
                if (at_parameter_start and kind == .open_paren) return true;
                if (kind == .comma) {
                    at_parameter_start = true;
                    continue;
                }
                if (at_parameter_start) at_parameter_start = false;
            }
            switch (kind) {
                .open_paren => paren_depth += 1,
                .close_paren => if (paren_depth > 0) {
                    paren_depth -= 1;
                },
                .open_bracket => bracket_depth += 1,
                .close_bracket => if (bracket_depth > 0) {
                    bracket_depth -= 1;
                },
                .open_brace => brace_depth += 1,
                .close_brace => if (brace_depth > 0) {
                    brace_depth -= 1;
                },
                else => {},
            }
        }
        return false;
    }

    fn parenContentsLookLikeTypedOrRestParams(self: *Parser, open_paren_idx: u32, after_paren_idx: u32) bool {
        var i = open_paren_idx + 1;
        while (i < after_paren_idx and i < self.tokens.len) : (i += 1) {
            switch (self.tokens[i].kind) {
                .colon, .dot_dot_dot => return true,
                else => {},
            }
        }
        return false;
    }

    fn reportNumericArrowRecoveryBodyDiagnostics(self: *Parser, body: NodeId) ParseError!void {
        if (body == hir_mod.none_node_id or self.hir.kindOf(body) != .block_stmt) return;
        const body_span = self.hir.spanOf(body);
        if (body_span.start >= body_span.end or body_span.end > self.source.len) return;
        const text = self.source[body_span.start..body_span.end];
        if (std.mem.indexOfScalar(u8, text, ';')) |semi_rel| {
            const pos = body_span.start + @as(u32, @intCast(semi_rel));
            if (pos > 0) {
                try self.reportCodeAt(pos - 1, self.lineAt(pos), 1005, "':' expected.");
            } else {
                try self.reportCodeAt(pos, self.lineAt(pos), 1005, "':' expected.");
            }
        }
        if (std.mem.lastIndexOfScalar(u8, text, '}')) |brace_rel| {
            const pos = body_span.start + @as(u32, @intCast(brace_rel));
            if (pos > 0) {
                try self.reportCodeAt(pos - 1, self.lineAt(pos), 1005, "',' expected.");
            } else {
                try self.reportCodeAt(pos, self.lineAt(pos), 1005, "',' expected.");
            }
        }
    }

    fn tryParseArrowWithMissingCloseParen(
        self: *Parser,
        start_tok: Token,
        is_async: bool,
        type_params: []const NodeId,
    ) ParseError!?NodeId {
        const checkpoint = self.cursor;
        const diag_checkpoint = self.diagnostics.items.len;
        if (self.findTopLevelArrowBeforeCloseParen(self.cursor) == null) return null;

        const saved_allow = self.allow_parameter_list_arrow_recovery;
        const saved_recovered = self.parameter_list_recovered_arrow_missing_close;
        self.allow_parameter_list_arrow_recovery = true;
        self.parameter_list_recovered_arrow_missing_close = false;
        defer {
            self.allow_parameter_list_arrow_recovery = saved_allow;
            self.parameter_list_recovered_arrow_missing_close = saved_recovered;
        }

        // Bump `async_function_depth` ahead of the parameter parse so
        // `async (await) => …` flags TS1359 on `await` (mirrors tsc).
        if (is_async) self.async_function_depth += 1;
        const params = self.parseParameterList() catch |err| {
            if (is_async) self.async_function_depth -= 1;
            self.cursor = checkpoint;
            self.diagnostics.items.len = diag_checkpoint;
            switch (err) {
                error.UnexpectedToken, error.UnexpectedEof, error.InvalidLeftHandSide => return null,
                else => return err,
            }
        };
        if (is_async) self.async_function_depth -= 1;
        defer self.gpa.free(params);
        if (!self.parameter_list_recovered_arrow_missing_close) {
            self.cursor = checkpoint;
            self.diagnostics.items.len = diag_checkpoint;
            return null;
        }
        _ = try self.expect(.arrow, "'=>' in arrow function");
        self.function_depth += 1;
        if (is_async) self.async_function_depth += 1;
        const prev_generator_depth = self.generator_depth;
        self.generator_depth = 0;
        defer {
            self.generator_depth = prev_generator_depth;
            self.function_depth -= 1;
            if (is_async) self.async_function_depth -= 1;
        }
        const body = try self.parseArrowBody();
        const close = self.peek();
        try self.reportCodeAtWithMatchedPair(
            close.span.start,
            close.line,
            1005,
            "')' expected.",
            start_tok.span.start,
            "(",
            ")",
        );
        const sp: Span = .{ .start = start_tok.span.start, .end = self.hir.spanOf(body).end };
        _ = type_params;
        return try self.builder.addFnDecl(
            sp,
            hir_mod.none_node_id,
            params,
            hir_mod.none_node_id,
            body,
            .{ .is_arrow = true, .is_async = is_async },
        );
    }

    /// Speculative: cursor points at `<` after a callee. Walk
    /// balanced angles + parens until we find the matching `>` at
    /// angle-depth 0. If the next non-trivia token is `(`, return
    /// the cursor at the `(`. Otherwise return null — the `<` is
    /// a less-than operator and the caller falls back to binop.
    ///
    /// Conservative: we bail on tokens that don't appear in TS
    /// type-arg lists (assignment, semicolon, EOF, etc.) since they
    /// indicate the `<` was a comparison.
    fn findCallTypeArgsEnd(self: *Parser, start: u32) ?u32 {
        if (start >= self.tokens.len or self.tokens[start].kind != .less_than) return null;
        var depth: i32 = 1;
        var i: u32 = start + 1;
        while (i < self.tokens.len) : (i += 1) {
            const tk = self.tokens[i].kind;
            switch (tk) {
                .less_than => depth += 1,
                .greater_than, .greater_greater, .greater_greater_greater => {
                    const count: u8 = switch (tk) {
                        .greater_than => 1,
                        .greater_greater => 2,
                        .greater_greater_greater => 3,
                        else => unreachable,
                    };
                    var n: u8 = 0;
                    while (n < count) : (n += 1) {
                        depth -= 1;
                        if (depth == 0) {
                            // Next token must be `(` or a template
                            // literal for this to be a generic call /
                            // tagged-template call.
                            const next = i + 1;
                            if (next < self.tokens.len and
                                (self.tokens[next].kind == .open_paren or
                                    self.tokens[next].kind == .no_substitution_template or
                                    self.tokens[next].kind == .template_head))
                            {
                                return next;
                            }
                            return null;
                        }
                    }
                },
                // Balanced delimiters that may appear inside type args.
                .open_paren, .open_bracket, .open_brace => {
                    if (self.skipBalancedFrom(i)) |after| {
                        i = after - 1; // -1 because the loop increments
                    } else return null;
                },
                // Tokens that disqualify this from being type args.
                .equal,
                .semicolon,
                .arrow,
                .question_dot,
                .invalid,
                .eof,
                => return null,
                else => {},
            }
        }
        return null;
    }

    fn findInstantiationTypeArgsEnd(self: *Parser, start: u32) ?u32 {
        if (start >= self.tokens.len or self.tokens[start].kind != .less_than) return null;
        var depth: i32 = 1;
        var i: u32 = start + 1;
        while (i < self.tokens.len) : (i += 1) {
            const tk = self.tokens[i].kind;
            switch (tk) {
                .less_than => depth += 1,
                .greater_than, .greater_greater, .greater_greater_greater => {
                    const count: u8 = switch (tk) {
                        .greater_than => 1,
                        .greater_greater => 2,
                        .greater_greater_greater => 3,
                        else => unreachable,
                    };
                    var n: u8 = 0;
                    while (n < count) : (n += 1) {
                        depth -= 1;
                        if (depth == 0) {
                            const next = i + 1;
                            if (next >= self.tokens.len) return null;
                            switch (self.tokens[next].kind) {
                                .dot,
                                .semicolon,
                                .comma,
                                .close_paren,
                                .close_bracket,
                                .close_brace,
                                .eof,
                                => return next,
                                else => return null,
                            }
                        }
                    }
                },
                .open_paren, .open_bracket, .open_brace => {
                    if (self.skipBalancedFrom(i)) |after| {
                        i = after - 1;
                    } else return null;
                },
                .equal,
                .semicolon,
                .arrow,
                .question_dot,
                .invalid,
                .eof,
                => return null,
                else => {},
            }
        }
        return null;
    }

    /// Parse the comma-separated type arguments of an explicit
    /// generic call. Cursor enters at `<`; returns with the cursor
    /// positioned at the token after `>` (the index `after_gt`
    /// returned by `findCallTypeArgsEnd`). The caller owns the
    /// returned slice.
    fn parseExplicitCallTypeArgs(self: *Parser, after_gt: u32) ParseError![]NodeId {
        var args: std.ArrayListUnmanaged(NodeId) = .empty;
        errdefer args.deinit(self.gpa);
        // Skip the opening `<`.
        std.debug.assert(self.peek().kind == .less_than);
        _ = self.advance();
        while (self.peek().kind != .greater_than) {
            const t = try self.parseTypeAnnotation();
            try args.append(self.gpa, t);
            if (self.peek().kind == .comma) {
                _ = self.advance();
                continue;
            }
            // No comma + no `>` → bail to checkpoint.
            if (self.peek().kind != .greater_than and
                self.peek().kind != .greater_greater and
                self.peek().kind != .greater_greater_greater) break;
        }
        // Force-advance to the verified continuation token even if
        // structural recovery failed.
        self.pending_type_gt = 0;
        self.pending_type_eq = false;
        self.cursor = after_gt;
        return args.toOwnedSlice(self.gpa);
    }

    fn isRegexFlagByte(c: u8) bool {
        return (c >= 'a' and c <= 'z') or
            (c >= 'A' and c <= 'Z') or
            (c >= '0' and c <= '9') or
            c == '_' or
            c == '$';
    }

    /// After resolving the regex literal end, walk the trailing flag
    /// characters and emit the same scanner diagnostics as tsc/tsgo:
    /// TS1499 for unknown flags, TS1500 for duplicate known flags, and
    /// TS1502 when `u` and `v` would both be active.
    fn reportInvalidRegexFlags(self: *Parser, start: u32, line: u32, end: u32) ParseError!void {
        const start_i: usize = @intCast(start);
        const end_i: usize = @intCast(end);
        if (start_i >= self.source.len) return;
        // Locate the closing `/` so we know where the flag run begins.
        var i: usize = start_i + 1;
        var escaped = false;
        var in_class = false;
        var close_at: ?usize = null;
        while (i < end_i and i < self.source.len) : (i += 1) {
            const c = self.source[i];
            if (escaped) {
                escaped = false;
                continue;
            }
            if (c == '\\') {
                escaped = true;
                continue;
            }
            if (c == '[') {
                in_class = true;
                continue;
            }
            if (c == ']' and in_class) {
                in_class = false;
                continue;
            }
            if (c == '/' and !in_class) {
                close_at = i;
                break;
            }
        }
        const flag_start = (close_at orelse return) + 1;
        var fi: usize = flag_start;
        var seen_flags: u8 = 0;
        while (fi < end_i and fi < self.source.len) : (fi += 1) {
            const fc = self.source[fi];
            const flag_bit: u8 = switch (fc) {
                'd' => 1 << 0,
                'g' => 1 << 1,
                'i' => 1 << 2,
                'm' => 1 << 3,
                's' => 1 << 4,
                'u' => 1 << 5,
                'v' => 1 << 6,
                'y' => 1 << 7,
                else => 0,
            };
            if (flag_bit == 0) {
                try self.reportCodeAtWithSpan(@intCast(fi), line, 1, 1499, "Unknown regular expression flag.");
            } else if ((seen_flags & flag_bit) != 0) {
                try self.reportCodeAtWithSpan(@intCast(fi), line, 1, 1500, "Duplicate regular expression flag.");
            } else if (((seen_flags | flag_bit) & ((1 << 5) | (1 << 6))) == ((1 << 5) | (1 << 6))) {
                try self.reportCodeAtWithSpan(@intCast(fi), line, 1, 1502, "The Unicode (u) flag and the Unicode Sets (v) flag cannot be set simultaneously.");
            } else {
                seen_flags |= flag_bit;
            }
        }
    }

    fn findRegexLiteralEnd(self: *Parser, start: u32) ?u32 {
        const start_i: usize = @intCast(start);
        if (start_i >= self.source.len or self.source[start_i] != '/') return null;
        var i: usize = start_i + 1;
        var escaped = false;
        var in_class = false;
        while (i < self.source.len) : (i += 1) {
            const c = self.source[i];
            if (c == '\n' or c == '\r') return null;
            if (escaped) {
                escaped = false;
                continue;
            }
            if (c == '\\') {
                escaped = true;
                continue;
            }
            if (c == '[') {
                in_class = true;
                continue;
            }
            if (c == ']' and in_class) {
                in_class = false;
                continue;
            }
            if (c == '/' and !in_class) {
                i += 1;
                while (i < self.source.len and isRegexFlagByte(self.source[i])) : (i += 1) {}
                return @intCast(i);
            }
        }
        return null;
    }

    fn findUnterminatedRegexRecoveryEnd(self: *Parser, start: u32) u32 {
        var i: usize = @intCast(start);
        if (i < self.source.len and self.source[i] == '/') i += 1;
        while (i < self.source.len) : (i += 1) {
            switch (self.source[i]) {
                '\n', '\r', ')', ']', '}', ';', ',' => break,
                else => {},
            }
        }
        return @intCast(i);
    }

    fn parseRegexLiteralExpression(self: *Parser) ParseError!NodeId {
        const start_tok = self.peek();
        const end = self.findRegexLiteralEnd(start_tok.span.start) orelse {
            try self.reportCodeAt(start_tok.span.start, start_tok.line, 1161, "Unterminated regular expression literal.");
            const recovery_end = self.findUnterminatedRegexRecoveryEnd(start_tok.span.start);
            var next = self.cursor;
            while (next < self.tokens.len and
                self.tokens[next].kind != .eof and
                self.tokens[next].span.end <= recovery_end)
            {
                next += 1;
            }
            if (next == self.cursor) next += 1;
            self.cursor = next;
            return try self.builder.addLiteralRegex(.{ .start = start_tok.span.start, .end = recovery_end });
        };
        try self.reportUnbalancedRegexGroup(start_tok, end);
        try self.reportRegexPatternModifierDiagnostics(start_tok, end);
        try self.reportRegexQuantifierDiagnostics(start_tok, end);
        try self.reportRegexEscapeAndClassDiagnostics(start_tok, end);
        try self.reportRegexGroupAndBackrefDiagnostics(start_tok, end);
        try self.reportRegexUnicodePropertyDiagnostics(start_tok, end);
        try self.reportRegexClassSetExpressionDiagnostics(start_tok, end);
        try self.reportInvalidRegexFlags(start_tok.span.start, start_tok.line, end);
        // The scanner committed to `.slash` (vs. `regex_literal`) based
        // on the preceding token, but the parser now knows this span is
        // a regex body. Record the span so the driver can drop any
        // scanner-emitted TS1127 ("Invalid character.") diagnostics
        // that landed on `\` or other stray bytes inside the regex.
        // Mirrors tsc's `reScanSlashToken` flow.
        if (start_tok.kind == .slash) {
            try self.regex_rescan_spans.append(self.gpa, .{
                .start = start_tok.span.start,
                .end = end,
            });
        }
        var next = self.cursor;
        while (next < self.tokens.len and
            self.tokens[next].kind != .eof and
            self.tokens[next].span.end <= end)
        {
            next += 1;
        }
        if (next == self.cursor) next += 1;
        self.cursor = next;
        return try self.builder.addLiteralRegex(.{ .start = start_tok.span.start, .end = end });
    }

    fn reportRegexQuantifierDiagnostics(self: *Parser, start_tok: Token, end: u32) ParseError!void {
        const start_i: usize = @intCast(start_tok.span.start);
        const end_i: usize = @intCast(end);
        if (start_i >= self.source.len or self.source[start_i] != '/') return;
        const close_at = self.regexLiteralClose(start_i, end_i) orelse return;
        const unicode_mode = self.regexLiteralHasFlag(close_at + 1, end_i, 'u') or
            self.regexLiteralHasFlag(close_at + 1, end_i, 'v');

        var i = start_i + 1;
        var previous_quantifiable = false;
        while (i < close_at and i < self.source.len) {
            const ch = self.source[i];
            switch (ch) {
                '\\' => {
                    if (i + 1 < close_at and (self.source[i + 1] == 'b' or self.source[i + 1] == 'B')) {
                        i += 2;
                        previous_quantifiable = false;
                    } else {
                        i += if (i + 1 < close_at) 2 else 1;
                        previous_quantifiable = true;
                    }
                },
                '[' => {
                    i += 1;
                    var escaped = false;
                    while (i < close_at and i < self.source.len) : (i += 1) {
                        const cc = self.source[i];
                        if (escaped) {
                            escaped = false;
                            continue;
                        }
                        if (cc == '\\') {
                            escaped = true;
                            continue;
                        }
                        if (cc == ']') {
                            i += 1;
                            break;
                        }
                    }
                    previous_quantifiable = true;
                },
                '(' => {
                    i += 1;
                    previous_quantifiable = false;
                },
                ')' => {
                    i += 1;
                    previous_quantifiable = true;
                },
                '|' => {
                    i += 1;
                    previous_quantifiable = false;
                },
                '^', '$' => {
                    i += 1;
                    previous_quantifiable = false;
                },
                '*', '+', '?' => {
                    const quant_start = i;
                    i += 1;
                    if (i < close_at and self.source[i] == '?') i += 1;
                    if (!previous_quantifiable) {
                        try self.reportCodeAtWithSpan(
                            @intCast(quant_start),
                            start_tok.line,
                            @intCast(i - quant_start),
                            1507,
                            "There is nothing available for repetition.",
                        );
                    }
                    previous_quantifiable = false;
                },
                '{' => {
                    const quant_start = i;
                    var j = i + 1;
                    const min_start = j;
                    while (j < close_at and std.ascii.isDigit(self.source[j])) : (j += 1) {}
                    const min_end = j;
                    const min_len = min_end - min_start;
                    var recognized = false;
                    if (j < close_at and self.source[j] == ',') {
                        j += 1;
                        const max_start = j;
                        while (j < close_at and std.ascii.isDigit(self.source[j])) : (j += 1) {}
                        const max_end = j;
                        if (min_len == 0) {
                            if (max_end > max_start or (j < close_at and self.source[j] == '}')) {
                                try self.reportCodeAtWithSpan(
                                    @intCast(min_start),
                                    start_tok.line,
                                    0,
                                    1505,
                                    "Incomplete quantifier. Digit expected.",
                                );
                                recognized = true;
                            } else if (unicode_mode) {
                                recognized = true;
                            } else {
                                previous_quantifiable = true;
                                i = quant_start + 1;
                                continue;
                            }
                        } else if (max_end > max_start and decimalStringGreater(self.source[min_start..min_end], self.source[max_start..max_end]) and
                            (unicode_mode or (j < close_at and self.source[j] == '}')))
                        {
                            try self.reportCodeAtWithSpan(
                                @intCast(min_start),
                                start_tok.line,
                                @intCast(max_end - min_start),
                                1506,
                                "Numbers out of order in quantifier.",
                            );
                        }
                        if (min_len > 0 or unicode_mode) recognized = true;
                    } else if (min_len > 0) {
                        recognized = true;
                    } else if (!unicode_mode) {
                        previous_quantifiable = true;
                        i = quant_start + 1;
                        continue;
                    }
                    if (recognized and j < close_at and self.source[j] == '}') {
                        j += 1;
                        if (j < close_at and self.source[j] == '?') j += 1;
                        if (!previous_quantifiable) {
                            try self.reportCodeAtWithSpan(
                                @intCast(quant_start),
                                start_tok.line,
                                @intCast(j - quant_start),
                                1507,
                                "There is nothing available for repetition.",
                            );
                        }
                        previous_quantifiable = false;
                        i = j;
                    } else {
                        previous_quantifiable = true;
                        i = quant_start + 1;
                    }
                },
                else => {
                    i += 1;
                    previous_quantifiable = true;
                },
            }
        }
    }

    fn reportRegexPatternModifierDiagnostics(self: *Parser, start_tok: Token, end: u32) ParseError!void {
        const start_i: usize = @intCast(start_tok.span.start);
        const end_i: usize = @intCast(end);
        if (start_i >= self.source.len or self.source[start_i] != '/') return;
        const close_at = self.regexLiteralClose(start_i, end_i) orelse return;

        var i = start_i + 1;
        var escaped = false;
        var in_class = false;
        while (i < close_at and i < self.source.len) : (i += 1) {
            const ch = self.source[i];
            if (escaped) {
                escaped = false;
                continue;
            }
            if (ch == '\\') {
                escaped = true;
                continue;
            }
            if (ch == '[') {
                in_class = true;
                continue;
            }
            if (ch == ']' and in_class) {
                in_class = false;
                continue;
            }
            if (in_class) continue;
            if (ch != '(' or i + 1 >= close_at or self.source[i + 1] != '?') continue;
            if (i + 2 < close_at) {
                switch (self.source[i + 2]) {
                    '=', '!', '<' => continue,
                    else => {},
                }
            }

            const flags_start = i + 2;
            var pos = flags_start;
            var set_flags: u8 = 0;
            pos = try self.scanRegexPatternModifiers(pos, close_at, start_tok.line, set_flags);
            set_flags = self.regexPatternModifierMask(flags_start, pos);
            if (pos < close_at and self.source[pos] == '-') {
                pos += 1;
                _ = try self.scanRegexPatternModifiers(pos, close_at, start_tok.line, set_flags);
                if (pos == flags_start + 1) {
                    try self.reportCodeAtWithSpan(
                        @intCast(flags_start),
                        start_tok.line,
                        @intCast(pos - flags_start),
                        1504,
                        "Subpattern flags must be present when there is a minus sign.",
                    );
                }
            }
        }
    }

    fn scanRegexPatternModifiers(self: *Parser, start: usize, close_at: usize, line: u32, initial_flags: u8) ParseError!usize {
        var pos = start;
        var seen_flags = initial_flags;
        while (pos < close_at and pos < self.source.len and isRegexFlagByte(self.source[pos])) : (pos += 1) {
            const fc = self.source[pos];
            const flag_bit: u8 = switch (fc) {
                'd' => 1 << 0,
                'g' => 1 << 1,
                'i' => 1 << 2,
                'm' => 1 << 3,
                's' => 1 << 4,
                'u' => 1 << 5,
                'v' => 1 << 6,
                'y' => 1 << 7,
                else => 0,
            };
            if (flag_bit == 0) {
                try self.reportCodeAtWithSpan(@intCast(pos), line, 1, 1499, "Unknown regular expression flag.");
            } else if ((seen_flags & flag_bit) != 0) {
                try self.reportCodeAtWithSpan(@intCast(pos), line, 1, 1500, "Duplicate regular expression flag.");
            } else if ((flag_bit & ((1 << 2) | (1 << 3) | (1 << 4))) == 0) {
                try self.reportCodeAtWithSpan(@intCast(pos), line, 1, 1509, "This regular expression flag cannot be toggled within a subpattern.");
            } else {
                seen_flags |= flag_bit;
            }
        }
        return pos;
    }

    fn regexPatternModifierMask(self: *Parser, start: usize, end: usize) u8 {
        var mask: u8 = 0;
        var i = start;
        while (i < end and i < self.source.len) : (i += 1) {
            mask |= switch (self.source[i]) {
                'd' => 1 << 0,
                'g' => 1 << 1,
                'i' => 1 << 2,
                'm' => 1 << 3,
                's' => 1 << 4,
                'u' => 1 << 5,
                'v' => 1 << 6,
                'y' => 1 << 7,
                else => 0,
            };
        }
        return mask;
    }

    fn regexLiteralClose(self: *Parser, start_i: usize, end_i: usize) ?usize {
        var i = start_i + 1;
        var escaped = false;
        var in_class = false;
        while (i < end_i and i < self.source.len) : (i += 1) {
            const c = self.source[i];
            if (escaped) {
                escaped = false;
                continue;
            }
            if (c == '\\') {
                escaped = true;
                continue;
            }
            if (c == '[') {
                in_class = true;
                continue;
            }
            if (c == ']' and in_class) {
                in_class = false;
                continue;
            }
            if (c == '/' and !in_class) return i;
        }
        return null;
    }

    fn regexLiteralHasFlag(self: *Parser, flag_start: usize, end_i: usize, flag: u8) bool {
        var i = flag_start;
        while (i < end_i and i < self.source.len) : (i += 1) {
            if (self.source[i] == flag) return true;
        }
        return false;
    }

    fn regexLiteralHasNamedCaptureGroup(self: *Parser, body_start: usize, close_at: usize) bool {
        var i = body_start;
        var escaped = false;
        var in_class = false;
        while (i < close_at and i < self.source.len) : (i += 1) {
            const c = self.source[i];
            if (escaped) {
                escaped = false;
                continue;
            }
            if (c == '\\') {
                escaped = true;
                continue;
            }
            if (c == '[') {
                in_class = true;
                continue;
            }
            if (c == ']' and in_class) {
                in_class = false;
                continue;
            }
            if (in_class) continue;
            if (c == '(' and i + 2 < close_at and self.source[i + 1] == '?' and self.source[i + 2] == '<') {
                if (i + 3 < close_at and (self.source[i + 3] == '=' or self.source[i + 3] == '!')) continue;
                return true;
            }
        }
        return false;
    }

    fn decimalStringGreater(a_raw: []const u8, b_raw: []const u8) bool {
        var a = a_raw;
        var b = b_raw;
        while (a.len > 0 and a[0] == '0') a = a[1..];
        while (b.len > 0 and b[0] == '0') b = b[1..];
        if (a.len != b.len) return a.len > b.len;
        return std.mem.order(u8, a, b) == .gt;
    }

    fn reportRegexEscapeAndClassDiagnostics(self: *Parser, start_tok: Token, end: u32) ParseError!void {
        const start_i: usize = @intCast(start_tok.span.start);
        const end_i: usize = @intCast(end);
        if (start_i >= self.source.len or self.source[start_i] != '/') return;
        const close_at = self.regexLiteralClose(start_i, end_i) orelse return;
        const unicode_sets_mode = self.regexLiteralHasFlag(close_at + 1, end_i, 'v');
        const unicode_mode = self.regexLiteralHasFlag(close_at + 1, end_i, 'u') or unicode_sets_mode;
        const named_capture_groups = self.regexLiteralHasNamedCaptureGroup(start_i + 1, close_at);

        var i = start_i + 1;
        while (i < close_at and i < self.source.len) {
            const ch = self.source[i];
            if (ch == '\\') {
                if ((unicode_mode or named_capture_groups) and i + 1 < close_at and self.source[i + 1] == 'k' and
                    (i + 2 >= close_at or self.source[i + 2] != '<'))
                {
                    try self.reportCodeAtWithSpan(
                        @intCast(i),
                        start_tok.line,
                        2,
                        1510,
                        "'\\k' must be followed by a capturing group name enclosed in angle brackets.",
                    );
                }
                if (unicode_sets_mode and i + 1 < close_at and self.source[i + 1] == 'q') {
                    try self.reportCodeAtWithSpan(
                        @intCast(i),
                        start_tok.line,
                        2,
                        1511,
                        "'\\q' is only available inside character class.",
                    );
                }
                try self.reportInvalidControlEscapeIfNeeded(i, close_at, start_tok.line, unicode_mode);
                try self.reportRegexAtomEscapeDiagnostics(i, close_at, start_tok.line, unicode_mode);
                i += if (i + 1 < close_at) 2 else 1;
                continue;
            }
            if (ch == '[') {
                i = try self.scanRegexClassForRangeDiagnostics(i + 1, close_at, start_tok.line, unicode_mode);
                continue;
            }
            i += 1;
        }
    }

    /// Diagnostics for a single `\`-escape that appears OUTSIDE a
    /// character class (an "atom escape"). Ports the relevant arms of
    /// tsc's `scanCharacterEscape`/`scanEscapeSequence`:
    ///   - TS1538 `Unicode escape sequences are only available when the
    ///     Unicode (u) flag or the Unicode Sets (v) flag is set.` — an
    ///     extended `\u{...}` escape used without the u/v flag.
    ///   - TS1535 `This character cannot be escaped in a regular
    ///     expression.` — an identity escape of an identifier-part
    ///     character that is not a recognized escape, only diagnosed in
    ///     Unicode mode (mirrors the non-AnnexB default arm).
    ///   - TS1513 `Undetermined character escape.` — the escape marker
    ///     reaches the end of the regex body without an escaped
    ///     character.
    /// `slash_pos` points at the `\`.
    fn reportRegexAtomEscapeDiagnostics(
        self: *Parser,
        slash_pos: usize,
        limit: usize,
        line: u32,
        unicode_mode: bool,
    ) ParseError!void {
        if (slash_pos + 1 >= limit or slash_pos + 1 >= self.source.len) {
            try self.reportCodeAtWithSpan(@intCast(slash_pos), line, 1, 1513, "Undetermined character escape.");
            return;
        }
        const esc = self.source[slash_pos + 1];
        // Extended `\u{...}` escapes require Unicode mode.
        if (esc == 'u' and slash_pos + 2 < limit and self.source[slash_pos + 2] == '{' and !unicode_mode) {
            var p = slash_pos + 3;
            while (p < limit and self.source[p] != '}') : (p += 1) {}
            const span_end = if (p < limit and self.source[p] == '}') p + 1 else p;
            try self.reportCodeAtWithSpan(
                @intCast(slash_pos),
                line,
                @intCast(span_end - slash_pos),
                1538,
                "Unicode escape sequences are only available when the Unicode (u) flag or the Unicode Sets (v) flag is set.",
            );
            return;
        }
        if (!unicode_mode) return;
        // In Unicode mode, only the recognized escape set is valid. An
        // identity escape of an identifier-part character that is not a
        // recognized class/character escape is an error. Mirrors the
        // `IdentifierPart` default arm of tsc's scanner.
        if (isRegexValidIdentityOrKnownEscape(esc)) return;
        if (isRegexIdentifierPart(esc)) {
            try self.reportCodeAtWithSpan(@intCast(slash_pos), line, 2, 1535, "This character cannot be escaped in a regular expression.");
        }
    }

    /// The set of characters that form a recognized escape in a regular
    /// expression body (control/character-class escapes, hex/unicode
    /// escapes, the syntax-character identity escapes, and back/named
    /// references). Anything outside this set that is an identifier
    /// part triggers TS1535 in Unicode mode.
    fn isRegexValidIdentityOrKnownEscape(c: u8) bool {
        return switch (c) {
            // Control + character-class escapes.
            'b', 'B', 'd', 'D', 's', 'S', 'w', 'W', 'f', 'n', 'r', 't', 'v', '0' => true,
            // Hex / unicode / control-letter / property / named-ref.
            'x', 'u', 'c', 'p', 'P', 'k' => true,
            // Syntax-character identity escapes.
            '^', '$', '/', '\\', '.', '*', '+', '?', '(', ')', '[', ']', '{', '}', '|', '-' => true,
            else => false,
        };
    }

    /// Approximation of tsc's `IsIdentifierPart` restricted to the ASCII
    /// range relevant for regex identity escapes (`\q`, `\m`, etc.).
    fn isRegexIdentifierPart(c: u8) bool {
        return std.ascii.isAlphanumeric(c) or c == '_' or c == '$';
    }

    fn reportInvalidControlEscapeIfNeeded(
        self: *Parser,
        slash_pos: usize,
        limit: usize,
        line: u32,
        unicode_mode: bool,
    ) ParseError!void {
        if (!unicode_mode) return;
        if (slash_pos + 1 >= limit or self.source[slash_pos + 1] != 'c') return;
        if (slash_pos + 2 < limit and std.ascii.isAlphabetic(self.source[slash_pos + 2])) return;
        try self.reportCodeAtWithSpan(
            @intCast(slash_pos),
            line,
            2,
            1512,
            "'\\c' must be followed by an ASCII letter.",
        );
    }

    const RegexClassAtom = struct {
        start: usize,
        end: usize,
        value: ?u21,
    };

    fn scanRegexClassForRangeDiagnostics(
        self: *Parser,
        class_start: usize,
        close_at: usize,
        line: u32,
        unicode_mode: bool,
    ) ParseError!usize {
        var i = class_start;
        if (i < close_at and self.source[i] == '^') i += 1;
        while (i < close_at and i < self.source.len) {
            if (self.source[i] == ']') return i + 1;
            const min_atom = try self.scanRegexClassAtom(i, close_at, line, unicode_mode);
            i = min_atom.end;
            if (i >= close_at or i >= self.source.len or self.source[i] != '-') continue;
            if (i + 1 >= close_at or self.source[i + 1] == ']') {
                i += 1;
                continue;
            }
            i += 1;
            const max_atom = try self.scanRegexClassAtom(i, close_at, line, unicode_mode);
            i = max_atom.end;
            if (min_atom.value) |min_value| {
                if (max_atom.value) |max_value| {
                    if (min_value > max_value) {
                        try self.reportCodeAtWithSpan(
                            @intCast(min_atom.start),
                            line,
                            @intCast(max_atom.end - min_atom.start),
                            1517,
                            "Range out of order in character class.",
                        );
                    }
                }
            }
        }
        return i;
    }

    fn scanRegexClassAtom(
        self: *Parser,
        start: usize,
        limit: usize,
        line: u32,
        unicode_mode: bool,
    ) ParseError!RegexClassAtom {
        if (start >= limit or start >= self.source.len) return .{ .start = start, .end = start, .value = null };
        if (self.source[start] != '\\') {
            return .{ .start = start, .end = start + 1, .value = self.source[start] };
        }
        if (start + 1 >= limit) return .{ .start = start, .end = start + 1, .value = null };
        const esc = self.source[start + 1];
        if (esc == 'c') {
            try self.reportInvalidControlEscapeIfNeeded(start, limit, line, unicode_mode);
            if (start + 2 < limit and std.ascii.isAlphabetic(self.source[start + 2])) {
                return .{ .start = start, .end = start + 3, .value = @as(u21, self.source[start + 2]) & 0x1f };
            }
            return .{ .start = start, .end = @min(start + 2, limit), .value = null };
        }
        switch (esc) {
            'n' => return .{ .start = start, .end = start + 2, .value = '\n' },
            'r' => return .{ .start = start, .end = start + 2, .value = '\r' },
            't' => return .{ .start = start, .end = start + 2, .value = '\t' },
            'f' => return .{ .start = start, .end = start + 2, .value = 0x0c },
            'v' => return .{ .start = start, .end = start + 2, .value = 0x0b },
            'b' => return .{ .start = start, .end = start + 2, .value = 0x08 },
            'd', 'D', 's', 'S', 'w', 'W' => return .{ .start = start, .end = start + 2, .value = null },
            // Octal escape sequences inside a character class.
            // TS1536: `\1`..`\7` (and `\0` followed by another octal
            // digit) are not allowed in a character class. `\0` alone
            // is the NUL byte and stays legal. Mirrors tsc's
            // `scanEscapeSequence` octal arm with the AtomEscape flag
            // cleared (the character-class context).
            '0'...'7' => {
                var p = start + 1;
                // `\0` not followed by a digit is the NUL character.
                if (esc == '0' and (p + 1 >= limit or !std.ascii.isDigit(self.source[p + 1]))) {
                    return .{ .start = start, .end = start + 2, .value = 0 };
                }
                // Consume the octal run: leading digit + up to two more
                // octal digits (three total for a leading 0-3, two for
                // 4-7). Match tsc's longest-octal-run shape.
                p += 1;
                const max_digits: usize = if (esc <= '3') 2 else 1;
                var consumed: usize = 0;
                while (consumed < max_digits and p < limit and p < self.source.len and
                    self.source[p] >= '0' and self.source[p] <= '7') : (p += 1)
                {
                    consumed += 1;
                }
                var code: u21 = 0;
                for (self.source[start + 1 .. p]) |d| code = code * 8 + (d - '0');
                const msg = try std.fmt.allocPrint(
                    self.diag_arena.allocator(),
                    "Octal escape sequences and backreferences are not allowed in a character class. If this was intended as an escape sequence, use the syntax '\\x{x:0>2}' instead.",
                    .{code},
                );
                try self.reportCodeWithSpanAt(@intCast(start), line, 1536, @intCast(p - start), msg);
                return .{ .start = start, .end = p, .value = code };
            },
            // TS1537: decimal escapes `\8`/`\9` are not allowed in a
            // character class.
            '8', '9' => {
                try self.reportCodeWithSpanAt(@intCast(start), line, 1537, 2, "Decimal escape sequences and backreferences are not allowed in a character class.");
                return .{ .start = start, .end = start + 2, .value = esc };
            },
            'x' => {
                if (start + 3 < limit) {
                    if (hexValue(self.source[start + 2])) |hi| {
                        if (hexValue(self.source[start + 3])) |lo| {
                            return .{ .start = start, .end = start + 4, .value = (@as(u21, hi) << 4) | lo };
                        }
                    }
                }
                return .{ .start = start, .end = start + 2, .value = null };
            },
            'u' => {
                if (start + 2 < limit and self.source[start + 2] == '{') {
                    var p = start + 3;
                    var value: u21 = 0;
                    var saw_digit = false;
                    while (p < limit and self.source[p] != '}') : (p += 1) {
                        const hv = hexValue(self.source[p]) orelse return .{ .start = start, .end = p + 1, .value = null };
                        saw_digit = true;
                        value = (value << 4) | hv;
                    }
                    if (saw_digit and p < limit and self.source[p] == '}') {
                        // TS1538: extended `\u{...}` escapes are only
                        // valid with the u/v flag. Mirrors tsc's
                        // `AllowExtendedUnicodeEscape` gate.
                        if (!unicode_mode) {
                            try self.reportCodeWithSpanAt(@intCast(start), line, 1538, @intCast(p + 1 - start), "Unicode escape sequences are only available when the Unicode (u) flag or the Unicode Sets (v) flag is set.");
                        }
                        return .{ .start = start, .end = p + 1, .value = value };
                    }
                } else if (start + 5 < limit) {
                    var value: u21 = 0;
                    var p = start + 2;
                    while (p < start + 6) : (p += 1) {
                        const hv = hexValue(self.source[p]) orelse return .{ .start = start, .end = p + 1, .value = null };
                        value = (value << 4) | hv;
                    }
                    return .{ .start = start, .end = start + 6, .value = value };
                }
                return .{ .start = start, .end = start + 2, .value = null };
            },
            else => {
                // TS1535: in Unicode mode, an identity escape of an
                // identifier-part character that is not a recognized
                // escape is invalid (e.g. `[\q]` under the `u` flag).
                if (unicode_mode and !isRegexValidIdentityOrKnownEscape(esc) and isRegexIdentifierPart(esc)) {
                    try self.reportCodeWithSpanAt(@intCast(start), line, 1535, 2, "This character cannot be escaped in a regular expression.");
                }
                return .{ .start = start, .end = start + 2, .value = esc };
            },
        }
    }

    fn hexValue(ch: u8) ?u21 {
        return switch (ch) {
            '0'...'9' => ch - '0',
            'a'...'f' => 10 + ch - 'a',
            'A'...'F' => 10 + ch - 'A',
            else => null,
        };
    }

    fn reportUnbalancedRegexGroup(self: *Parser, start_tok: Token, end: u32) ParseError!void {
        const start_i: usize = @intCast(start_tok.span.start);
        const end_i: usize = @intCast(end);
        if (start_i >= self.source.len or self.source[start_i] != '/') return;
        var i = start_i + 1;
        var escaped = false;
        var in_class = false;
        var group_depth: u32 = 0;
        while (i < end_i and i < self.source.len) : (i += 1) {
            const c = self.source[i];
            if (escaped) {
                escaped = false;
                continue;
            }
            if (c == '\\') {
                escaped = true;
                continue;
            }
            if (c == '[') {
                in_class = true;
                continue;
            }
            if (c == ']' and in_class) {
                in_class = false;
                continue;
            }
            if (c == '/' and !in_class) break;
            if (in_class) continue;
            if (c == '(') {
                group_depth += 1;
            } else if (c == ')' and group_depth > 0) {
                group_depth -= 1;
            }
        }
        if (group_depth > 0) {
            try self.reportCodeAt(@intCast(i), start_tok.line, 1005, "')' expected.");
        }
    }

    // ====================================================================
    // Capturing-group / backreference resolution (ports the bookkeeping of
    // tsc's `regExpParser` in typescript-go's scanner/regexp.go).
    //
    // tsc collects, during a single pass over the body:
    //   - the number of (named + unnamed) capturing groups,
    //   - the set of named-group specifiers (with per-alternation-branch
    //     scopes so duplicate names in *mutually exclusive* branches are
    //     allowed),
    //   - every `\k<name>` named reference,
    //   - every `\1`..`\NN` decimal escape.
    // After the pass it reports:
    //   - TS1514 Expected a capturing group name. (empty `(?<>`/`\k<>`)
    //   - TS1515 Named capturing groups with the same name must be
    //            mutually exclusive to each other.
    //   - TS1532 There is no capturing group named '{0}' ... (dangling ref)
    //   - TS1533 ... only {0} capturing groups ... (decimal escape > count)
    //   - TS1534 ... no capturing groups ... (decimal escape, count == 0)
    // ====================================================================

    const RegexGroupRef = struct {
        pos: usize,
        len: usize,
        name: []const u8,
    };
    const RegexDecimalEscape = struct {
        pos: usize,
        len: usize,
        value: u64,
    };

    /// A flat representation of the group-name scope stack. Each named
    /// definition records the alternation-branch path (a sequence of
    /// disjunction-instance ids) under which it was declared. Two names
    /// collide (TS1515) only when one path is a prefix of the other —
    /// i.e. they are reachable on the same alternation path. Names in
    /// sibling `|` branches diverge at some level and never collide.
    const RegexNamedDef = struct {
        name: []const u8,
        path: []const u32,
    };

    fn reportRegexGroupAndBackrefDiagnostics(self: *Parser, start_tok: Token, end: u32) ParseError!void {
        const start_i: usize = @intCast(start_tok.span.start);
        const end_i: usize = @intCast(end);
        if (start_i >= self.source.len or self.source[start_i] != '/') return;
        const close_at = self.regexLiteralClose(start_i, end_i) orelse return;
        const unicode_mode = self.regexLiteralHasFlag(close_at + 1, end_i, 'u') or
            self.regexLiteralHasFlag(close_at + 1, end_i, 'v');
        const named_capture_groups = self.regexLiteralHasNamedCaptureGroup(start_i + 1, close_at);
        const allow_named_refs = unicode_mode or named_capture_groups;

        var arena = std.heap.ArenaAllocator.init(self.gpa);
        defer arena.deinit();
        const a = arena.allocator();

        var defs: std.ArrayListUnmanaged(RegexNamedDef) = .empty;
        var refs: std.ArrayListUnmanaged(RegexGroupRef) = .empty;
        var decimals: std.ArrayListUnmanaged(RegexDecimalEscape) = .empty;
        var group_count: u64 = 0;

        // Branch path stack: each `(`-opened disjunction pushes a fresh
        // branch counter; a `|` at the current depth advances the counter
        // so siblings diverge. The path is the running prefix.
        var path: std.ArrayListUnmanaged(u32) = .empty;
        try path.append(a, 0);

        var i = start_i + 1;
        var in_class = false;
        while (i < close_at and i < self.source.len) {
            const ch = self.source[i];
            if (ch == '\\') {
                // Escapes: handle named refs and decimal escapes outside
                // a character class. Inside a class, decimal escapes are
                // handled by the class diagnostics (TS1536/1537) and do
                // not contribute backreferences.
                if (!in_class and i + 1 < close_at) {
                    const e = self.source[i + 1];
                    if (e == 'k' and allow_named_refs and i + 2 < close_at and self.source[i + 2] == '<') {
                        const name_start = i + 3;
                        var p = name_start;
                        while (p < close_at and self.source[p] != '>') : (p += 1) {}
                        const name = self.source[name_start..@min(p, close_at)];
                        if (name.len == 0) {
                            try self.reportCodeAtWithSpan(@intCast(name_start), start_tok.line, 0, 1514, "Expected a capturing group name.");
                        } else {
                            try refs.append(a, .{ .pos = name_start, .len = name.len, .name = name });
                        }
                        i = if (p < close_at) p + 1 else p;
                        continue;
                    }
                    if (e >= '1' and e <= '9') {
                        const ds = i + 1;
                        var p = ds;
                        while (p < close_at and std.ascii.isDigit(self.source[p])) : (p += 1) {}
                        var value: u64 = 0;
                        var overflow = false;
                        for (self.source[ds..p]) |d| {
                            value = std.math.mul(u64, value, 10) catch blk: {
                                overflow = true;
                                break :blk std.math.maxInt(u64);
                            };
                            value = std.math.add(u64, value, d - '0') catch blk: {
                                overflow = true;
                                break :blk std.math.maxInt(u64);
                            };
                        }
                        if (overflow) value = std.math.maxInt(u64);
                        try decimals.append(a, .{ .pos = i, .len = p - i, .value = value });
                        i = p;
                        continue;
                    }
                }
                // Skip the escaped char (2 bytes), or a lone trailing `\`.
                i += if (i + 1 < close_at) 2 else 1;
                continue;
            }
            if (ch == '[') {
                in_class = true;
                i += 1;
                continue;
            }
            if (ch == ']' and in_class) {
                in_class = false;
                i += 1;
                continue;
            }
            if (in_class) {
                i += 1;
                continue;
            }
            if (ch == '|') {
                // Advance the current branch counter so the names declared
                // after the `|` live in a divergent path.
                path.items[path.items.len - 1] += 1;
                i += 1;
                continue;
            }
            if (ch == '(') {
                if (i + 1 < close_at and self.source[i + 1] == '?') {
                    // (?:  (?=  (?!  (?<=  (?<!  (?<name>  (?flags...:
                    if (i + 2 < close_at and self.source[i + 2] == '<' and
                        (i + 3 >= close_at or (self.source[i + 3] != '=' and self.source[i + 3] != '!')))
                    {
                        // Named capturing group `(?<name>`.
                        group_count += 1;
                        const name_start = i + 3;
                        var p = name_start;
                        while (p < close_at and self.source[p] != '>') : (p += 1) {}
                        const name = self.source[name_start..@min(p, close_at)];
                        if (name.len == 0) {
                            try self.reportCodeAtWithSpan(@intCast(name_start), start_tok.line, 0, 1514, "Expected a capturing group name.");
                        } else {
                            // TS1515: duplicate name on a shared path.
                            var collides = false;
                            for (defs.items) |d| {
                                if (std.mem.eql(u8, d.name, name) and regexPathsShareAlternation(d.path, path.items)) {
                                    collides = true;
                                    break;
                                }
                            }
                            if (collides) {
                                try self.reportCodeAtWithSpan(@intCast(name_start), start_tok.line, @intCast(name.len), 1515, "Named capturing groups with the same name must be mutually exclusive to each other.");
                            } else {
                                const path_copy = try a.dupe(u32, path.items);
                                try defs.append(a, .{ .name = name, .path = path_copy });
                            }
                        }
                        // Enter a new disjunction scope inside this group.
                        try path.append(a, 0);
                        i = if (p < close_at) p + 1 else p;
                        continue;
                    }
                    // Non-capturing group / lookaround / modifier group:
                    // still opens a disjunction scope.
                    try path.append(a, 0);
                    i += 2;
                    continue;
                }
                // Plain capturing group.
                group_count += 1;
                try path.append(a, 0);
                i += 1;
                continue;
            }
            if (ch == ')') {
                if (path.items.len > 1) _ = path.pop();
                i += 1;
                continue;
            }
            i += 1;
        }

        // Resolve named references (TS1532).
        for (refs.items) |ref| {
            var found = false;
            for (defs.items) |d| {
                if (std.mem.eql(u8, d.name, ref.name)) {
                    found = true;
                    break;
                }
            }
            if (!found) {
                const msg = try std.fmt.allocPrint(
                    self.diag_arena.allocator(),
                    "There is no capturing group named '{s}' in this regular expression.",
                    .{ref.name},
                );
                try self.reportCodeAtWithSpan(@intCast(ref.pos), start_tok.line, @intCast(ref.len), 1532, msg);
            }
        }

        // Resolve numeric backreferences (TS1533 / TS1534). tsc reports a
        // decimal escape whose value exceeds the number of capturing
        // groups even though Annex B would otherwise treat it as a legacy
        // octal/identity escape.
        for (decimals.items) |de| {
            if (de.value > group_count) {
                if (group_count > 0) {
                    const msg = try std.fmt.allocPrint(
                        self.diag_arena.allocator(),
                        "This backreference refers to a group that does not exist. There are only {d} capturing groups in this regular expression.",
                        .{group_count},
                    );
                    try self.reportCodeAtWithSpan(@intCast(de.pos), start_tok.line, @intCast(de.len), 1533, msg);
                } else {
                    try self.reportCodeAtWithSpan(@intCast(de.pos), start_tok.line, @intCast(de.len), 1534, "This backreference refers to a group that does not exist. There are no capturing groups in this regular expression.");
                }
            }
        }
    }

    /// Two branch paths share an alternation path (and therefore their
    /// named groups collide for TS1515) when neither diverges from the
    /// other before its end: one must be a prefix of the other. Mirrors
    /// tsc's `namedCapturingGroupsContains`, which only consults scopes on
    /// the stack at the time a group is declared.
    fn regexPathsShareAlternation(a: []const u32, b: []const u32) bool {
        const n = @min(a.len, b.len);
        var i: usize = 0;
        while (i < n) : (i += 1) {
            if (a[i] != b[i]) return false;
        }
        return true;
    }

    // ====================================================================
    // Unicode property value expression validation (`\p{...}` / `\P{...}`).
    // Ports tsc's `scanCharacterClassEscape` property arm + the property
    // tables from typescript-go's scanner/unicodeproperties.go:
    //   - TS1523 Expected a Unicode property name. (`\p{=value}`)
    //   - TS1524 Unknown Unicode property name.
    //   - TS1525 Expected a Unicode property value. (`\p{name=}`)
    //   - TS1526 Unknown Unicode property value.
    //   - TS1527 Expected a Unicode property name or value. (`\p{}`)
    //   - TS1528 Any Unicode property that would possibly match more than a
    //            single character ... (string-prop without v flag)
    //   - TS1529 Unknown Unicode property name or value.
    //   - TS1530 Unicode property value expressions are only available when
    //            the Unicode (u) flag or the Unicode Sets (v) flag is set.
    //   - TS1531 '\p'/'\P' must be followed by a Unicode property value
    //            expression enclosed in braces.
    // ====================================================================

    fn reportRegexUnicodePropertyDiagnostics(self: *Parser, start_tok: Token, end: u32) ParseError!void {
        const start_i: usize = @intCast(start_tok.span.start);
        const end_i: usize = @intCast(end);
        if (start_i >= self.source.len or self.source[start_i] != '/') return;
        const close_at = self.regexLiteralClose(start_i, end_i) orelse return;
        const unicode_sets_mode = self.regexLiteralHasFlag(close_at + 1, end_i, 'v');
        const unicode_mode = self.regexLiteralHasFlag(close_at + 1, end_i, 'u') or unicode_sets_mode;
        const named_capture_groups = self.regexLiteralHasNamedCaptureGroup(start_i + 1, close_at);
        // `anyUnicodeModeOrNonAnnexB`: tsc treats a regex with named
        // capture groups as non-AnnexB even without the u/v flag.
        const any_unicode_or_non_annexb = unicode_mode or named_capture_groups;

        var i = start_i + 1;
        var in_negated_class = false;
        var class_depth: u32 = 0;
        while (i < close_at and i < self.source.len) {
            const ch = self.source[i];
            if (ch == '[') {
                // Track whether we are inside a negated class (`[^...]`)
                // for the TS1518 mayContainStrings check.
                const negated = i + 1 < close_at and self.source[i + 1] == '^';
                if (class_depth == 0) in_negated_class = negated;
                class_depth += 1;
                i += if (negated) 2 else 1;
                continue;
            }
            if (ch == ']' and class_depth > 0) {
                class_depth -= 1;
                if (class_depth == 0) in_negated_class = false;
                i += 1;
                continue;
            }
            if (ch != '\\' or i + 1 >= close_at) {
                i += 1;
                continue;
            }
            const e = self.source[i + 1];
            if (e != 'p' and e != 'P') {
                // Skip the escaped char.
                i += 2;
                continue;
            }
            const is_complement = e == 'P';
            const prop_escape_start = i;
            i += 2; // past `\p`
            if (i >= close_at or self.source[i] != '{') {
                // `\p` not followed by `{`.
                if (any_unicode_or_non_annexb) {
                    const msg = try std.fmt.allocPrint(
                        self.diag_arena.allocator(),
                        "'\\{c}' must be followed by a Unicode property value expression enclosed in braces.",
                        .{e},
                    );
                    try self.reportCodeAtWithSpan(@intCast(prop_escape_start), start_tok.line, 2, 1531, msg);
                }
                continue;
            }
            i += 1; // past `{`
            const name_or_value_start = i;
            while (i < close_at and isRegexWordCharacter(self.source[i])) : (i += 1) {}
            const name_or_value = self.source[name_or_value_start..i];
            if (i < close_at and self.source[i] == '=') {
                // Property name = value form.
                if (name_or_value.len == 0) {
                    try self.reportCodeAtWithSpan(@intCast(i), start_tok.line, 0, 1523, "Expected a Unicode property name.");
                } else if (canonicalNonBinaryUnicodeProperty(name_or_value) == null) {
                    try self.reportCodeAtWithSpan(@intCast(name_or_value_start), start_tok.line, @intCast(name_or_value.len), 1524, "Unknown Unicode property name.");
                    try self.reportRegexUnicodeSuggestion(name_or_value_start, start_tok.line, name_or_value, regexUnicodePropertyNameSuggestion(name_or_value));
                }
                const canonical = canonicalNonBinaryUnicodeProperty(name_or_value);
                i += 1; // past `=`
                const value_start = i;
                while (i < close_at and isRegexWordCharacter(self.source[i])) : (i += 1) {}
                const value = self.source[value_start..i];
                if (value.len == 0) {
                    try self.reportCodeAtWithSpan(@intCast(i), start_tok.line, 0, 1525, "Expected a Unicode property value.");
                } else if (canonical) |prop| {
                    if (!nonBinaryUnicodePropertyValueIsValid(prop, value)) {
                        try self.reportCodeAtWithSpan(@intCast(value_start), start_tok.line, @intCast(value.len), 1526, "Unknown Unicode property value.");
                        try self.reportRegexUnicodeSuggestion(value_start, start_tok.line, value, regexUnicodePropertyValueSuggestion(prop, value));
                    }
                }
            } else {
                // Lone property name-or-value form.
                if (name_or_value.len == 0) {
                    try self.reportCodeAtWithSpan(@intCast(i), start_tok.line, 0, 1527, "Expected a Unicode property name or value.");
                } else if (isBinaryUnicodePropertyOfStrings(name_or_value)) {
                    if (!unicode_sets_mode) {
                        try self.reportCodeAtWithSpan(@intCast(name_or_value_start), start_tok.line, @intCast(name_or_value.len), 1528, "Any Unicode property that would possibly match more than a single character is only available when the Unicode Sets (v) flag is set.");
                    } else if (is_complement or in_negated_class) {
                        try self.reportCodeAtWithSpan(@intCast(name_or_value_start), start_tok.line, @intCast(name_or_value.len), 1518, "Anything that would possibly match more than a single character is invalid inside a negated character class.");
                    }
                } else if (!nonBinaryUnicodePropertyValueIsValid("General_Category", name_or_value) and
                    !isBinaryUnicodeProperty(name_or_value))
                {
                    try self.reportCodeAtWithSpan(@intCast(name_or_value_start), start_tok.line, @intCast(name_or_value.len), 1529, "Unknown Unicode property name or value.");
                    try self.reportRegexUnicodeSuggestion(name_or_value_start, start_tok.line, name_or_value, regexUnicodePropertyNameOrValueSuggestion(name_or_value));
                }
            }
            // Consume the closing `}`.
            if (i < close_at and self.source[i] == '}') i += 1;
            // TS1530: property expressions need the u/v flag.
            if (!unicode_mode) {
                try self.reportCodeAtWithSpan(@intCast(prop_escape_start), start_tok.line, @intCast(i - prop_escape_start), 1530, "Unicode property value expressions are only available when the Unicode (u) flag or the Unicode Sets (v) flag is set.");
            }
        }
    }

    fn isRegexWordCharacter(c: u8) bool {
        return std.ascii.isAlphanumeric(c) or c == '_';
    }

    // ====================================================================
    // ClassSetExpression grammar (the `v`-flag character-class syntax).
    // Ports the structural diagnostics of tsc's `scanClassSetExpression`,
    // `scanClassSetSubExpression`, `scanClassSetOperand`, and
    // `scanClassSetCharacter`:
    //   - TS1516 A character class range must not be bounded by another
    //            character class.
    //   - TS1519 Operators must not be mixed within a character class.
    //   - TS1520 Expected a class set operand.
    //   - TS1521 '\q' must be followed by string alternatives enclosed in
    //            braces.
    //   - TS1522 A character class must not contain a reserved double
    //            punctuator. Did you mean to escape it with backslash?
    // (TS1518 negated-class "may contain strings" lives in the property
    // pass; TS1517 range-order already lives in the class-range pass.)
    // ====================================================================

    fn reportRegexClassSetExpressionDiagnostics(self: *Parser, start_tok: Token, end: u32) ParseError!void {
        const start_i: usize = @intCast(start_tok.span.start);
        const end_i: usize = @intCast(end);
        if (start_i >= self.source.len or self.source[start_i] != '/') return;
        const close_at = self.regexLiteralClose(start_i, end_i) orelse return;
        // The ClassSetExpression grammar only applies under the `v` flag.
        if (!self.regexLiteralHasFlag(close_at + 1, end_i, 'v')) return;

        var i = start_i + 1;
        while (i < close_at and i < self.source.len) {
            const ch = self.source[i];
            if (ch == '\\') {
                // Skip an escaped atom outside a class.
                i += if (i + 1 < close_at) 2 else 1;
                continue;
            }
            if (ch == '[') {
                i = try self.scanRegexClassSet(i + 1, close_at, start_tok.line);
                continue;
            }
            i += 1;
        }
    }

    const RegexClassSetOp = enum { union_op, intersection, subtraction };

    /// Scan a single (possibly nested) `[...]` class-set body for v-flag
    /// grammar diagnostics. `body_start` points just past the opening `[`.
    /// Returns the index just past the matching `]` (or close_at). Mirrors
    /// the two-phase structure of tsc's `scanClassSetExpression`: scan the
    /// first operand, decide the expression type from the first operator,
    /// then loop requiring that operator.
    fn scanRegexClassSet(self: *Parser, body_start: usize, close_at: usize, line: u32) ParseError!usize {
        var i = body_start;
        if (i < close_at and self.source[i] == '^') i += 1;
        if (i >= close_at or i >= self.source.len or self.source[i] == ']') {
            return if (i < close_at and self.source[i] == ']') i + 1 else i;
        }

        // Empty leading operator (`[&&...]` / `[--...]`) — TS1520.
        if (self.twoCharOpAt(i, close_at)) |_| {
            try self.reportCodeAtWithSpan(@intCast(i), line, 0, 1520, "Expected a class set operand.");
        } else {
            i = try self.scanRegexClassSetRangeOrOperand(i, close_at, line, true);
        }

        // Determine the expression operator from the first operator we see.
        if (i >= close_at or i >= self.source.len) return i;
        const expr_op: RegexClassSetOp = blk: {
            if (self.twoCharOpAt(i, close_at)) |op| break :blk op;
            break :blk .union_op;
        };

        while (i < close_at and i < self.source.len) {
            const ch = self.source[i];
            if (ch == ']') return i + 1;

            if (self.twoCharOpAt(i, close_at)) |op| {
                // Operator mixing (TS1519): a `--`/`&&` that differs from
                // the operator that defines this expression, or any
                // operator after a plain union of operands.
                if (op != expr_op or expr_op == .union_op) {
                    try self.reportCodeAtWithSpan(@intCast(i), line, 2, 1519, "Operators must not be mixed within a character class. Wrap it in a nested class instead.");
                }
                i += 2;
                if (i >= close_at or i >= self.source.len or self.source[i] == ']') {
                    try self.reportCodeAtWithSpan(@intCast(i), line, 0, 1520, "Expected a class set operand.");
                    if (i < close_at and self.source[i] == ']') return i + 1;
                    return i;
                }
                i = try self.scanRegexClassSetRangeOrOperand(i, close_at, line, false);
                continue;
            }

            // Single `-` (range) belongs to a union; in an
            // intersection/subtraction context a bare `-` operand is a
            // ClassSetCharacter handled by the operand scanner.
            i = try self.scanRegexClassSetRangeOrOperand(i, close_at, line, false);
        }
        return i;
    }

    /// If `[i, i+2)` is a class-set operator (`&&` or `--`), return it.
    fn twoCharOpAt(self: *Parser, i: usize, close_at: usize) ?RegexClassSetOp {
        if (i + 1 >= close_at or i + 1 >= self.source.len) return null;
        const a = self.source[i];
        const b = self.source[i + 1];
        if (a == '&' and b == '&') return .intersection;
        if (a == '-' and b == '-') return .subtraction;
        return null;
    }

    /// Scan one operand, including a possible `-`-delimited range, and emit
    /// the reserved-double-punctuator (TS1522) and class-bounded-range
    /// (TS1516) diagnostics. `is_first` allows the caller to distinguish
    /// the leading operand (unused for now but mirrors the reference's
    /// dedicated first-operand handling).
    fn scanRegexClassSetRangeOrOperand(self: *Parser, start: usize, close_at: usize, line: u32, is_first: bool) ParseError!usize {
        _ = is_first;
        // Reserved double punctuator (TS1522): two identical reserved
        // punctuators that are not the `&&`/`--` operators.
        if (start + 1 < close_at and self.source[start + 1] == self.source[start] and
            isReservedDoublePunctuator(self.source[start]))
        {
            try self.reportCodeAtWithSpan(@intCast(start), line, 2, 1522, "A character class must not contain a reserved double punctuator. Did you mean to escape it with backslash?");
            return start + 2;
        }

        const min_is_class = self.classSetOperandIsClass(start, close_at);
        var i = try self.scanRegexClassSetOperand(start, close_at, line);

        // Range `min-max`.
        if (i < close_at and i < self.source.len and self.source[i] == '-' and
            (i + 1 >= close_at or self.source[i + 1] != '-'))
        {
            // A trailing `-` right before `]` is a literal dash, not a range.
            if (i + 1 < close_at and self.source[i + 1] != ']') {
                i += 1; // past `-`
                // TS1516: a range bound must be a single character, not a
                // class (`\d`, `\w`, `\p{...}`, or a nested `[...]`).
                if (min_is_class) {
                    try self.reportCodeAtWithSpan(@intCast(start), line, @intCast(i - 1 - start), 1516, "A character class range must not be bounded by another character class.");
                }
                if (self.classSetOperandIsClass(i, close_at)) {
                    try self.reportCodeAtWithSpan(@intCast(i), line, 1, 1516, "A character class range must not be bounded by another character class.");
                }
                i = try self.scanRegexClassSetOperand(i, close_at, line);
            }
        }
        return i;
    }

    /// True if the operand starting at `pos` is a class (a nested `[...]`
    /// or a `\d`/`\w`/`\p{...}` shorthand) rather than a single character.
    fn classSetOperandIsClass(self: *Parser, pos: usize, close_at: usize) bool {
        if (pos >= close_at or pos >= self.source.len) return false;
        const ch = self.source[pos];
        if (ch == '[') return true;
        if (ch == '\\' and pos + 1 < close_at and isRegexClassShorthand(self.source[pos + 1])) return true;
        return false;
    }

    /// Scan one ClassSetOperand: a nested `[...]`, a `\`-escape (including
    /// `\q{...}` string disjunctions), or a single ClassSetCharacter.
    /// Returns the index past the operand.
    fn scanRegexClassSetOperand(self: *Parser, start: usize, close_at: usize, line: u32) ParseError!usize {
        if (start >= close_at or start >= self.source.len) return start;
        const ch = self.source[start];
        if (ch == '[') {
            return try self.scanRegexClassSet(start + 1, close_at, line);
        }
        if (ch == '\\') {
            if (start + 1 >= close_at) return start + 1;
            const e = self.source[start + 1];
            if (e == 'q') {
                if (start + 2 < close_at and self.source[start + 2] == '{') {
                    // `\q{...}` string disjunction — skip to closing `}`.
                    var p = start + 3;
                    while (p < close_at and self.source[p] != '}') {
                        if (self.source[p] == '\\' and p + 1 < close_at) p += 2 else p += 1;
                    }
                    return if (p < close_at) p + 1 else p;
                }
                // `\q` not followed by `{`.
                try self.reportCodeAtWithSpan(@intCast(start), line, 2, 1521, "'\\q' must be followed by string alternatives enclosed in braces.");
                return start + 2;
            }
            // `\u{...}` and `\p{...}` escapes consume their braces.
            if ((e == 'u' or e == 'p' or e == 'P') and start + 2 < close_at and self.source[start + 2] == '{') {
                var p = start + 3;
                while (p < close_at and self.source[p] != '}') : (p += 1) {}
                return if (p < close_at) p + 1 else p;
            }
            return start + 2;
        }
        return start + 1;
    }

    fn isRegexClassShorthand(c: u8) bool {
        return switch (c) {
            'd', 'D', 's', 'S', 'w', 'W', 'p', 'P' => true,
            else => false,
        };
    }

    fn isReservedDoublePunctuator(c: u8) bool {
        return switch (c) {
            '&', '!', '#', '%', '*', '+', ',', '.', ':', ';', '<', '=', '>', '?', '@', '`', '~' => true,
            else => false,
        };
    }

    // --- Unicode property database (ports unicodeproperties.go tables) ---

    fn regexSetHas(set: []const []const u8, key: []const u8) bool {
        for (set) |s| {
            if (std.mem.eql(u8, s, key)) return true;
        }
        return false;
    }

    fn reportRegexUnicodeSuggestion(self: *Parser, start: usize, line: u32, typo: []const u8, suggestion: ?[]const u8) ParseError!void {
        const sug = suggestion orelse return;
        const msg = try std.fmt.allocPrint(self.diag_arena.allocator(), "Did you mean '{s}'?", .{sug});
        try self.reportCodeAtWithSpan(@intCast(start), line, @intCast(typo.len), 1369, msg);
    }

    fn closestRegexCandidate(typo: []const u8, candidates: []const []const u8) ?[]const u8 {
        var best: ?[]const u8 = null;
        var best_distance: usize = std.math.maxInt(usize);
        for (candidates) |candidate| {
            const distance = levenshteinIcase(typo, candidate);
            if (distance < best_distance) {
                best = candidate;
                best_distance = distance;
            }
        }
        const threshold = @max(@as(usize, 2), typo.len / 4);
        return if (best != null and best_distance <= threshold) best else null;
    }

    /// Table 66: non-binary Unicode property aliases → canonical name.
    fn canonicalNonBinaryUnicodeProperty(name: []const u8) ?[]const u8 {
        if (std.mem.eql(u8, name, "General_Category") or std.mem.eql(u8, name, "gc")) return "General_Category";
        if (std.mem.eql(u8, name, "Script") or std.mem.eql(u8, name, "sc")) return "Script";
        if (std.mem.eql(u8, name, "Script_Extensions") or std.mem.eql(u8, name, "scx")) return "Script_Extensions";
        return null;
    }

    fn regexUnicodePropertyNameSuggestion(name: []const u8) ?[]const u8 {
        const candidates = [_][]const u8{ "General_Category", "gc", "Script", "sc", "Script_Extensions", "scx" };
        return closestRegexCandidate(name, &candidates);
    }

    fn regexUnicodePropertyValueSuggestion(canonical: []const u8, value: []const u8) ?[]const u8 {
        if (std.mem.eql(u8, canonical, "General_Category")) {
            return closestRegexCandidate(value, &general_category_values);
        }
        if (std.mem.eql(u8, canonical, "Script") or std.mem.eql(u8, canonical, "Script_Extensions")) {
            return closestRegexCandidate(value, &script_values);
        }
        return null;
    }

    fn regexUnicodePropertyNameOrValueSuggestion(name: []const u8) ?[]const u8 {
        var best: ?[]const u8 = null;
        var best_distance: usize = std.math.maxInt(usize);
        for ([_][]const []const u8{ &general_category_values, &binary_unicode_properties, &binary_unicode_properties_of_strings }) |candidates| {
            for (candidates) |candidate| {
                const distance = levenshteinIcase(name, candidate);
                if (distance < best_distance) {
                    best = candidate;
                    best_distance = distance;
                }
            }
        }
        const threshold = @max(@as(usize, 2), name.len / 4);
        return if (best != null and best_distance <= threshold) best else null;
    }

    fn nonBinaryUnicodePropertyValueIsValid(canonical: []const u8, value: []const u8) bool {
        if (std.mem.eql(u8, canonical, "General_Category")) {
            return regexSetHas(&general_category_values, value);
        }
        // Script and Script_Extensions share the script value set.
        if (std.mem.eql(u8, canonical, "Script") or std.mem.eql(u8, canonical, "Script_Extensions")) {
            return regexSetHas(&script_values, value);
        }
        return false;
    }

    fn isBinaryUnicodeProperty(name: []const u8) bool {
        return regexSetHas(&binary_unicode_properties, name);
    }

    fn isBinaryUnicodePropertyOfStrings(name: []const u8) bool {
        return regexSetHas(&binary_unicode_properties_of_strings, name);
    }

    /// Skip a balanced (), [], or {} starting at `start`. Returns
    /// the cursor *after* the matching closer, or null on mismatch.
    fn skipBalancedFrom(self: *Parser, start: u32) ?u32 {
        if (start >= self.tokens.len) return null;
        const opener = self.tokens[start].kind;
        const closer: ts_lexer.TokenKind = switch (opener) {
            .open_paren => .close_paren,
            .open_bracket => .close_bracket,
            .open_brace => .close_brace,
            else => return null,
        };
        var depth: i32 = 1;
        var i: u32 = start + 1;
        while (i < self.tokens.len) : (i += 1) {
            const tk = self.tokens[i].kind;
            if (tk == opener) depth += 1;
            if (tk == closer) {
                depth -= 1;
                if (depth == 0) return i + 1;
            }
            if (tk == .eof) return null;
        }
        return null;
    }

    /// Cursor points at `(`. Returns the cursor *after* the matching `)`.
    fn findMatchingParenEnd(self: *Parser, start: u32) ?u32 {
        if (start >= self.tokens.len or self.tokens[start].kind != .open_paren) return null;
        var depth: i32 = 1;
        var i: u32 = start + 1;
        while (i < self.tokens.len) : (i += 1) {
            const tk = self.tokens[i].kind;
            switch (tk) {
                .open_paren, .open_bracket, .open_brace, .less_than => depth += 1,
                .close_paren, .close_bracket, .close_brace, .greater_than => {
                    depth -= 1;
                    if (depth == 0 and tk == .close_paren) return i + 1;
                },
                .eof => return null,
                else => {},
            }
        }
        return null;
    }

    fn findTopLevelArrowBeforeCloseParen(self: *Parser, start: u32) ?u32 {
        if (start >= self.tokens.len or self.tokens[start].kind != .open_paren) return null;
        var depth: i32 = 1;
        var arrow_index: ?u32 = null;
        var i: u32 = start + 1;
        while (i < self.tokens.len) : (i += 1) {
            const tk = self.tokens[i].kind;
            if (depth == 1 and tk == .arrow and arrow_index == null) arrow_index = i;
            switch (tk) {
                .open_paren, .open_bracket, .open_brace, .less_than => depth += 1,
                .close_paren => {
                    depth -= 1;
                    if (depth == 0) return null;
                },
                .close_bracket, .close_brace, .greater_than => {
                    if (depth > 1) depth -= 1;
                },
                .eof => return arrow_index,
                else => {},
            }
        }
        return arrow_index;
    }

    /// From `idx` (right after `:`), scan past a type annotation and
    /// return true if we eventually hit `=>` at the top level.
    fn scanForArrowAfterColon(self: *Parser, idx: u32) bool {
        var depth: i32 = 0;
        var i: u32 = idx;
        while (i < self.tokens.len) : (i += 1) {
            const tk = self.tokens[i].kind;
            if (depth == 0) {
                if (tk == .arrow) return true;
                if (tk == .semicolon or tk == .comma or tk == .close_paren or
                    tk == .close_brace or tk == .close_bracket or tk == .eof)
                {
                    return false;
                }
            }
            switch (tk) {
                .less_than, .open_paren, .open_brace, .open_bracket => depth += 1,
                .greater_than, .close_paren, .close_brace, .close_bracket => {
                    if (depth > 0) depth -= 1;
                },
                else => {},
            }
        }
        return false;
    }

    fn scanForMissingArrowBlockAfterColon(self: *Parser, idx: u32) bool {
        var depth: i32 = 0;
        var saw_type_token = false;
        var i: u32 = idx;
        while (i < self.tokens.len) : (i += 1) {
            const tk = self.tokens[i].kind;
            if (depth == 0) {
                if (tk == .open_brace) return saw_type_token;
                if (tk == .semicolon or tk == .comma or tk == .close_paren or
                    tk == .close_brace or tk == .close_bracket or tk == .eof)
                {
                    return false;
                }
                saw_type_token = true;
            }
            switch (tk) {
                .less_than, .open_paren, .open_bracket => depth += 1,
                .greater_than, .close_paren, .close_bracket => {
                    if (depth > 0) depth -= 1;
                },
                else => {},
            }
        }
        return false;
    }

    fn parseArrowBody(self: *Parser) ParseError!NodeId {
        if (self.peek().kind == .open_brace) {
            return try self.parseBlockStatement();
        }
        if (self.arrowBodyStartsStatementOnly()) {
            return try self.parseBlockStatementWithMissingOpenBrace(true);
        }
        return try self.parseAssignmentExpression();
    }

    fn arrowBodyStartsStatementOnly(self: *const Parser) bool {
        return switch (self.peek().kind) {
            .at,
            .kw_var,
            .kw_const,
            .kw_enum,
            .kw_if,
            .kw_do,
            .kw_while,
            .kw_for,
            .kw_continue,
            .kw_break,
            .kw_return,
            .kw_with,
            .kw_switch,
            .kw_throw,
            .kw_try,
            .kw_debugger,
            .kw_catch,
            .kw_finally,
            .kw_export,
            => true,
            .kw_let => blk: {
                const next = self.peekAt(1);
                break :blk !next.flags.preceded_by_newline and
                    (next.kind == .identifier or next.kind == .open_brace or next.kind == .open_bracket);
            },
            .kw_using => blk: {
                const next = self.peekAt(1);
                break :blk !next.flags.preceded_by_newline and next.kind == .identifier;
            },
            else => false,
        };
    }

    fn parseCompoundAssign(self: *Parser, left: NodeId, op: hir_mod.BinOp, allow_in: bool) ParseError!NodeId {
        _ = self.advance();
        try self.reportInvalidStrictIdentifierNode(left);
        try self.reportInvalidAssignmentTarget(left);
        const right = try self.parseAssignmentExpressionWithIn(allow_in);
        const sp: Span = .{ .start = self.hir.spanOf(left).start, .end = self.hir.spanOf(right).end };
        return try self.builder.addAssignment(sp, left, right, op);
    }

    /// Lower `a <op>= b` (where <op> is `??`, `||`, or `&&`) into
    /// `a = a <op> b`. The target and the operator's lhs need
    /// independent HIR nodes because parent pointers are single-owner.
    fn parseLogicalAssign(self: *Parser, left: NodeId, op: hir_mod.LogicalOp, allow_in: bool) ParseError!NodeId {
        _ = self.advance();
        try self.reportInvalidStrictIdentifierNode(left);
        try self.reportInvalidAssignmentTarget(left);
        const right = try self.parseAssignmentExpressionWithIn(allow_in);
        const left_span = self.hir.spanOf(left);
        const op_span: Span = .{ .start = left_span.start, .end = self.hir.spanOf(right).end };
        // Preserve the logical-assignment natively (`a ||= b`) rather than
        // desugaring to `a = a || b` (which is the wrong semantics — `||=`
        // short-circuits — and non-native). The emitter renders `||=`/`&&=`/
        // `??=` at ES2021+, or the short-circuit form below.
        const assign_op: hir_mod.BinOp = switch (op) {
            .@"or" => .logical_or,
            .@"and" => .logical_and,
            .nullish => .nullish_coalesce,
        };
        return try self.builder.addAssignment(op_span, left, right, assign_op);
    }

    fn cloneLogicalAssignmentTarget(self: *Parser, node: NodeId) ParseError!NodeId {
        const sp = self.hir.spanOf(node);
        return switch (self.hir.kindOf(node)) {
            .identifier => blk: {
                const id_payload = hir_mod.identifierOf(self.hir, node);
                break :blk try self.builder.addIdentifier(sp, id_payload.name);
            },
            .member_access => blk: {
                const m = hir_mod.memberOf(self.hir, node);
                const obj = try self.cloneLogicalAssignmentTarget(m.object);
                break :blk try self.builder.addMemberAccess(sp, obj, m.name, m.optional);
            },
            .element_access => blk: {
                const e = hir_mod.elementOf(self.hir, node);
                const obj = try self.cloneLogicalAssignmentTarget(e.object);
                const idx = try self.cloneLogicalAssignmentIndex(e.index);
                break :blk try self.builder.addElementAccess(sp, obj, idx, e.optional);
            },
            else => error.InvalidLeftHandSide,
        };
    }

    fn cloneLogicalAssignmentIndex(self: *Parser, node: NodeId) ParseError!NodeId {
        const sp = self.hir.spanOf(node);
        return switch (self.hir.kindOf(node)) {
            .identifier => blk: {
                const id_payload = hir_mod.identifierOf(self.hir, node);
                break :blk try self.builder.addIdentifier(sp, id_payload.name);
            },
            .literal_string => blk: {
                const id = hir_mod.literalStringOf(self.hir, node).value;
                break :blk try self.builder.addLiteralString(sp, id);
            },
            .literal_number => blk: {
                const n = hir_mod.literalNumberOf(self.hir, node);
                break :blk try self.builder.addLiteralNumber(sp, n);
            },
            else => error.InvalidLeftHandSide,
        };
    }

    fn parseConditionalExpression(self: *Parser) ParseError!NodeId {
        return try self.parseConditionalExpressionWithIn(true);
    }

    fn parseConditionalExpressionWithIn(self: *Parser, allow_in: bool) ParseError!NodeId {
        const cond = try self.parseBinaryExpressionWithIn(.nullish, allow_in);
        if (self.peek().kind == .question) {
            _ = self.advance();
            // TS parity: the `true` branch is parsed with
            // `allowReturnTypeInArrowFunction=false` so that
            // `x ? (y): T => y : z` doesn't greedily consume the
            // outer ternary `:` as a typed-arrow return-type colon.
            // The `false` branch inherits the surrounding flag.
            // See parserArrowFunctionExpression8/9/10/11/12.
            const saved_disallow_arrow_rt = self.disallow_arrow_return_type;
            self.disallow_arrow_return_type = true;
            const then_branch = self.parseAssignmentExpressionWithIn(allow_in) catch |err| {
                self.disallow_arrow_return_type = saved_disallow_arrow_rt;
                return err;
            };
            self.disallow_arrow_return_type = saved_disallow_arrow_rt;
            _ = try self.expect(.colon, "':' in ternary");
            const else_branch = try self.parseAssignmentExpressionWithIn(allow_in);
            const sp: Span = .{ .start = self.hir.spanOf(cond).start, .end = self.hir.spanOf(else_branch).end };
            return try self.builder.addConditional(sp, cond, then_branch, else_branch);
        }
        return cond;
    }

    fn parseBinaryExpression(self: *Parser, min_prec: prec_mod.Prec) ParseError!NodeId {
        return try self.parseBinaryExpressionWithIn(min_prec, true);
    }

    fn parseBinaryExpressionWithIn(self: *Parser, min_prec: prec_mod.Prec, allow_in: bool) ParseError!NodeId {
        var left = try self.parseUnaryExpression();
        while (true) {
            const t = self.peek();
            if (!allow_in and t.kind == .kw_in) break;
            const prec = prec_mod.binaryPrec(t.kind) orelse break;
            if (@intFromEnum(prec) < @intFromEnum(min_prec)) break;
            if ((t.kind == .kw_as or t.kind == .kw_satisfies) and t.flags.preceded_by_newline) break;
            // TSX-only ASI guard: in `.tsx` sources, a `<` token that
            // starts on a new line and is followed by a JSX-name part
            // (identifier/keyword) or a `>`/`/` (fragment / closing-tag
            // start) is a NEW JSX statement, not a less-than
            // continuation of the previous expression. Without this
            // guard, `<Foo/>\n<Bar/>;` would parse as
            // `<Foo/> < <Bar/>;` which then trips downstream parsers
            // when the second JSX expression doesn't fit the binary
            // RHS slot.
            if (self.is_tsx and t.kind == .less_than and t.flags.preceded_by_newline) {
                const next = self.peekAt(1).kind;
                if (next == .identifier or
                    next == .greater_than or
                    next == .slash or
                    next.isKeyword() or
                    next.isContextualKeyword()) break;
            }
            _ = self.advance();
            if (t.kind == .asterisk_asterisk) {
                try self.reportUnaryExponentiationLeft(left, t.line);
            }
            // `as` / `satisfies` take a TYPE on the right, not an
            // expression — handle them before the generic
            // expression-RHS path so we don't try to parse `number`
            // as an identifier.
            if (t.kind == .kw_as or t.kind == .kw_satisfies) {
                // `expr as const` is a special form — `const` isn't
                // a valid type, it's a contextual keyword that asks
                // the checker to type the LHS as its literal form
                // (rather than the widened type). Build a synthetic
                // type_ref to "const" so the checker can recognize
                // and handle it.
                if (t.kind == .kw_as and self.peek().kind == .kw_const) {
                    const const_tok = self.advance();
                    const const_id = self.interner.intern("const") catch return error.OutOfMemory;
                    const type_node = try self.builder.addTypeRef(
                        tokenSpan(const_tok),
                        const_id,
                        &.{},
                        &.{},
                    );
                    const sp: Span = .{ .start = self.hir.spanOf(left).start, .end = const_tok.span.end };
                    left = try self.builder.addAsExpression(.as_expr, sp, left, type_node);
                    continue;
                }
                const type_node = try self.parseTypeAnnotation();
                if (t.kind == .kw_as) {
                    try self.reportTypeAssertionOnlyInTsIfNeeded(type_node);
                }
                const sp: Span = .{ .start = self.hir.spanOf(left).start, .end = self.hir.spanOf(type_node).end };
                const kind: hir_mod.NodeKind = if (t.kind == .kw_as) .as_expr else .satisfies_expr;
                left = try self.builder.addAsExpression(kind, sp, left, type_node);
                continue;
            }
            // Right-associative operators recurse with `prec`,
            // left-associative with `prec + 1`.
            const next_min: prec_mod.Prec = if (prec_mod.isRightAssociative(prec))
                prec
            else
                @enumFromInt(@intFromEnum(prec) + 1);
            if (self.peek().kind == .close_paren) {
                const missing = self.advance();
                try self.reportCodeAt(missing.span.start, missing.line, 1109, "Expression expected.");
                const right = try self.builder.addLiteralNumber(.{ .start = missing.span.start, .end = missing.span.start }, 0);
                const sp: Span = .{ .start = self.hir.spanOf(left).start, .end = t.span.end };
                if (prec_mod.binOpOf(t.kind)) |bop| {
                    left = try self.builder.addBinaryOp(sp, bop, left, right);
                } else if (prec_mod.logicalOpOf(t.kind)) |lop| {
                    left = try self.builder.addLogicalOp(sp, lop, left, right);
                } else {
                    left = right;
                }
                continue;
            }
            // `a +;`, `a +,`, `a +}`, `a +eof` — binary RHS is missing.
            // Anchor TS1109 at the offending token (matches the
            // `close_paren` arm above and the unary-prefix recovery in
            // `parseUnaryExpression`) so the outer statement keeps
            // parsing instead of bubbling `error.UnexpectedToken` and
            // dropping the diagnostic. We deliberately drop the
            // binary node and keep `left` as the recovered value:
            // synthesising a numeric `0` RHS would feed a phantom
            // operand into the checker and surface false-positive
            // TS2365 / TS2304 on top of the parse error. Regression
            // for upstream `plusOperatorInvalidOperations.ts(5,17)`
            // / `(8,15)`.
            if (self.peekIsUnaryOperandStopToken()) {
                const at = self.peek();
                try self.reportCodeAt(at.span.start, at.line, 1109, "Expression expected.");
                continue;
            }
            // `1 > > 2`, `1 < < 2`, etc. — the binary RHS is missing
            // and the next token is itself another binary/comparison
            // operator. tsc anchors TS1109 at the second operator and
            // SYNTHESIZES a literal `0` RHS for the first so the
            // outer comparison still typechecks (yielding
            // `boolean > 2` → TS2365). Mirrors
            // `parserGreaterThanTokenAmbiguity2/3/4` baselines. Limited
            // to the comparison family to avoid the false-positive
            // TS2365 / TS2304 that motivated the `left`-only recovery
            // above for `+`/`-` chains
            // (`plusOperatorInvalidOperations`).
            const peek_is_type_assertion_rhs = self.peek().kind == .less_than and
                self.lessThanStartsTypeAssertionExpression(self.cursor);
            const peek_is_chained_comparison = !peek_is_type_assertion_rhs and
                (t.kind == .greater_than or t.kind == .less_than or
                    t.kind == .greater_than_equal or t.kind == .less_than_equal) and
                (self.peek().kind == .greater_than or self.peek().kind == .less_than or
                    self.peek().kind == .greater_than_equal or self.peek().kind == .less_than_equal) and
                !(!self.is_tsx and self.peek().kind == .less_than);
            if (peek_is_chained_comparison) {
                const at = self.peek();
                try self.reportCodeAt(at.span.start, at.line, 1109, "Expression expected.");
                const right_synth = try self.builder.addLiteralNumber(.{ .start = at.span.start, .end = at.span.start }, 0);
                const sp: Span = .{ .start = self.hir.spanOf(left).start, .end = at.span.start };
                if (prec_mod.binOpOf(t.kind)) |bop| {
                    left = try self.builder.addBinaryOp(sp, bop, left, right_synth);
                }
                continue;
            }
            const right = try self.parseBinaryExpressionWithIn(next_min, allow_in);
            if (t.kind == .kw_instanceof and self.peek().kind == .less_than) {
                if (self.findStandaloneInstantiationTypeArgsEnd(self.cursor)) |after_gt| {
                    const pos = self.hir.spanOf(right).start;
                    try self.reportCodeAt(pos, self.sourceLineAtPos(pos), 2848, "The right-hand side of an 'instanceof' expression must not be an instantiation expression.");
                    const type_args = try self.parseExplicitCallTypeArgs(after_gt);
                    defer self.gpa.free(type_args);
                    try self.reportTypeArgumentsOnlyInTsIfNeeded(type_args);
                }
            } else if (t.kind == .kw_instanceof and
                self.hir.kindOf(right) == .call_expr and
                hir_mod.callArgs(self.hir, right).len == 0 and
                hir_mod.callTypeArgs(self.hir, right).len > 0)
            {
                const pos = self.hir.spanOf(right).start;
                try self.reportCodeAt(pos, self.sourceLineAtPos(pos), 2848, "The right-hand side of an 'instanceof' expression must not be an instantiation expression.");
            }
            const sp: Span = .{ .start = self.hir.spanOf(left).start, .end = self.hir.spanOf(right).end };
            if (prec_mod.binOpOf(t.kind)) |bop| {
                left = try self.builder.addBinaryOp(sp, bop, left, right);
            } else if (prec_mod.logicalOpOf(t.kind)) |lop| {
                try self.reportMixedNullishLogical(t, lop, left, right);
                left = try self.builder.addLogicalOp(sp, lop, left, right);
            } else {
                left = right;
            }
        }
        return left;
    }

    fn tokenCanStartTypeAssertionType(kind: TokenKind) bool {
        return kind == .identifier or
            kind.isPrimitiveTypeKeyword() or
            kind.isContextualKeyword() or
            kind == .open_brace or
            kind == .open_paren or
            kind == .open_bracket or
            kind == .kw_this or
            kind == .kw_typeof or
            kind == .kw_new;
    }

    fn tokenCanStartTypeAssertionOperand(kind: TokenKind) bool {
        return kind.canStartExpression() or kind == .less_than;
    }

    fn lessThanStartsTypeAssertionExpression(self: *Parser, start: u32) bool {
        if (self.is_tsx) return false;
        if (start >= self.tokens.len or self.tokens[start].kind != .less_than) return false;
        if (start + 1 >= self.tokens.len or !tokenCanStartTypeAssertionType(self.tokens[start + 1].kind)) return false;

        var depth: i32 = 1;
        var i: u32 = start + 1;
        while (i < self.tokens.len) : (i += 1) {
            const kind = self.tokens[i].kind;
            switch (kind) {
                .eof, .semicolon => return false,
                .less_than => depth += 1,
                .greater_than, .greater_greater, .greater_greater_greater => {
                    const count: u8 = switch (kind) {
                        .greater_than => 1,
                        .greater_greater => 2,
                        .greater_greater_greater => 3,
                        else => unreachable,
                    };
                    var n: u8 = 0;
                    while (n < count) : (n += 1) {
                        depth -= 1;
                        if (depth == 0) {
                            const next = i + 1;
                            return next < self.tokens.len and tokenCanStartTypeAssertionOperand(self.tokens[next].kind);
                        }
                    }
                },
                else => {},
            }
        }
        return false;
    }

    fn reportUnaryExponentiationLeft(self: *Parser, left: NodeId, line: u32) ParseError!void {
        if (self.nodeLooksParenthesized(left)) return;
        if (self.hir.kindOf(left) == .type_assertion) {
            try self.reportCodeAt(self.hir.spanOf(left).start, line, 17007, "A type assertion expression is not allowed in the left-hand side of an exponentiation expression. Consider enclosing the expression in parentheses.");
            return;
        }
        if (self.hir.kindOf(left) != .unary_op) return;
        const u = hir_mod.unaryOf(self.hir, left);
        const op_text: []const u8 = switch (u.op) {
            .neg => "-",
            .plus => "+",
            .not => "!",
            .bit_not => "~",
            .typeof => "typeof",
            .void_ => "void",
            .delete => "delete",
        };
        const msg = try std.fmt.allocPrint(
            self.gpa,
            "An unary expression with the '{s}' operator is not allowed in the left-hand side of an exponentiation expression. Consider enclosing the expression in parentheses.",
            .{op_text},
        );
        defer self.gpa.free(msg);
        try self.reportCodeAt(self.hir.spanOf(left).start, line, 17006, msg);
    }

    fn reportMixedNullishLogical(
        self: *Parser,
        op_tok: Token,
        op: hir_mod.LogicalOp,
        left: NodeId,
        right: NodeId,
    ) ParseError!void {
        const left_mixed = self.unparenthesizedLogicalOp(left);
        const right_mixed = self.unparenthesizedLogicalOp(right);
        // tsc renders the specific operator pair in source order
        // (e.g. `'??' and '||'`, `'||' and '??'`) rather than the
        // generic `'??' and '&&' or '||'`. Mirrors baseline
        // `nullishCoalescingOperator5`.
        if (op == .nullish) {
            if (left_mixed) |lop| {
                if (lop != .nullish) {
                    const msg = try std.fmt.allocPrint(
                        self.diag_arena.allocator(),
                        "'{s}' and '??' operations cannot be mixed without parentheses.",
                        .{logicalOpTextForMixError(lop)},
                    );
                    try self.reportCodeAt(self.hir.spanOf(left).start, op_tok.line, 5076, msg);
                    return;
                }
            }
            if (right_mixed) |rop| {
                if (rop != .nullish) {
                    const msg = try std.fmt.allocPrint(
                        self.diag_arena.allocator(),
                        "'??' and '{s}' operations cannot be mixed without parentheses.",
                        .{logicalOpTextForMixError(rop)},
                    );
                    try self.reportCodeAt(self.hir.spanOf(right).start, op_tok.line, 5076, msg);
                    return;
                }
            }
        } else {
            if (left_mixed) |lop| {
                if (lop == .nullish) {
                    const msg = try std.fmt.allocPrint(
                        self.diag_arena.allocator(),
                        "'??' and '{s}' operations cannot be mixed without parentheses.",
                        .{logicalOpTextForMixError(op)},
                    );
                    try self.reportCodeAt(self.hir.spanOf(left).start, op_tok.line, 5076, msg);
                    return;
                }
            }
            if (right_mixed) |rop| {
                if (rop == .nullish) {
                    const msg = try std.fmt.allocPrint(
                        self.diag_arena.allocator(),
                        "'{s}' and '??' operations cannot be mixed without parentheses.",
                        .{logicalOpTextForMixError(op)},
                    );
                    try self.reportCodeAt(self.hir.spanOf(right).start, op_tok.line, 5076, msg);
                    return;
                }
            }
        }
    }

    fn logicalOpTextForMixError(op: hir_mod.LogicalOp) []const u8 {
        return switch (op) {
            .@"and" => "&&",
            .@"or" => "||",
            .nullish => "??",
        };
    }

    fn unparenthesizedLogicalOp(self: *Parser, node: NodeId) ?hir_mod.LogicalOp {
        if (self.hir.kindOf(node) != .logical_op) return null;
        if (self.nodeLooksParenthesized(node)) return null;
        return hir_mod.logicalOf(self.hir, node).op;
    }

    fn nodeLooksParenthesized(self: *Parser, node: NodeId) bool {
        const sp = self.hir.spanOf(node);
        var before = sp.start;
        while (before > 0) {
            const c = self.source[before - 1];
            if (!std.ascii.isWhitespace(c)) break;
            before -= 1;
        }
        var after = sp.end;
        while (after < self.source.len) : (after += 1) {
            if (!std.ascii.isWhitespace(self.source[after])) break;
        }
        return before > 0 and after < self.source.len and self.source[before - 1] == '(' and self.source[after] == ')';
    }

    /// True when the upcoming token cannot start an operand for a
    /// unary prefix operator. Used by `parseUnaryExpression` to anchor
    /// TS1109 at the offending token (matching upstream tsc) rather
    /// than bubbling `error.UnexpectedToken` and dropping the
    /// diagnostic on the floor.
    fn peekIsUnaryOperandStopToken(self: *Parser) bool {
        const k = self.peek().kind;
        // Inside a switch-case body, `case` / `default` start the next
        // case clause, so they STOP the current expression rather than
        // becoming a candidate primary. Mirrors
        // `parserErrorRecovery_SwitchStatement1`: `1 + case` should
        // anchor TS1109 at the `case` token and let the outer switch
        // loop pick up the next case rather than bubbling
        // `error.UnexpectedToken` and dropping the rest of the body.
        const is_switch_clause_keyword = self.in_switch_case_clause and
            (k == .kw_case or k == .kw_default);
        return k == .semicolon or k == .close_paren or k == .close_brace or
            k == .close_bracket or k == .comma or k == .colon or k == .eof or
            is_switch_clause_keyword;
    }

    /// Recovery for `<op>;` / `<op>,` / `<op>)` etc. — the unary
    /// operator already consumed `<op>`, the operand is missing.
    /// Anchor TS1109 at the offending follow-on token (same anchor
    /// convention as `parsePrimaryExpression`'s stop-token branch)
    /// and synthesize an empty identifier so the outer statement
    /// keeps parsing instead of bubbling `error.UnexpectedToken`.
    fn recoverUnaryMissingOperand(self: *Parser, op_tok: ts_lexer.Token, op_kind: hir_mod.UnaryOp) ParseError!NodeId {
        const at = self.peek();
        const operand_pos = if (op_kind == .delete) op_tok.span.end else at.span.start;
        if (op_kind == .delete) {
            try self.reportCodeAt(operand_pos, op_tok.line, 1102, "'delete' cannot be called on an identifier in strict mode.");
            try self.reportCodeAt(operand_pos, op_tok.line, 2703, "The operand of a 'delete' operator must be a property reference.");
        }
        try self.reportCodeAt(at.span.start, at.line, 1109, "Expression expected.");
        // Synthesize a numeric `0` operand: it satisfies the unary
        // operator's type expectations (`+`/`-`/`~` all take number,
        // `!` widens any) so the checker won't pile downstream
        // TS2362 / TS2304 onto the already-reported parse error.
        // Mirrors the `(<bin>)` close-paren recovery a few lines
        // above which also synthesizes `0` for the missing operand.
        const operand_span: Span = .{ .start = operand_pos, .end = operand_pos };
        const operand = try self.builder.addLiteralNumber(operand_span, 0);
        const sp: Span = .{ .start = op_tok.span.start, .end = at.span.start };
        return try self.builder.addUnaryOp(sp, op_kind, operand);
    }

    fn parseUnaryExpression(self: *Parser) ParseError!NodeId {
        const t = self.peek();
        switch (t.kind) {
            .plus => {
                _ = self.advance();
                if (self.peekIsUnaryOperandStopToken()) {
                    return try self.recoverUnaryMissingOperand(t, .plus);
                }
                const operand = try self.parseUnaryExpression();
                const sp: Span = .{ .start = t.span.start, .end = self.hir.spanOf(operand).end };
                return try self.builder.addUnaryOp(sp, .plus, operand);
            },
            .minus => {
                _ = self.advance();
                if (self.peekIsUnaryOperandStopToken()) {
                    return try self.recoverUnaryMissingOperand(t, .neg);
                }
                const operand = try self.parseUnaryExpression();
                const sp: Span = .{ .start = t.span.start, .end = self.hir.spanOf(operand).end };
                return try self.builder.addUnaryOp(sp, .neg, operand);
            },
            .bang => {
                _ = self.advance();
                if (self.peekIsUnaryOperandStopToken()) {
                    return try self.recoverUnaryMissingOperand(t, .not);
                }
                const operand = try self.parseUnaryExpression();
                const sp: Span = .{ .start = t.span.start, .end = self.hir.spanOf(operand).end };
                return try self.builder.addUnaryOp(sp, .not, operand);
            },
            .tilde => {
                _ = self.advance();
                if (self.peekIsUnaryOperandStopToken()) {
                    return try self.recoverUnaryMissingOperand(t, .bit_not);
                }
                const operand = try self.parseUnaryExpression();
                const sp: Span = .{ .start = t.span.start, .end = self.hir.spanOf(operand).end };
                return try self.builder.addUnaryOp(sp, .bit_not, operand);
            },
            .kw_typeof => {
                _ = self.advance();
                if (self.peekIsUnaryOperandStopToken()) {
                    return try self.recoverUnaryMissingOperand(t, .typeof);
                }
                const operand = try self.parseUnaryExpression();
                const sp: Span = .{ .start = t.span.start, .end = self.hir.spanOf(operand).end };
                return try self.builder.addUnaryOp(sp, .typeof, operand);
            },
            .kw_void => {
                _ = self.advance();
                if (self.peekIsUnaryOperandStopToken()) {
                    return try self.recoverUnaryMissingOperand(t, .void_);
                }
                const operand = try self.parseUnaryExpression();
                const sp: Span = .{ .start = t.span.start, .end = self.hir.spanOf(operand).end };
                return try self.builder.addUnaryOp(sp, .void_, operand);
            },
            .kw_delete => {
                _ = self.advance();
                if (self.peekIsUnaryOperandStopToken()) {
                    return try self.recoverUnaryMissingOperand(t, .delete);
                }
                const operand = try self.parseUnaryExpression();
                // ES2015+ parsing uses the strict-mode delete-identifier
                // early-error shape for unqualified identifiers, while
                // `delete this` and property references stay on their
                // ordinary checker paths.
                if ((self.strict_mode or self.target_es2015_or_later) and self.hir.kindOf(operand) == .identifier and !self.isThisIdentifier(operand)) {
                    const operand_span = self.hir.spanOf(operand);
                    try self.reportCodeAt(operand_span.start, self.lineAt(operand_span.start), 1102, "'delete' cannot be called on an identifier in strict mode.");
                }
                const sp: Span = .{ .start = t.span.start, .end = self.hir.spanOf(operand).end };
                return try self.builder.addUnaryOp(sp, .delete, operand);
            },
            .kw_await => {
                // `await expr` — parses as a unary expression.
                // Per spec, `await` is only valid inside async fns or
                // module top-level; we don't enforce that here (the
                // checker will). The HIR lands as `await_expr`.
                if (self.ambient_depth > 0) {
                    _ = self.advance();
                    const id = try self.internToken(t);
                    return try self.builder.addIdentifier(tokenSpan(t), id);
                }
                const in_async = self.async_function_depth > 0;
                const next_kind = self.peekAt(1).kind;
                const terminator_follows = next_kind == .semicolon or
                    next_kind == .close_paren or
                    next_kind == .close_bracket or
                    next_kind == .close_brace or
                    next_kind == .comma or
                    next_kind == .colon or
                    next_kind == .eof;
                if (!in_async and self.static_block_depth == 0 and next_kind == .open_paren) {
                    _ = self.advance();
                    const id = try self.internToken(t);
                    const callee = try self.builder.addIdentifier(tokenSpan(t), id);
                    const args = try self.parseArgumentList();
                    defer self.gpa.free(args);
                    const close_pos = self.tokens[self.cursor - 1].span.end;
                    return try self.builder.addCall(.{ .start = t.span.start, .end = close_pos }, callee, args);
                }
                if (terminator_follows and !in_async) {
                    _ = self.advance();
                    const id = try self.internToken(t);
                    return try self.builder.addIdentifier(tokenSpan(t), id);
                }
                if (terminator_follows and in_async) {
                    // `await)` / `await]` / `await,` inside an async
                    // function — `await` is a reserved keyword here,
                    // so treat it as an await-expression with a
                    // missing operand. Mirrors tsc: TS2524 at the
                    // `await` token when inside a parameter
                    // initializer, plus TS1109 at the position right
                    // after `await` for the missing operand.
                    _ = self.advance();
                    if (self.param_initializer_depth > 0) {
                        try self.reportCodeAt(t.span.start, t.line, 2524, "'await' expressions cannot be used in a parameter initializer.");
                    }
                    const err_pos = t.span.end;
                    try self.reportCodeAt(err_pos, t.line, 1109, "Expression expected.");
                    return try self.builder.addAwaitExpr(tokenSpan(t), hir_mod.none_node_id);
                }
                _ = self.advance();
                const operand = try self.parseUnaryExpression();
                const sp: Span = .{ .start = t.span.start, .end = self.hir.spanOf(operand).end };
                if (self.param_initializer_depth > 0) {
                    try self.reportCodeAt(t.span.start, t.line, 2524, "'await' expressions cannot be used in a parameter initializer.");
                }
                return try self.builder.addAwaitExpr(sp, operand);
            },
            .kw_yield => {
                if (self.generator_depth == 0) {
                    _ = self.advance();
                    if (self.function_depth > 0) {
                        try self.reportCodeAt(t.span.start, t.line, 1163, "A 'yield' expression is only allowed in a generator body.");
                        const is_delegated = self.match(.asterisk);
                        if (self.peek().kind == .semicolon or
                            self.peek().flags.preceded_by_newline or
                            self.peek().kind == .close_paren or
                            self.peek().kind == .close_bracket or
                            self.peek().kind == .close_brace or
                            self.peek().kind == .comma or
                            self.peek().kind == .eof)
                        {
                            return try self.builder.addYieldExpr(tokenSpan(t), hir_mod.none_node_id, is_delegated);
                        }
                        const operand = try self.parseAssignmentExpression();
                        const sp: Span = .{ .start = t.span.start, .end = self.hir.spanOf(operand).end };
                        return try self.builder.addYieldExpr(sp, operand, is_delegated);
                    }
                    // Top-level `yield` used as an identifier. When the
                    // target is ES2015+ (or we're in explicit strict
                    // mode), `yield` is a reserved word; tsc emits
                    // TS1212 at the keyword position in addition to
                    // the checker-side TS2304. Matches baselines like
                    // `YieldExpression1_es6` / `YieldExpression8_es6`
                    // / `YieldExpression18_es6`. The `* operand` form
                    // is treated by tsc as a multiplication of the
                    // `yield` identifier by the operand, so TS1212
                    // still fires (mirrors YieldStarExpression1_es6).
                    // The `*` followed by a terminator is the broken
                    // yield-star case: TS1109 fires and TS1212 does
                    // NOT (mirrors YieldStarExpression2_es6).
                    const next_is_star = self.peek().kind == .asterisk;
                    var star_operand_missing = false;
                    if (next_is_star) {
                        const after_star_kind = self.peekAt(1).kind;
                        star_operand_missing = after_star_kind == .semicolon or
                            after_star_kind == .eof or
                            after_star_kind == .close_paren or
                            after_star_kind == .close_bracket or
                            after_star_kind == .close_brace or
                            after_star_kind == .comma;
                    }
                    const operand_follows = !next_is_star and
                        self.peek().kind != .open_paren and
                        self.peek().kind != .semicolon and
                        !self.peek().flags.preceded_by_newline and
                        self.peek().kind != .close_paren and
                        self.peek().kind != .close_bracket and
                        self.peek().kind != .close_brace and
                        self.peek().kind != .comma and
                        self.peek().kind != .eof;
                    if (operand_follows and (self.target_es2015_or_later or self.strict_mode)) {
                        try self.reportCodeAt(t.span.start, t.line, 1163, "A 'yield' expression is only allowed in a generator body.");
                        const operand = try self.parseAssignmentExpression();
                        const sp: Span = .{ .start = t.span.start, .end = self.hir.spanOf(operand).end };
                        return try self.builder.addYieldExpr(sp, operand, false);
                    }
                    if (!star_operand_missing and self.isYieldReservedName(t)) {
                        if (self.class_body_depth > 0) {
                            try self.reportCodeAt(t.span.start, t.line, 1213, "Identifier expected. 'yield' is a reserved word in strict mode. Class definitions are automatically in strict mode.");
                        } else {
                            try self.reportCodeAt(t.span.start, t.line, 1212, "Identifier expected. 'yield' is a reserved word in strict mode.");
                        }
                    }
                    const id = try self.internToken(t);
                    var ident = try self.builder.addIdentifier(tokenSpan(t), id);
                    if (star_operand_missing and self.match(.asterisk)) {
                        const err_pos = if (self.cursor > 0) self.tokens[self.cursor - 1].span.end else t.span.end;
                        try self.reportCodeAt(err_pos, t.line, 1109, "Expression expected.");
                    }
                    // Consume an immediate call-args suffix so `yield(foo)`
                    // (YieldExpression8_es6 / YieldExpression18_es6) parses
                    // as a call on the yield identifier instead of leaving
                    // `(foo)` to a follow-on statement parser that would
                    // synthesise a spurious TS1005 between them.
                    if (self.peek().kind == .open_paren) {
                        const args = try self.parseArgumentList();
                        defer self.gpa.free(args);
                        const close_pos = self.tokens[self.cursor - 1].span.end;
                        const sp: Span = .{ .start = t.span.start, .end = close_pos };
                        ident = try self.builder.addCall(sp, ident, args);
                    }
                    return ident;
                }
                // `yield` / `yield expr` / `yield* expr`.
                _ = self.advance();
                const is_delegated = self.match(.asterisk);
                // `yield` with no operand is allowed at expression
                // statement position; we accept any expression that
                // a unary parser would.
                if (self.peek().kind == .semicolon or
                    self.peek().flags.preceded_by_newline or
                    self.peek().kind == .close_paren or
                    self.peek().kind == .close_bracket or
                    self.peek().kind == .close_brace or
                    self.peek().kind == .comma or
                    self.peek().kind == .arrow or
                    self.peek().kind == .eof)
                {
                    if (is_delegated) {
                        // tsc anchors TS1109 at the next token (the
                        // token after `yield*` when the operand is
                        // missing) — e.g. for `yield*\n}` the `}`
                        // line/col is reported, not the end of the
                        // `*`. Mirrors YieldExpression5_es6.
                        const next_tok = self.peek();
                        try self.reportCodeAt(next_tok.span.start, next_tok.line, 1109, "Expression expected.");
                    }
                    // TS2523: `yield` expression inside a parameter
                    // initializer (`function * f(a = yield) {}`) is
                    // illegal — mirrors `yieldInParameterInitializerIsError`.
                    if (self.param_initializer_depth > 0) {
                        try self.reportCodeAt(t.span.start, t.line, 2523, "'yield' expressions cannot be used in a parameter initializer.");
                        // tsc additionally emits TS7057 ("'yield'
                        // expression implicitly results in an 'any'
                        // type because its containing generator lacks
                        // a return-type annotation.") at the same
                        // yield position when the bare yield cleanly
                        // terminates the param init (next token is
                        // `)` or `,`). In the recovery case where
                        // `=>` follows (`FunctionDeclaration10_es6`),
                        // tsc skips TS7057 — the recovery TS1005 is
                        // enough. Gate accordingly so #6/#7 match
                        // (`)` / `}` termination) but #10 does not.
                        if (self.async_function_depth == 0 and
                            (self.peek().kind == .close_paren or
                                self.peek().kind == .comma))
                        {
                            try self.reportCodeAt(t.span.start, t.line, 7057, "'yield' expression implicitly results in an 'any' type because its containing generator lacks a return-type annotation.");
                        }
                        // `function * f(a = yield => …)` — when the
                        // bare yield in param init is followed by `=>`,
                        // tsc emits TS1005 (',' expected) at the arrow
                        // and skips the rest of the param's recovery
                        // tokens silently. Mirrors
                        // `FunctionDeclaration10_es6`. We consume the
                        // arrow and following tokens up to the next
                        // param-list boundary so the outer param-list
                        // arrow recovery doesn't double-emit TS1005 and
                        // doesn't re-parse the trailing `yield)` as a
                        // second parameter (which would surface a
                        // spurious TS1212 on the second `yield`).
                        if (self.peek().kind == .arrow) {
                            const arrow_tok = self.advance();
                            try self.reportCodeAt(arrow_tok.span.start, arrow_tok.line, 1005, "',' expected.");
                            var paren_depth: u32 = 0;
                            while (true) {
                                const nk = self.peek().kind;
                                if (nk == .eof) break;
                                if (nk == .open_paren or nk == .open_bracket or nk == .open_brace) {
                                    paren_depth += 1;
                                    _ = self.advance();
                                    continue;
                                }
                                if (nk == .close_paren or nk == .close_bracket or nk == .close_brace) {
                                    if (paren_depth == 0) break;
                                    paren_depth -= 1;
                                    _ = self.advance();
                                    continue;
                                }
                                if (paren_depth == 0 and nk == .comma) break;
                                _ = self.advance();
                            }
                        }
                    }
                    return try self.builder.addYieldExpr(tokenSpan(t), hir_mod.none_node_id, is_delegated);
                }
                const operand = try self.parseAssignmentExpression();
                const sp: Span = .{ .start = t.span.start, .end = self.hir.spanOf(operand).end };
                if (self.param_initializer_depth > 0) {
                    try self.reportCodeAt(t.span.start, t.line, 2523, "'yield' expressions cannot be used in a parameter initializer.");
                }
                return try self.builder.addYieldExpr(sp, operand, is_delegated);
            },
            .plus_plus, .minus_minus => {
                _ = self.advance();
                if (self.peek().kind == .plus_plus or self.peek().kind == .minus_minus) {
                    const bad = self.advance();
                    try self.reportCodeAt(bad.span.start, bad.line, 1109, "Expression expected.");
                    if (self.peek().kind == .semicolon or
                        self.peek().kind == .close_paren or
                        self.peek().kind == .close_bracket or
                        self.peek().kind == .close_brace or
                        self.peek().kind == .comma or
                        self.peek().kind == .eof)
                    {
                        const one = try self.builder.addLiteralNumber(tokenSpan(bad), 1);
                        return one;
                    }
                }
                if (self.peek().kind == .kw_delete) {
                    const bad = self.peek();
                    try self.reportCodeAt(bad.span.start, bad.line, 1109, "Expression expected.");
                    return try self.parseUnaryExpression();
                }
                // `++await …` / `--await …` — per spec the operand of a
                // prefix update operator is a LeftHandSideExpression, so
                // `await` (a unary expression form) is not allowed here.
                // tsc anchors TS1109 at the `await` token and treats the
                // operand as missing.
                if (self.peek().kind == .kw_await and self.async_function_depth > 0) {
                    const bad = self.peek();
                    try self.reportCodeAt(bad.span.start, bad.line, 1109, "Expression expected.");
                    _ = try self.parseUnaryExpression();
                    return try self.builder.addLiteralNumber(tokenSpan(bad), 1);
                }
                const operand = try self.parseUnaryExpression();
                if (self.nodeIsSynthesizedUpdateAssignment(operand)) {
                    const update = hir_mod.assignmentOf(self.hir, operand);
                    const update_op_span = self.hir.spanOf(update.value);
                    try self.reportCodeAt(update_op_span.start, t.line, 1005, "';' expected.");
                    const next = self.peek();
                    const expr_pos = if (next.kind == .semicolon or next.kind == .eof) next.span.start else update_op_span.end;
                    try self.reportCodeAt(expr_pos, t.line, 1109, "Expression expected.");
                    return operand;
                }
                if (!self.isValidUpdateOperand(operand)) {
                    const operand_span = self.hir.spanOf(operand);
                    if (self.prefixUpdateUsesArithmeticOperandDiagnostic(operand)) {
                        try self.reportCodeAt(operand_span.start, t.line, 2356, "An arithmetic operand must be of type 'any', 'number', 'bigint' or an enum type.");
                        if (self.isThisIdentifier(operand)) {
                            return try self.builder.addLiteralNumber(operand_span, 1);
                        }
                        return operand;
                    }
                    if (self.prefixUpdateDefersDiagnosticToChecker(operand)) {
                        // `--foo()` / `--(x + y)` — tsc skips the
                        // grammar-level TS2357 lvalue error and
                        // relies on the checker to emit TS2356 when
                        // the operand's type isn't numeric. Build the
                        // assignment so the synthesised-update path
                        // in `checkBinop` runs.
                        return try self.buildUpdateAssignment(t, operand, t.kind == .plus_plus, true);
                    }
                    if (self.hir.kindOf(operand) == .literal_null or self.hir.kindOf(operand) == .literal_undefined) {
                        return try self.buildUpdateAssignment(t, operand, t.kind == .plus_plus, true);
                    }
                    try self.reportCodeAt(operand_span.start, t.line, 2357, "The operand of an increment or decrement operator must be a variable or a property access.");
                    if (self.isThisIdentifier(operand)) {
                        return try self.builder.addLiteralNumber(operand_span, 1);
                    }
                    return operand;
                }
                return try self.buildUpdateAssignment(t, operand, t.kind == .plus_plus, true);
            },
            else => return try self.parseCallOrMemberExpression(),
        }
    }

    /// Parse a member-access chain off a primary expression — `dot`,
    /// `?.`, and `[index]` — but stop at `(`. Used as the callee of
    /// a `new` expression so the parenthesized argument list belongs
    /// to the `new`, not to a call wrapped around it.
    fn parseMemberExpressionOnly(self: *Parser) ParseError!NodeId {
        var node = try self.parsePrimaryExpression();
        while (true) {
            const t = self.peek();
            switch (t.kind) {
                .dot => {
                    if (self.hir.kindOf(node) == .assignment and self.parenthesizedNodeStart(node) == null) break;
                    _ = self.advance();
                    if (self.hir.kindOf(node) == .literal_number and
                        self.peek().kind == .dot and
                        (self.peekAt(1).kind == .identifier or self.peekAt(1).kind.isContextualKeyword()))
                    {
                        _ = self.advance();
                    }
                    if (self.peek().kind == .invalid) {
                        const bad = self.advance();
                        try self.reportCodeAt(bad.span.start, bad.line, 1127, "Invalid character.");
                        break;
                    }
                    const name_tok = try self.expectIdentifierLike();
                    const name_id = try self.internToken(name_tok);
                    const sp: Span = .{ .start = self.hir.spanOf(node).start, .end = name_tok.span.end };
                    node = try self.builder.addMemberAccess(sp, node, name_id, false);
                },
                .open_bracket => {
                    const open_bracket = self.advance();
                    node = try self.finishElementAccess(node, false, open_bracket.span.start);
                },
                else => break,
            }
        }
        return node;
    }

    fn parseCallOrMemberExpression(self: *Parser) ParseError!NodeId {
        var node = try self.parsePrimaryExpression();
        while (true) {
            const t = self.peek();
            switch (t.kind) {
                .dot => {
                    if (self.hir.kindOf(node) == .assignment and self.parenthesizedNodeStart(node) == null) break;
                    _ = self.advance();
                    if (self.hir.kindOf(node) == .literal_number and
                        self.peek().kind == .dot and
                        (self.peekAt(1).kind == .identifier or self.peekAt(1).kind.isContextualKeyword()))
                    {
                        _ = self.advance();
                    }
                    if (self.peek().kind == .invalid) {
                        const bad = self.advance();
                        try self.reportCodeAt(bad.span.start, bad.line, 1127, "Invalid character.");
                        break;
                    }
                    const name_tok = try self.expectIdentifierLike();
                    if (name_tok.kind == .private_identifier and self.nodeIsOptionalChain(node)) {
                        try self.reportCodeAt(name_tok.span.start, name_tok.line, 18030, "An optional chain cannot contain private identifiers.");
                    }
                    const name_id = try self.internToken(name_tok);
                    const sp: Span = .{ .start = self.hir.spanOf(node).start, .end = name_tok.span.end };
                    node = try self.builder.addMemberAccess(sp, node, name_id, false);
                },
                .question_dot => {
                    _ = self.advance();
                    if (self.peek().kind == .open_paren) {
                        // `a?.()` — optional call.
                        const args = try self.parseArgumentList();
                        defer self.gpa.free(args);
                        const close_pos = self.tokens[self.cursor - 1].span.end;
                        const sp: Span = .{ .start = self.hir.spanOf(node).start, .end = close_pos };
                        node = try self.builder.addOptionalCall(sp, node, args);
                    } else if (self.peek().kind == .open_bracket) {
                        const ob = self.advance();
                        node = try self.finishElementAccess(node, true, ob.span.start);
                    } else if (self.peek().kind == .no_substitution_template or self.peek().kind == .template_head) {
                        try self.reportCodeAt(self.peek().span.start, self.peek().line, 1358, "Tagged template expressions are not permitted in an optional chain.");
                        node = try self.parseTaggedTemplateWithTypeArgs(node, &.{});
                    } else {
                        const name_tok = try self.expectIdentifierLike();
                        if (name_tok.kind == .private_identifier) {
                            try self.reportCodeAt(name_tok.span.start, name_tok.line, 18030, "An optional chain cannot contain private identifiers.");
                        }
                        const name_id = try self.internToken(name_tok);
                        const sp: Span = .{ .start = self.hir.spanOf(node).start, .end = name_tok.span.end };
                        node = try self.builder.addMemberAccess(sp, node, name_id, true);
                    }
                },
                .open_paren => {
                    const args = try self.parseArgumentList();
                    defer self.gpa.free(args);
                    const close_pos = self.tokens[self.cursor - 1].span.end;
                    const sp: Span = .{ .start = self.hir.spanOf(node).start, .end = close_pos };
                    node = try self.builder.addCall(sp, node, args);
                },
                .less_than => {
                    // Speculative: `id<T, U>(...)` — explicit type args
                    // for a generic call. We accept the form only when
                    // a matching `>` is followed immediately by `(` or
                    // a tagged-template literal. Otherwise we bail out
                    // and leave `<` to the binop path.
                    if (self.findCallTypeArgsEnd(self.cursor)) |after_gt| {
                        // `super<T>(...)` — TS2754 fires unconditionally at
                        // the `<`, mirroring typescript-go parser.go where
                        // the diagnostic is emitted as soon as type
                        // arguments are encountered on a `super` callee.
                        // We anchor at the `<` token so the column matches
                        // upstream (`parserSuperExpression2.ts(3,10)`).
                        const less_tok = self.peek();
                        if (self.hir.kindOf(node) == .identifier) {
                            const ident = hir_mod.identifierOf(self.hir, node);
                            if (std.mem.eql(u8, self.interner.get(ident.name), "super")) {
                                try self.reportCodeAt(less_tok.span.start, less_tok.line, 2754, "'super' may not use type arguments.");
                            }
                        }
                        // Parse the type args so the checker can use
                        // them to override call-site inference.
                        const type_args = try self.parseExplicitCallTypeArgs(after_gt);
                        defer self.gpa.free(type_args);
                        try self.reportTypeArgumentsOnlyInTsIfNeeded(type_args);
                        if (self.peek().kind == .no_substitution_template or self.peek().kind == .template_head) {
                            node = try self.parseTaggedTemplateWithTypeArgs(node, type_args);
                        } else {
                            const args = try self.parseArgumentList();
                            defer self.gpa.free(args);
                            const close_pos = self.tokens[self.cursor - 1].span.end;
                            const sp: Span = .{ .start = self.hir.spanOf(node).start, .end = close_pos };
                            node = try self.builder.addCallWithTypeArgs(sp, node, args, type_args);
                        }
                    } else if (self.findInstantiationTypeArgsEnd(self.cursor)) |after_gt| {
                        const less = self.peek();
                        const type_args = try self.parseExplicitCallTypeArgs(after_gt);
                        defer self.gpa.free(type_args);
                        try self.reportTypeArgumentsOnlyInTsIfNeeded(type_args);
                        if (after_gt < self.tokens.len and self.tokens[after_gt].kind == .dot) {
                            try self.reportCodeAt(less.span.start, less.line, 1477, "An instantiation expression cannot be followed by a property access.");
                        }
                        const end_pos = if (self.cursor > 0) self.tokens[self.cursor - 1].span.end else self.hir.spanOf(node).end;
                        const sp: Span = .{ .start = self.hir.spanOf(node).start, .end = end_pos };
                        node = try self.builder.addCallWithTypeArgs(sp, node, &.{}, type_args);
                    } else break;
                },
                .open_bracket => {
                    const ob = self.advance();
                    node = try self.finishElementAccess(node, false, ob.span.start);
                },
                .bang => {
                    // Postfix `!` — non-null assertion. TS only
                    // recognizes this as a postfix when there's no
                    // space between the operand and the `!` *and*
                    // the next token isn't an expression continuation
                    // (`(`, `=`, etc. would re-introduce ambiguity
                    // with the boolean negation prefix). The lexer
                    // emits `bang` either way; the disambiguation
                    // here is sufficient for the common case.
                    _ = self.advance();
                    const sp: Span = .{ .start = self.hir.spanOf(node).start, .end = t.span.end };
                    try self.reportNonNullOnlyInTsIfNeeded(sp.start);
                    node = try self.builder.addNonNullExpression(sp, node);
                },
                .plus_plus, .minus_minus => {
                    if (t.flags.preceded_by_newline) break;
                    if (self.hir.kindOf(node) == .assignment) {
                        _ = self.advance();
                        try self.reportCodeAt(t.span.start, t.line, 1005, "';' expected.");
                        const next = self.peek();
                        const pos = if (next.kind == .semicolon or next.kind == .eof) next.span.start else t.span.end;
                        try self.reportCodeAt(pos, t.line, 1109, "Expression expected.");
                        break;
                    }
                    _ = self.advance();
                    node = try self.buildUpdateAssignment(t, node, t.kind == .plus_plus, false);
                    // ECMAScript: postfix `++`/`--` produces a value, not
                    // a LeftHandSideExpression — so it cannot be followed
                    // by `[…]`, `.id`, call `()` etc. Break the chain so
                    // `id++[e2]` doesn't get glued together as element
                    // access, which would swallow the following enum
                    // member. Mirrors `parserComputedPropertyName30`.
                    //
                    // Exception: a chained `++ ++` / `-- --` (no newline
                    // between) should fall into the `node == .assignment`
                    // branch above so tsc's TS1005 + TS1109 pair fires at
                    // the second operator. Mirrors fixtures
                    // `parserPostfixUnaryExpression1` and
                    // `parserPostfixPostfixExpression1`.
                    const after = self.peek();
                    if ((after.kind == .plus_plus or after.kind == .minus_minus) and !after.flags.preceded_by_newline) continue;
                    break;
                },
                .no_substitution_template, .template_head => {
                    // Tagged template literal: `` tag`…` `` desugars to
                    // a call `tag(stringsArr, …values)`. v0 just types
                    // `stringsArr` as `string[]` (no
                    // TemplateStringsArray shape yet).
                    if (self.nodeIsOptionalChain(node)) {
                        try self.reportCodeAt(t.span.start, t.line, 1358, "Tagged template expressions are not permitted in an optional chain.");
                    }
                    node = try self.parseTaggedTemplateWithTypeArgs(node, &.{});
                },
                else => break,
            }
        }
        return node;
    }

    fn nodeIsOptionalChain(self: *Parser, node: NodeId) bool {
        if (node == hir_mod.none_node_id) return false;
        return switch (self.hir.kindOf(node)) {
            .member_access => blk: {
                const m = hir_mod.memberOf(self.hir, node);
                break :blk m.optional or self.nodeIsOptionalChain(m.object);
            },
            .element_access => blk: {
                const e = hir_mod.elementOf(self.hir, node);
                break :blk e.optional or self.nodeIsOptionalChain(e.object);
            },
            .call_expr => blk: {
                const c = hir_mod.callOf(self.hir, node);
                break :blk c.optional or self.nodeIsOptionalChain(c.callee);
            },
            else => false,
        };
    }

    fn finishElementAccess(self: *Parser, object: NodeId, optional: bool, open_bracket_pos: u32) ParseError!NodeId {
        const idx = if (self.peek().kind == .close_bracket) blk: {
            const close = self.peek();
            try self.reportCodeAt(close.span.start, close.line, 1011, "An element access expression should take an argument.");
            break :blk try self.builder.addLiteralNumber(.{ .start = close.span.start, .end = close.span.start }, 0);
        } else try self.parseExpression();
        const close = try self.expectClosingMatch(.close_bracket, "']' to close index access", open_bracket_pos, "[", "]");
        const sp: Span = .{ .start = self.hir.spanOf(object).start, .end = close.span.end };
        return try self.builder.addElementAccess(sp, object, idx, optional);
    }

    /// Parse a substitution template literal expression
    /// (`` `a${x}b` ``). Cursor at `template_head`. Produces a
    /// `template_literal` HIR node with interleaved text/expr
    /// children.
    fn parseTemplateLiteralExpr(self: *Parser) ParseError!NodeId {
        var texts: std.ArrayListUnmanaged(NodeId) = .empty;
        defer texts.deinit(self.gpa);
        var exprs: std.ArrayListUnmanaged(NodeId) = .empty;
        defer exprs.deinit(self.gpa);

        const head = self.advance(); // template_head: `` `…${ ``
        const head_slice_full = self.source[head.span.start..head.span.end];
        const head_inner = if (head_slice_full.len >= 3)
            head_slice_full[1 .. head_slice_full.len - 2]
        else
            head_slice_full;
        const head_id = self.interner.intern(head_inner) catch return error.OutOfMemory;
        const head_lit = try self.builder.addLiteralString(tokenSpan(head), head_id);
        try texts.append(self.gpa, head_lit);

        while (true) {
            const v = try self.parseExpression();
            try exprs.append(self.gpa, v);
            const next = self.peek();
            if (next.kind == .template_middle) {
                _ = self.advance();
                const sl = self.source[next.span.start..next.span.end];
                const inner = if (sl.len >= 3) sl[1 .. sl.len - 2] else sl;
                const id = self.interner.intern(inner) catch return error.OutOfMemory;
                const lit = try self.builder.addLiteralString(tokenSpan(next), id);
                try texts.append(self.gpa, lit);
                continue;
            }
            if (next.kind == .template_tail) {
                _ = self.advance();
                const sl = self.source[next.span.start..next.span.end];
                const inner = if (sl.len >= 2) sl[1 .. sl.len - 1] else sl;
                const id = self.interner.intern(inner) catch return error.OutOfMemory;
                const lit = try self.builder.addLiteralString(tokenSpan(next), id);
                try texts.append(self.gpa, lit);
                break;
            }
            try self.reportCodeAt(next.span.start, next.line, 1005, "'}' expected.");
            const empty_id = self.interner.intern("") catch return error.OutOfMemory;
            const empty_lit = try self.builder.addLiteralString(.{ .start = next.span.start, .end = next.span.start }, empty_id);
            try texts.append(self.gpa, empty_lit);
            break;
        }

        const end_pos = if (self.cursor > 0) self.tokens[self.cursor - 1].span.end else head.span.end;
        const sp: Span = .{ .start = head.span.start, .end = end_pos };
        return try self.builder.addTemplateLiteralExpr(sp, texts.items, exprs.items);
    }

    /// Parse a tagged template literal as a call expression. Cursor at
    /// `no_substitution_template` or `template_head`. We collect the
    /// string segments into an array literal and the interpolated
    /// expressions as call arguments.
    fn parseTaggedTemplateWithTypeArgs(self: *Parser, tag: NodeId, type_args: []const NodeId) ParseError!NodeId {
        var strings: std.ArrayListUnmanaged(NodeId) = .empty;
        defer strings.deinit(self.gpa);
        var values: std.ArrayListUnmanaged(NodeId) = .empty;
        defer values.deinit(self.gpa);

        const head = self.advance();
        const tag_span = self.hir.spanOf(tag);
        if (self.hir.kindOf(tag) == .identifier) {
            const tag_id = hir_mod.identifierOf(self.hir, tag);
            if (std.mem.eql(u8, self.interner.get(tag_id.name), "super")) {
                if (type_args.len > 0) {
                    try self.reportCodeAt(tag_span.end, self.lineAt(tag_span.end), 2754, "'super' may not use type arguments.");
                }
                try self.reportCodeAt(head.span.start, head.line, 1034, "'super' must be followed by an argument list or member access.");
            }
        }

        if (head.kind == .no_substitution_template) {
            // `` `…` `` — single string segment, no values.
            const slice_full = self.source[head.span.start..head.span.end];
            const inner = if (slice_full.len >= 2) slice_full[1 .. slice_full.len - 1] else slice_full;
            const id = self.interner.intern(inner) catch return error.OutOfMemory;
            const lit = try self.builder.addLiteralString(tokenSpan(head), id);
            try strings.append(self.gpa, lit);
        } else {
            // template_head: `` `…${ ``
            const head_slice_full = self.source[head.span.start..head.span.end];
            const head_inner = if (head_slice_full.len >= 3)
                head_slice_full[1 .. head_slice_full.len - 2]
            else
                head_slice_full;
            const head_id = self.interner.intern(head_inner) catch return error.OutOfMemory;
            const head_lit = try self.builder.addLiteralString(tokenSpan(head), head_id);
            try strings.append(self.gpa, head_lit);

            // Loop: parse expression, then template_middle / template_tail.
            while (true) {
                const v = try self.parseExpression();
                try values.append(self.gpa, v);
                const next = self.peek();
                if (next.kind == .template_middle) {
                    _ = self.advance();
                    const sl = self.source[next.span.start..next.span.end];
                    const inner = if (sl.len >= 3) sl[1 .. sl.len - 2] else sl;
                    const id = self.interner.intern(inner) catch return error.OutOfMemory;
                    const lit = try self.builder.addLiteralString(tokenSpan(next), id);
                    try strings.append(self.gpa, lit);
                    continue;
                }
                if (next.kind == .template_tail) {
                    _ = self.advance();
                    const sl = self.source[next.span.start..next.span.end];
                    const inner = if (sl.len >= 2) sl[1 .. sl.len - 1] else sl;
                    const id = self.interner.intern(inner) catch return error.OutOfMemory;
                    const lit = try self.builder.addLiteralString(tokenSpan(next), id);
                    try strings.append(self.gpa, lit);
                    break;
                }
                try self.reportCodeAt(next.span.start, next.line, 1005, "'}' expected.");
                const empty_id = self.interner.intern("") catch return error.OutOfMemory;
                const empty_lit = try self.builder.addLiteralString(.{ .start = next.span.start, .end = next.span.start }, empty_id);
                try strings.append(self.gpa, empty_lit);
                break;
            }
        }

        const end_pos = if (self.cursor > 0) self.tokens[self.cursor - 1].span.end else head.span.end;
        const call_sp: Span = .{ .start = tag_span.start, .end = end_pos };
        const arr_span: Span = .{ .start = head.span.start, .end = end_pos };
        const strings_arr = try self.builder.addArrayLiteral(arr_span, strings.items);

        // Build args: [stringsArr, ...values]
        var args: std.ArrayListUnmanaged(NodeId) = .empty;
        defer args.deinit(self.gpa);
        try args.append(self.gpa, strings_arr);
        try args.appendSlice(self.gpa, values.items);

        const call_node = if (type_args.len > 0)
            try self.builder.addCallWithTypeArgs(call_sp, tag, args.items, type_args)
        else
            try self.builder.addCall(call_sp, tag, args.items);
        // Flag the desugared call so the emitter re-renders it natively as
        // `` tag`…` `` (the checker keeps its own source-based detection).
        self.hir.call_payloads.items[self.hir.payloads.items[call_node]].is_tagged_template = true;
        return call_node;
    }

    /// Allocates the args slice; caller must `gpa.free` it.
    fn parseArgumentList(self: *Parser) ParseError![]NodeId {
        const arg_list_open = try self.expect(.open_paren, "'(' for argument list");
        // Reset `disallow_arrow_return_type` for argument expressions
        // (a fresh assignment-expression context). Mirrors TS's
        // `parseArgumentExpression` calling
        // `parseAssignmentExpressionOrHigher()` with the default
        // `allowReturnTypeInArrowFunction=true`. See
        // parserArrowFunctionExpression8/9/10/11/12.
        const saved_disallow_arrow_rt = self.disallow_arrow_return_type;
        self.disallow_arrow_return_type = false;
        defer self.disallow_arrow_return_type = saved_disallow_arrow_rt;
        var args: std.ArrayListUnmanaged(NodeId) = .empty;
        errdefer args.deinit(self.gpa);
        var missing_arg_before_statement = false;
        if (self.peek().kind != .close_paren) {
            while (true) {
                const start_tok = self.peek();
                if (start_tok.kind == .invalid) {
                    const bad = self.advance();
                    try self.reportCodeAt(bad.span.start, bad.line, 1127, "Invalid character.");
                    break;
                }
                if (start_tok.kind == .comma) {
                    try self.reportCodeAt(start_tok.span.start, start_tok.line, 1135, "Argument expression expected.");
                    _ = self.advance();
                    if (self.peek().kind == .close_paren) break;
                    continue;
                }
                if (start_tok.kind == .kw_return) {
                    try self.reportCodeAt(start_tok.span.start, start_tok.line, 1135, "Argument expression expected.");
                    missing_arg_before_statement = true;
                    break;
                }
                if (start_tok.kind == .semicolon or start_tok.kind == .close_brace or start_tok.kind == .eof) break;
                const arg = if (self.peek().kind == .dot_dot_dot) blk: {
                    const dot_tok = self.advance();
                    const inner = try self.parseAssignmentExpression();
                    const end = self.tokens[self.cursor - 1].span.end;
                    break :blk try self.builder.addSpread(.{ .start = dot_tok.span.start, .end = end }, inner);
                } else try self.parseAssignmentExpression();
                try args.append(self.gpa, arg);
                if (!self.match(.comma)) {
                    if (self.peek().kind == .invalid) {
                        const bad = self.advance();
                        try self.reportCodeAt(bad.span.start, bad.line, 1127, "Invalid character.");
                    }
                    break;
                }
                if (self.peek().kind == .close_paren) break; // trailing comma
            }
        }
        if (self.peek().kind == .close_paren) {
            _ = self.advance();
        } else {
            const close_tok = self.peek();
            if (close_tok.kind == .kw_return and !missing_arg_before_statement and args.items.len > 0) {
                try self.reportCodeAt(close_tok.span.start, close_tok.line, 1005, "',' expected.");
            } else if (!missing_arg_before_statement) {
                try self.reportCodeAtWithMatchedPair(
                    close_tok.span.start,
                    close_tok.line,
                    1005,
                    "')' expected.",
                    arg_list_open.span.start,
                    "(",
                    ")",
                );
            }
        }
        return try args.toOwnedSlice(self.gpa);
    }

    fn parsePrimaryExpression(self: *Parser) ParseError!NodeId {
        const t = self.peek();
        switch (t.kind) {
            .number_literal => {
                _ = self.advance();
                const slice = self.source[t.span.start..t.span.end];
                try self.reportStrictLegacyOctal(t, slice);
                try self.reportNumericLiteralDiagnostics(t, slice);
                const value = parseNumericLiteral(slice);
                return try self.builder.addLiteralNumber(tokenSpan(t), value);
            },
            .bigint_literal => {
                _ = self.advance();
                // Strip the trailing `n` suffix.
                const slice_with_n = self.source[t.span.start..t.span.end];
                const digits_slice = slice_with_n[0 .. slice_with_n.len - 1];
                const id = self.interner.intern(digits_slice) catch return error.OutOfMemory;
                return try self.builder.addLiteralBigInt(tokenSpan(t), id);
            },
            .string_literal => {
                _ = self.advance();
                const id = try self.internStringLiteral(t);
                return try self.builder.addLiteralString(tokenSpan(t), id);
            },
            .regex_literal, .slash => {
                return try self.parseRegexLiteralExpression();
            },
            .no_substitution_template => {
                _ = self.advance();
                // Build a template_literal HIR node so the emitter can
                // pick the right form for the target (native backticks
                // at ES2015+, string concat at ES5).
                const slice = self.source[t.span.start..t.span.end];
                const inner = if (slice.len >= 2) slice[1 .. slice.len - 1] else slice;
                const id = self.interner.intern(inner) catch return error.OutOfMemory;
                const text_lit = try self.builder.addLiteralString(tokenSpan(t), id);
                return try self.builder.addTemplateLiteralExpr(tokenSpan(t), &.{text_lit}, &.{});
            },
            .template_head => {
                return try self.parseTemplateLiteralExpr();
            },
            .kw_true => {
                _ = self.advance();
                return try self.builder.addLiteralBool(tokenSpan(t), true);
            },
            .kw_false => {
                _ = self.advance();
                return try self.builder.addLiteralBool(tokenSpan(t), false);
            },
            .kw_null => {
                _ = self.advance();
                return try self.builder.addLiteralNull(tokenSpan(t));
            },
            .kw_undefined => {
                _ = self.advance();
                return try self.builder.addLiteralUndefined(tokenSpan(t));
            },
            .identifier => {
                _ = self.advance();
                if (std.mem.eql(u8, self.source[t.span.start..t.span.end], "undefined")) {
                    // `undefined` is a regular identifier in the JS
                    // grammar but emits as a literal in HIR for
                    // Phase 3's narrowing convenience. Treat for
                    // Phase 1.D as a normal identifier; type-checker
                    // patches up.
                }
                const id = try self.internToken(t);
                return try self.builder.addIdentifier(tokenSpan(t), id);
            },
            .kw_any, .kw_unknown, .kw_never, .kw_void, .kw_string, .kw_number, .kw_boolean, .kw_bigint, .kw_symbol, .kw_object, .kw_get, .kw_set, .kw_global, .kw_from, .kw_require, .kw_module, .kw_namespace, .kw_interface, .kw_declare, .kw_of, .kw_type, .kw_using, .kw_await, .kw_static, .kw_let => {
                _ = self.advance();
                if (!(t.kind == .kw_let and self.namespace_depth > 0 and !self.strict_mode) and
                    !(t.kind == .kw_static and self.accessibilityKeywordIsMemberRoot(t)))
                {
                    try self.reportInvalidFutureReservedName(t);
                }
                const id = try self.internToken(t);
                return try self.builder.addIdentifier(tokenSpan(t), id);
            },
            .kw_public, .kw_private, .kw_protected => {
                // Strict-future-reserved words like `public` are valid
                // identifier expressions when reached in expression
                // position (e.g. inside a computed property name
                // `[public]: 0` or a class-body computed key). Emit the
                // upstream TS1212 / TS1213 strict-reserved diagnostic
                // and synthesize an identifier so downstream checker
                // reports TS2304 instead of TS1109. Mirrors fixtures
                // `parserComputedPropertyName36`-`39`.
                _ = self.advance();
                if (!self.accessibilityKeywordIsMemberRoot(t)) {
                    try self.reportInvalidClassStrictIdentifier(t);
                    try self.reportInvalidFutureReservedName(t);
                }
                const id = try self.internToken(t);
                return try self.builder.addIdentifier(tokenSpan(t), id);
            },
            .private_identifier => {
                _ = self.advance();
                const outside_private_brand_check = self.class_body_depth == 0 and
                    self.strict_grammar_mode and self.peek().kind == .kw_in;
                if (self.class_body_depth == 0 and
                    (self.strict_grammar_mode or self.peek().kind != .kw_in))
                {
                    const diag_index: u32 = @intCast(self.diagnostics.items.len);
                    try self.reportCodeAt(
                        t.span.start,
                        t.line,
                        18016,
                        "Private identifiers are not allowed outside class bodies.",
                    );
                    if (outside_private_brand_check) {
                        try self.pending_outside_private_brand_diag_indices.append(self.gpa, diag_index);
                    }
                } else if (self.peek().kind != .kw_in) {
                    try self.reportCodeAt(
                        t.span.start,
                        t.line,
                        1451,
                        "Private identifiers are only allowed in class bodies and may only be used as part of a class member declaration, property access, or on the left-hand-side of an 'in' expression",
                    );
                }
                const id = try self.internToken(t);
                return try self.builder.addIdentifier(tokenSpan(t), id);
            },
            .open_paren => {
                _ = self.advance();
                // Reset `disallow_arrow_return_type` inside a
                // parenthesized expression — the inner expression is a
                // fresh assignment-expression context. Mirrors TS
                // arg-expression handling. See
                // parserArrowFunctionExpression8/9/10/11/12.
                const saved_disallow_arrow_rt = self.disallow_arrow_return_type;
                self.disallow_arrow_return_type = false;
                const e = self.parseExpression() catch |err| {
                    self.disallow_arrow_return_type = saved_disallow_arrow_rt;
                    return err;
                };
                self.disallow_arrow_return_type = saved_disallow_arrow_rt;
                // §6.A parserArrowFunctionExpression3: `(() => { } || a)`
                // — when the speculative arrow inside the parens has a
                // block body, `parseAssignmentExpression` exits as
                // soon as the arrow is parsed (since the next token
                // is `||`, not an assignment op). Control returns
                // here with the cursor on `||`, but tsc still treats
                // the `||` as a binary operator INSIDE the parens
                // (so `a` on the RHS still binds and reports TS2304).
                // Emit the TS1005 `')' expected.` at the operator
                // (matching the baseline at col 16), then continue
                // parsing the `|| a)` tail as if the `)` were
                // already in place. The remaining identifier becomes
                // its own expression-statement after the trailing
                // `)` triggers a second TS1005 `';' expected.`.
                if (self.peek().kind == .pipe_pipe or
                    self.peek().kind == .ampersand_ampersand or
                    self.peek().kind == .question_question)
                {
                    const op_tok = self.peek();
                    try self.reportCodeAtWithMatchedPair(
                        op_tok.span.start,
                        op_tok.line,
                        1005,
                        "')' expected.",
                        t.span.start,
                        "(",
                        ")",
                    );
                    return e;
                }
                _ = try self.expectClosingMatch(.close_paren, "')' to close parenthesized expression", t.span.start, "(", ")");
                return e;
            },
            .less_than => {
                if (self.isJsxSyntaxAt(t.span.start)) return try self.parseJsx();
                // In .ts files `<T>expr` is a type assertion. Parse
                // the full type node so forms like `<T[]>null` and
                // `<Array<T>>null` consume nested `>` tokens through
                // the same rescan path used by type references.
                _ = self.advance();
                const type_node = try self.parseTypeAnnotation();
                try self.reportErasableSyntaxOnlyTypeAssertionIfNeeded(t);
                const consumed_gt = try self.consumeTypeAssertionGreater();
                const expr = if (!consumed_gt and self.peek().kind == .eof)
                    try self.syntheticTypeAssertionOperandAt(self.peek())
                else
                    try self.parseUnaryExpression();
                return try self.builder.addAsExpression(.type_assertion, .{
                    .start = t.span.start,
                    .end = self.hir.spanOf(expr).end,
                }, expr, type_node);
            },
            .open_bracket => return try self.parseArrayLiteral(),
            .open_brace => return try self.parseObjectLiteral(),
            .at => {
                _ = try self.parseDecoratorExpression();
                if (self.peek().kind == .kw_class or
                    (self.peek().kind == .kw_abstract and self.abstractClassFollowsOnSameLine()))
                {
                    return try self.parseClassDeclaration();
                }
                // Mirrors typescript-go's `parseDecoratedExpression`:
                // decorators in expression position are consumed first,
                // then a missing declaration is synthesized when no class
                // follows. Anchor TS1109 at the end of the decorator
                // sequence (the full-start position of the next token) so
                // outer statement recovery can report the follow-on token.
                // For `var F = @dec () => {}`, that produces TS1109 after
                // `)` and lets `consumeStatementTerminator` emit TS1005 on
                // `=>`, matching decoratorOnArrowFunction exactly.
                const missing_pos = if (self.cursor > 0)
                    self.tokens[self.cursor - 1].span.end
                else
                    t.span.end;
                try self.reportCodeAt(missing_pos, t.line, 1109, "Expression expected.");
                return try self.builder.addLiteralNumber(
                    .{ .start = t.span.start, .end = missing_pos },
                    0,
                );
            },
            .kw_class => return try self.parseClassDeclaration(),
            .kw_abstract => {
                if (self.abstractClassFollowsOnSameLine()) return try self.parseClassDeclaration();
                _ = self.advance();
                const id = try self.internToken(t);
                return try self.builder.addIdentifier(tokenSpan(t), id);
            },
            .kw_this => {
                _ = self.advance();
                const this_id = self.interner.intern("this") catch return error.OutOfMemory;
                return try self.builder.addIdentifier(tokenSpan(t), this_id);
            },
            .kw_super => {
                _ = self.advance();
                const super_id = self.interner.intern("super") catch return error.OutOfMemory;
                return try self.builder.addIdentifier(tokenSpan(t), super_id);
            },
            .kw_new => {
                if (self.peekAt(1).kind == .dot and
                    (self.peekAt(2).kind == .identifier or self.peekAt(2).kind.isContextualKeyword()) and
                    self.tokenTextEquals(self.peekAt(2), "target"))
                {
                    const new_tok = self.advance();
                    _ = self.advance(); // dot
                    const target_tok = self.advance();
                    if (self.new_target_depth == 0) {
                        try self.reportCodeAt(new_tok.span.start, new_tok.line, 17013, "Meta-property 'new.target' is only allowed in the body of a function declaration, function expression, or constructor.");
                    }
                    const id = self.interner.intern("new.target") catch return error.OutOfMemory;
                    return try self.builder.addIdentifier(.{ .start = new_tok.span.start, .end = target_tok.span.end }, id);
                }
                if (self.peekAt(1).kind == .less_than) {
                    const less = self.peekAt(1);
                    try self.reportCodeAt(less.span.start, less.line, 1109, "Expression expected.");
                    const name_tok = self.peekAt(2);
                    if (name_tok.kind == .identifier or name_tok.kind.isContextualKeyword()) {
                        const name_text = self.source[name_tok.span.start..name_tok.span.end];
                        const msg = try std.fmt.allocPrint(self.diag_arena.allocator(), "Cannot find name '{s}'.", .{name_text});
                        try self.reportCodeAt(name_tok.span.start, name_tok.line, 2304, msg);
                    }
                }
                _ = self.advance();
                // Lowered as a dedicated `new_expr` so the checker can
                // produce the class instance type rather than the
                // constructor's call return type. The callee starts as a
                // member-only parse so `new Foo(args)` doesn't get
                // pre-consumed as a call, then admits the one call-like
                // form that can be the constructed expression:
                // `new tag<T> `...` <U>(...)`.
                var callee = try self.parseMemberExpressionOnly();
                if (self.peek().kind == .less_than) {
                    if (self.findCallTypeArgsEnd(self.cursor)) |after_gt| {
                        const after_kind = self.tokens[after_gt].kind;
                        if (after_kind == .no_substitution_template or after_kind == .template_head) {
                            const callee_type_args = try self.parseExplicitCallTypeArgs(after_gt);
                            defer self.gpa.free(callee_type_args);
                            callee = try self.parseTaggedTemplateWithTypeArgs(callee, callee_type_args);
                        }
                    }
                }
                if (self.peek().kind == .no_substitution_template or self.peek().kind == .template_head) {
                    callee = try self.parseTaggedTemplateWithTypeArgs(callee, &.{});
                }
                if (self.peek().kind == .question_dot) {
                    const qdot = self.peek();
                    const callee_span = self.hir.spanOf(callee);
                    const callee_text = self.source[callee_span.start..callee_span.end];
                    const msg = try std.fmt.allocPrint(
                        self.diag_arena.allocator(),
                        "Invalid optional chain from new expression. Did you mean to call '{s}()'?",
                        .{callee_text},
                    );
                    try self.reportCodeAtWithSpan(qdot.span.start, qdot.line, qdot.span.end - qdot.span.start, 1209, msg);
                }
                var type_args: []NodeId = &.{};
                if (self.peek().kind == .less_than) {
                    const saved_cursor = self.cursor;
                    const saved_diag_len = self.diagnostics.items.len;
                    const saved_pending_type_gt = self.pending_type_gt;
                    const saved_pending_type_gt_pos = self.pending_type_gt_pos;
                    const saved_pending_type_gt_line = self.pending_type_gt_line;
                    const saved_pending_type_gt_flags = self.pending_type_gt_flags;
                    const saved_pending_type_eq = self.pending_type_eq;
                    const saved_pending_type_eq_pos = self.pending_type_eq_pos;
                    const saved_pending_type_eq_line = self.pending_type_eq_line;
                    const saved_pending_type_eq_flags = self.pending_type_eq_flags;
                    if (self.parseTypeArgumentList()) |parsed| {
                        if (self.peek().kind == .open_paren) {
                            type_args = parsed;
                            try self.reportTypeArgumentsOnlyInTsIfNeeded(type_args);
                        } else if (self.newExpressionTypeArgsCanEndHere()) {
                            type_args = parsed;
                            try self.reportTypeArgumentsOnlyInTsIfNeeded(type_args);
                        } else {
                            self.gpa.free(parsed);
                            self.cursor = saved_cursor;
                            self.diagnostics.items.len = saved_diag_len;
                            self.pending_type_gt = saved_pending_type_gt;
                            self.pending_type_gt_pos = saved_pending_type_gt_pos;
                            self.pending_type_gt_line = saved_pending_type_gt_line;
                            self.pending_type_gt_flags = saved_pending_type_gt_flags;
                            self.pending_type_eq = saved_pending_type_eq;
                            self.pending_type_eq_pos = saved_pending_type_eq_pos;
                            self.pending_type_eq_line = saved_pending_type_eq_line;
                            self.pending_type_eq_flags = saved_pending_type_eq_flags;
                        }
                    } else |_| {
                        self.cursor = saved_cursor;
                        self.diagnostics.items.len = saved_diag_len;
                        self.pending_type_gt = saved_pending_type_gt;
                        self.pending_type_gt_pos = saved_pending_type_gt_pos;
                        self.pending_type_gt_line = saved_pending_type_gt_line;
                        self.pending_type_gt_flags = saved_pending_type_gt_flags;
                        self.pending_type_eq = saved_pending_type_eq;
                        self.pending_type_eq_pos = saved_pending_type_eq_pos;
                        self.pending_type_eq_line = saved_pending_type_eq_line;
                        self.pending_type_eq_flags = saved_pending_type_eq_flags;
                    }
                }
                defer if (type_args.len > 0) self.gpa.free(type_args);
                if (self.peek().kind == .open_paren) {
                    const args = try self.parseArgumentList();
                    defer self.gpa.free(args);
                    const close_pos = self.tokens[self.cursor - 1].span.end;
                    return try self.builder.addNewWithTypeArgs(.{ .start = t.span.start, .end = close_pos }, callee, args, type_args);
                }
                const end_pos = if (type_args.len > 0 and self.cursor > 0) self.tokens[self.cursor - 1].span.end else self.hir.spanOf(callee).end;
                return try self.builder.addNewWithTypeArgs(.{ .start = t.span.start, .end = end_pos }, callee, &.{}, type_args);
            },
            .kw_import => {
                // Dynamic `import("module")` — parses as a call
                // expression with `import` as the callee. We synthesize
                // an identifier named `import` so downstream emit can
                // route the call site through the appropriate
                // module-system lowering (a no-op at .esm; an
                // async require() at .commonjs).
                //
                // `import.meta` — ES2020 module-meta property. The
                // `import` keyword is materialized as an identifier
                // and the surrounding `parseCallOrMemberExpression`
                // loop consumes the `.meta` (and any further
                // chains like `.url`) as ordinary member accesses.
                // The checker treats `import` as a builtin so the
                // chain types as `any` for now (full `ImportMeta`
                // shape is a follow-up).
                _ = self.advance();
                const import_id = self.interner.intern("import") catch return error.OutOfMemory;
                const callee = try self.builder.addIdentifier(tokenSpan(t), import_id);
                if (self.peek().kind != .open_paren) {
                    if (self.peek().kind == .dot and (self.peekAt(1).kind == .identifier or self.peekAt(1).kind.isContextualKeyword())) {
                        const prop = self.peekAt(1);
                        const is_meta = self.tokenTextEquals(prop, "meta");
                        const is_defer = self.tokenTextEquals(prop, "defer");
                        if (is_defer and self.peekAt(2).kind != .open_paren) {
                            try self.reportCodeAt(prop.span.end, prop.line, 1005, "'(' expected.");
                        } else if (!is_meta and !is_defer) {
                            // `import.foo()` → TS18061 (call site suggests
                            // both `meta` and `defer`); `import.foo` →
                            // TS17012 (non-call site only suggests `meta`).
                            // Mirrors upstream `importMetaPropertyInvalidInCall`.
                            const prop_text = self.source[prop.span.start..prop.span.end];
                            if (self.peekAt(2).kind == .open_paren) {
                                const msg = try std.fmt.allocPrint(
                                    self.diag_arena.allocator(),
                                    "'{s}' is not a valid meta-property for keyword 'import'. Did you mean 'meta' or 'defer'?",
                                    .{prop_text},
                                );
                                try self.reportCodeAt(prop.span.start, prop.line, 18061, msg);
                            } else {
                                const msg = try std.fmt.allocPrint(
                                    self.diag_arena.allocator(),
                                    "'{s}' is not a valid meta-property for keyword 'import'. Did you mean 'meta'?",
                                    .{prop_text},
                                );
                                try self.reportCodeAt(prop.span.start, prop.line, 17012, msg);
                            }
                        }
                    }
                    // Not a dynamic import — return the synthesized
                    // identifier so postfix `.meta`/`.meta.url` can
                    // attach as member accesses upstream.
                    return callee;
                }
                const args = try self.parseArgumentList();
                defer self.gpa.free(args);
                const close_pos = self.tokens[self.cursor - 1].span.end;
                // TS1450: a dynamic `import()` expression accepts only a
                // module specifier and an optional attributes object, so
                // an empty argument list or more than two arguments is a
                // grammar error. Mirrors upstream tsgo
                // `checkGrammarImportCallExpression` (grammarchecks.go
                // ~L2192): `argumentNodes == 0 || > 2`. Anchored at the
                // whole call expression (`import(...)`), matching tsc's
                // `grammarErrorOnNode(node, …)` span.
                if (args.len == 0 or args.len > 2) {
                    try self.reportCodeWithSpanAt(
                        t.span.start,
                        t.line,
                        1450,
                        close_pos - t.span.start,
                        "Dynamic imports can only accept a module specifier and an optional set of attributes as arguments",
                    );
                }
                return try self.builder.addCall(.{ .start = t.span.start, .end = close_pos }, callee, args);
            },
            .kw_function => {
                return try self.parseFunctionDeclaration(false, true);
            },
            .kw_async => {
                if (self.peekAt(1).kind == .kw_function) {
                    _ = self.advance();
                    // Bump `async_function_depth` so `await` used as
                    // the function-expression name or as a parameter
                    // name is correctly diagnosed as reserved (TS1359).
                    self.async_function_depth += 1;
                    defer self.async_function_depth -= 1;
                    const fd = try self.parseFunctionDeclaration(false, true);
                    self.hir.markFnAsync(fd);
                    return fd;
                }
                _ = self.advance();
                const id = try self.internToken(t);
                return try self.builder.addIdentifier(tokenSpan(t), id);
            },
            .invalid => {
                const bad = self.advance();
                try self.reportCodeAt(bad.span.start, bad.line, 1127, "Invalid character.");
                if (!self.peek().flags.preceded_by_newline and self.peek().kind == .asterisk) {
                    const star = self.advance();
                    try self.reportCodeAt(star.span.start, star.line, 1109, "Expression expected.");
                    if (!self.peek().flags.preceded_by_newline and arrayLiteralElementCanStart(self.peek().kind)) {
                        return try self.parseUnaryExpression();
                    }
                    return try self.builder.addLiteralNumber(.{ .start = star.span.start, .end = star.span.start }, 0);
                }
                if (!self.peek().flags.preceded_by_newline and arrayLiteralElementCanStart(self.peek().kind)) {
                    return try self.parseUnaryExpression();
                }
                return error.UnexpectedToken;
            },
            .kw_finally => {
                _ = self.advance();
                try self.reportCodeAt(t.span.start, t.line, 1109, "Expression expected.");
                if (self.peek().kind != .open_brace) {
                    const at = self.peek();
                    try self.reportCodeAt(at.span.start, at.line, 1005, "'{' expected.");
                }
                return try self.builder.addLiteralNumber(.{ .start = t.span.start, .end = t.span.start }, 0);
            },
            else => {
                if (t.kind == .kw_from) {
                    _ = self.advance();
                    try self.reportCodeAt(t.span.start, t.line, 1434, "Unexpected keyword or identifier.");
                    const id = try self.internToken(t);
                    return try self.builder.addIdentifier(tokenSpan(t), id);
                }
                if (t.kind.isContextualKeyword()) {
                    _ = self.advance();
                    if (t.kind == .kw_from and self.peek().kind == .string_literal and !self.peek().flags.preceded_by_newline) {
                        try self.reportCodeAt(t.span.start, t.line, 1434, "Unexpected keyword or identifier.");
                    }
                    const id = try self.internToken(t);
                    return try self.builder.addIdentifier(tokenSpan(t), id);
                }
                if (t.kind == .pipe_pipe or t.kind == .ampersand_ampersand or t.kind == .question_question) {
                    _ = self.advance();
                    try self.reportCodeAt(t.span.start, t.line, 1109, "Expression expected.");
                    return try self.parseUnaryExpression();
                }
                if (t.kind == .close_paren or
                    t.kind == .close_brace or
                    t.kind == .semicolon or
                    t.kind == .colon or
                    t.kind == .eof or
                    t.kind == .kw_return or
                    t.kind == .kw_case or
                    t.kind == .kw_default or
                    t.kind == .kw_enum)
                {
                    try self.reportCodeAt(t.span.start, t.line, 1109, "Expression expected.");
                    return error.UnexpectedToken;
                }
                // §6.A 2000-3000 ratchet: emit the canonical tsc
                // "Expression expected." (TS1109) instead of a
                // Home-internal "unexpected token in expression: ..."
                // payload. Aligns recovery diagnostics with upstream
                // baselines on fixtures like `parserMissingLambdaOpenBrace1`
                // (lambda body opens with `var`) where tsc anchors
                // TS1109 at the offending token.
                try self.reportCodeAt(t.span.start, t.line, 1109, "Expression expected.");
                return error.UnexpectedToken;
            },
        }
    }

    fn isThisIdentifier(self: *const Parser, node: NodeId) bool {
        if (self.hir.kindOf(node) != .identifier) return false;
        const id = hir_mod.identifierOf(self.hir, node);
        return std.mem.eql(u8, self.interner.get(id.name), "this");
    }

    fn isValidUpdateOperand(self: *const Parser, operand: NodeId) bool {
        return switch (self.hir.kindOf(operand)) {
            .identifier => !self.isThisIdentifier(operand),
            .member_access, .element_access => true,
            else => false,
        };
    }

    fn nodeIsSynthesizedUpdateAssignment(self: *const Parser, node: NodeId) bool {
        if (self.hir.kindOf(node) != .assignment) return false;
        const a = hir_mod.assignmentOf(self.hir, node);
        if (a.op == null) return false;
        if (a.op.? != .add and a.op.? != .sub) return false;
        if (self.hir.kindOf(a.value) != .literal_number) return false;
        if (hir_mod.literalNumberOf(self.hir, a.value) != 1.0) return false;
        const value_span = self.hir.spanOf(a.value);
        return value_span.end - value_span.start == 2;
    }

    fn prefixUpdateUsesArithmeticOperandDiagnostic(self: *const Parser, operand: NodeId) bool {
        return switch (self.hir.kindOf(operand)) {
            // Operands whose type cannot be coerced to a numeric for
            // increment/decrement render as TS2356 ("An arithmetic
            // operand must be …") instead of TS2357 ("must be a
            // variable or a property access."). Mirrors tsc, which
            // prefers the operand-type error when the operand has a
            // concrete non-numeric shape (object/array/fn/string).
            .array_literal, .object_literal, .fn_decl, .fn_expr, .literal_string, .literal_bool, .template_literal => true,
            .identifier => self.isThisIdentifier(operand),
            else => false,
        };
    }

    /// Operands the parser cannot classify by shape alone — the
    /// checker decides between TS2356 (non-numeric operand type)
    /// and silently accepting once it knows the call/expression's
    /// return type. Build the synthesised assignment so
    /// `checkBinop`'s synth-update path runs.
    fn prefixUpdateDefersDiagnosticToChecker(self: *const Parser, operand: NodeId) bool {
        return switch (self.hir.kindOf(operand)) {
            .call_expr, .binary_op => true,
            else => false,
        };
    }

    fn isValidAssignmentTarget(self: *const Parser, node: NodeId) bool {
        return switch (self.hir.kindOf(node)) {
            // `undefined` parses to a literal_undefined HIR node but
            // is syntactically a valid identifier expression — JS lets
            // you write `undefined = ...` and only the checker rejects
            // it via TS2539. Keep the parser permissive so we don't
            // double-emit TS2364. Mirrors `nullAssignedToUndefined.ts`.
            .identifier, .member_access, .element_access, .array_literal, .object_literal, .literal_undefined => true,
            // `(x as T) = v`, `(x satisfies T) = v`, `(<T>x) = v`, `(x!) = v`:
            // tsc treats the assertion/non-null wrapper (and the stripped
            // parentheses) as transparent for the assignment-target check and
            // validates the wrapped expression. Mirrors
            // `privateNameFieldParenthesisLeftAssignment.ts`.
            .as_expr, .satisfies_expr, .type_assertion, .non_null_expr => self.isValidAssignmentTarget(hir_mod.asExpressionOf(self.hir, node).expr),
            else => false,
        };
    }

    fn parenthesizedNodeStart(self: *const Parser, node: NodeId) ?u32 {
        const sp = self.hir.spanOf(node);
        var before = sp.start;
        while (before > 0) {
            const c = self.source[before - 1];
            if (!std.ascii.isWhitespace(c)) break;
            before -= 1;
        }
        var after = sp.end;
        while (after < self.source.len) : (after += 1) {
            if (!std.ascii.isWhitespace(self.source[after])) break;
        }
        if (before > 0 and after < self.source.len and self.source[before - 1] == '(' and self.source[after] == ')') {
            return before - 1;
        }
        return null;
    }

    fn sourceLineAtPos(self: *const Parser, pos: u32) u32 {
        var line: u32 = 1;
        var i: u32 = 0;
        const limit = @min(pos, @as(u32, @intCast(self.source.len)));
        while (i < limit) : (i += 1) {
            if (self.source[i] == '\n') line += 1;
        }
        return line;
    }

    fn reportInvalidAssignmentTarget(self: *Parser, node: NodeId) ParseError!void {
        if (self.isValidAssignmentTarget(node)) return;
        const pos = self.parenthesizedNodeStart(node) orelse self.hir.spanOf(node).start;
        try self.reportCodeAt(pos, self.sourceLineAtPos(pos), 2364, "The left-hand side of an assignment expression must be a variable or a property access.");
    }

    fn buildUpdateAssignment(self: *Parser, op_tok: Token, operand: NodeId, is_inc: bool, is_prefix: bool) ParseError!NodeId {
        // tsc anchors TS2357 at the operand expression itself
        // (e.g. column of `this` in `++this`, or `new` in `++ new Foo()`).
        const operand_span = self.hir.spanOf(operand);
        const diag_pos = operand_span.start;
        // For prefix updates the operand follows the op token on the
        // same logical token-line; postfix is the inverse. The
        // diagnostic's line field is informational — downstream
        // recomputes it from `pos`. Reuse `op_tok.line` as a safe
        // approximation when the operand lacks a token line.
        const diag_line = op_tok.line;
        try self.reportInvalidStrictIdentifierNode(operand);
        switch (self.hir.kindOf(operand)) {
            .identifier => {
                const id = hir_mod.identifierOf(self.hir, operand);
                if (std.mem.eql(u8, self.interner.get(id.name), "this")) {
                    try self.reportCodeAt(diag_pos, diag_line, 2357, "The operand of an increment or decrement operator must be a variable or a property access.");
                }
            },
            .member_access, .element_access, .literal_undefined => {},
            // Concrete non-numeric operands (`"x"--`, `{}--`, `[]--`)
            // render as TS2356 ("An arithmetic operand must be …")
            // to match tsc, which prefers the operand-type error
            // for these shapes over the bare TS2357 lvalue error.
            .literal_string, .literal_bool, .template_literal, .array_literal, .object_literal, .fn_decl, .fn_expr => {
                try self.reportCodeAt(diag_pos, diag_line, 2356, "An arithmetic operand must be of type 'any', 'number', 'bigint' or an enum type.");
            },
            // Calls / parenthesised binary results
            // are not l-values in JS, but tsc skips TS2357 for them
            // and relies on the checker to emit TS2356 when the
            // return type is non-numeric. Stay silent so the synth
            // path in `checkBinop` picks the right code.
            .call_expr, .binary_op => {},
            else => try self.reportCodeAt(diag_pos, diag_line, 2357, "The operand of an increment or decrement operator must be a variable or a property access."),
        }
        const one = try self.builder.addLiteralNumber(tokenSpan(op_tok), 1);
        const sp: Span = if (is_prefix)
            .{ .start = op_tok.span.start, .end = operand_span.end }
        else
            .{ .start = operand_span.start, .end = op_tok.span.end };
        return try self.builder.addAssignment(sp, operand, one, if (is_inc) .add else .sub);
    }

    // ========================================================================
    // JSX (TSX-only)
    // ========================================================================
    //
    // Phase 1 JSX coverage — *structured* JSX that doesn't require
    // free-text-content tokenization:
    //   - <Foo />, <Foo></Foo>, <Foo>...</Foo>
    //   - Attributes: name="str", name={expr}, name (boolean
    //     shorthand), {...spread}
    //   - Child expression containers: {expr}
    //   - Nested JSX elements as children
    //   - Fragments: <>…</>
    //
    // *Not* yet supported — would require lexer mode switching:
    //   - Bare text content: <p>hello world</p>
    //   - HTML entities: <p>&amp;</p>
    // The parser diagnoses these and continues.

    fn parseJsx(self: *Parser) ParseError!NodeId {
        var node = try self.parseJsxElementOrFragment();
        while (self.peek().kind == .less_than and self.peekAt(1).kind != .slash) {
            // tsgo wraps adjacent JSX elements in expression position in a
            // synthetic comma BinaryExpression so EVERY sibling stays in the
            // AST and still gets checked (each yields its own open/close
            // TS7026 pair); the TS2657 span runs from the first element's
            // start through the invalid sibling's end. Home used to parse
            // and drop the siblings, losing their checker diagnostics
            // entirely (upstream `tsxErrorRecovery2`).
            const first_span = self.hir.spanOf(node);
            const sib = self.parseJsxElementOrFragment() catch |err| switch (err) {
                error.UnexpectedToken => return node,
                else => return err,
            };
            const sib_span = self.hir.spanOf(sib);
            try self.reportCodeAtWithSpan(first_span.start, self.lineForPos(first_span.start), sib_span.end - first_span.start, 2657, "JSX expressions must have one parent element.");
            try self.jsx_comma_recovery_spans.append(self.gpa, .{ .start = first_span.start, .end = sib_span.end });
            node = try self.builder.addBinaryOp(.{ .start = first_span.start, .end = sib_span.end }, .comma, node, sib);
        }
        return node;
    }

    fn jsxTagText(self: *const Parser, tag: NodeId) []const u8 {
        const tag_span = self.hir.spanOf(tag);
        if (tag_span.end <= tag_span.start or tag_span.end > self.source.len) return "";
        return self.source[tag_span.start..tag_span.end];
    }

    /// Compares two JSX tag-name texts byte-for-byte while skipping ASCII
    /// whitespace in both. A qualified name (`A.B.C`) may be written with
    /// whitespace around its dots in the closing tag — `</A . B . C>` — and
    /// still corresponds to `<A.B.C>`. Identifier runs themselves cannot
    /// contain interior whitespace, so dropping all whitespace yields the
    /// canonical comparison form without conflating distinct names.
    fn jsxTagNamesEqualIgnoringWhitespace(a: []const u8, b: []const u8) bool {
        var i: usize = 0;
        var j: usize = 0;
        while (true) {
            while (i < a.len and std.ascii.isWhitespace(a[i])) i += 1;
            while (j < b.len and std.ascii.isWhitespace(b[j])) j += 1;
            const a_done = i >= a.len;
            const b_done = j >= b.len;
            if (a_done or b_done) return a_done and b_done;
            if (a[i] != b[j]) return false;
            i += 1;
            j += 1;
        }
    }

    fn lineForPos(self: *const Parser, pos: u32) u32 {
        var line: u32 = 1;
        var i: usize = 0;
        const raw: usize = @intCast(pos);
        const end: usize = @min(raw, self.source.len);
        while (i < end) : (i += 1) {
            if (self.source[i] == '\n') line += 1;
        }
        return line;
    }

    fn reportJsxCommaExpressionIfNeeded(self: *Parser, expr: NodeId) ParseError!void {
        if (expr == hir_mod.none_node_id or self.hir.kindOf(expr) != .binary_op) return;
        const bin = hir_mod.binopOf(self.hir, expr);
        if (bin.op != .comma) return;
        const expr_span = self.hir.spanOf(expr);
        const line = self.lineForPos(expr_span.start);
        try self.reportCodeAt(expr_span.start, line, 18007, "JSX expressions may not use the comma operator. Did you mean to write an array?");
    }

    fn newExpressionTypeArgsCanEndHere(self: *const Parser) bool {
        return switch (self.peek().kind) {
            .eof,
            .semicolon,
            .close_paren,
            .close_brace,
            .comma,
            => true,
            else => false,
        };
    }

    fn parseJsxElementOrFragment(self: *Parser) ParseError!NodeId {
        const open = try self.expect(.less_than, "'<' to start JSX element");
        // Fragment: `<>...</>`
        if (self.peek().kind == .greater_than) {
            _ = self.advance(); // `>`
            var children: std.ArrayListUnmanaged(NodeId) = .empty;
            defer children.deinit(self.gpa);
            const content_start = self.tokens[self.cursor - 1].span.end;
            try self.parseJsxChildren(&children, content_start);
            // Closing `</>`. Recover when the user wrote a NAMED
            // closing tag (`</div>`) instead of the empty `</>` —
            // emit tsc's TS17015 (`Expected corresponding closing tag
            // for JSX fragment.`) at the offending tag identifier and
            // continue parsing as if it were a fragment close. Mirrors
            // upstream `tsxFragmentErrors` line 13 (`<>hi</div>`).
            // Custom error path when the fragment was never closed:
            // tsc emits `'</' expected.` (TS1005) anchored just past
            // the trailing source content of the fragment's last
            // child — i.e. at the end of the same line where the
            // children ran out, not the start of the NEXT statement.
            // Mirrors `tsxFragmentErrors` line 11's unterminated
            // `<>eof   // Error` fragment where tsc anchors at col 17
            // (end of `<>eof   // Error`).
            if (self.peek().kind != .less_than) {
                const t = self.peek();
                const src = self.source;
                // tsc anchors `'</' expected.` at the end of the
                // line that the fragment's last content was on,
                // INCLUDING any trailing `// …` line comments —
                // i.e. just past the last non-newline character on
                // that line. Walk back from the next token's start
                // through whitespace + newlines, then forward to the
                // newline that terminates the current line, then back
                // to the last non-whitespace character on that line.
                var anchor = t.span.start;
                if (anchor > 0 and anchor <= src.len) {
                    var i: usize = anchor;
                    // Skip leading whitespace/newlines back to the
                    // previous non-empty char.
                    while (i > 0 and (src[i - 1] == ' ' or src[i - 1] == '\t' or src[i - 1] == '\r' or src[i - 1] == '\n')) i -= 1;
                    // Now `i` sits just past the last significant byte
                    // on the previous content line. That's the column
                    // tsc uses.
                    anchor = @intCast(i);
                }
                var anchor_line: u32 = 1;
                {
                    var j: usize = 0;
                    while (j < @as(usize, anchor) and j < src.len) : (j += 1) {
                        if (src[j] == '\n') anchor_line += 1;
                    }
                }
                try self.reportCodeAt(anchor, anchor_line, 1005, "'</' expected.");
                return try self.builder.addJsxFragment(.{ .start = open.span.start, .end = anchor }, children.items);
            }
            const lt_tok = self.advance();
            _ = try self.expect(.slash, "'/' in fragment close");
            const after_slash = self.peek();
            var named_close_recovered = false;
            var named_close_end: u32 = after_slash.span.end;
            if (after_slash.kind != .greater_than and isJsxNamePart(after_slash.kind)) {
                // tsc treats the bogus close-tag name as a regular
                // identifier reference (not a JSX tag) and runs it
                // through normal name resolution, so an unresolved
                // `</div>` inside a fragment emits BOTH TS2304 and
                // TS17015 at the name. Mirrors tsxFragmentErrors line 9
                // `<>hi</div>` — `Cannot find name 'div'.` precedes
                // `Expected corresponding closing tag for JSX fragment.`
                // The close-tag name never participates in real value
                // resolution from this recovery, so emitting from the
                // parser keeps the path self-contained.
                const name_text = self.source[after_slash.span.start..after_slash.span.end];
                const ts2304_msg = try std.fmt.allocPrint(
                    self.diag_arena.allocator(),
                    "Cannot find name '{s}'.",
                    .{name_text},
                );
                try self.diagnostics.append(self.gpa, .{
                    .pos = after_slash.span.start,
                    .line = after_slash.line,
                    .code = 2304,
                    .message = ts2304_msg,
                });
                try self.reportCodeAt(after_slash.span.start, after_slash.line, 17015, "Expected corresponding closing tag for JSX fragment.");
                // Consume the bogus name (and any hyphenation /
                // namespacing) so the trailing `>` is reachable.
                named_close_recovered = true;
                const first = self.advance();
                named_close_end = first.span.end;
                while (true) {
                    const k = self.peek().kind;
                    if ((k == .minus or k == .colon) and isJsxNamePart(self.peekAt(1).kind)) {
                        _ = self.advance();
                        const part = self.advance();
                        named_close_end = part.span.end;
                        continue;
                    }
                    break;
                }
            }
            // tsc additionally emits TS17014 (`JSX fragment has no
            // corresponding closing tag.`) at the `>` that closes
            // the bogus `</name>` (or at the position immediately
            // after the consumed name when no `>` is present). The
            // fragment was never closed by a matching `</>`.
            if (named_close_recovered) {
                const anchor = if (self.peek().kind == .greater_than)
                    self.peek().span.end
                else
                    named_close_end;
                try self.reportCodeAt(anchor, lt_tok.line, 17014, "JSX fragment has no corresponding closing tag.");
            }
            if (self.peek().kind != .greater_than) {
                if (!named_close_recovered) {
                    try self.reportCodeAt(lt_tok.span.start, lt_tok.line, 17014, "JSX fragment has no corresponding closing tag.");
                }
                return try self.builder.addJsxFragment(.{ .start = open.span.start, .end = lt_tok.span.end }, children.items);
            }
            const close = self.advance();
            return try self.builder.addJsxFragment(.{ .start = open.span.start, .end = close.span.end }, children.items);
        }

        // Tag identifier — accept identifier, keyword-like intrinsic names,
        // and member-access (`Foo.Bar`, `this._tagName`).
        var tag = try self.parseJsxTagName("JSX tag name");
        while (self.peek().kind == .dot) {
            _ = self.advance();
            const member_tok = try self.expectIdentifierLike();
            if (member_tok.flags.has_escape) {
                try self.reportCodeAt(member_tok.span.start, member_tok.line, 17021, "Unicode escape sequence cannot appear here.");
            }
            const member_id = try self.internToken(member_tok);
            tag = try self.builder.addMemberAccess(
                .{ .start = self.hir.spanOf(tag).start, .end = member_tok.span.end },
                tag,
                member_id,
                false,
            );
        }
        if (self.peek().kind == .less_than) {
            const type_args = try self.parseTypeArgumentList();
            self.gpa.free(type_args);
        }

        // Attributes.
        var attrs: std.ArrayListUnmanaged(NodeId) = .empty;
        defer attrs.deinit(self.gpa);
        var seen_attr_names: std.ArrayListUnmanaged(hir_mod.StringId) = .empty;
        defer seen_attr_names.deinit(self.gpa);
        while (true) {
            const t = self.peek();
            // Context-free lexer hazard: in `<Foo x={0} />;` the `}`
            // of `{0}` puts the scanner in a position where `slash-
            // starts-regex` returns true, so the rest of the line —
            // `/>; ...` plus any trailing line comment — gets glued
            // into a single `regex_literal`. We detect that here
            // (regex literals always start with `/`) and break the
            // attribute loop so the self-close handler below can
            // unwrap it back into `/` + `>`.
            if (t.kind == .regex_literal and tokenIsJsxSelfCloseRegex(self.source, t)) break;
            switch (t.kind) {
                .greater_than, .slash, .eof => break,
                .open_brace => {
                    _ = self.advance();
                    _ = try self.expect(.dot_dot_dot, "'...' in JSX spread attribute");
                    const expr = try self.parseAssignmentExpression();
                    const close = try self.expectClosingMatch(.close_brace, "'}' to close JSX spread attribute", t.span.start, "{", "}");
                    const node = try self.builder.addJsxSpreadAttribute(
                        .{ .start = t.span.start, .end = close.span.end },
                        expr,
                    );
                    try attrs.append(self.gpa, node);
                },
                else => {
                    // `name`, `name="str"`, `name={expr}`.
                    const name = try self.parseJsxName("JSX attribute name");
                    var duplicate_attr = false;
                    for (seen_attr_names.items) |seen_name| {
                        if (seen_name == name.name) {
                            duplicate_attr = true;
                            break;
                        }
                    }
                    if (duplicate_attr) {
                        const line = self.lineForPos(name.span.start);
                        try self.reportCodeAt(name.span.start, line, 17001, "JSX elements cannot have multiple attributes with the same name.");
                    } else {
                        try seen_attr_names.append(self.gpa, name.name);
                    }
                    var value: NodeId = hir_mod.none_node_id;
                    if (self.match(.equal)) {
                        if (self.peek().kind == .string_literal) {
                            const str_tok = self.advance();
                            const str_id = try self.internStringLiteral(str_tok);
                            value = try self.builder.addLiteralString(tokenSpan(str_tok), str_id);
                        } else if (self.peek().kind == .open_brace) {
                            const jsx_attr_open = self.advance();
                            const expr = try self.parseExpression();
                            try self.reportJsxCommaExpressionIfNeeded(expr);
                            _ = try self.expectClosingMatch(.close_brace, "'}' to close JSX expression value", jsx_attr_open.span.start, "{", "}");
                            value = try self.builder.addJsxExpression(name.span, expr);
                        } else if (self.peek().kind == .less_than) {
                            // JSX-as-attribute-value: `prop={…}` is canonical
                            // but `prop=<Inner/>` is permitted by some
                            // dialects. Phase 1 follow-up.
                            value = try self.parseJsx();
                        } else {
                            const bad = self.peek();
                            try self.reportCodeAt(bad.span.start, bad.line, 1145, "'{' or JSX element expected.");
                        }
                    }
                    const node = try self.builder.addJsxAttribute(
                        .{ .start = name.span.start, .end = self.tokens[self.cursor - 1].span.end },
                        name.name,
                        value,
                    );
                    try attrs.append(self.gpa, node);
                },
            }
        }

        // Self-closing `/>`.
        if (self.match(.slash)) {
            const close = try self.expect(.greater_than, "'>' to close self-closing JSX element");
            return try self.builder.addJsxElement(
                .{ .start = open.span.start, .end = close.span.end },
                tag,
                attrs.items,
                &.{},
                true,
            );
        }
        // Self-closing `/>` whose tokens were swallowed into a
        // `regex_literal` by the slash-starts-regex heuristic.
        // Treat the literal as the self-close marker — consume the
        // whole token. The regex pattern starts at `/>` (the
        // self-close marker) and runs forward through the trailing
        // `;` plus enough of the next line's source for the regex
        // scanner to find a closing `/`. After consuming the
        // regex_literal token, the lexer's residual tokenization
        // from the closing-`/` position forward is garbage (typically
        // `.slash` + `.identifier "OK"` from a `// OK` line comment
        // that got bisected). Skip those until we reach a
        // newline-prefixed token, EOF, or close-brace — equivalent
        // to ASI eating the rest of the bogus statement tail.
        if (self.peek().kind == .regex_literal and tokenIsJsxSelfCloseRegex(self.source, self.peek())) {
            const tok = self.advance();
            const close_end: u32 = @intCast(tok.span.start + 2);
            while (true) {
                const after = self.peek();
                if (after.kind == .eof or after.kind == .close_brace or after.flags.preceded_by_newline) break;
                _ = self.advance();
            }
            return try self.builder.addJsxElement(
                .{ .start = open.span.start, .end = close_end },
                tag,
                attrs.items,
                &.{},
                true,
            );
        }
        const open_close = try self.expect(.greater_than, "'>' to close JSX opening tag");

        var children: std.ArrayListUnmanaged(NodeId) = .empty;
        defer children.deinit(self.gpa);
        try self.parseJsxChildren(&children, open_close.span.end);

        if (self.peek().kind == .eof) {
            const tag_text = self.jsxTagText(tag);
            const tag_span = self.hir.spanOf(tag);
            const msg = try std.fmt.allocPrint(
                self.diag_arena.allocator(),
                "JSX element '{s}' has no corresponding closing tag.",
                .{tag_text},
            );
            try self.diagnostics.append(self.gpa, .{
                .pos = tag_span.start,
                .line = self.lineForPos(tag_span.start),
                .code = 17008,
                .message = msg,
            });
            return try self.builder.addJsxElement(
                .{ .start = open.span.start, .end = self.peek().span.start },
                tag,
                attrs.items,
                children.items,
                false,
            );
        }

        // Closing tag `</Foo>`.
        _ = try self.expect(.less_than, "'<' to start JSX closing tag");
        _ = try self.expect(.slash, "'/' in JSX closing tag");
        var close_name_span: ?Span = null;
        if (self.peek().kind == .identifier or self.peek().kind.isKeyword() or self.peek().kind.isContextualKeyword()) {
            const close_name = try self.parseJsxName("JSX closing tag name");
            close_name_span = close_name.span;
            while (self.peek().kind == .dot) {
                _ = self.advance();
                const part = try self.parseJsxName("JSX closing tag name");
                close_name_span.?.end = part.span.end;
            }
        }
        if (close_name_span) |close_span| {
            const open_text = self.jsxTagText(tag);
            const close_text = self.source[close_span.start..close_span.end];
            // A qualified JSX tag name may carry whitespace around its dots
            // (`</A . B . C.D>`); tsc matches the opening tag structurally,
            // so compare ignoring insignificant whitespace rather than by
            // raw source slice — otherwise `tsxOpeningClosingNames` false-
            // fires TS17002 on `<A.B.C.D>…</A . B . C.D>`.
            if (!jsxTagNamesEqualIgnoringWhitespace(open_text, close_text)) {
                const msg = try std.fmt.allocPrint(
                    self.diag_arena.allocator(),
                    "Expected corresponding JSX closing tag for '{s}'.",
                    .{open_text},
                );
                try self.diagnostics.append(self.gpa, .{
                    .pos = close_span.start,
                    .line = self.lineForPos(close_span.start),
                    .code = 17002,
                    .message = msg,
                });
            }
        }
        const close = try self.expect(.greater_than, "'>' to close JSX closing tag");
        return try self.builder.addJsxElement(
            .{ .start = open.span.start, .end = close.span.end },
            tag,
            attrs.items,
            children.items,
            false,
        );
    }

    const JsxName = struct {
        name: hir_mod.StringId,
        span: Span,
    };

    fn isJsxNamePart(kind: TokenKind) bool {
        return kind == .identifier or kind.isKeyword() or kind.isContextualKeyword();
    }

    /// Primitive type keywords that are reserved as type-alias names.
    /// `type any = ...` etc. is a parser-level error (TS2457). Mirrors
    /// upstream's `reservedNamesInAliases.ts` baseline.
    fn isReservedTypeAliasName(name: []const u8) bool {
        const reserved = [_][]const u8{
            "any",       "unknown", "never",     "object",  "string",
            "number",    "bigint",  "symbol",    "boolean", "void",
            "undefined", "null",    "intrinsic",
        };
        for (reserved) |r| {
            if (std.mem.eql(u8, r, name)) return true;
        }
        return false;
    }

    /// True when the next token's lexeme matches one of the reserved
    /// primitive-type names — even when the lexer classified it as a
    /// keyword (e.g. `kw_any`). Lets `parseTypeAlias` consume `any`
    /// as the alias-name slot before emitting TS2457.
    fn tokenLexemeIsReservedTypeAliasName(self: *Parser) bool {
        const tok = self.peek();
        if (tok.span.end > self.source.len or tok.span.start >= tok.span.end) return false;
        return isReservedTypeAliasName(self.source[tok.span.start..tok.span.end]);
    }

    /// Variant of `tokenLexemeIsReservedTypeAliasName` that probes an
    /// arbitrary token index. Used by the `type` dispatch so a
    /// `kw_any` (etc.) following `type` routes to `parseTypeAlias`
    /// for the TS2457 diagnostic.
    fn tokenAtLexemeIsReservedTypeAliasName(self: *Parser, idx: usize) bool {
        if (idx >= self.tokens.len) return false;
        const tok = self.tokens[idx];
        if (tok.span.end > self.source.len or tok.span.start >= tok.span.end) return false;
        return isReservedTypeAliasName(self.source[tok.span.start..tok.span.end]);
    }

    /// `<Foo x={0} />` is a JSX self-close, but the lexer is context-
    /// free and the `}` of `{0}` enables the slash-starts-regex
    /// heuristic — so `/>; ...` gets swallowed into a single
    /// `regex_literal` whenever the trailing source happens to contain
    /// another `/`. This helper detects that shape so the JSX parser
    /// can unwrap the bogus regex back into a self-close marker.
    fn tokenIsJsxSelfCloseRegex(source: []const u8, tok: Token) bool {
        if (tok.kind != .regex_literal) return false;
        if (tok.span.end <= tok.span.start + 1) return false;
        if (tok.span.start >= source.len) return false;
        if (source[tok.span.start] != '/') return false;
        if (tok.span.start + 1 >= source.len) return false;
        return source[tok.span.start + 1] == '>';
    }

    fn parseJsxName(self: *Parser, what: []const u8) ParseError!JsxName {
        const tok = self.peek();
        if (!isJsxNamePart(tok.kind)) {
            _ = try self.expect(.identifier, what);
        }
        const first = self.advance();
        var parsed_span = tokenSpan(first);
        var has_escape = first.flags.has_escape;
        // Hyphenated parts (`data-foo`) AND single-colon namespaced
        // parts (`svg:path`, `xlink:href`). The namespaced form is
        // never a valid lowercase intrinsic in the React JSX rules —
        // upstream tsc parses it without TS1109 and lets the checker
        // emit TS7026 (no `JSX.IntrinsicElements`) at the JSX element
        // anchor. Capturing the whole `svg:path` as one identifier
        // here gives the checker exactly that handle.
        while (true) {
            const k = self.peek().kind;
            if (k == .minus and isJsxNamePart(self.peekAt(1).kind)) {
                _ = self.advance();
                const part = self.advance();
                parsed_span.end = part.span.end;
                has_escape = has_escape or part.flags.has_escape;
                continue;
            }
            if (k == .colon and isJsxNamePart(self.peekAt(1).kind)) {
                _ = self.advance();
                const part = self.advance();
                parsed_span.end = part.span.end;
                has_escape = has_escape or part.flags.has_escape;
                continue;
            }
            break;
        }
        if (has_escape) {
            try self.reportCodeAt(parsed_span.start, first.line, 17021, "Unicode escape sequence cannot appear here.");
        }
        const text = self.source[parsed_span.start..parsed_span.end];
        const id = self.interner.intern(text) catch return error.OutOfMemory;
        return .{ .name = id, .span = parsed_span };
    }

    fn parseJsxTagName(self: *Parser, what: []const u8) ParseError!NodeId {
        const tok = self.peek();
        if (tok.kind == .kw_this) {
            _ = self.advance();
            const this_id = self.interner.intern("this") catch return error.OutOfMemory;
            return try self.builder.addIdentifier(tokenSpan(tok), this_id);
        }
        const name = try self.parseJsxName(what);
        return try self.builder.addIdentifier(name.span, name.name);
    }

    fn parseJsxChildren(self: *Parser, out: *std.ArrayListUnmanaged(NodeId), content_start: u32) ParseError!void {
        var last_child_end = content_start;
        while (true) {
            const t = self.peek();
            if (t.span.start > last_child_end and self.jsxTextShouldBecomeChild(last_child_end, t.span.start)) {
                try self.reportJsxTextStrayTokens(last_child_end, self.lineAt(last_child_end), t.span.start);
                const id = self.interner.intern(self.source[last_child_end..t.span.start]) catch return error.OutOfMemory;
                const text = try self.builder.addLiteralString(.{ .start = last_child_end, .end = t.span.start }, id);
                try out.append(self.gpa, text);
                last_child_end = t.span.start;
                continue;
            }
            switch (t.kind) {
                .less_than => {
                    if (self.peekAt(1).kind == .slash) return; // `</Foo>`
                    const child = try self.parseJsxElementOrFragment();
                    try out.append(self.gpa, child);
                    last_child_end = self.hir.spanOf(child).end;
                },
                .open_brace => {
                    if (self.jsxCommentExpressionEnd(t.span.start)) |comment_end| {
                        while (self.peek().kind != .eof and self.peek().span.end <= comment_end) _ = self.advance();
                        const node = try self.builder.addJsxExpression(.{ .start = t.span.start, .end = comment_end }, hir_mod.none_node_id);
                        try out.append(self.gpa, node);
                        last_child_end = comment_end;
                        continue;
                    }
                    _ = self.advance();
                    if (self.peek().kind == .close_brace) {
                        _ = self.advance();
                        const node = try self.builder.addJsxExpression(tokenSpan(t), hir_mod.none_node_id);
                        try out.append(self.gpa, node);
                        last_child_end = self.hir.spanOf(node).end;
                        continue;
                    }
                    // tsgo `parseJsxExpression` recovery: a `<` inside a JSX
                    // child expression only re-enters JSX parsing when the
                    // next token is an identifier/keyword/`>`; when the
                    // element's own closing tag (`</…`) shows up where an
                    // expression was expected, tsgo reports TS1109
                    // "Expression expected." at the `<` and recovers with a
                    // missing expression so `</…>` still closes the element
                    // (upstream `tsxErrorRecovery1/2/3`). Home previously
                    // re-entered JSX parsing and emitted "expected JSX tag
                    // name" at the `/`, losing the element (and its TS7026
                    // pair) entirely.
                    if (self.peek().kind == .less_than and self.peekAt(1).kind == .slash) {
                        const bad = self.peek();
                        try self.reportCodeAt(bad.span.start, bad.line, 1109, "Expression expected.");
                        const node = try self.builder.addJsxExpression(.{ .start = t.span.start, .end = bad.span.start }, hir_mod.none_node_id);
                        try out.append(self.gpa, node);
                        last_child_end = bad.span.start;
                        continue;
                    }
                    const expr = if (self.match(.dot_dot_dot)) blk: {
                        const dot_tok = self.tokens[self.cursor - 1];
                        const inner = try self.parseAssignmentExpression();
                        const end = self.hir.spanOf(inner).end;
                        break :blk try self.builder.addSpread(.{ .start = dot_tok.span.start, .end = end }, inner);
                    } else try self.parseExpression();
                    try self.reportJsxCommaExpressionIfNeeded(expr);
                    const close = try self.expectClosingMatch(.close_brace, "'}' to close JSX child expression", t.span.start, "{", "}");
                    const node = try self.builder.addJsxExpression(
                        .{ .start = t.span.start, .end = close.span.end },
                        expr,
                    );
                    try out.append(self.gpa, node);
                    last_child_end = close.span.end;
                },
                .eof => return,
                else => {
                    const text_start = t.span.start;
                    var text_end = t.span.end;
                    // TS1382/TS1381: a literal `>` or `}` appearing in
                    // JSX child text is invalid — tsc's `scanJsxText`
                    // flags each occurrence and suggests the escaped
                    // forms. Mirrors scanner.go ~L1268. We scan the raw
                    // source bytes of the text run (token granularity
                    // would miss `>`/`}` glued to adjacent text) and
                    // anchor a 1-char span at each offending character,
                    // matching upstream's `errorAt(…, s.pos, 1)`.
                    try self.reportJsxTextStrayTokens(text_start, t.line, t.span.end);
                    while (self.peek().kind != .less_than and
                        self.peek().kind != .open_brace and
                        self.peek().kind != .eof)
                    {
                        const part = self.advance();
                        try self.reportJsxTextStrayTokens(part.span.start, part.line, part.span.end);
                        text_end = part.span.end;
                    }
                    if (self.jsxTextShouldBecomeChild(text_start, text_end)) {
                        const id = self.interner.intern(self.source[text_start..text_end]) catch return error.OutOfMemory;
                        const text = try self.builder.addLiteralString(.{ .start = text_start, .end = text_end }, id);
                        try out.append(self.gpa, text);
                    }
                    last_child_end = text_end;
                },
            }
        }
    }

    fn jsxCommentExpressionEnd(self: *const Parser, start: u32) ?u32 {
        if (start + 3 > self.source.len) return null;
        if (!std.mem.startsWith(u8, self.source[start..], "{/*")) return null;
        const body_start = start + 3;
        const rel = std.mem.indexOf(u8, self.source[body_start..], "*/}") orelse return null;
        const end = body_start + rel + 3;
        return @intCast(end);
    }

    /// Scan a JSX child-text byte range and emit TS1382 for each
    /// literal `>` and TS1381 for each literal `}`, anchored at the
    /// offending character with a 1-byte span. Mirrors upstream
    /// `scanJsxText` (scanner.go ~L1268), which surfaces these as the
    /// raw text is consumed. `start`/`end` are absolute source offsets;
    /// `line` is the line of the run's first character (close enough for
    /// the single-line JSX text runs these checks target).
    fn reportJsxTextStrayTokens(self: *Parser, start: u32, line: u32, end: u32) ParseError!void {
        if (end > self.source.len or start >= end) return;
        var i: u32 = start;
        var cur_line = line;
        while (i < end) : (i += 1) {
            const ch = self.source[i];
            switch (ch) {
                '>' => try self.reportCodeWithSpanAt(i, cur_line, 1382, 1, "Unexpected token. Did you mean `{'>'}` or `&gt;`?"),
                '}' => try self.reportCodeWithSpanAt(i, cur_line, 1381, 1, "Unexpected token. Did you mean `{'}'}` or `&rbrace;`?"),
                '\n' => cur_line += 1,
                else => {},
            }
        }
    }

    fn jsxTextShouldBecomeChild(self: *const Parser, start: u32, end: u32) bool {
        if (end <= start or end > self.source.len) return false;
        var saw_non_ws = false;
        var saw_newline = false;
        for (self.source[start..end]) |ch| {
            switch (ch) {
                ' ', '\t', '\r', '\n' => {
                    if (ch == '\r' or ch == '\n') saw_newline = true;
                },
                else => saw_non_ws = true,
            }
        }
        if (saw_non_ws) return true;
        return !saw_newline;
    }

    fn parseArrayLiteral(self: *Parser) ParseError!NodeId {
        const start = try self.expect(.open_bracket, "'[' to start array literal");
        // Reset `disallow_arrow_return_type` for element expressions
        // (a fresh assignment-expression context). Mirrors TS handling.
        // See parserArrowFunctionExpression8/9/10/11/12.
        const saved_disallow_arrow_rt = self.disallow_arrow_return_type;
        self.disallow_arrow_return_type = false;
        defer self.disallow_arrow_return_type = saved_disallow_arrow_rt;
        var elements: std.ArrayListUnmanaged(NodeId) = .empty;
        defer elements.deinit(self.gpa);
        while (self.peek().kind != .close_bracket and self.peek().kind != .eof) {
            if (self.peek().kind == .close_brace) {
                const close = self.peek();
                try self.reportCodeAt(close.span.start, close.line, 1137, "Expression or comma expected.");
                return try self.builder.addArrayLiteral(.{ .start = start.span.start, .end = close.span.start }, elements.items);
            }
            if (self.peek().kind == .comma) {
                // Hole — represent as `none` for now. (TS treats
                // `[,1]` as `[undefined, 1]`.)
                _ = self.advance();
                try elements.append(self.gpa, hir_mod.none_node_id);
                continue;
            }
            // Spread element: `...expr`. Trailing-comma after the
            // spread is permitted in plain array literals (`[1, ...a,]`
            // is legal JS), so TS1013 fires only when the literal is
            // later reinterpreted as a destructuring pattern — that
            // check lives in the checker rather than the parser.
            if (self.peek().kind == .dot_dot_dot) {
                const dot_tok = self.advance();
                const inner = try self.parseAssignmentExpression();
                const end = self.tokens[self.cursor - 1].span.end;
                const sp = try self.builder.addSpread(.{ .start = dot_tok.span.start, .end = end }, inner);
                try elements.append(self.gpa, sp);
                if (!self.match(.comma)) break;
                continue;
            }
            const e = try self.parseAssignmentExpression();
            try elements.append(self.gpa, e);
            if (self.match(.comma)) continue;
            if (self.peek().kind == .close_bracket or self.peek().kind == .eof) break;
            if (self.peek().kind == .semicolon) {
                try self.reportCodeAt(self.peek().span.start, self.peek().line, 1005, "',' expected.");
                const end = if (self.cursor > 0) self.tokens[self.cursor - 1].span.end else start.span.end;
                return try self.builder.addArrayLiteral(.{ .start = start.span.start, .end = end }, elements.items);
            }
            if (arrayLiteralElementCanStart(self.peek().kind)) {
                try self.reportCodeAt(self.peek().span.start, self.peek().line, 1005, "',' expected.");
                continue;
            }
            break;
        }
        const close = try self.expectClosingMatch(.close_bracket, "']' to close array literal", start.span.start, "[", "]");
        return try self.builder.addArrayLiteral(.{ .start = start.span.start, .end = close.span.end }, elements.items);
    }

    fn parseObjectLiteral(self: *Parser) ParseError!NodeId {
        const start = try self.expect(.open_brace, "'{' to start object literal");
        // Template literal as the first property-name token is a hard
        // syntactic error — `{ \`a\`: 321 }` cannot be expressed in TS.
        // tsc handles this by closing the object as empty, emitting
        // TS1136 at the template token, and re-routing the template
        // to the outer call-expression continuation so the empty `{}`
        // becomes the tag of a tagged-template call (which in turn
        // surfaces TS2349 `{} is not callable`). Mirrors
        // templateStringInPropertyName{1,2}, templateStringIn
        // PropertyNameES6_{1,2}, templateStringInObjectLiteral{,ES6}.
        if (self.peek().kind == .no_substitution_template or
            self.peek().kind == .template_head)
        {
            const tmpl = self.peek();
            try self.reportCodeAt(tmpl.span.start, tmpl.line, 1136, "Property assignment expected.");
            return try self.builder.addObjectLiteral(
                .{ .start = start.span.start, .end = start.span.end },
                &.{},
            );
        }
        // Reset `disallow_arrow_return_type` for property values (a
        // fresh assignment-expression context). Prevents false rewinds
        // in `cond ? { k: (x): T => x } : y`. See
        // parserArrowFunctionExpression8/9/10/11/12.
        const saved_disallow_arrow_rt = self.disallow_arrow_return_type;
        self.disallow_arrow_return_type = false;
        defer self.disallow_arrow_return_type = saved_disallow_arrow_rt;
        var props: std.ArrayListUnmanaged(NodeId) = .empty;
        defer props.deinit(self.gpa);
        while (self.peek().kind != .close_brace and self.peek().kind != .eof) {
            if (self.peek().kind == .comma) {
                const comma = self.advance();
                try self.reportCodeAt(comma.span.start, comma.line, 1136, "Property assignment expected.");
                continue;
            }
            if (self.peek().kind == .colon) {
                const colon = self.advance();
                try self.reportCodeAt(colon.span.start, colon.line, 1136, "Property assignment expected.");
                continue;
            }
            const prop_start = self.peek();
            var method_is_async = false;
            if (self.peek().kind == .kw_async) {
                const next = self.peekAt(1).kind;
                const after_next = self.peekAt(2).kind;
                if (next == .asterisk or
                    next == .open_bracket or
                    ((next == .identifier or next.isContextualKeyword()) and
                        (after_next == .open_paren or after_next == .less_than)))
                {
                    _ = self.advance();
                    method_is_async = true;
                }
            }
            const method_is_generator = self.match(.asterisk);
            // Generator-method shorthand requires a property-name token
            // (or `[` for a computed key) after `*`. When the next
            // token cannot start a property name, tsc reports
            // `TS1003 Identifier expected.` at that token and stops
            // parsing this property. Matches FunctionPropertyAssignments
            // {2,3,4,6}_es6 baselines (`var v = { * ... }` forms with
            // `*(`, `*{`, `* }`, or `*<T>()`).
            if (method_is_generator) {
                const next_kind = self.peek().kind;
                const can_start_method_name = switch (next_kind) {
                    .identifier,
                    .private_identifier,
                    .string_literal,
                    .number_literal,
                    .open_bracket,
                    => true,
                    else => next_kind.isKeyword() or next_kind.isContextualKeyword(),
                };
                if (!can_start_method_name) {
                    const bad = self.peek();
                    try self.reportCodeAt(bad.span.start, bad.line, 1003, "Identifier expected.");
                    // Skip ahead until the next `,` or the OUTER
                    // closing `}` so the object-literal scan can
                    // close cleanly. Tracks nested `{`/`(`/`[` depth
                    // so a synthetic method body (`{}`), parameter
                    // list (`()`), or type-arg list (`<>`) doesn't
                    // confuse the scan into terminating early.
                    // Mirrors tsc which silently consumes the broken
                    // property and resumes at the next list item.
                    var depth: u32 = 0;
                    while (self.peek().kind != .eof) {
                        const k = self.peek().kind;
                        if (depth == 0 and (k == .close_brace or k == .comma)) break;
                        if (k == .open_brace or k == .open_paren or k == .open_bracket) {
                            depth += 1;
                        } else if (k == .close_brace or k == .close_paren or k == .close_bracket) {
                            if (depth > 0) depth -= 1;
                        }
                        _ = self.advance();
                    }
                    if (!self.match(.comma)) break;
                    continue;
                }
            }
            // Spread element: `...expr`. Wrap in a `.spread` node so
            // diagnostics anchored at the prop point at the `...` token
            // (matching upstream tsc's TS2698 column position).
            if (self.match(.dot_dot_dot)) {
                const dot_tok = self.tokens[self.cursor - 1];
                if (self.peek().kind == .identifier and
                    self.peekAt(1).kind == .question and
                    self.peekAt(2).kind == .close_brace)
                {
                    const ident_tok = self.advance();
                    const ident_id = try self.internToken(ident_tok);
                    const value = try self.builder.addIdentifier(tokenSpan(ident_tok), ident_id);
                    const question_tok = self.advance();
                    try self.reportCodeAt(question_tok.span.start + 2, question_tok.line, 1109, "Expression expected.");
                    const spread_node = try self.builder.addSpread(
                        .{ .start = dot_tok.span.start, .end = self.hir.spanOf(value).end },
                        value,
                    );
                    try props.append(self.gpa, spread_node);
                    if (!self.match(.comma)) break;
                    continue;
                }
                if (self.peek().kind == .asterisk) {
                    try self.reportCodeAt(dot_tok.span.start, dot_tok.line, 2698, "Spread types may only be created from object types.");
                    const star_tok = self.advance();
                    try self.reportCodeAt(star_tok.span.start, star_tok.line, 1109, "Expression expected.");
                    const value = self.parseAssignmentExpression() catch try self.missingIdentifierAt(star_tok.span.end);
                    const spread_node = try self.builder.addSpread(
                        .{ .start = dot_tok.span.start, .end = self.hir.spanOf(value).end },
                        value,
                    );
                    try props.append(self.gpa, spread_node);
                    if (!self.match(.comma)) break;
                    continue;
                }
                if (self.peek().kind == .kw_get and self.peekAt(1).kind == .identifier) {
                    const get_tok = self.advance();
                    try self.reportCodeAt(get_tok.span.start, get_tok.line, 2304, "Cannot find name 'get'.");
                    const value = try self.builder.addObjectLiteral(tokenSpan(get_tok), &.{});
                    const name_tok = self.peek();
                    try self.reportCodeAt(name_tok.span.start, name_tok.line, 1005, "',' expected.");
                    while (self.peek().kind != .eof and self.peek().kind != .close_brace) _ = self.advance();
                    if (self.peek().kind == .close_brace and self.peekAt(1).kind == .close_brace) _ = self.advance();
                    const spread_node = try self.builder.addSpread(
                        .{ .start = dot_tok.span.start, .end = self.hir.spanOf(value).end },
                        value,
                    );
                    try props.append(self.gpa, spread_node);
                    if (!self.match(.comma)) break;
                    continue;
                }
                const value = try self.parseAssignmentExpression();
                if (self.peek().kind == .open_brace) {
                    const body_open = self.advance();
                    try self.reportCodeAt(body_open.span.start, body_open.line, 1005, "',' expected.");
                    if (self.peek().kind == .close_brace and self.peekAt(1).kind == .close_brace) {
                        const body_close = self.advance();
                        try self.reportCodeAt(body_close.span.start + 1, body_close.line, 1128, "Declaration or statement expected.");
                    }
                }
                const value_end = self.hir.spanOf(value).end;
                const spread_node = try self.builder.addSpread(
                    .{ .start = dot_tok.span.start, .end = value_end },
                    value,
                );
                try props.append(self.gpa, spread_node);
                if (!self.match(.comma)) break;
                continue;
            }

            if (isAccessibilityModifier(self.peek().kind) and
                (self.peekAt(1).kind == .kw_get or self.peekAt(1).kind == .kw_set))
            {
                const mod = self.advance();
                const mod_name = self.source[mod.span.start..mod.span.end];
                const msg = try std.fmt.allocPrint(self.diag_arena.allocator(), "'{s}' modifier cannot be used here.", .{mod_name});
                try self.reportCodeAt(mod.span.start, mod.line, 1042, msg);
            }

            if (!method_is_async and
                !method_is_generator and
                (self.peek().kind == .kw_get or self.peek().kind == .kw_set) and
                (((self.peekAt(1).kind == .identifier or
                    self.peekAt(1).kind == .private_identifier or
                    self.peekAt(1).kind == .string_literal or
                    self.peekAt(1).kind == .number_literal or
                    self.peekAt(1).kind.isContextualKeyword()) and
                    (self.peekAt(2).kind == .open_paren or self.peekAt(2).kind == .less_than)) or
                    self.peekAt(1).kind == .open_bracket))
            {
                const accessor_kw = self.advance();
                var is_computed_key = false;
                const key = if (self.peek().kind == .open_bracket) blk: {
                    const ob = self.advance();
                    const expr = try self.parseAssignmentExpression();
                    _ = try self.expectClosingMatch(.close_bracket, "']' to close computed accessor key", ob.span.start, "[", "]");
                    is_computed_key = true;
                    break :blk expr;
                } else blk: {
                    const key_tok = self.advance();
                    var key_span = tokenSpan(key_tok);
                    if (key_tok.kind == .private_identifier) {
                        try self.reportCodeAt(key_tok.span.start, key_tok.line, 18016, "Private identifiers are not allowed outside class bodies.");
                        try self.reportPrivateIdentifierTargetDiagnostic(key_tok);
                    }
                    if (key_tok.kind == .number_literal and self.peek().kind == .dot and self.peekAt(1).kind == .open_paren) {
                        const dot_tok = self.advance();
                        key_span.end = dot_tok.span.end;
                    }
                    const key_id = try self.internPropertyName(key_tok, key_span);
                    break :blk try self.builder.addIdentifier(key_span, key_id);
                };
                var type_params: []NodeId = &.{};
                if (self.peek().kind == .less_than) {
                    type_params = try self.parseTypeParameterDeclaration();
                    const name_span = self.hir.spanOf(key);
                    try self.reportCodeAt(name_span.start, self.lineAt(name_span.start), 1094, "An accessor cannot have type parameters.");
                }
                defer if (type_params.len > 0) self.gpa.free(type_params);
                const params = try self.parseParameterList();
                defer self.gpa.free(params);
                var return_type: NodeId = hir_mod.none_node_id;
                if (self.match(.colon)) return_type = try self.parseReturnTypeAnnotation(params);
                try self.validateAccessorSignature(accessor_kw.kind, key, params, return_type);
                var body: NodeId = hir_mod.none_node_id;
                if (self.peek().kind == .open_brace) {
                    // Object-literal accessor bodies are function bodies
                    // — track the function depth so nested context-
                    // sensitive parsing (e.g. `yield` inside a getter
                    // body) routes through the in-function path that
                    // reports TS1163 instead of treating `yield` as a
                    // top-level identifier (TS1212). Mirrors fixture
                    // `YieldExpression17_es6` where `get foo() { yield foo; }`
                    // baselines a single TS1163, not TS1212.
                    self.function_depth += 1;
                    const prev_generator_depth = self.generator_depth;
                    self.generator_depth = 0;
                    defer {
                        self.generator_depth = prev_generator_depth;
                        self.function_depth -= 1;
                    }
                    body = try self.parseBlockStatement();
                }
                const value = try self.builder.addFnDeclGeneric(
                    .{ .start = accessor_kw.span.start, .end = self.tokens[self.cursor - 1].span.end },
                    key,
                    type_params,
                    params,
                    return_type,
                    body,
                    .{
                        .is_method = true,
                        .is_getter = accessor_kw.kind == .kw_get,
                        .is_setter = accessor_kw.kind == .kw_set,
                    },
                );
                const prop = try self.builder.addObjectProperty(
                    .{ .start = prop_start.span.start, .end = self.tokens[self.cursor - 1].span.end },
                    key,
                    value,
                    is_computed_key,
                    false,
                    true,
                );
                try props.append(self.gpa, prop);
                if (!self.match(.comma)) break;
                continue;
            }

            // Computed key: `[expr]: value`.
            var key: NodeId = undefined;
            var is_computed = false;
            var can_be_shorthand_property = false;
            var accessibility_shorthand_before_computed = false;
            if (self.peek().kind == .open_bracket) {
                const obj_key_open = self.advance();
                key = try self.parseAssignmentExpression();
                // tsc parses the full Expression inside the brackets so it
                // can recognize a comma expression as a key. TS1171 is
                // emitted by the checker (after TS2695 from
                // `comma_left_unused`) so the ordering at identical
                // `(line,col)` matches tsc's `35.ts(2,6)` baseline.
                if (self.peek().kind == .comma) {
                    while (self.match(.comma)) {
                        const right = try self.parseAssignmentExpression();
                        key = try self.builder.addBinaryOp(
                            .{ .start = self.hir.spanOf(key).start, .end = self.hir.spanOf(right).end },
                            .comma,
                            key,
                            right,
                        );
                    }
                }
                if (self.peek().kind == .close_bracket) {
                    _ = self.advance();
                } else {
                    try self.reportCodeAtWithMatchedPair(
                        self.peek().span.start,
                        self.peek().line,
                        1005,
                        "']' expected.",
                        obj_key_open.span.start,
                        "[",
                        "]",
                    );
                }
                is_computed = true;
            } else {
                // Template literal as a property key is invalid. tsc
                // closes the object literal at this point (without
                // consuming the template), emits TS1136, and lets the
                // outer call-expression continuation pick the
                // template up as the tag of a tagged-template call.
                // Mirrors templateStringInObjectLiteral{,ES6} where
                // `{ a: ..., \`b\`: 321 }` ends up as `{a:...}\`b\`:
                // 321 }` with the trailing `: 321 }` driven by the
                // var-decl `,` recovery + stray `}` TS1128 path.
                if (self.peek().kind == .no_substitution_template or
                    self.peek().kind == .template_head)
                {
                    const tmpl = self.peek();
                    try self.reportCodeAt(tmpl.span.start, tmpl.line, 1136, "Property assignment expected.");
                    return try self.builder.addObjectLiteral(
                        .{ .start = start.span.start, .end = tmpl.span.start },
                        props.items,
                    );
                }
                const key_tok = self.advance();
                accessibility_shorthand_before_computed = isAccessibilityModifier(key_tok.kind) and
                    self.peek().kind == .open_bracket;
                can_be_shorthand_property = isExpressionIdentifierToken(key_tok.kind) or
                    accessibility_shorthand_before_computed;
                var key_span = tokenSpan(key_tok);
                // TS18016: private identifiers are not allowed outside
                // class bodies. tsc fires this at the `#foo` key of
                // an object literal. Mirrors fixture
                // `privateNameInObjectLiteral-1`.
                if (key_tok.kind == .private_identifier) {
                    try self.reportCodeAt(key_tok.span.start, key_tok.line, 18016, "Private identifiers are not allowed outside class bodies.");
                }
                // TS1539: a `bigint` literal (e.g. `1n`) cannot be used
                // as a property name. tsc's grammar check fires this at
                // the literal token for object-literal property
                // assignments. Mirrors upstream
                // `checkGrammarObjectLiteralExpression`.
                if (key_tok.kind == .bigint_literal) {
                    try self.reportCodeAtWithSpan(
                        key_span.start,
                        key_tok.line,
                        key_span.end - key_span.start,
                        1539,
                        "A 'bigint' literal cannot be used as a property name.",
                    );
                }
                if (key_tok.kind == .number_literal and self.peek().kind == .dot and self.peekAt(1).kind == .colon) {
                    const dot_tok = self.advance();
                    key_span.end = dot_tok.span.end;
                }
                const key_id = try self.internPropertyName(key_tok, key_span);
                key = try self.builder.addIdentifier(key_span, key_id);
            }

            var value: NodeId = hir_mod.none_node_id;
            var is_shorthand = false;
            var is_method = false;
            if (!is_computed and self.peek().kind == .question) {
                const question_tok = self.advance();
                try self.reportCodeAt(question_tok.span.start, question_tok.line, 1162, "An object member cannot be declared optional.");
            }
            var recovered_missing_colon_value = false;
            if (method_is_generator and self.peek().kind != .less_than and self.peek().kind != .open_paren) {
                const key_span_for_error = self.hir.spanOf(key);
                const anchor_pos = if (self.peek().kind == .colon or self.peek().kind == .equal)
                    self.peek().span.start
                else if (self.hir.kindOf(key) == .identifier and
                    (self.peek().kind == .identifier or self.peek().kind.isContextualKeyword()))
                    self.peek().span.start
                else
                    key_span_for_error.start;
                try self.reportCodeAt(anchor_pos, self.lineAt(anchor_pos), 1005, "'(' expected.");
                var depth: u32 = 0;
                while (self.peek().kind != .eof) {
                    const k = self.peek().kind;
                    if (depth == 0 and (k == .close_brace or k == .comma)) break;
                    if (k == .open_brace or k == .open_paren or k == .open_bracket) {
                        depth += 1;
                    } else if (k == .close_brace or k == .close_paren or k == .close_bracket) {
                        if (depth > 0) depth -= 1;
                    }
                    _ = self.advance();
                }
                const fn_node = try self.builder.addFnDeclGeneric(
                    .{ .start = prop_start.span.start, .end = if (self.cursor > 0) self.tokens[self.cursor - 1].span.end else prop_start.span.end },
                    hir_mod.none_node_id,
                    &.{},
                    &.{},
                    hir_mod.none_node_id,
                    hir_mod.none_node_id,
                    .{
                        .is_method = true,
                        .is_async = method_is_async,
                        .is_generator = true,
                    },
                );
                const prop = try self.builder.addObjectProperty(
                    .{ .start = prop_start.span.start, .end = if (self.cursor > 0) self.tokens[self.cursor - 1].span.end else prop_start.span.end },
                    key,
                    fn_node,
                    is_computed,
                    false,
                    true,
                );
                try props.append(self.gpa, prop);
                if (!self.match(.comma)) break;
                continue;
            }
            if (self.match(.colon)) {
                if (arrayLiteralElementCanStart(self.peek().kind)) {
                    value = try self.parseAssignmentExpression();
                } else {
                    try self.reportCodeAt(self.peek().span.start, self.peek().line, 1109, "Expression expected.");
                    recovered_missing_colon_value = true;
                }
            } else if (method_is_generator or self.peek().kind == .less_than or self.peek().kind == .open_paren) {
                // Method shorthand: `{ foo<T>() {} }`.
                var type_params: []NodeId = &.{};
                var owns_tps = false;
                if (self.peek().kind == .less_than) {
                    type_params = try self.parseTypeParameterDeclaration();
                    owns_tps = true;
                }
                defer if (owns_tps) self.gpa.free(type_params);
                if (method_is_generator) self.generator_depth += 1;
                if (method_is_async) self.async_function_depth += 1;
                const params = try self.parseParameterList();
                if (method_is_generator) self.generator_depth -= 1;
                if (method_is_async) self.async_function_depth -= 1;
                defer self.gpa.free(params);
                var return_type: NodeId = hir_mod.none_node_id;
                var invalid_post_params_optional = false;
                if (self.peek().kind == .question) {
                    const question_tok = self.advance();
                    invalid_post_params_optional = true;
                    try self.reportCodeAt(question_tok.span.start, question_tok.line, 1005, "'{' expected.");
                    if (self.peek().kind == .colon) {
                        const colon_tok = self.advance();
                        try self.reportCodeAt(colon_tok.span.start, colon_tok.line, 1136, "Property assignment expected.");
                        while (self.peek().kind != .close_brace and
                            self.peek().kind != .comma and
                            self.peek().kind != .eof)
                        {
                            _ = self.advance();
                        }
                        if (self.peek().kind == .close_brace) {
                            const close_tok = self.peek();
                            try self.reportCodeAt(close_tok.span.start, close_tok.line, 1005, "':' expected.");
                        }
                    }
                }
                if (self.match(.colon)) return_type = try self.parseReturnTypeAnnotation(params);
                var body: NodeId = hir_mod.none_node_id;
                if (invalid_post_params_optional) {
                    // Diagnostics above recover the malformed tail.
                } else if (self.peek().kind == .open_brace) {
                    const prev_generator_depth = self.generator_depth;
                    self.generator_depth = if (method_is_generator) prev_generator_depth + 1 else 0;
                    defer self.generator_depth = prev_generator_depth;
                    self.function_depth += 1;
                    if (method_is_async) self.async_function_depth += 1;
                    defer {
                        self.function_depth -= 1;
                        if (method_is_async) self.async_function_depth -= 1;
                    }
                    body = try self.parseBlockStatement();
                } else {
                    // An object-literal method shorthand (`foo(...)`) must have
                    // a body. When the body is missing, tsc reports `'{' expected`
                    // at the token where the body should begin (e.g. the `,` in
                    // `{ foo(x = 1), }`). Mirrors
                    // callSignaturesWithParameterInitializers2.
                    const tok = self.peek();
                    try self.reportCodeAt(tok.span.start, tok.line, 1005, "'{' expected.");
                }
                value = try self.builder.addFnDeclGeneric(
                    .{ .start = prop_start.span.start, .end = self.tokens[self.cursor - 1].span.end },
                    hir_mod.none_node_id,
                    type_params,
                    params,
                    return_type,
                    body,
                    .{
                        .is_method = true,
                        .is_async = method_is_async,
                        .is_generator = method_is_generator,
                    },
                );
                is_method = true;
            } else if (can_be_shorthand_property) {
                // Shorthand property: `{ foo }` — value mirrors the
                // key. With trailing `= expr` it's the
                // CoverInitializedName production used in destructuring
                // assignment patterns like `({ y = E.x } = o)` and the
                // for-of variant `for ({y = E.x} of …)`. Lower to an
                // assignment node so destructuring checks observe the
                // default value.
                is_shorthand = true;
                if (self.peek().kind == .equal) {
                    _ = self.advance();
                    const default_expr = try self.parseAssignmentExpression();
                    value = try self.builder.addAssignment(
                        .{ .start = self.hir.spanOf(key).start, .end = self.hir.spanOf(default_expr).end },
                        key,
                        default_expr,
                        null,
                    );
                } else {
                    value = key;
                }
            } else {
                try self.reportCodeAt(self.peek().span.start, self.peek().line, 1005, "':' expected.");
            }
            const prop = try self.builder.addObjectProperty(
                .{ .start = prop_start.span.start, .end = self.tokens[self.cursor - 1].span.end },
                key,
                value,
                is_computed,
                is_shorthand,
                is_method,
            );
            try props.append(self.gpa, prop);
            if (self.match(.comma)) continue;
            if (accessibility_shorthand_before_computed and self.peek().kind == .open_bracket) continue;
            if (is_computed and self.peek().kind == .close_bracket) {
                const close = self.advance();
                try self.reportCodeAt(close.span.start, close.line, 1005, "',' expected.");
                continue;
            }
            if (recovered_missing_colon_value and objectLiteralPropertyCanStart(self.peek().kind)) continue;
            // Recover from missing `,` between properties — TS reports
            // TS1005 at the offending token and continues parsing the
            // next property. Mirrors `tsc`'s `parseDelimitedList` recovery
            // for object literals (matters for fixtures like
            // `stringNamedPropertyDuplicates` whose intentional missing
            // commas would otherwise abort the whole source-file parse).
            if (objectLiteralPropertyCanStart(self.peek().kind)) {
                try self.reportCodeAt(self.peek().span.start, self.peek().line, 1005, "',' expected.");
                continue;
            }
            break;
        }
        if (self.peek().kind == .semicolon and self.peekAt(1).kind == .close_brace and props.items.len > 0) {
            const semi = self.advance();
            try self.reportCodeAt(semi.span.start, semi.line, 1005, "',' expected.");
            const close = self.advance();
            return try self.builder.addObjectLiteral(.{ .start = start.span.start, .end = close.span.end }, props.items);
        }
        if (self.peek().kind == .semicolon) {
            const semi = self.advance();
            try self.reportCodeAtWithMatchedPair(
                semi.span.end,
                semi.line,
                1005,
                "'}' expected.",
                start.span.start,
                "{",
                "}",
            );
            return try self.builder.addObjectLiteral(.{ .start = start.span.start, .end = semi.span.end }, props.items);
        }
        const close = try self.expectClosingMatch(.close_brace, "'}' to close object literal", start.span.start, "{", "}");
        return try self.builder.addObjectLiteral(.{ .start = start.span.start, .end = close.span.end }, props.items);
    }

    /// Returns true when `kind` can begin an object-literal property —
    /// used by `parseObjectLiteral` to recover from missing comma
    /// separators (TS1005) without aborting the whole file parse.
    fn objectLiteralPropertyCanStart(kind: TokenKind) bool {
        return switch (kind) {
            .identifier,
            .private_identifier,
            .string_literal,
            .number_literal,
            .open_bracket,
            .dot_dot_dot,
            .asterisk,
            .no_substitution_template,
            .template_head,
            => true,
            else => kind.isKeyword() or kind.isContextualKeyword(),
        };
    }

    /// Accept any token that can appear after `.` — identifier or
    /// keyword (`obj.class`, `obj.let`, etc., are valid because
    /// keywords are allowed as property names).
    fn expectIdentifierLike(self: *Parser) ParseError!Token {
        const t = self.peek();
        if (t.kind == .identifier or t.kind == .private_identifier or t.kind.isKeyword()) {
            return self.advance();
        }
        if (t.kind == .invalid) {
            _ = self.advance();
            const recovered = self.peek();
            if (recovered.kind == .identifier or recovered.kind == .private_identifier or recovered.kind.isKeyword()) {
                return self.advance();
            }
            return t;
        }
        try self.reportCodeAt(t.span.start, t.line, 1003, "Identifier expected.");
        return error.UnexpectedToken;
    }

    fn expectModuleExportName(self: *Parser) ParseError!Token {
        const t = self.peek();
        if (self.tokenCanStartModuleExportName(t)) {
            return self.advance();
        }
        try self.reportCodeAt(t.span.start, t.line, 1003, "Identifier expected.");
        return error.UnexpectedToken;
    }

    fn tokenCanStartModuleExportName(_: *Parser, tok: Token) bool {
        return tok.kind == .string_literal or tok.kind == .identifier or tok.kind.isKeyword();
    }

    /// Port of tsgo's `parseImportOrExportSpecifier`. The leading contextual
    /// `type` is only a modifier when the following token sequence proves it;
    /// otherwise it remains the imported/exported name.
    fn parseImportOrExportSpecifier(self: *Parser, is_import: bool) ParseError!ImportExportSpecifier {
        var name = try self.expectModuleExportName();
        var imported: ?Token = null;
        var is_type_only = false;
        var can_parse_as_keyword = true;
        var name_is_disallowed_import_keyword = is_import and name.kind.isKeyword() and !name.kind.isContextualKeyword();

        if (self.tokenTextEquals(name, "type")) {
            if (self.peek().kind == .kw_as) {
                const first_as = self.advance();
                if (self.peek().kind == .kw_as) {
                    const second_as = self.advance();
                    if (self.tokenCanStartModuleExportName(self.peek())) {
                        is_type_only = true;
                        imported = first_as;
                        name = self.advance();
                        name_is_disallowed_import_keyword = is_import and name.kind.isKeyword() and !name.kind.isContextualKeyword();
                        can_parse_as_keyword = false;
                    } else {
                        imported = name;
                        name = second_as;
                        name_is_disallowed_import_keyword = false;
                        can_parse_as_keyword = false;
                    }
                } else if (self.tokenCanStartModuleExportName(self.peek())) {
                    imported = name;
                    name = self.advance();
                    name_is_disallowed_import_keyword = is_import and name.kind.isKeyword() and !name.kind.isContextualKeyword();
                    can_parse_as_keyword = false;
                } else {
                    is_type_only = true;
                    name = first_as;
                    name_is_disallowed_import_keyword = false;
                }
            } else if (self.tokenCanStartModuleExportName(self.peek())) {
                is_type_only = true;
                name = self.advance();
                name_is_disallowed_import_keyword = is_import and name.kind.isKeyword() and !name.kind.isContextualKeyword();
            }
        }

        if (can_parse_as_keyword and self.match(.kw_as)) {
            imported = name;
            name = try self.expectModuleExportName();
            name_is_disallowed_import_keyword = is_import and name.kind.isKeyword() and !name.kind.isContextualKeyword();
        }

        if (is_import and (name.kind == .string_literal or name_is_disallowed_import_keyword)) {
            try self.reportCodeAt(name.span.start, name.line, 1003, "Identifier expected.");
        }

        return .{
            .imported = imported orelse name,
            .local = name,
            .is_type_only = is_type_only,
        };
    }

    fn internModuleExportName(self: *Parser, tok: Token) ParseError!hir_mod.StringId {
        return if (tok.kind == .string_literal)
            try self.internStringLiteral(tok)
        else
            try self.internToken(tok);
    }

    fn accessibilityKeywordIsMemberRoot(self: *Parser, tok: Token) bool {
        if (self.strict_mode) return false;
        return switch (tok.kind) {
            .kw_public, .kw_private, .kw_protected, .kw_static => self.peek().kind == .dot or self.peek().kind == .open_bracket,
            else => false,
        };
    }

    fn findStandaloneInstantiationTypeArgsEnd(self: *Parser, start: u32) ?u32 {
        if (start >= self.tokens.len or self.tokens[start].kind != .less_than) return null;
        var depth: i32 = 1;
        var i: u32 = start + 1;
        while (i < self.tokens.len) : (i += 1) {
            const tk = self.tokens[i].kind;
            switch (tk) {
                .less_than => depth += 1,
                .greater_than, .greater_greater, .greater_greater_greater => {
                    const count: u8 = switch (tk) {
                        .greater_than => 1,
                        .greater_greater => 2,
                        .greater_greater_greater => 3,
                        else => unreachable,
                    };
                    var n: u8 = 0;
                    while (n < count) : (n += 1) {
                        depth -= 1;
                        if (depth == 0) {
                            const next = i + 1;
                            if (next >= self.tokens.len) return null;
                            switch (self.tokens[next].kind) {
                                .semicolon,
                                .comma,
                                .colon,
                                .question,
                                .close_paren,
                                .close_bracket,
                                .close_brace,
                                .eof,
                                => return next,
                                else => return null,
                            }
                        }
                    }
                },
                .open_paren, .open_bracket, .open_brace => {
                    if (self.skipBalancedFrom(i)) |after| {
                        i = after - 1;
                    } else return null;
                },
                .equal,
                .semicolon,
                .arrow,
                .question_dot,
                .invalid,
                .eof,
                => return null,
                else => {},
            }
        }
        return null;
    }
};

