test "parser: invalid bitwise-not operations preserve declaration recovery" {
    var s = try newTestSetup(
        \\var q;
        \\var a = q~;
        \\var mul = ~[1, 2, "abc"], "";
        \\var b =~;
    );
    defer destroyTestSetup(s);

    const root = try s.parser.parseSourceFile();
    const stmts = hir_mod.blockStmts(&s.hir, root);
    try T.expectEqual(@as(usize, 4), stmts.len);
    const expected_codes = [_]u32{ 1005, 1109, 1134, 1109 };
    try T.expectEqual(expected_codes.len, s.parser.diagnostics.items.len);
    for (expected_codes, s.parser.diagnostics.items) |expected, diagnostic| {
        try T.expectEqual(expected, diagnostic.code);
    }
}

test "parser: nested var initializer preserves recovered binding" {
    var s = try newTestSetup(
        \\var NUMBER1 = var NUMBER-;
        \\var NUMBER2 = -(null - undefined);
        \\var NUMBER =-;
    );
    defer destroyTestSetup(s);

    const root = try s.parser.parseSourceFile();
    const stmts = hir_mod.blockStmts(&s.hir, root);
    try T.expectEqual(@as(usize, 4), stmts.len);
    const outer = hir_mod.varDeclOf(&s.hir, stmts[0]);
    try T.expectEqual(hir_mod.NodeKind.type_ref, s.hir.kindOf(outer.type_annotation));
    const recovered = hir_mod.varDeclOf(&s.hir, stmts[1]);
    try T.expectEqual(hir_mod.NodeKind.type_ref, s.hir.kindOf(recovered.type_annotation));
    const recovered_name = hir_mod.identifierOf(&s.hir, recovered.name);
    try T.expectEqualStrings("NUMBER", s.interner.get(recovered_name.name));
    const expected_codes = [_]u32{ 1109, 1005, 1109, 1109 };
    try T.expectEqual(expected_codes.len, s.parser.diagnostics.items.len);
    for (expected_codes, s.parser.diagnostics.items) |expected, diagnostic| {
        try T.expectEqual(expected, diagnostic.code);
    }
}

test "parser: for-init multi-declarator wraps every binding into the init block" {
    // `for (var i = 0, j = 10; i < j; i++, j--)` — the second
    // declarator `j` previously parsed-and-discarded, so any
    // reference to `j` inside the for header raised TS2304. Mirrors
    // `commaOperatorOtherValidOperation.ts` baseline (clean run).
    //
    // The current parser wraps multi-declarator inits in a synthetic
    // block as the for-stmt's `init` slot (rather than draining them
    // out to the enclosing block via `for_init_extras`). Validate that
    // shape so the binder + checker visit both `i` and `j`.
    var s = try newTestSetup("for (var i = 0, j = 10; i < j; i++, j--) {}");
    defer destroyTestSetup(s);
    const root = try s.parser.parseSourceFile();
    const stmts = hir_mod.blockStmts(&s.hir, root);
    try T.expectEqual(@as(usize, 1), stmts.len);
    try T.expectEqual(hir_mod.NodeKind.for_stmt, s.hir.kindOf(stmts[0]));
    const init = hir_mod.forStmtOf(&s.hir, stmts[0]).init;
    try T.expectEqual(hir_mod.NodeKind.block_stmt, s.hir.kindOf(init));
    const decls = hir_mod.blockStmts(&s.hir, init);
    try T.expectEqual(@as(usize, 2), decls.len);
    var saw_extra_var = false;
    for (decls) |stmt| {
        switch (s.hir.kindOf(stmt)) {
            .var_decl => {
                const v = hir_mod.varDeclOf(&s.hir, stmt);
                if (v.name != hir_mod.none_node_id and s.hir.kindOf(v.name) == .identifier) {
                    const name = hir_mod.identifierOf(&s.hir, v.name).name;
                    if (std.mem.eql(u8, s.parser.interner.get(name), "j")) saw_extra_var = true;
                }
            },
            else => {},
        }
    }
    try T.expect(saw_extra_var);
}

