    const asserted = hir_mod.asExpressionOf(&s.hir, loop.source);
    try T.expectEqual(hir_mod.NodeKind.binary_op, s.hir.kindOf(asserted.expr));
    try T.expectEqual(hir_mod.BinOp.in, hir_mod.binopOf(&s.hir, asserted.expr).op);
}

