        \\;<video data-\u0076ideo />;
        \\;<video \u0073rc="" />;
        \\let v = <a></\u0061>;
    );
    defer destroyTestSetup(s);
    _ = s.parser.parseSourceFile() catch {};

    var count: usize = 0;
    for (s.parser.diagnostics.items) |d| {
        if (d.code == 17021) {
            count += 1;
            try T.expectEqualStrings("Unicode escape sequence cannot appear here.", d.message);
        }
