    _ = try s.parser.parseSourceFile();
    var saw_1123 = false;
    var saw_1155 = false;
    for (s.parser.diagnostics.items) |d| {
        if (d.code == 1123) saw_1123 = true;
        if (d.code == 1155) saw_1155 = true;
    }
    try T.expect(saw_1123);
    try T.expect(!saw_1155);
}

