    _ = try s.parser.parseSourceFile();
    var count_1100: u32 = 0;
    for (s.parser.diagnostics.items) |d| {
        if (d.code == 1100) count_1100 += 1;
        try T.expect(d.code != 1215);
    }
    try T.expectEqual(@as(u32, 1), count_1100);
}

