    try T.expectEqualStrings("Declaration expected.", d.message);
    try T.expectEqual(@as(u32, 1), countDiag(s, 1005));
    try T.expectEqual(@as(u32, 1), countDiag(s, 1128));
    // TS1442 must NOT also fire for the same site — the swap is
